    // ─── Decision Layer V1 — DB helpers ───────────────────────────────────────

    // Load all blockers for a role (ordered by creation, oldest first).
    async function _loadRoleBlockers(roleId) {
      if (!roleId) return [];
      try {
        const { data, error } = await db
          .from('role_blockers')
          .select('id, blocker_key, label, evidence, user_state, created_at')
          .eq('role_id', roleId)
          .order('created_at', { ascending: true });
        if (error) throw error;
        return data || [];
      } catch (e) {
        console.warn('[_loadRoleBlockers]', e);
        return [];
      }
    }

    // Upsert a blocker record. If (role_id, blocker_key) already exists, update
    // user_state only. Otherwise insert. Returns the record or null on error.
    async function _upsertRoleBlocker(roleId, blockerKey, label, evidence, userState) {
      if (!roleId || !blockerKey) return null;
      try {
        const { data, error } = await db
          .from('role_blockers')
          .upsert(
            { role_id: roleId, blocker_key: blockerKey, label, evidence: evidence || null, user_state: userState || null },
            { onConflict: 'role_id,blocker_key' }
          )
          .select('id, blocker_key, label, evidence, user_state')
          .single();
        if (error) throw error;
        return data;
      } catch (e) {
        console.warn('[_upsertRoleBlocker]', e);
        return null;
      }
    }

    // Save a decision snapshot — role DNA + confirmed blockers + optional skip
    // reason and notes. Fire-and-forget; never throws to caller.
    async function _saveDecisionSnapshot(role, decision, { skipReason = null, skipReasonOther = null, notes = null, confirmedBlockers = [] } = {}) {
      if (!role?.id || !decision) return;
      const output = role.latest_match_output || role.analysis || {};
      const pd     = output.practical_details || {};
      const roleDna = {
        role_title:       role.role_title      || null,
        company_name:     role.company_name    || null,
        location_text:    role.location_text   || null,
        work_model:       role.work_model       || null,
        engagement_type:  role.engagement_type || null,
        ir35_status:      role.ir35_status      || null,
        salary_text_raw:  role.salary_text_raw || null,
        salary_annual:    pd.salary_annual      || null,
        working_pattern:  pd.working_pattern   || null,
        contract_type:    pd.contract_type      || null,
        role_archetype:   output.role_archetype  || null,
        rolewise_verdict: output.rolewise_verdict || null,
        source:           role.source           || null,
      };
      try {
        await db.from('role_decision_snapshots').insert({
          role_id:            role.id,
          user_decision:      decision,
          role_dna:           roleDna,
          confirmed_blockers: confirmedBlockers,
          skip_reason:        skipReason       || null,
          skip_reason_other:  skipReasonOther  || null,
          notes:              notes            || null,
        });
      } catch (e) {
        console.warn('[_saveDecisionSnapshot]', e);
      }
    }

    // Load the user's saved personal boundaries.
    async function _loadUserBoundaries() {
      try {
        const { data, error } = await db
          .from('user_boundaries')
          .select('id, blocker_key, label, boundary_type, created_at')
          .order('created_at', { ascending: false });
        if (error) throw error;
        return data || [];
      } catch (e) {
        console.warn('[_loadUserBoundaries]', e);
        return [];
      }
    }

    // Warms (or refreshes) the module-level _boundaryKeyCache.
    // Call at startup after refresh() and after any boundary is saved.
    async function _warmBoundaryCache() {
      try {
        const boundaries = await _loadUserBoundaries();
        _boundaryKeyCache = new Set(boundaries.map(b => b.blocker_key));
      } catch (_) {
        _boundaryKeyCache = new Set();
      }
    }

    // Upsert a personal boundary (hard or soft). profile_id comes from _profileId.
    async function _saveUserBoundary(blockerKey, label, boundaryType = 'hard') {
      if (!blockerKey || !_profileId) return;
      try {
        await db.from('user_boundaries').upsert(
          { profile_id: _profileId, blocker_key: blockerKey, label, boundary_type: boundaryType },
          { onConflict: 'profile_id,blocker_key' }
        );
        // Optimistic cache update so inbox indicators appear immediately
        if (_boundaryKeyCache) _boundaryKeyCache.add(blockerKey);
        else _boundaryKeyCache = new Set([blockerKey]);
      } catch (e) {
        console.warn('[_saveUserBoundary]', e);
      }
    }

    // ─────────────────────────────────────────────────────────────────────────

    // Lightweight workspace-presence check — 4 parallel HEAD queries, no row data fetched.
    // Returns true if the role has ANY record in any of the 4 workspace tables.
    // Used by renderRoleDoc to decide whether to open workspace or legacy view.
    async function _wsHasData(roleId) {
      if (!roleId) return false;
      try {
        const [convRes, artRes, interRes, insiRes] = await Promise.all([
          db.from('role_conversations').select('id', { count: 'exact', head: true }).eq('role_id', roleId).limit(1),
          db.from('role_artifacts')   .select('id', { count: 'exact', head: true }).eq('role_id', roleId).limit(1),
          db.from('role_interactions').select('id', { count: 'exact', head: true }).eq('role_id', roleId).limit(1),
          db.from('role_insights')    .select('id', { count: 'exact', head: true }).eq('role_id', roleId).limit(1),
        ]);
        return (convRes.count  || 0) > 0
            || (artRes.count   || 0) > 0
            || (interRes.count || 0) > 0
            || (insiRes.count  || 0) > 0;
      } catch (_) {
        return false; // on error, fall through to legacy view safely
      }
    }
    // ─────────────────────────────────────────────────────────────────────────

    // ── Accent theme ──────────────────────────────────────────────────────────
    const ACCENT_THEMES = {
      blue:   { accent: '#3B7DD8', soft: '#EAF2FF', soft2: '#D7E7FF' },
      indigo: { accent: '#5B6CF0', soft: '#EEF0FF', soft2: '#DDE2FF' },
      teal:   { accent: '#0F8B8D', soft: '#E7F7F7', soft2: '#D2EFEF' },
      forest: { accent: '#2F7A4A', soft: '#EAF5ED', soft2: '#D8ECDC' },
      plum:   { accent: '#7C4D8B', soft: '#F4ECF7', soft2: '#E7D8ED' },
    };
    function setAccentTheme(key) {
      const t = ACCENT_THEMES[key] || ACCENT_THEMES.blue;
      const r = document.documentElement;
      r.style.setProperty('--accent',        t.accent);
      r.style.setProperty('--accent-soft',   t.soft);
      r.style.setProperty('--accent-soft-2', t.soft2);
      try { localStorage.setItem('rw-accent-theme', key); } catch (_) {}
      document.querySelectorAll('.accent-swatch').forEach(el => {
        el.classList.toggle('active', el.dataset.theme === key);
      });
    }
    // Restore saved accent on page load
    (function () {
      const _saved = localStorage.getItem('rw-accent-theme');
      if (_saved && ACCENT_THEMES[_saved]) setAccentTheme(_saved);
    })();

    // ── Appearance mode (Light / Dark / System) ────────────────────────────────
    const _appearanceMQ = window.matchMedia('(prefers-color-scheme: dark)');
    function setAppearanceMode(mode) {
      const root = document.documentElement;
      const systemIsDark = _appearanceMQ.matches;
      if (mode === 'dark' || (mode === 'system' && systemIsDark)) {
        root.setAttribute('data-theme', 'dark');
      } else {
        root.removeAttribute('data-theme');
      }
      try { localStorage.setItem('rw-appearance-mode', mode); } catch (_) {}
      document.querySelectorAll('.appearance-mode-btn').forEach(el => {
        el.classList.toggle('active', el.dataset.mode === mode);
      });
    }
    // Re-apply when system preference changes (for System mode users)
    _appearanceMQ.addEventListener('change', () => {
      const _cur = localStorage.getItem('rw-appearance-mode') || 'system';
      if (_cur === 'system') setAppearanceMode('system');
    });
    // Apply on page load
    (function () {
      const _savedMode = localStorage.getItem('rw-appearance-mode') || 'system';
      setAppearanceMode(_savedMode);
    })();

    // ─── Location normalisation ───────────────────────────────────────────────
    // Strips intermediate region labels (e.g. "England", "California", "Bavaria")
    // from LinkedIn-style "City, Region, Country" strings and normalises country names.
    // Returns "City, Country" format, or the original string if no normalisation needed.
    function normaliseLocation(raw) {
      if (!raw || typeof raw !== 'string') return raw;
      // Strip parenthetical work model suffixes e.g. " (Remote)", " (Hybrid)"
      let loc = raw.replace(/\s*\([^)]*\)\s*$/, '').trim();
      // Country name normalisation map (lowercase input → canonical output)
      const COUNTRY_NORM = {
        'uk': 'United Kingdom', 'united kingdom': 'United Kingdom',
        'us': 'United States', 'usa': 'United States',
        'united states of america': 'United States', 'united states': 'United States',
        'ireland': 'Ireland', 'australia': 'Australia', 'canada': 'Canada',
        'germany': 'Germany', 'france': 'France', 'netherlands': 'Netherlands',
        'sweden': 'Sweden', 'spain': 'Spain', 'portugal': 'Portugal',
        'poland': 'Poland', 'czech republic': 'Czech Republic', 'czechia': 'Czech Republic',
        'romania': 'Romania', 'india': 'India', 'singapore': 'Singapore',
        'new zealand': 'New Zealand',
      };
      // Intermediate region labels to strip (lowercase)
      const STRIP_REGIONS = new Set([
        // UK regions / countries
        'england', 'scotland', 'wales', 'northern ireland', 'greater london',
        'greater manchester', 'west midlands', 'yorkshire', 'kent',
        // US states (abbreviated)
        'california', 'new york', 'texas', 'washington', 'massachusetts',
        'florida', 'illinois', 'pennsylvania', 'ohio', 'georgia',
        'north carolina', 'michigan', 'new jersey', 'virginia', 'arizona',
        'colorado', 'maryland', 'tennessee', 'minnesota', 'oregon',
        // German Bundesländer
        'bavaria', 'saxony', 'hesse', 'north rhine-westphalia', 'berlin',
        'hamburg', 'bavaria', 'lower saxony', 'rhineland-palatinate',
        // Other
        'ontario', 'british columbia', 'quebec', 'new south wales', 'victoria',
        'île-de-france', 'catalonia',
      ]);
      const parts = loc.split(',').map(p => p.trim()).filter(Boolean);
      if (parts.length < 2) return loc || null;
      const lastLower = parts[parts.length - 1].toLowerCase();
      const normCountry = COUNTRY_NORM[lastLower];
      if (normCountry) {
        if (parts.length >= 3) {
          const secondLastLower = parts[parts.length - 2].toLowerCase();
          if (STRIP_REGIONS.has(secondLastLower)) {
            const cityParts = parts.slice(0, parts.length - 2);
            return `${cityParts.join(', ')}, ${normCountry}`;
          }
        }
        const cityParts = parts.slice(0, parts.length - 1);
        return `${cityParts.join(', ')}, ${normCountry}`;
      }
      return loc || null;
    }

    // ─── Shared UI helpers ────────────────────────────────────────────────────

    // shortenReasonPhrase — trims a friction signal label to a clean 2–4 word phrase.
    // Avoids cutting mid-sentence by backing off from "bad" ending words.
    // Returns null if a clean phrase cannot be formed.
    function shortenReasonPhrase(label) {
      if (!label || typeof label !== 'string') return null;
      const trimmed = label.trim();
      const words   = trimmed.split(/\s+/);
      if (words.length <= 4) return trimmed; // Already short — use as-is

      // If phrase contains a mid-phrase conjunction, cut before it to avoid dangling "and/or"
      const conjIdx = words.findIndex((w, i) => i >= 1 && /^(and|or)$/i.test(w));
      if (conjIdx >= 2 && conjIdx <= 4) {
        return words.slice(0, conjIdx).join(' ');
      }

      // Trim to 4 words max, backing off from words that make bad phrase endings
      const BAD_ENDINGS = new Set([
        'and','or','of','the','a','an','in','on','at','for','to','by','from',
        'with','but','nor','so','that','which','is','are','was','has','have',
        'been','be','means','carries','includes','involves','without','no','not',
        'very','more','less','quite',
      ]);
      for (let len = 4; len >= 2; len--) {
        const endWord = words[len - 1].toLowerCase().replace(/[.,;:!?]+$/, '');
        if (!BAD_ENDINGS.has(endWord)) return words.slice(0, len).join(' ');
      }
      return null; // Can't form a clean phrase — skip
    }

    // verdictDecisionReasons — returns up to 2 clean, short reason phrases for inbox cards.
    // Source: friction_signals labels only (risk text produces truncated fragments).
    function verdictDecisionReasons(output) {
      if (!output || typeof output !== 'object') return [];
      const reasons = [];

      if (Array.isArray(output.friction_signals)) {
        for (const f of output.friction_signals) {
          if (reasons.length >= 2) break;
          const phrase = f && f.label ? shortenReasonPhrase(f.label) : null;
          if (phrase) reasons.push(phrase);
        }
      }

      return reasons;
    }

    // verdictChipHtml — renders a calm chip badge for a Rolewise Verdict outcome.
    // small = true uses the compact .verdict-chip-sm variant (for inbox list rows).
    // Outcomes: "Worth exploring" | "Unclear fit" | "Lower alignment"
    function verdictChipHtml(outcome, small = false) {
      if (!outcome) return '';
      const styles = {
        'Worth exploring': 'background:#eef7f0;color:#2f6f44;border-color:#d6eadb;',
        'Unclear fit':     'background:#f4f5f7;color:#4b5563;border-color:#e5e7eb;',
        'Lower alignment': 'background:#fbefef;color:#7f3a3a;border-color:#f0d6d6;',
      };
      const style = styles[outcome] || 'background:#f4f5f7;color:#4b5563;border-color:#e5e7eb;';
      const cls   = small ? 'verdict-chip verdict-chip-sm' : 'verdict-chip';
      return `<span class="${cls}" style="${style}">${esc(outcome)}</span>`;
    }

    // ─── Helpers ──────────────────────────────────────────────────────────────
    function esc(s) {
      if (s == null) return '';
      return String(s)
        .replace(/&/g, '&amp;').replace(/</g, '&lt;')
        .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
    }

    // Guard against section headings or JD marketing copy stored as company name.
    function sanitiseCompanyName(name) {
      if (!name || typeof name !== 'string') return '';
      const n = name.trim();
      if (!n) return '';
      // Reject if ends with ":" — a section label, not a company name
      if (n.endsWith(':')) return '';
      const nl = n.toLowerCase();
      // Reject known JD section heading words
      const _headings = [
        'overview', 'role overview', 'job overview', 'about the role', 'about the job',
        'about us', 'about the company', 'introduction', 'summary', 'background',
        'responsibilities', 'requirements', 'qualifications', 'benefits', 'description',
        'the position', 'the role', 'the team',
      ];
      if (_headings.some(h => nl === h || nl === h + ':')) return '';
      // Reject if too short — single letters / two-letter fragments are not company names
      if (n.length < 3) return '';
      // Reject if too long — genuine company names are short
      if (n.length > 60) return '';
      // Reject if more than 5 words — almost certainly a JD sentence, not a name
      if (n.split(/\s+/).length > 5) return '';
      // Reject if it starts with common JD opener words (marketing / descriptive copy)
      if (/^(a |an |the |we |our |you |your |this |we're |we are |join us|about )/i.test(n)) return '';
      // Reject if it contains a comma followed by a capital letter — suggests a sentence fragment
      // e.g. "A Fast-Growing, International Design..." → company name would never look like this
      if (/,\s*[A-Z]/.test(n)) return '';
      // Reject ALL-CAPS strings longer than 3 words — tends to be JD copy, not company branding
      if (n === n.toUpperCase() && n.replace(/[^A-Z]/g, '').length > 3 && n.split(/\s+/).length > 3) return '';
      return n;
    }

    const STATUS_LABELS = {
      applied:     'Applied',
      in_progress: 'In progress',
      rejected:    'Rejected',
      skipped:     'Skipped',
    };

    // ─── State ────────────────────────────────────────────────────────────────
    let allRoles       = [];
    let selectedRoleId = null;
    let currentNav     = 'applications';
    let inboxTab       = 'active'; // 'active' | 'archive'
    let userProfile    = null;     // preferences_json from profiles table
    let _profileId     = null;     // profiles.id UUID — used as user_id in usage_events
    let _cachedCvVersions = null; // Loaded once on first use; re-used by computeFitAssessment
    let _boundaryKeyCache = null; // Set<string> of saved blocker keys; null = not yet loaded

    // ─── Analysis trace stages ────────────────────────────────────────────────
    // Shared between the workspace paste trace (_wsRunAnalysis), the Add JD modal
    // trace (saveRole), and the intake panel. Keep labels calm and factual.
    const _ANALYSIS_STAGES = [
      'Reading job description',
      'Extracting practical details',
      'Identifying likely risks',
      'Detecting role signals',
      'Preparing fit summary',
      'Finalising analysis',
    ];
    // Timer offsets (ms) for advancing from stage 1 → 2 → 3 → 4 → 5 → 6.
    // Stage 1 is active at t=0. These fire stages 2–6.
    // Calibrated to a typical AI response time of 6–14s; later stages may not
    // be reached before the API returns — that is correct and expected.
    const _ANALYSIS_TIMINGS = [1800, 3600, 5400, 7200, 9500];

    // ─── Recruiter state ──────────────────────────────────────────────────────
    let allRecruiters        = [];
    let selectedRecruiterId  = null;
    const RC_FOLLOWUP_NO_REPLY_DAYS  = 5;   // Recruiter contacted; no reply for N days
    const RC_FOLLOWUP_ACTIVE_ROLE_DAYS = 7; // Active role with no update for N days

    let compareRoleIds = new Set(); // Role IDs selected for the comparison panel (max 3)

    // ─── Filter panel state ───────────────────────────────────────────────────
    let filterPanelOpen   = false;
    let listPanelVisible  = true;  // mirrors current setListPanelVisible state
    let rightPanelVisible = true;  // false on Radar, Recruiters, Review
    const filterState = {
      decision:   new Set(),  // 'awaiting' | 'apply' | 'save' | 'skip'
      engagement: new Set(),  // 'Contract' | 'Permanent' | 'Freelance'
      workModel:  new Set(),  // 'remote' | 'hybrid' | 'on-site'
      response:   new Set(),  // 'active' | 'waiting' | 'stale' | 'ghosted'
      recruiter:  new Set(),  // 'with' | 'without'
    };
    function _hasActiveFilters() {
      return filterState.decision.size > 0 || filterState.engagement.size > 0 ||
             filterState.workModel.size > 0  || filterState.response.size > 0  ||
             filterState.recruiter.size > 0;
    }
    function _applyGridColumns() {
      const app = document.querySelector('.app');
      if (!app) return;
      const fw = (listPanelVisible && filterPanelOpen) ? '220px' : '0px';
      const lw = listPanelVisible ? '260px' : '0px';
      const rw = rightPanelVisible ? '360px' : '0px';
      app.style.gridTemplateColumns = `204px ${fw} ${lw} 1fr ${rw}`;
    }

    // Reset the chat panel to its empty state (no role selected).
    // Removes ws-active, clears all conversation history, and shows the idle message.
    function _resetChatPanel() {
      const chatEl = document.getElementById('col-chat');
      if (!chatEl) return;
      chatEl.classList.remove('ws-active');
      chatEl.innerHTML = '<div class="doc-empty">Select a role from the list to open the workspace.</div>';
    }

    // Show or hide the decision rail section within the overview panel.
    // Rail is visible only when a role is selected in Applications view.
    // Hiding the rail also clears the sticky header (no role context needed).
    // Set the Applications inbox filter and sync the active state on nav sub-items.
    // Use this everywhere inboxTab is set so the nav always stays in sync.
    function _setAppFilter(filter) {
      inboxTab = filter;
      document.querySelectorAll('.nav-sub-item').forEach(b =>
        b.classList.toggle('active', b.dataset.filter === filter)
      );
    }

    function _setRailVisible(visible) {
      const railEl  = document.getElementById('col-rail-section');
      const chipsEl = document.getElementById('role-chips-section');
      if (railEl)  railEl.style.display  = visible ? '' : 'none';
      if (chipsEl) chipsEl.style.display = visible ? '' : 'none';
      if (!visible) {
        if (railEl)  railEl.innerHTML  = '';
        if (chipsEl) chipsEl.innerHTML = '';
        // Clear decision capture, blockers, and history slots (inside .rw-overview-wrap)
        const dcEl = document.getElementById('ws-decision-capture');
        if (dcEl) { dcEl.innerHTML = ''; dcEl.style.display = 'none'; }
        const bsEl = document.getElementById('ws-blockers-section');
        if (bsEl) { bsEl.innerHTML = ''; bsEl.style.display = 'none'; }
        const dhEl = document.getElementById('ws-decision-history-dl');
        if (dhEl) { dhEl.innerHTML = ''; dhEl.style.display = 'none'; }
        _clearStickyHeader();
        _clearRoleHeader();
        _clearNextAction();
        _clearJDSection();
      }
    }

    // Populate the sticky role context strip pinned to the top of the overview panel.
    function _renderStickyHeader(role) {
      const el = document.getElementById('role-sticky-header');
      if (!el || !role) return;
      const parts = [];
      if (role.location_text) parts.push(esc(role.location_text));
      if (role.work_model && role.work_model !== 'unknown') {
        parts.push(esc(role.work_model.charAt(0).toUpperCase() + role.work_model.slice(1)));
      }
      if (role.salary_text_raw) parts.push(esc(role.salary_text_raw));
      const company = sanitiseCompanyName(role.company_name) || '';
      const metaParts = company ? [company, ...parts] : parts;
      el.innerHTML = `
        <div class="rsh-title">${esc(role.role_title || 'Untitled role')}</div>
        ${metaParts.length ? `<div class="rsh-meta">${metaParts.join(' · ')}</div>` : ''}
      `;
      el.style.display = '';
    }

    // Hide and clear the sticky role context strip.
    function _clearStickyHeader() {
      const el = document.getElementById('role-sticky-header');
      if (el) { el.innerHTML = ''; el.style.display = 'none'; }
    }

    // ── Role Header (overview column) ─────────────────────────────────────────
    // Prominent header at the top of .rw-overview-wrap. Shows company, title, metadata,
    // added date, and action buttons. Prepended as first child of .rw-overview-wrap so
    // it shares the wrap's padding and sits inside the overview flow, not above it.
    // Idempotent — removes any existing #col-role-header before injecting a fresh one.

    function _renderRoleHeader(role) {
      // Remove any existing instance (wrap may have been replaced)
      document.querySelectorAll('#col-role-header').forEach(el => el.remove());
      if (!role || role._isTemp) return;

      const _company  = sanitiseCompanyName(role.company_name) || null;
      const _title    = role.role_title || 'Untitled role';

      // Metadata parts: Location (Work model) · Engagement type
      const _metaParts = [];
      if (role.location_text) {
        const _wmRaw   = role.work_model && role.work_model !== 'unknown' ? role.work_model : null;
        const _wmLabel = _wmRaw ? (_wmRaw.charAt(0).toUpperCase() + _wmRaw.slice(1)) : null;
        _metaParts.push(esc(_wmLabel ? `${role.location_text} (${_wmLabel})` : role.location_text));
      } else if (role.work_model && role.work_model !== 'unknown') {
        _metaParts.push(esc(role.work_model.charAt(0).toUpperCase() + role.work_model.slice(1)));
      }
      if (role.engagement_type && role.engagement_type !== 'Unknown') {
        _metaParts.push(esc(role.engagement_type));
      }
      const _metaLine = _metaParts.join(' · ');

      const _days = Math.floor((Date.now() - new Date(role.created_at).getTime()) / 86400000);
      const _addedLabel = _days === 0 ? 'Added today'
        : _days === 1 ? 'Added yesterday'
        : `Added ${_days} days ago`;

      const headerEl = document.createElement('div');
      headerEl.id        = 'col-role-header';
      headerEl.className = 'col-role-header';
      headerEl.innerHTML = `
        <div class="rh-inner">
          <div class="rh-left">
            <div class="rh-company">${_company ? esc(_company.toUpperCase()) : 'COMPANY NOT SPECIFIED'}</div>
            <div class="rh-title">${esc(_title)}</div>
            ${_metaLine ? `<div class="rh-meta">${_metaLine}</div>` : ''}
            <div class="rh-added">${esc(_addedLabel)}</div>
          </div>
          <div class="rh-actions">
            <button class="btn-edit-details" id="rh-btn-edit-details" data-role-id="${esc(role.id)}">Edit details</button>
            <button class="btn-share-analysis" id="rh-btn-share-analysis" data-role-id="${esc(role.id)}" style="display:none;">Share analysis</button>
            ${window.ROLEWISE_REASONING_MAP ? `<button class="btn-reasoning-map" id="rh-btn-reasoning-map" data-role-id="${esc(role.id)}" title="Open Reasoning Map — advanced signal inspection">Reasoning Map ↗</button>` : ''}
          </div>
        </div>`;

      // Prepend inside .rw-overview-wrap so the header is the first card in the flow.
      // Falls back to #col-overview-cards if the wrap hasn't been created yet.
      const wrap    = document.querySelector('#col-overview-cards .rw-overview-wrap');
      const fallback = document.getElementById('col-overview-cards');
      (wrap || fallback)?.prepend(headerEl);
    }

    function _clearRoleHeader() {
      document.querySelectorAll('#col-role-header').forEach(el => el.remove());
    }

    // ─── Overview lower-card slots ─────────────────────────────────────────────
    // Ensures the four ordered slot divs (Blockers, My Verdict, Original JD,
    // Stage/Outcome) exist inside .rw-overview-wrap, right after the Fit Assessment.
    // Idempotent — safe to call multiple times; will not create duplicates.
    // Must be called before any of the four render functions populate their slot.
    function _ensureOverviewLowerCards() {
      const wrap = document.querySelector('#col-overview-cards .rw-overview-wrap');
      if (!wrap) return;
      // Already created — nothing to do
      if (wrap.querySelector('#ws-blockers-section')) return;

      const slots = [
        { id: 'ws-blockers-section',    cls: null },           // Decision Layer V1: blockers
        { id: 'ws-decision-capture',    cls: null },
        { id: 'ws-decision-history-dl', cls: null },           // Decision Layer V1: history read view
        { id: 'col-jd-section',         cls: 'col-jd-section' },
        { id: 'role-chips-section',     cls: 'role-chips-section' },
      ];

      // Insert after Fit Assessment card; fall back to end of wrap
      const faCard = wrap.querySelector('#section-fit-assessment');
      let anchor = faCard || null;

      for (const slot of slots) {
        const el = document.createElement('div');
        el.id = slot.id;
        if (slot.cls) el.className = slot.cls;
        el.style.display = 'none';
        if (anchor) {
          anchor.insertAdjacentElement('afterend', el);
        } else {
          wrap.appendChild(el);
        }
        anchor = el; // each subsequent slot goes after the previous
      }
    }

    // ─── Original Job Description card (overview panel) ───────────────────────
    // Shows the pasted JD text and optional source URL in a collapsible card.
    // Called from _wsHandlePaste (fresh JD paste), _wsRenderTimelineEntry
    // (history restore), and the mismatch "Keep here" handler.
    function _renderJDSection(role, jdText) {
      _ensureOverviewLowerCards();
      const el = document.getElementById('col-jd-section');
      if (!el || !jdText) return;

      const wordCount = jdText.trim().split(/\s+/).filter(Boolean).length;
      const fullId    = 'jd-full-' + ((role && role.id) ? role.id : 'tmp');
      const urlHtml   = (role && role.job_url)
        ? `<div class="jd-source-row"><a href="${esc(role.job_url)}" target="_blank" rel="noopener" class="jd-source-link">View original posting</a></div>`
        : '';

      el.innerHTML = `
        <div class="jd-card">
          <div class="jd-card-header">
            <span class="jd-card-title">Original job description</span>
            <div class="jd-card-meta">
              <span class="jd-word-count">${wordCount.toLocaleString()} words</span>
              <button class="jd-toggle" data-target="${esc(fullId)}" aria-expanded="false">Show</button>
            </div>
          </div>
          ${urlHtml}
          <div class="jd-full hidden" id="${esc(fullId)}"><pre class="jd-pre">${esc(jdText)}</pre></div>
        </div>`;
      el.style.display = '';

      el.querySelector('.jd-toggle')?.addEventListener('click', function () {
        const target = document.getElementById(this.dataset.target);
        if (!target) return;
        const isOpen = !target.classList.contains('hidden');
        target.classList.toggle('hidden', isOpen);
        this.textContent = isOpen ? 'Show' : 'Hide';
        this.setAttribute('aria-expanded', String(!isOpen));
      });
    }

    function _clearJDSection() {
      const el = document.getElementById('col-jd-section');
      if (el) { el.innerHTML = ''; el.style.display = 'none'; }
    }

    // ─── Next-action bar (overview panel) ────────────────────────────────────
    // Clears the ws-next-action container (decision bar moved to overview).
    function _clearNextAction() {
      const el = document.getElementById('ws-next-action');
      if (el) { el.innerHTML = ''; el.style.display = 'none'; }
    }

    // Exit the Add JD intake mode — hide the intake panel and restore the col-chat column.
    // Safe to call at any time; no-ops if intake mode is not currently active.
    function _exitIntakeMode() {
      const intakeEl = document.getElementById('intake-panel');
      if (intakeEl) {
        intakeEl._clearTimers?.();
        intakeEl.setAttribute('hidden', '');
        intakeEl.classList.remove('intake-panel--exit');
        delete intakeEl.dataset.cleanupPending;
      }
      document.querySelector('.app')?.classList.remove('intake-mode');
    }

    // Wire the intake panel to the hidden ws-workspace in col-chat.
    // Called once by openBlankWorkspace after renderWorkspaceView has populated col-chat.
    function _wireIntakePanel(tempRole) {
      const intakeEl     = document.getElementById('intake-panel');
      const textareaEl   = document.getElementById('intake-textarea');
      const sendBtnEl    = document.getElementById('intake-send-btn');
      const inputWrapEl  = document.getElementById('intake-input-wrap');
      const statusWrapEl = document.getElementById('intake-status-wrap');
      const statusTextEl = document.getElementById('intake-status-text');
      if (!intakeEl || !textareaEl || !sendBtnEl) return;

      // Reset state — panel may have been used in a previous Add JD session
      inputWrapEl.removeAttribute('hidden');
      statusWrapEl.setAttribute('hidden', '');
      textareaEl.value = '';
      sendBtnEl.disabled = true;

      // Auto-grow and enable send button
      textareaEl.addEventListener('input', () => {
        textareaEl.style.height = 'auto';
        textareaEl.style.height = Math.min(textareaEl.scrollHeight, 260) + 'px';
        sendBtnEl.disabled = !textareaEl.value.trim();
      });

      textareaEl.focus();

      let _intakeSubmitted = false;   // one-shot guard — prevents double-fire
      const doIntakeSubmit = () => {
        const text = textareaEl.value.trim();
        if (!text || sendBtnEl.disabled || _intakeSubmitted) return;
        _intakeSubmitted = true;
        sendBtnEl.disabled = true;      // visually disable the button too

        // ── State 2: Analysing ───────────────────────────────────────────
        inputWrapEl.setAttribute('hidden', '');
        statusWrapEl.removeAttribute('hidden');

        // Sequential status messages — mirrors _wsRunAnalysis / _ANALYSIS_STAGES timing
        if (statusTextEl) statusTextEl.textContent = _ANALYSIS_STAGES[0] + '…';
        let _statusDone = false;
        const _intakeStageTexts = _ANALYSIS_STAGES.slice(1).map(s => s + '…');
        const _intakeStageTimes = [2000, 4000, 6000, 8500, 11000];
        const _statusTimers = _intakeStageTimes.map((t, i) =>
          setTimeout(() => {
            if (!_statusDone && statusTextEl?.isConnected && _intakeStageTexts[i]) {
              statusTextEl.textContent = _intakeStageTexts[i];
            }
          }, t)
        );
        intakeEl._clearTimers = () => { _statusDone = true; _statusTimers.forEach(clearTimeout); };
        intakeEl.dataset.cleanupPending = '1';

        // Pass text through the hidden ws-chat-bar (doSend handles the rest)
        const wsInput = document.getElementById('ws-chat-input');
        const wsSend  = document.getElementById('ws-chat-send');
        if (wsInput && wsSend) {
          wsInput.value = text;
          wsInput.dispatchEvent(new Event('input'));
          wsSend.click();
        }
      };

      sendBtnEl.addEventListener('click', doIntakeSubmit);
      textareaEl.addEventListener('keydown', e => {
        if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
          e.preventDefault();
          doIntakeSubmit();
        }
      });
    }

    // Roles with these outcome_state values belong in Archive
    const ARCHIVE_OUTCOME_STATES = new Set(['rejected', 'skipped', 'withdrew', 'offer_accepted', 'closed', 'no_response', 'ghosted']);
    // Helper: is this role archived / terminal?
    const isArchivedRole = r => !!(r.archived || ARCHIVE_OUTCOME_STATES.has(r.outcome_state));

    const NEEDS_ATTENTION_STAGES = new Set(['JD Review', 'Applied', 'Recruiter Screen']);

    // ─── Data ─────────────────────────────────────────────────────────────────
    async function loadData() {
      const [rolesRes, analysesRes, jdDatesRes] = await Promise.all([
        db.from('roles')
          .select(`id, company_name, role_title, location_text, job_url, source,
                   salary_text_raw, work_model, engagement_type, ir35_status, day_rate_text, contract_length, start_timeline, job_description_raw, created_at, status,
                   archived, next_action, user_decision,
                   fit_assessment, fit_reasons, fit_assessed_at,
                   decision_state, verdict_state, nudge_snoozed_until,
                   outcome_state, outcome_reason, outcome_at, current_stage,
                   role_updates(id, status, event_type, stage_reached, outcome_state, note, created_at),
                   role_recruiters(id, recruiter_id, link_source, created_at,
                     recruiters(id, name, company, email, linkedin_url, recruiter_type, office_phone, mobile_phone, website_url, notes, notes_log, created_at, updated_at))`)
          .order('created_at', { ascending: false }),
        db.from('analyses')
          .select('role_id, decision, full_output'),
        // Fetch the latest jd_match date + output_json per role (for draft cards + sorting)
        db.from('jd_matches')
          .select('role_id, created_at, output_json')
          .not('role_id', 'is', null)
          .order('created_at', { ascending: false }),
      ]);

      if (rolesRes.error) throw rolesRes.error;

      const analysesMap = {};
      (analysesRes.data || []).forEach(a => { analysesMap[a.role_id] = a; });

      // Build maps: role_id → latest date + latest output_json
      const jdDateMap   = {};
      const jdOutputMap = {};
      (jdDatesRes.data || []).forEach(m => {
        if (m.role_id && !jdDateMap[m.role_id]) {
          jdDateMap[m.role_id]   = m.created_at;
          jdOutputMap[m.role_id] = m.output_json || null;
        }
      });

      const _RESP_STAGES = new Set(['Recruiter Screen', 'Hiring Manager', 'Panel', 'Final', 'Offer']);

      return (rolesRes.data || []).map(r => {
        r.role_updates = (r.role_updates || []).sort(
          (a, b) => new Date(b.created_at) - new Date(a.created_at)
        );
        r.analysis            = analysesMap[r.id] || null;
        r.latest_match_at     = jdDateMap[r.id]   || null;
        r.latest_match_output = jdOutputMap[r.id]  || null;

        // ── Derived role fields (Role as single source of truth) ────────────
        // Primary linked recruiter (first link, if any)
        r._recruiter = (r.role_recruiters?.[0])?.recruiters || null;

        // Applied date and first response date — computed from role_updates
        const _stageAsc = [...r.role_updates].reverse(); // oldest first
        const _applied  = _stageAsc.find(u =>
          (!u.event_type || u.event_type === 'stage') &&
          (u.stage_reached === 'Applied' || u.status === 'applied')
        );
        r._appliedDate = _applied?.created_at || null;
        const _appliedIdx = _applied ? _stageAsc.indexOf(_applied) : -1;
        const _response   = _appliedIdx >= 0
          ? _stageAsc.slice(_appliedIdx + 1).find(u =>
              (!u.event_type || u.event_type === 'stage') && _RESP_STAGES.has(u.stage_reached)
            )
          : null;
        r._firstResponseDate = _response?.created_at || null;

        return r;
      });
    }

    // ─── Stage dot colour map ─────────────────────────────────────────────────
    const STAGE_DOT = {
      'JD Review':    'dot-grey',
      'Applied':      'dot-blue',
      'Recruiter Screen': 'dot-purple',
      'Hiring Manager':   'dot-purple',
      'Panel':        'dot-orange',
      'Final':        'dot-orange',
      'Offer':        'dot-green',
      'Rejected':     'dot-red',
      'Skipped':      'dot-grey',
      'Withdrew':     'dot-muted',
    };

    // ─── Role clustering ─────────────────────────────────────────────────────
    // Lightweight automatic grouping of roles by shared characteristics.
    // Signal sources: role_title, company_name, and latest_match_output fields.
    // Returns { clusters: [{label, roles}], singletons: [role] }
    // Clusters are only formed when 2+ roles share the same signal.
    function clusterRoles(roles) {
      // Signals in priority order — first match wins per role
      const SIGNAL_DEFS = [
        // Delivery / design position type (most differentiating)
        { key: 'founding',   label: 'Founding / first designer',
          re: /\bfirst\s+(?:in-house\s+)?design|\bfounding\s+design|\bsolo\s+design|\bbuild(?:ing)?\s+(?:out\s+)?(?:the\s+)?design\s+(?:function|team|capability)/i },
        { key: 'leadership', label: 'Design leadership',
          re: /\bhead\s+of\s+design|\bdirector\b.*design|design\b.*director|\bvp\b.*design|\blead(?:ing)?\s+(?:a\s+)?(?:team of|team)\b/i },
        { key: 'design-sys', label: 'Design systems',
          re: /\bdesign\s+system|\bcomponent\s+librar|\bfigma\s+librar|\btoken\s+(?:system|architect)/i },
        { key: 'platform',   label: 'Platform product design',
          re: /\bplatform\s+(?:product|design|team|squad)|\binfrastructure\b.*design|\binternal\s+tool|\bdeveloper\s+(?:tool|platform)/i },
        // Technology domain
        { key: 'ai-ml',      label: 'AI / ML product design',
          re: /\bai[\s-]powered|\bllm\b|\bgenerative\s+ai|\bmachine\s+learning\b.*design|\bai\s+product/i },
        { key: 'data',       label: 'Data product design',
          re: /\bdata\s+(?:product|platform|visual|studio)|\banalytics\s+(?:product|platform)|\bdashboard\b.*design/i },
        // Industry vertical
        { key: 'fintech',    label: 'FinTech',
          re: /\bfintech\b|\bpayment[s]?\b|\bbanking\b|\binsur(?:ance|tech)|\bwealth\s+(?:management|tech)/i },
        { key: 'healthtech', label: 'HealthTech',
          re: /\bhealth[\s-]?tech|\bmedical\b|\bclinical\b|\bpatient\s+(?:care|experience|journey)/i },
        { key: 'marketplace',label: 'Marketplace design',
          re: /\bmarketplace\b|\btwo-sided\s+platform|\bsupply\s+&\s+demand/i },
        { key: 'growth',     label: 'Growth / acquisition',
          re: /\bgrowth\s+(?:design|product|team)|\bconversion\s+(?:rate|optimis)|\bacquisition\b.*product/i },
        { key: 'mobile',     label: 'Mobile product design',
          re: /\bmobile\s+(?:app|product|experience|design|first)|\bios\b.*(?:design|app)|\bandroid\b.*(?:design|app)/i },
        // Go-to-market model
        { key: 'b2b-saas',   label: 'B2B / SaaS',
          re: /\bb2b\b|\bsaas\b|\benterprise\s+(?:software|product|saas)/i },
        { key: 'consumer',   label: 'Consumer product design',
          re: /\bconsumer\s+(?:product|app|tech|internet)|\bb2c\b|\bmass\s+market\b/i },
      ];

      // Archetype-to-signal map: prefer AI archetype over keyword matching when available
      const ARCHETYPE_SIGNAL_MAP = {
        'Founding Product Designer':  { key: 'founding',   label: 'Founding / first designer' },
        'Product Squad Designer':     { key: 'squad',      label: 'Product squad design' },
        'Platform Systems Designer':  { key: 'platform',   label: 'Platform product design' },
        'Enterprise UX Operator':     { key: 'enterprise', label: 'Enterprise UX' },
        'Design Systems Designer':    { key: 'design-sys', label: 'Design systems' },
        'Growth Product Designer':    { key: 'growth',     label: 'Growth / acquisition' },
        'Service / Workflow Designer':{ key: 'service',    label: 'Service / workflow design' },
        'Craft-led UI/Product Designer':{ key: 'craft',    label: 'Craft-led product design' },
      };

      const getSignal = role => {
        // Priority 1: AI-generated archetype (most accurate)
        const aiArchetype = role.latest_match_output?.role_archetype?.primary;
        if (aiArchetype && ARCHETYPE_SIGNAL_MAP[aiArchetype]) {
          const mapped = ARCHETYPE_SIGNAL_MAP[aiArchetype];
          // Enrich label with secondary flavour if present
          const secondary = role.latest_match_output?.role_archetype?.secondary;
          const label = secondary ? `${mapped.label} · ${secondary}` : mapped.label;
          return { key: mapped.key, label };
        }
        // Priority 2: Keyword matching on text fields
        const searchText = [
          role.role_title            || '',
          role.company_name          || '',
          role.latest_match_output?.role_reality         || '',
          role.latest_match_output?.role_summary         || '',
          role.latest_match_output?.why_this_role_exists || '',
        ].join(' ');
        return SIGNAL_DEFS.find(s => s.re.test(searchText)) || null;
      };

      // Assign each role a signal key
      const rolesWithSignal = roles.map(r => ({ role: r, signal: getSignal(r) }));

      // Group by signal key
      const clusterMap = new Map();
      rolesWithSignal.forEach(({ role, signal }) => {
        const key = signal ? signal.key : '__none__';
        if (!clusterMap.has(key)) clusterMap.set(key, { label: signal?.label || null, roles: [] });
        clusterMap.get(key).roles.push(role);
      });

      // Separate real clusters (2+ roles) from singletons
      const clusters   = [];
      const singletons = [];
      clusterMap.forEach((cluster, key) => {
        if (key !== '__none__' && cluster.roles.length >= 2) clusters.push(cluster);
        else singletons.push(...cluster.roles);
      });

      // Largest cluster first
      clusters.sort((a, b) => b.roles.length - a.roles.length);
      return { clusters, singletons };
    }

    // ─── Inbox ────────────────────────────────────────────────────────────────
    function daysWaiting(role) {
      // Don't show waiting days for closed/outcome roles
      if (role.outcome_state) return null;
      // Only consider stage rows (outcome rows must not shift the date baseline)
      const stageUpdates = (role.role_updates || []).filter(u => !u.event_type || u.event_type === 'stage');
      if (!stageUpdates.length) return null;
      // Earliest applied event (role_updates sorted desc → reverse for oldest-first)
      const appliedEvent = [...stageUpdates].reverse().find(u =>
        u.stage_reached === 'Applied' || u.status === 'applied'
      );
      if (!appliedEvent) return null;
      return Math.max(0, Math.floor((Date.now() - new Date(appliedEvent.created_at).getTime()) / 86400000));
    }

    // ─── Application response status classifier ──────────────────────────────
    // Returns { status, label, days } for Applied roles, null otherwise.
    // status: 'active' | 'waiting' | 'stale' | 'ghosted'
    // active  = employer has responded (label: 'Responded') — Recruiter Screen or later reached
    // waiting = no response yet, < 14 days since applied
    // stale   = no response, 14–21 days since applied
    // ghosted = no response, > 21 days since applied
    //
    // Uses the pre-computed _appliedDate / _firstResponseDate fields (set in
    // loadData) so this is now a pure O(1) lookup with no role_updates traversal.
    function _appResponseStatus(role) {
      if (role.outcome_state) return null; // Terminal roles — no classification

      // Use pre-computed derived fields from loadData (single source of truth)
      const appliedDate   = role._appliedDate;
      const responseDate  = role._firstResponseDate;

      if (!appliedDate) return null; // Role not yet at Applied stage

      if (responseDate) {
        // Response received — role is active
        return { status: 'active', label: 'Responded', days: null };
      }

      const daysSince = Math.floor((Date.now() - new Date(appliedDate).getTime()) / 86400000);
      if (daysSince > 21) return { status: 'ghosted', label: 'Ghosted', days: daysSince };
      if (daysSince > 14) return { status: 'stale',   label: 'Stale',   days: daysSince };
      return                      { status: 'waiting', label: 'Waiting', days: daysSince };
    }

    function stageTagClass(label) {
      const map = {
        'JD Review':        'stage-jd-review',
        'Reviewed':         'stage-jd-review',
        'Applied':          'stage-applied',
        'Recruiter Screen': 'stage-recruiter-screen',
        'Hiring Manager':   'stage-hiring-manager',
        'Panel':            'stage-panel',
        'Final':            'stage-final',
        'Offer':            'stage-offer',
      };
      return map[label] || '';
    }

    function daysSinceLastUpdate(role) {
      if (role.outcome_state) return null;
      const stageUpdates = (role.role_updates || []).filter(u => !u.event_type || u.event_type === 'stage');
      const ref = stageUpdates.length ? stageUpdates[0].created_at : role.created_at;
      return Math.max(0, Math.floor((Date.now() - new Date(ref).getTime()) / 86400000));
    }

    function daysAgeClass(days) {
      if (days >= 15) return 'days-age3';
      if (days >= 10) return 'days-age2';
      if (days >= 5)  return 'days-age1';
      return '';
    }

    function nextAction(stageLabel) {
      const map = {
        'JD Review':        'Decide',
        'Applied':          'Follow up',
        'Recruiter Screen': 'Prepare interview',
        'Hiring Manager':   'Prepare interview',
        'Panel':            'Prepare interview',
        'Final':            'Await decision',
        'Offer':            'Review offer',
      };
      return map[stageLabel] || null;
    }

    function needsAttentionDot(role) {
      if (role.outcome_state || role.archived) return false;
      const stage = currentStageLabel(role);
      if (stage === 'JD Review') {
        const days = Math.floor((Date.now() - new Date(role.created_at).getTime()) / 86400000);
        return days > 3;
      }
      if (stage === 'Applied') {
        const d = daysWaiting(role);
        return d !== null && d > 5;
      }
      return false;
    }

    function currentStageLabel(role) {
      // Only look at stage rows — outcome rows must not become the displayed stage label
      const stageUpdates = (role.role_updates || []).filter(u => !u.event_type || u.event_type === 'stage');
      const latest = stageUpdates[0]; // already sorted newest-first
      if (!latest) return 'JD Review';
      // Normalize legacy 'Reviewed' rows to 'JD Review'
      const label = latest.stage_reached || 'JD Review';
      return label === 'Reviewed' ? 'JD Review' : label;
    }

    // ─── Shared sort: outcome_at → latest_match_at → created_at ─────────────
    function roleSort(a, b) {
      const ta = new Date(a.outcome_at || a.latest_match_at || a.created_at).getTime();
      const tb = new Date(b.outcome_at || b.latest_match_at || b.created_at).getTime();
      return tb - ta;
    }

    function renderInbox(roles) {
      const el = document.getElementById('role-inbox');

      // Preserve scroll position across re-renders
      const prevScroll = el ? el.scrollTop : 0;

      const searchQ = (document.getElementById('filter-search')?.value || '').trim().toLowerCase();
      let filtered = roles.filter(r => {
        if (inboxTab === 'archive') return isArchivedRole(r) || r.user_decision === 'skip';
        if (inboxTab === 'all')     return true;
        // Needs attention: active roles flagged by needsAttentionDot
        if (inboxTab === 'needs_attention')
          return !isArchivedRole(r) && r.user_decision !== 'skip' && needsAttentionDot(r);
        // In progress: applied or advanced past JD Review (no terminal outcome)
        if (inboxTab === 'in_progress')
          return !isArchivedRole(r) && r.user_decision !== 'skip' && (
            r.user_decision === 'apply' ||
            (r.user_decision === null && currentStageLabel(r) !== 'JD Review' && r.job_description_raw)
          );
        // Active tab: exclude terminal/archived roles AND roles the user has explicitly skipped
        return !isArchivedRole(r) && r.user_decision !== 'skip';
      });

      if (searchQ) {
        filtered = filtered.filter(r =>
          (r.role_title   || '').toLowerCase().includes(searchQ) ||
          (r.company_name || '').toLowerCase().includes(searchQ)
        );
      }

      // ── Panel filter state ────────────────────────────────────────────────
      if (_hasActiveFilters()) {
        if (filterState.decision.size > 0) {
          filtered = filtered.filter(r => {
            const dec   = r.user_decision;
            const stage = currentStageLabel(r);
            if (filterState.decision.has('awaiting') && !dec && stage === 'JD Review') return true;
            if (filterState.decision.has('apply')    && dec === 'apply')               return true;
            if (filterState.decision.has('skip')     && dec === 'skip')                return true;
            return false;
          });
        }
        if (filterState.engagement.size > 0) {
          filtered = filtered.filter(r => filterState.engagement.has(r.engagement_type));
        }
        if (filterState.workModel.size > 0) {
          filtered = filtered.filter(r => {
            const wm = (r.work_model || '').toLowerCase();
            if (filterState.workModel.has('remote') && wm === 'remote') return true;
            if (filterState.workModel.has('hybrid') && wm === 'hybrid') return true;
            if (filterState.workModel.has('on-site') && (wm === 'on-site' || wm === 'onsite')) return true;
            return false;
          });
        }
        if (filterState.response.size > 0) {
          filtered = filtered.filter(r => {
            const ars = _appResponseStatus(r);
            return ars && filterState.response.has(ars.status);
          });
        }
        if (filterState.recruiter.size > 0) {
          filtered = filtered.filter(r => {
            const hasRec = !!(r.role_recruiters?.length);
            if (filterState.recruiter.has('with')    && hasRec)  return true;
            if (filterState.recruiter.has('without') && !hasRec) return true;
            return false;
          });
        }
      }

      filtered = [...filtered].sort(roleSort);

      // Update clear button visibility
      const _clearBtn = document.getElementById('btn-search-clear');
      const _hasQuery = searchQ.length > 0;
      if (_clearBtn) _clearBtn.classList.toggle('visible', _hasQuery);

      // Results count — always shown inside the search field; hidden while typing (clear btn takes that slot)
      const _countEl = document.getElementById('inbox-results-count');
      if (_countEl) {
        _countEl.textContent = _hasQuery ? '' : String(filtered.length);
      }

      if (!filtered.length) {
        el.innerHTML = !roles.length
          ? `<div class="state-msg">No roles yet.<br><span style="font-size:12px;color:var(--text-light);line-height:1.6;">Paste a job description in Add JD to analyse your first role.</span></div>`
          : searchQ
            ? '<div class="state-msg">No matching roles.</div>'
            : '<div class="state-msg">No roles match this filter.</div>';
        return;
      }

      // ── Contextual state explanation ─────────────────────────────────────────
      // Short sentence explaining the role's current state for inbox row display.
      const inboxStateExplanation = role => {
        const outcome = role.outcome_state;
        const stage   = currentStageLabel(role);
        // Prefer stage label if it's meaningful (anything other than JD Review = user took action)
        const stageForCopy = (stage && stage !== 'JD Review') ? stage : null;
        if (outcome === 'rejected')      return stageForCopy ? `Process ended after ${stage}` : 'Process ended after review';
        if (outcome === 'no_response')   return stageForCopy ? `No response after ${stage}` : 'No response';
        if (outcome === 'ghosted')       return stageForCopy ? `Ghosted after ${stage}` : 'Ghosted';
        if (outcome === 'skipped')       return 'Closed without applying';
        if (outcome === 'withdrew')      return stageForCopy ? `Withdrawn after ${stage}` : 'Withdrawn after review';
        if (outcome === 'offer_accepted') return 'Offer accepted';
        if (outcome === 'closed')        return 'Closed';
        if (!role.job_description_raw)   return 'Paste a job description to begin';
        if (stage === 'JD Review')       return 'Awaiting decision';
        if (stage === 'Applied') {
          const _ars = _appResponseStatus(role);
          if (_ars) {
            if (_ars.status === 'active')  return 'Response received';
            if (_ars.status === 'waiting') return `Waiting · ${_ars.days}d since applied`;
            if (_ars.status === 'stale')   return `No response · ${_ars.days}d since applied`;
            if (_ars.status === 'ghosted') return `Ghosted · ${_ars.days}d since applied`;
          }
          return 'Applied — awaiting response';
        }
        return 'In progress';
      };

      // ── Decision colour helper ───────────────────────────────────────────────
      // Returns 'green' | 'amber' | 'red' | null based on analysis outcome
      const inboxDecisionColor = role => {
        const fo  = role.latest_match_output || role.analysis?.full_output;
        const dec = role.analysis?.decision;
        if (fo?.hard_no) return 'red';
        if (dec === 'Skip')  return 'red';
        if (dec === 'Apply') return 'green';
        if (dec === 'Maybe') return 'amber';
        const ns = (fo?.suggested_actions?.next_step || fo?.suggested_actions?.primary || '').toLowerCase();
        if (ns === 'apply') return 'green';
        if (ns === 'skip')  return 'red';
        if (ns)             return 'amber';
        const rv = (fo?.rolewise_verdict?.outcome || '').toLowerCase();
        if (/strong\s*fit|excellent/i.test(rv))          return 'green';
        if (/not\s*worth|skip|avoid|hard\s*no/i.test(rv)) return 'red';
        if (rv)                                           return 'amber';
        return null;
      };

      // ── Decision pill helper ─────────────────────────────────────────────────
      const inboxDecisionPill = role => {
        const fo  = role.latest_match_output || role.analysis?.full_output;
        const dec = role.analysis?.decision;
        if (fo?.hard_no)     return { color: 'red',   label: 'Hard No' };
        if (dec === 'Apply') return { color: 'green', label: 'Apply'   };
        if (dec === 'Maybe') return { color: 'amber', label: 'Maybe'   };
        if (dec === 'Skip')  return { color: 'grey',  label: 'Skip'    };
        const ns = (fo?.suggested_actions?.next_step || fo?.suggested_actions?.primary || '').toLowerCase();
        if (ns === 'apply') return { color: 'green', label: 'Apply' };
        if (ns === 'skip')  return { color: 'grey',  label: 'Skip'  };
        if (ns)             return { color: 'amber', label: 'Maybe' };
        return null;
      };

      // ── Render a single role card ────────────────────────────────────────────
      // Derives the hiring signal (company behaviour) for a role card.
      // Returns { status, label } or null if no signal applies.
      const _hiringSignal = role => {
        const outcome = role.outcome_state;
        const stage   = currentStageLabel(role);
        // Terminal outcomes
        if (outcome === 'offer_accepted') return { status: 'accepted',   label: 'Offer accepted' };
        if (outcome === 'rejected' || outcome === 'no_response')
                                          return { status: 'rejected',   label: 'Rejected' };
        if (outcome === 'ghosted')        return { status: 'ghosted',    label: 'No response' };
        if (outcome === 'withdrew')       return { status: 'withdrew',   label: 'Withdrawn' };
        if (outcome === 'closed' || outcome === 'skipped') return null;
        // Active stages
        if (stage === 'Offer')            return { status: 'offer',      label: 'Offer received' };
        if (['Recruiter Screen', 'Hiring Manager', 'Panel', 'Final'].includes(stage))
                                          return { status: 'interviewing', label: 'Interviewing' };
        if (stage === 'Applied')          return _appResponseStatus(role); // existing waiting/responded logic
        return null;
      };

      // ── Single intelligence signal for inbox card subtitle ─────────────────
      // Returns a short phrase (string) or null. Priority: warning signals first
      // (weak evaluation, high-volume funnel, intense pace, inflated seniority),
      // then positive/informational (ownership, hiring route). Only one signal
      // surfaces per role — the most noteworthy characteristic.
      const _buildInboxSignal = lmo => {
        if (!lmo || typeof lmo !== 'object') return null;
        // 1 — Low-signal evaluation (top priority — affects analysis confidence)
        if (lmo._weakSignal) return 'Low-signal evaluation';
        // 2 — High-volume funnel (warn: poor candidate experience expected)
        if (lmo.hiring_system?.type === 'high_volume_funnel') return 'High-volume hiring funnel';
        // 3 — Intense pace (warn: energy cost to flag early)
        if (lmo.delivery_pressure === 'intense') return 'Intense pace expected';
        // 4 — Seniority inflated (warn: scope/comp misalignment risk)
        if (lmo.seniority_authenticity === 'inflated') return 'Seniority may be inflated';
        // 5 — High ownership (positive signal, worth surfacing)
        if (['high', 'company_level', 'platform'].includes(lmo.ownership_level))
          return 'High ownership role';
        // 6 — Low ownership (informational)
        if (lmo.ownership_level === 'low') return 'Low ownership role';
        // 7 — Founder-led or direct hire (positive: lean process)
        if (lmo.hiring_system?.type === 'founder_led') return 'Founder-led hire';
        if (lmo.hiring_system?.type === 'direct_employer') return 'Direct employer hire';
        // 8 — Understated scope (interesting edge case)
        if (lmo.seniority_authenticity === 'understated') return 'Understated scope';
        return null;
      };

      const renderRoleCard = role => {
        const company    = sanitiseCompanyName(role.company_name);
        const title      = role.role_title || 'Untitled role';
        const attnDot    = needsAttentionDot(role) ? '<span class="inbox-attn-dot"></span>' : '';
        const stageLabel = currentStageLabel(role);
        const days       = daysSinceLastUpdate(role);

        // Left-border colour — only at JD Review (decision primary); removed once progressed
        const _cardProgressed = PROGRESSED_STAGES.has(stageLabel);
        const decColor = _cardProgressed ? null : inboxDecisionColor(role);
        const decAttr  = decColor ? ` data-decision="${decColor}"` : '';

        // ── User action label (what the user did) ──────────────────────────────
        const _userAction = (() => {
          if (role.outcome_state) return null;
          if (stageLabel === 'Applied' || _cardProgressed) return 'Applied';
          if (role.user_decision === 'save') return 'Saved';
          if (stageLabel === 'JD Review' && role.job_description_raw) return 'Analysed';
          return null;
        })();

        // ── Natural time label ─────────────────────────────────────────────────
        const _timeLabel = days === null ? '' :
          days === 0 ? 'Today' :
          days === 1 ? 'Yesterday' :
          `${days}d ago`;

        // ── Meta line: Location · Engagement · User action · Time ──────────────
        const metaParts = [];
        if (role.location_text) metaParts.push(role.location_text);
        if (role.engagement_type && role.engagement_type !== 'Unknown') metaParts.push(role.engagement_type);
        if (_userAction) metaParts.push(_userAction);
        if (_timeLabel) metaParts.push(_timeLabel);
        const metaHtml = `<div class="inbox-meta">${metaParts.map(esc).join(' \u00B7 ')}</div>`;

        // ── Hiring signal badge (company behaviour, not user action) ───────────
        const _hs = _hiringSignal(role);
        const hiringBadgeHtml = _hs
          ? `<div class="inbox-hs"><span class="ars-badge ars-${_hs.status}">${esc(_hs.label)}</span></div>`
          : '';

        // ── Mini reason line — up to 2 decision signals ────────────────────────
        const lmo              = role.latest_match_output || {};
        const _frictionPhrases = verdictDecisionReasons(lmo);
        const _archPrimary     = lmo.role_archetype?.primary || null;
        const _miniSignals     = [..._frictionPhrases];
        if (_archPrimary && _miniSignals.length < 2) _miniSignals.push(_archPrimary);
        const miniReasonHtml = _miniSignals.length
          ? `<div class="inbox-mini-reasons">${_miniSignals.slice(0, 2).map(esc).join(' \u00B7 ')}</div>`
          : '';

        // ── Intelligence signal — single notable characteristic beneath title ──
        const _intelSig    = _buildInboxSignal(lmo);
        const intelSigHtml = _intelSig
          ? `<div class="inbox-signals">${esc(_intelSig)}</div>`
          : '';

        // ── Boundary match indicator (Decision Layer V1) ───────────────────────
        // Only shown when boundaries are loaded and the role has analysis data with
        // at least one detected blocker that matches a saved boundary.
        const _boundaryMatchHtml = (() => {
          if (!_boundaryKeyCache || _boundaryKeyCache.size === 0) return '';
          const _lmo = role.latest_match_output || role.analysis;
          if (!_lmo) return '';
          const _matchedBlockers = _detectBlockers(role).filter(b => _boundaryKeyCache.has(b.key));
          if (!_matchedBlockers.length) return '';
          return `<div class="inbox-boundary-match">Boundary match</div>`;
        })();

        return `<div class="inbox-role${role.id === selectedRoleId ? ' active' : ''}"${decAttr} data-id="${esc(role.id)}">
          <div class="inbox-company inbox-role-company${company ? '' : ' inbox-company-unknown'}">${attnDot}${esc(company || 'Unknown company')}</div>
          <div class="inbox-title inbox-role-title">${esc(title)}</div>
          ${intelSigHtml}
          ${metaHtml}
          ${hiringBadgeHtml}
          ${miniReasonHtml}
          ${_boundaryMatchHtml}
        </div>`;
      };

      // ── Build list HTML — flat list for all filter tabs ─────────────────────
      // Section grouping has been replaced by nav sub-filters (Active / Archive /
      // All / Needs attention / In progress). The list is always a clean flat list.
      const listHtml = filtered.map(renderRoleCard).join('');

      el.innerHTML = listHtml;

      el.querySelectorAll('.inbox-role').forEach(row => {
        row.addEventListener('click', () => selectRole(row.dataset.id));
      });

      // Wire compare checkboxes
      el.querySelectorAll('.inbox-compare-cb').forEach(cb => {
        cb.addEventListener('click', e => e.stopPropagation());
        cb.addEventListener('change', () => {
          const id = cb.dataset.id;
          if (cb.checked) {
            if (compareRoleIds.size >= 3) { cb.checked = false; return; }
            compareRoleIds.add(id);
          } else {
            compareRoleIds.delete(id);
          }
          // Refresh cards to update compare-active class on all rows
          renderInbox(allRoles);
          updateCompareBar();
        });
      });
      updateCompareBar();

      // Restore scroll, then nudge selected row into view only if out of bounds
      if (el) {
        el.scrollTop = prevScroll;
        const activeRow = el.querySelector('.inbox-role.active');
        if (activeRow) {
          const { top: rTop, bottom: rBot } = activeRow.getBoundingClientRect();
          const { top: cTop, bottom: cBot } = el.getBoundingClientRect();
          if (rBot > cBot || rTop < cTop) {
            activeRow.scrollIntoView({ block: 'nearest' });
          }
        }
      }
    }


    // ─── Role comparison ──────────────────────────────────────────────────────

    function updateCompareBar() {
      const barEl  = document.getElementById('compare-bar');
      const infoEl = document.getElementById('compare-bar-info');
      const btnEl  = document.getElementById('btn-compare-roles');
      const clrEl  = document.getElementById('btn-compare-clear');
      if (!barEl) return;

      const n = compareRoleIds.size;
      barEl.style.display = n > 0 ? 'flex' : 'none';

      if (infoEl) {
        infoEl.textContent = n === 1 ? 'Select 1 more to compare' : `${n} roles selected`;
      }
      if (btnEl) {
        btnEl.disabled = n < 2;
        btnEl.textContent = n >= 2 ? `Compare ${n}` : 'Compare';
      }
      if (clrEl) {
        clrEl.onclick = () => {
          compareRoleIds.clear();
          renderInbox(allRoles);
          updateCompareBar();
          // Restore role doc if we're showing compare panel
          const centerEl = document.getElementById('col-overview-cards');
          if (centerEl?.querySelector('.compare-panel')) {
            if (selectedRoleId) {
              const role = allRoles.find(r => r.id === selectedRoleId);
              if (role) { renderRoleDoc(role); renderRail(role); }
            } else {
              centerEl.innerHTML = `<div class="doc-empty">${NAV_EMPTY_STATES['applications']}</div>`;
            }
          }
        };
      }
      if (btnEl && n >= 2) {
        btnEl.onclick = () => renderCompareView();
      }
    }

    function renderCompareView() {
      const roles = [...compareRoleIds]
        .map(id => allRoles.find(r => r.id === id))
        .filter(Boolean);
      if (roles.length < 2) return;

      // Helper: decision pill for a role
      const _cmpPill = role => {
        const fo  = role.latest_match_output || role.analysis?.full_output;
        const dec = role.analysis?.decision;
        if (fo?.hard_no)     return { color: 'red',   label: 'Hard No' };
        if (dec === 'Apply') return { color: 'green', label: 'Apply'   };
        if (dec === 'Maybe') return { color: 'amber', label: 'Maybe'   };
        if (dec === 'Skip')  return { color: 'red',   label: 'Hard No' };
        return null;
      };

      // Helper: key signals (friction phrases + archetype fill)
      const _cmpSignals = role => {
        const lmo     = role.latest_match_output || {};
        const phrases = verdictDecisionReasons(lmo);
        const arch    = lmo.role_archetype?.primary || null;
        const signals = [...phrases];
        if (arch && signals.length < 3) signals.push(arch);
        return signals.slice(0, 3);
      };

      // Helper: salary display
      const _cmpSalary = role => {
        const pd  = role.latest_match_output?.practical_details;
        const sal = pd?.salary_annual || role.salary_text_raw || null;
        return (sal && sal !== 'Not stated') ? sal : null;
      };

      // Helper: work model display
      const _cmpWorkModel = role => {
        const pd = role.latest_match_output?.practical_details;
        const wm = pd?.remote_model || role.work_model || null;
        if (!wm || wm === 'unknown') return null;
        return wm.charAt(0).toUpperCase() + wm.slice(1);
      };

      // Helper: employment type
      const _cmpEmpType = role => {
        const pd = role.latest_match_output?.practical_details;
        return pd?.employment_type || null;
      };

      // Helper: archetype
      const _cmpArchetype = role => {
        const lmo = role.latest_match_output || {};
        return lmo.role_archetype?.primary || null;
      };

      // Helper: next action
      const _cmpNextAction = role => {
        return role.next_action || _nextActionSuggestion(role) || null;
      };

      // Build column headers (role titles)
      const colHeaders = roles.map(r =>
        `<th class="compare-role-col">
          <div style="font-size:13px;font-weight:700;color:var(--text);">${esc(sanitiseCompanyName(r.company_name) || 'Unknown')}</div>
          <div style="font-size:12px;color:var(--text-muted);font-weight:400;margin-top:2px;">${esc(r.role_title || 'Untitled')}</div>
        </th>`
      ).join('');

      // Build row helper
      const _row = (label, cellFn) => {
        const cells = roles.map(r => `<td class="compare-cell">${cellFn(r)}</td>`).join('');
        return `<tr><td class="compare-label-col">${esc(label)}</td>${cells}</tr>`;
      };

      const na = `<span class="compare-na">—</span>`;

      const tableHtml = `
        <table class="compare-table">
          <thead>
            <tr>
              <th style="width:130px;"></th>
              ${colHeaders}
            </tr>
          </thead>
          <tbody>
            ${_row('Salary', r => {
              const s = _cmpSalary(r);
              return s ? esc(s) : na;
            })}
            ${_row('Work model', r => {
              const w = _cmpWorkModel(r);
              return w ? esc(w) : na;
            })}
            ${_row('Employment', r => {
              const e = _cmpEmpType(r);
              return e ? esc(e) : na;
            })}
            ${_row('Stage', r => esc(currentStageLabel(r) || '—'))}
            ${_row('Archetype', r => {
              const a = _cmpArchetype(r);
              return a ? esc(a) : na;
            })}
            ${_row('Signals', r => {
              const sigs = _cmpSignals(r);
              if (!sigs.length) return na;
              return sigs.map(s => `<span class="compare-signal-item">${esc(s)}</span>`).join('');
            })}
            ${_row('Decision', r => {
              const pill = _cmpPill(r);
              if (!pill) return na;
              return `<span class="compare-pill compare-pill-${pill.color}">${esc(pill.label)}</span>`;
            })}
            ${_row('Next action', r => {
              const na2 = _cmpNextAction(r);
              return na2 ? esc(na2) : na;
            })}
          </tbody>
        </table>`;

      const centerEl = document.getElementById('col-overview-cards');
      centerEl.innerHTML = `
        <div class="compare-panel">
          <div class="compare-panel-header">
            <div class="compare-panel-title">Compare roles</div>
            <button class="compare-close-btn" id="btn-compare-close">Close ✕</button>
          </div>
          ${tableHtml}
        </div>`;

      document.getElementById('btn-compare-close').addEventListener('click', () => {
        compareRoleIds.clear();
        renderInbox(allRoles);
        updateCompareBar();
        if (selectedRoleId) {
          const role = allRoles.find(r => r.id === selectedRoleId);
          if (role) { renderRoleDoc(role); renderRail(role); }
        } else {
          centerEl.innerHTML = `<div class="doc-empty">${NAV_EMPTY_STATES['applications']}</div>`;
        }
      });
    }

    // ─── Select role ──────────────────────────────────────────────────────────
    // Generation counter for the role-switch animation. Incremented on every
    // selectRole call so that in-flight exit timers from a previous (superseded)
    // switch bail out before swapping content, preventing a stale role from
    // flashing in during rapid navigation.
    let _rsSwitchGen = 0;

    function selectRole(roleId, { scrollIntoView = false } = {}) {
      selectedRoleId = roleId;
      _wsDuplicateDetected = false;   // any active duplicate state is invalidated by navigation
      const role = allRoles.find(r => r.id === roleId);
      if (!role) return;

      // Update active state in inbox
      document.querySelectorAll('.inbox-role').forEach(row => {
        row.classList.toggle('active', row.dataset.id === roleId);
      });

      // Scroll selected row into view only when explicitly requested (keyboard nav)
      if (scrollIntoView) {
        const inboxEl = document.getElementById('role-inbox');
        const activeRow = inboxEl?.querySelector('.inbox-role.active');
        if (activeRow && inboxEl) {
          const { top: rTop, bottom: rBot } = activeRow.getBoundingClientRect();
          const { top: cTop, bottom: cBot } = inboxEl.getBoundingClientRect();
          if (rBot > cBot || rTop < cTop) {
            activeRow.scrollIntoView({ block: 'nearest' });
          }
        }
      }

      // ── Slide + fade panel swap ───────────────────────────────────────────────
      //
      // Phase 1 (exit,  110 ms): panels slide DOWN (translateY 0 → 12px) and
      //   fade out (opacity 1 → 0.35) simultaneously. Content is still visible
      //   at the start so the user sees a directional exit gesture.
      //
      // Phase 2 (swap,  at 110 ms): renderRoleDoc + renderRail fire while panels
      //   are at their dimmest / lowest point. DOM replacement is imperceptible.
      //   Scroll is reset here too — no visible jump.
      //
      // Phase 3 (enter, 160 ms): panels slide UP (translateY 12px → 0) and fade
      //   back in (opacity 0.35 → 1). New content rises into place.
      //
      // Rapid switching: _rsSwitchGen is incremented on each selectRole call.
      // In-flight callbacks compare the captured generation and bail if a newer
      // switch has superseded them — only the last-clicked role ever renders.
      //
      // prefers-reduced-motion: transforms are suppressed entirely; a short
      // opacity-only fade is used instead. The CSS @media rule in styles.css
      // enforces this at the CSS layer as a belt-and-suspenders fallback.
      const _ovBody   = document.getElementById('col-overview-body');
      const _chatEl   = document.getElementById('col-chat');
      const _panels   = [_ovBody, _chatEl].filter(Boolean);
      const _noMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

      // Snap panels to a clean baseline so any in-progress transition from a
      // previous switch does not interfere. transition:none prevents the reset
      // itself from animating.
      _panels.forEach(p => {
        p.style.transition = 'none';
        p.style.opacity    = '1';
        p.style.transform  = 'translateY(0)';
      });

      // Capture current generation. A single rAF ensures the browser commits
      // the clean baseline to the compositor before the exit begins.
      const _gen = ++_rsSwitchGen;
      requestAnimationFrame(() => {
        if (_rsSwitchGen !== _gen) return; // superseded by a faster click

        if (_noMotion) {
          // Reduced-motion path: opacity-only, no transform.
          _panels.forEach(p => {
            p.style.transition = 'opacity 60ms ease';
            p.style.opacity    = '0.75';
          });
        } else {
          // Full motion path: slide down + fade out.
          _panels.forEach(p => {
            p.style.transition = 'opacity 110ms ease-in-out, transform 110ms ease-in-out';
            p.style.opacity    = '0.35';
            p.style.transform  = 'translateY(12px)';
          });
        }

        // Swap content at the end of the exit window. Panels are at their
        // dimmest / lowest point so the DOM replacement is imperceptible.
        setTimeout(() => {
          if (_rsSwitchGen !== _gen) return; // superseded — do not render stale role

          renderRoleDoc(role);
          renderRail(role);

          // Scroll reset while faded — no visible position jump.
          if (_ovBody) _ovBody.scrollTop = 0;

          // Two rAFs: the first lets the browser commit the new content to the
          // render tree; the second triggers the enter transition on the next
          // paint so it fires against the freshly rendered content.
          requestAnimationFrame(() => {
            requestAnimationFrame(() => {
              if (_rsSwitchGen !== _gen) return; // superseded

              if (_noMotion) {
                _panels.forEach(p => {
                  p.style.transition = 'opacity 60ms ease';
                  p.style.opacity    = '1';
                });
              } else {
                // Full motion path: slide up + fade in.
                _panels.forEach(p => {
                  p.style.transition = 'opacity 160ms ease-in-out, transform 160ms ease-in-out';
                  p.style.opacity    = '1';
                  p.style.transform  = 'translateY(0)';
                });
              }
            });
          });
        }, _noMotion ? 60 : 110);
      });
    }

    // ─── Role memory helpers ──────────────────────────────────────────────────
    // role_events = system lifecycle log (stage changes, notes, analyses, recruiter links).
    // GUARD RAIL: Do NOT use insertEvent() for workspace interactions (emails, calls, interviews).
    //             Workspace interactions belong in role_interactions via wsAddInteraction().

    // Fire-and-forget: insert a role_events row; silently ignores errors.
    // Accepts event_date (ISO date string, defaults to today) and note for user-facing events.
    function insertEvent(roleId, payload) {
      if (!roleId) return;
      const _today = new Date().toISOString().slice(0, 10);
      db.from('role_events').insert({
        role_id:      roleId,
        event_type:   payload.event_type,
        title:        payload.title,
        detail:       payload.detail  || null,
        source:       payload.source  || 'system',
        ref_match_id: payload.ref_match_id || null,
        ref_url:      payload.ref_url || null,
        event_date:   payload.event_date || _today,
        note:         payload.note || null,
      }).then(() => {}).catch(() => {});
    }

    // Load up to 50 events for a role, ordered by event_date DESC (then created_at for tie-breaking).
    async function loadTimeline(roleId) {
      try {
        const { data } = await db.from('role_events')
          .select('id, event_type, title, detail, created_at, source, ref_match_id, event_date, note')
          .eq('role_id', roleId)
          .order('event_date', { ascending: false })
          .order('created_at', { ascending: false })
          .limit(50);
        return data || [];
      } catch (_) { return []; }
    }

    // Human-friendly relative time string.
    function relativeTime(isoString) {
      const diff = Date.now() - new Date(isoString).getTime();
      const mins = Math.floor(diff / 60000);
      if (mins < 1)  return 'just now';
      if (mins < 60) return `${mins}m ago`;
      const hrs = Math.floor(mins / 60);
      if (hrs < 24)  return `${hrs}h ago`;
      const days = Math.floor(hrs / 24);
      if (days < 30) return `${days} day${days !== 1 ? 's' : ''} ago`;
      const months = Math.floor(days / 30);
      return `${months} month${months !== 1 ? 's' : ''} ago`;
    }

    // ─── Role Timeline ─────────────────────────────────────────────────────────
    // Structured lifecycle event types available for user selection.
    const TIMELINE_EVENT_TYPES = [
      { value: 'application_submitted',  label: 'Application submitted' },
      { value: 'recruiter_contacted',    label: 'Recruiter contacted me' },
      { value: 'interview_scheduled',    label: 'Interview scheduled' },
      { value: 'technical_task',         label: 'Technical task requested' },
      { value: 'offer_received',         label: 'Offer received' },
      { value: 'rejected',               label: 'Rejected' },
      { value: 'withdrawn',              label: 'Withdrawn' },
      { value: 'ghosted',                label: 'Ghosted' },
      { value: 'no_response',            label: 'No response' },
      { value: 'note_added',             label: 'Note' },
    ];

    // Format a date string (ISO date or ISO timestamptz) as "12 Jan" or "12 Jan 2024"
    function _fmtEventDate(dateStr) {
      if (!dateStr) return '';
      const d = new Date(dateStr);
      if (isNaN(d.getTime())) return '';
      const thisYear = new Date().getFullYear();
      const opts = { day: 'numeric', month: 'short' };
      if (d.getFullYear() !== thisYear) opts.year = 'numeric';
      return d.toLocaleDateString('en-GB', opts);
    }

    // Render a single timeline event row.
    function _renderTimelineRow(ev) {
      const isUser   = ev.source === 'user';
      const dotClass = isUser ? 'role-memory-dot user' : 'role-memory-dot';
      // Prefer event_date for display; fall back to created_at
      const displayDate = ev.event_date
        ? _fmtEventDate(ev.event_date)
        : _fmtEventDate(ev.created_at);
      const relTime  = relativeTime(ev.created_at);
      // Use note if present (new field); fall back to detail (legacy field)
      const noteText = ev.note || ev.detail || null;
      const noteHtml = noteText
        ? `<div class="role-memory-detail">${esc(noteText)}</div>`
        : '';
      return `<div class="role-memory-event">
        <span class="${dotClass}"></span>
        <div class="role-memory-body">
          <div class="role-memory-title">${esc(ev.title)}</div>
          <div class="role-memory-time">${esc(displayDate)} <span style="color:var(--text-light);">&middot; ${esc(relTime)}</span></div>
          ${noteHtml}
        </div>
      </div>`;
    }

    // Render the Role Timeline section (replaces old "Role memory" section).
    function renderTimelineSection(events, roleId, sectionEl) {
      const _today = new Date().toISOString().slice(0, 10);

      // ── Add event form ─────────────────────────────────────────────────────
      const typeOptions = TIMELINE_EVENT_TYPES.map(t =>
        `<option value="${t.value}">${t.label}</option>`
      ).join('');

      const addFormHtml = `
        <div class="rt-add-form" id="rt-add-form">
          <div class="rt-add-row">
            <select class="rt-type-select" id="rt-type-select">
              ${typeOptions}
            </select>
            <input type="date" class="rt-date-input" id="rt-date-input" value="${_today}" max="${_today}">
          </div>
          <div class="rt-add-row">
            <input type="text" class="rt-note-input" id="rt-note-input"
                   placeholder="Optional note…" maxlength="300" autocomplete="off" spellcheck="true">
            <button class="rt-add-btn" id="rt-add-btn">Add</button>
          </div>
        </div>`;

      // ── Events list ────────────────────────────────────────────────────────
      let eventsHtml;
      if (!events.length) {
        eventsHtml = `<div class="role-memory-empty">No events yet. Add the first milestone or note above.</div>`;
      } else {
        eventsHtml = events.map(_renderTimelineRow).join('');
      }

      sectionEl.innerHTML = `
        <div class="doc-section-heading">Timeline</div>
        ${addFormHtml}
        <div id="role-memory-events" class="rt-events-list">${eventsHtml}</div>`;

      // ── Wire add button ────────────────────────────────────────────────────
      const typeSelect  = document.getElementById('rt-type-select');
      const dateInput   = document.getElementById('rt-date-input');
      const noteInput   = document.getElementById('rt-note-input');
      const addBtn      = document.getElementById('rt-add-btn');

      const doAdd = async () => {
        const typeVal   = typeSelect?.value || 'note_added';
        const dateVal   = dateInput?.value  || _today;
        const noteVal   = noteInput?.value.trim() || '';
        const typeLabel = TIMELINE_EVENT_TYPES.find(t => t.value === typeVal)?.label || 'Event';

        addBtn.disabled = true;
        try {
          const _today2 = new Date().toISOString().slice(0, 10);
          const { data: newEv, error: evErr } = await db.from('role_events').insert({
            role_id:    roleId,
            event_type: typeVal,
            title:      typeLabel,
            source:     'user',
            event_date: dateVal,
            note:       noteVal || null,
            detail:     noteVal || null, // legacy compat
          }).select('id, event_type, title, created_at, source, event_date, note, detail').single();
          if (evErr) throw evErr;

          noteInput.value = '';

          // Prepend new row into events list
          const eventsEl = document.getElementById('role-memory-events');
          if (eventsEl) {
            const emptyEl = eventsEl.querySelector('.role-memory-empty');
            if (emptyEl) eventsEl.innerHTML = '';
            eventsEl.insertAdjacentHTML('afterbegin', _renderTimelineRow(newEv));
          }
        } catch (_) {
          // Fail silently — user can retry
        } finally {
          addBtn.disabled = false;
          noteInput.focus();
        }
      };

      addBtn?.addEventListener('click', doAdd);
      noteInput?.addEventListener('keydown', e => {
        if (e.key === 'Enter') { e.preventDefault(); doAdd(); }
      });
    }

    // ─── Role Snapshots helpers ───────────────────────────────────────────────

    // Fire-and-forget snapshot creation.
    // Dedup cache: roleId → Set<snapshotType>. Populated from DB on role open + updated on insert.
    const _snapDedupCache = new Map();
    function _snapCacheAdd(roleId, type) {
      if (!_snapDedupCache.has(roleId)) _snapDedupCache.set(roleId, new Set());
      _snapDedupCache.get(roleId).add(type);
    }
    function _snapCacheHas(roleId, type) {
      return _snapDedupCache.has(roleId) && _snapDedupCache.get(roleId).has(type);
    }

    function createSnapshot(roleId, snapshotType, snapshotTitle, snapshotData) {
      if (!roleId) return;
      if (_snapCacheHas(roleId, snapshotType)) return; // duplicate prevention
      _snapCacheAdd(roleId, snapshotType);
      db.from('role_snapshots').insert({
        role_id:        roleId,
        snapshot_type:  snapshotType,
        snapshot_title: snapshotTitle,
        snapshot_data:  snapshotData || {},
      }).then(() => {}).catch(() => {});
    }

    // Load all snapshots for a role, newest first.
    async function loadSnapshots(roleId) {
      try {
        const { data } = await db.from('role_snapshots')
          .select('id, snapshot_type, snapshot_title, snapshot_data, created_at')
          .eq('role_id', roleId)
          .order('created_at', { ascending: false })
          .limit(30);
        // Populate dedup cache with existing types so we don't re-create them this session
        (data || []).forEach(s => _snapCacheAdd(roleId, s.snapshot_type));
        return data || [];
      } catch (_) { return []; }
    }

    // Render a single snapshot's expanded body from its snapshot_data.
    function renderSnapshotBody(sd) {
      if (!sd || typeof sd !== 'object') return '';
      const rows = [];

      const addRow = (label, value) => {
        if (!value && value !== 0) return;
        const str = typeof value === 'string' ? value : String(value);
        if (!str.trim()) return;
        rows.push({ label, value: str, isList: false });
      };
      const addList = (label, arr) => {
        if (!Array.isArray(arr) || !arr.length) return;
        rows.push({ label, value: arr, isList: true });
      };

      // Structural fields
      addRow('Company',      sd.company_name);
      addRow('Role',         sd.role_title);
      addRow('Location',     sd.location_text);
      addRow('Work model',   sd.work_model);
      addRow('Salary',       sd.salary_text_raw || sd.salary_range);
      addRow('Stage',        sd.stage || sd.role_status);
      addRow('Notes',        sd.notes);

      // Analysis fields
      addList('Reality summary',    sd.fit_reality_summary);
      addList('Looking for',        sd.what_they_are_really_looking_for);
      addList('You would do',       sd.what_you_would_actually_do);
      addList('Risks',              sd.risks_and_unknowns);

      // Raw JD (truncated)
      if (sd.raw_jd || sd.clean_jd) {
        const jd = (sd.clean_jd || sd.raw_jd || '').slice(0, 400);
        addRow('Job description', jd + ((sd.clean_jd || sd.raw_jd || '').length > 400 ? '…' : ''));
      }

      if (!rows.length) return '<div style="font-size:12.5px;color:var(--text-light);padding:10px 0;">No detail stored.</div>';

      return rows.map(r => {
        const valueHtml = r.isList
          ? `<ul>${r.value.map(item => `<li>${esc(String(item))}</li>`).join('')}</ul>`
          : esc(r.value);
        return `<div class="role-snapshot-field">
          <div class="role-snapshot-field-label">${esc(r.label)}</div>
          <div class="role-snapshot-field-value">${valueHtml}</div>
        </div>`;
      }).join('');
    }

    // Map snapshot_type to a human-readable event title for the timeline
    const SNAP_EVENT_LABELS = {
      'initial_analysis':       'Analysis recorded',
      'decision_set':           'Decision',
      'stage_applied':          'Application submitted',
      'stage_recruiter_screen': 'Recruiter replied',
      'stage_interview':        'Interview scheduled',
      'stage_offer':            'Offer received',
      'outcome_set':            'Outcome recorded',
      // User decision bar events
      'user_decision_skip':     'Role skipped',
      'user_decision_save':     'Role saved',
      'user_decision_apply':    'Application submitted',
      // legacy type — keep working
      'interview_stage':        'Interview stage reached',
    };

    // Dynamic title for a decision_set snapshot based on the raw decision value
    function _decisionSnapTitle(decisionRaw) {
      const map = {
        Apply: 'Marked Apply', apply: 'Marked Apply',
        Maybe: 'Marked Worth Exploring', maybe: 'Marked Worth Exploring',
        Skip:  'Marked Hard No',  skip:  'Marked Hard No',
      };
      return map[decisionRaw] || 'Decision noted';
    }

    // Friendly label for decision values
    function snapDecisionLabel(d) {
      if (!d) return null;
      const map = { Apply: 'Apply', Maybe: 'Worth exploring', Skip: 'Hard no',
                    apply: 'Apply', maybe: 'Worth exploring', skip: 'Hard no' };
      return map[d] || d;
    }

    // Friendly label for outcome values
    function snapOutcomeLabel(o) {
      if (!o) return null;
      const map = { rejected: 'Rejected', skipped: 'Closed without applying',
                    withdrew: 'Withdrew', offer_accepted: 'Offer accepted', closed: 'Closed',
                    no_response: 'No response', ghosted: 'Ghosted' };
      return map[o] || o;
    }

    // Render the Role snapshots section into a container element.
    function renderSnapshotsSection(snapshots, sectionEl) {
      const header = `<div class="rsnap-header">
        <div class="rsnap-title">Snapshots</div>
        <div class="rsnap-subtitle">Key moments in the lifecycle of this role.</div>
      </div>`;

      if (!snapshots.length) {
        sectionEl.innerHTML = `${header}<div class="rsnap-empty">Snapshots will appear here as this role evolves.</div>`;
        return;
      }

      // snapshots are already newest-first from the DB query
      const itemsHtml = snapshots.map(snap => {
        const sd = snap.snapshot_data || {};
        const dateStr = new Date(snap.created_at).toLocaleDateString('en-GB', {
          day: 'numeric', month: 'short', year: 'numeric',
        });

        // Derive event title: prefer mapped type label, fall back to stored title
        const eventTitle = SNAP_EVENT_LABELS[snap.snapshot_type] || snap.snapshot_title || 'Event';

        // Stage: prefer snapshot_data.stage, fall back by type
        const stage = sd.stage || sd.role_status ||
          (snap.snapshot_type === 'initial_analysis' ? 'JD Review' : null) ||
          (snap.snapshot_type === 'outcome_set'       ? 'Outcome'   : null);

        // Decision: from snapshot_data; for outcome_set derive from outcome
        const rawDecision = sd.decision || null;
        const decisionDisplay = rawDecision
          ? snapDecisionLabel(rawDecision)
          : (snap.snapshot_type === 'outcome_set' ? snapOutcomeLabel(sd.outcome) : null);

        // Notes: from snapshot_data.notes or outcome reason
        const notes = sd.notes || (snap.snapshot_type === 'outcome_set' && sd.reason ? sd.reason : null);

        // Build field rows — only show fields that have content
        const fields = [];
        if (stage)           fields.push({ label: 'Stage',               value: stage });
        if (decisionDisplay) fields.push({ label: 'Decision at the time', value: decisionDisplay });
        if (notes)           fields.push({ label: 'Notes',               value: notes });

        const fieldsHtml = fields.map(f =>
          `<div class="rsnap-field-row">
            <span class="rsnap-field-label">${esc(f.label)}</span>
            <span class="rsnap-field-value">${esc(f.value)}</span>
          </div>`
        ).join('');

        return `<div class="rsnap-item">
          <div class="rsnap-card">
            <div class="rsnap-card-top">
              <span class="rsnap-event-title">${esc(eventTitle)}</span>
              <span class="rsnap-date">${dateStr}</span>
            </div>
            ${fields.length ? `<div class="rsnap-fields">${fieldsHtml}</div>` : ''}
          </div>
        </div>`;
      }).join('');

      sectionEl.innerHTML = `${header}<div class="rsnap-timeline">${itemsHtml}</div>`;
    }

    // ─── Outcome Learning ─────────────────────────────────────────────────────

    const OUTCOME_LABELS = {
      // Current quick-outcome values (spec)
      skipped:           'Skip',
      applied:           'Applied',
      recruiter_replied: 'Recruiter replied',
      interviewed:       'Interviewed',
      rejected:          'Rejected',
      offer_received:    'Offer received',
      accepted:          'Accepted',
      // Legacy values (kept for backwards compatibility)
      offer:             'Offer received',
      withdrew:          'Withdrew',
      no_response:       'No response',
      ghosted:           'Ghosted',
      closed:            'Role closed',
    };

    // Ordered list for the quick-outcome button row
    const QUICK_OUTCOME_OPTIONS = [
      { val: 'skipped',           label: 'Skip'             },
      { val: 'applied',           label: 'Applied'          },
      { val: 'recruiter_replied', label: 'Recruiter replied'},
      { val: 'interviewed',       label: 'Interviewed'      },
      { val: 'rejected',          label: 'Rejected'         },
      { val: 'no_response',       label: 'No response'      },
      { val: 'ghosted',           label: 'Ghosted'          },
      { val: 'offer_received',    label: 'Offer received'   },
      { val: 'accepted',          label: 'Accepted'         },
    ];

    // Shared theme detector — returns a short label if the text corpus matches a cluster.
    function _detectThemeLabel(corpus) {
      const t = (corpus || '').toLowerCase();
      if (/design\s+system/i.test(t))                                         return 'design systems';
      if (/product\s+strateg|go.to.market|\bgtm\b|product\s+vision/i.test(t)) return 'product strategy';
      if (/people\s+manag|direct\s+report|manage\s+engineers/i.test(t))       return 'people management';
      if (/data\s+analytic|analytics\b|data.driven|data\s+strategy/i.test(t)) return 'data and analytics';
      if (/technical\s+(lead|leadership)|tech\s+lead/i.test(t))               return 'technical leadership';
      if (/early.stage|seed\s+stage|series\s+[ab]\b|scrappy\b/i.test(t))      return 'early-stage environments';
      if (/production\s+(code|coding)|hands.on\s+(coding|eng)/i.test(t))      return 'production engineering';
      if (/stakeholder|executive.*align|senior\s+stakeholder/i.test(t))       return 'stakeholder management';
      return null;
    }

    // Conservative rule-based learning generation.
    // Returns an array of 0–3 short observation strings.
    function generateLearningTexts(role, outcomeState, outcomeReason) {
      const texts = [];
      const mo       = role.latest_match_output || {};
      const hardNo   = mo.hard_no === true;
      const risks    = Array.isArray(mo.risks_and_unknowns)             ? mo.risks_and_unknowns             : [];
      const reality  = Array.isArray(mo.fit_reality_summary)            ? mo.fit_reality_summary            : [];
      const lookingFor = Array.isArray(mo.what_they_are_really_looking_for)
        ? mo.what_they_are_really_looking_for : [];

      const wasPromotedOrApplied = currentStageIndex(role) >= 0;

      // Rule 1 — promoted/applied + rejected + hard_no or multiple risks
      if (wasPromotedOrApplied && outcomeState === 'rejected' && (hardNo || risks.length >= 2)) {
        texts.push('This role carried risks you had already noticed. It\u2019s hard to know how much they mattered in the final decision.');
      }

      // Rule 2 — promoted/applied + reached interview or offer: positive signal
      if (wasPromotedOrApplied && ['interviewed', 'offer'].includes(outcomeState)) {
        const corpus = [...reality, ...lookingFor].join(' ');
        const theme  = _detectThemeLabel(corpus);
        if (theme) {
          texts.push(`It looks like roles involving ${theme} are worth pursuing for you.`);
        } else if (reality.length) {
          texts.push('Based on what you captured, this type of role resonated with your profile.');
        }
      }

      // Rule 3 — offer: reinforce positive signal (separate from interview rule)
      if (outcomeState === 'offer' && texts.length < 3) {
        texts.push('You received an offer here. Based on what you captured, this role aligned with your preferences.');
      }

      // Rule 4 — withdrew with a reason: reflect it back calmly
      if (outcomeState === 'withdrew' && outcomeReason && texts.length < 3) {
        texts.push(`Based on what you captured: \u201c${outcomeReason}\u201d.`);
      }

      // Rule 5 — no salary + no_response
      if (outcomeState === 'no_response' && !role.salary_text_raw && texts.length < 3) {
        const pd = role.latest_match_output?.practical_details;
        if (!pd?.salary_range && !pd?.salary) {
          texts.push('Salary wasn\u2019t listed for this role. This often correlates with lower response rates.');
        }
      }

      return texts.slice(0, 3);
    }

    // role_learnings = AI-extracted confidence signals about role quality/fit (system use only).
    // GUARD RAIL: Do NOT use saveLearnings()/loadLearnings() for workspace insights (concerns,
    //             observations, company context, recruiter signals). Those belong in role_insights
    //             via wsAddInsight(). role_learnings is system-generated; role_insights is user-facing.

    // Persist learning texts for a role (replaces any existing learnings for this role).
    async function saveLearnings(roleId, texts) {
      if (!roleId || !texts.length) return;
      // Delete old learnings then insert new ones
      await db.from('role_learnings').delete().eq('role_id', roleId).catch(() => {});
      for (const text of texts) {
        await db.from('role_learnings').insert({
          role_id:       roleId,
          learning_text: text,
          source:        'system',
          confidence:    'low',
        }).catch(() => {});
      }
    }

    // Load learnings for a role.
    async function loadLearnings(roleId) {
      try {
        const { data } = await db.from('role_learnings')
          .select('id, learning_text, confidence, created_at')
          .eq('role_id', roleId)
          .order('created_at', { ascending: true })
          .limit(5);
        return data || [];
      } catch (_) { return []; }
    }

    // Save outcome: update roles, log event, generate and persist learnings.
    async function saveOutcome(roleId, outcomeState, outcomeReason, role) {
      const now = new Date().toISOString();
      const { error } = await db.from('roles').update({
        outcome_state:  outcomeState,
        outcome_reason: outcomeReason || null,
        outcome_at:     now,
      }).eq('id', roleId);
      if (error) throw error;

      // Log outcome in role_updates so it appears in History
      const { data: newUpdateRow } = await db.from('role_updates').insert({
        role_id:       roleId,
        event_type:    'outcome',
        outcome_state: outcomeState,
        note:          outcomeReason || null,
        created_at:    now,
      }).select().single();

      // Update local cache — include new role_updates row so History section reflects it
      allRoles = allRoles.map(r => {
        if (r.id !== roleId) return r;
        const newEntry = newUpdateRow || {
          id: `tmp-${Date.now()}`, role_id: roleId,
          event_type: 'outcome', outcome_state: outcomeState,
          note: outcomeReason || null, created_at: now,
        };
        const updatedUpdates = [newEntry, ...(r.role_updates || [])];
        return { ...r, outcome_state: outcomeState, outcome_reason: outcomeReason || null, outcome_at: now, role_updates: updatedUpdates };
      });

      // Append to decision ledger
      const _ledgerType = { skipped: 'skip', withdrew: 'withdraw', offer_accepted: 'accept' }[outcomeState] || 'other';
      await wsAppendDecision(roleId, _ledgerType, outcomeReason || null);
      wsRefreshDecisionHistory(roleId).catch(() => {});

      // Generate and persist learnings
      const roleForLearning = allRoles.find(r => r.id === roleId) || role;
      const texts = generateLearningTexts(roleForLearning, outcomeState, outcomeReason || '');
      await saveLearnings(roleId, texts);
      return texts;
    }

    // Load past outcome_reason values for suggestion chips.
    async function loadOutcomeReasonChips() {
      try {
        const { data } = await db.from('roles')
          .select('outcome_reason')
          .not('outcome_reason', 'is', null)
          .order('outcome_at', { ascending: false })
          .limit(50);
        if (!data) return [];
        const seen = new Set();
        return data
          .map(r => r.outcome_reason?.trim())
          .filter(r => r && !seen.has(r) && seen.add(r))
          .slice(0, 6);
      } catch (_) { return []; }
    }

    // Render the full Outcome Learning section into a container element.
    function renderOutcomeSection(role, learnings, sectionEl) {
      const hasOutcome = !!role.outcome_state;
      const currentVal  = role.outcome_state || '';
      const outcomeLabel = OUTCOME_LABELS[currentVal] || currentVal || '';
      const recordedDate = role.outcome_at
        ? new Date(role.outcome_at).toLocaleDateString('en-GB', { day: 'numeric', month: 'short' })
        : '';

      // --- Learnings block (shown only when outcome recorded) ---
      let learningsHtml = '';
      if (hasOutcome && learnings.length) {
        const items = learnings.map(l => `<li>${esc(l.learning_text)}</li>`).join('');
        learningsHtml = `
          <div class="outcome-learnings-wrap" style="margin-top:12px;">
            <div class="outcome-learnings-label">What we learned</div>
            <ul class="outcome-learning-list">${items}</ul>
          </div>`;
      }

      // --- Recorded outcome display (when an outcome exists) ---
      const recordedDisplay = hasOutcome ? `
        <div class="outcome-recorded-row">
          <span class="outcome-recorded-label">Outcome recorded:</span>
          <span class="outcome-recorded-val">${esc(outcomeLabel)}</span>
          ${recordedDate ? `<span class="outcome-recorded-date">${esc(recordedDate)}</span>` : ''}
        </div>
        ${learningsHtml}` : '';

      // --- Quick-outcome buttons — always visible, current value highlighted ---
      const quickBtns = QUICK_OUTCOME_OPTIONS.map(opt => `
        <button class="quick-outcome-btn${opt.val === currentVal ? ' active' : ''}"
                data-val="${opt.val}"
                aria-pressed="${opt.val === currentVal ? 'true' : 'false'}"
        >${esc(opt.label)}</button>`).join('');

      const savingMsg = `<span class="outcome-saving-msg" id="outcome-saving-msg" style="display:none;">Saving\u2026</span>`;

      sectionEl.innerHTML = `
        <div class="doc-section-heading">Outcome</div>
        <div class="quick-outcome-buttons" id="quick-outcome-buttons">${quickBtns}</div>
        ${savingMsg}
        ${recordedDisplay}`;

      // ── Wire quick-outcome buttons: single click saves immediately ──────────
      sectionEl.querySelectorAll('.quick-outcome-btn').forEach(btn => {
        btn.addEventListener('click', async () => {
          const newVal = btn.dataset.val;
          if (newVal === currentVal) return; // already recorded — no-op

          // Optimistic UI: highlight the tapped button
          sectionEl.querySelectorAll('.quick-outcome-btn').forEach(b => {
            b.classList.remove('active');
            b.setAttribute('aria-pressed', 'false');
          });
          btn.classList.add('active');
          btn.setAttribute('aria-pressed', 'true');

          const msgEl = document.getElementById('outcome-saving-msg');
          if (msgEl) msgEl.style.display = '';

          try {
            await saveOutcome(role.id, newVal, '', role);
            const updatedRole = allRoles.find(r => r.id === role.id) || role;
            const updatedLearnings = await loadLearnings(role.id);
            renderOutcomeSection(updatedRole, updatedLearnings, sectionEl);

            // ── Refresh History section with the new outcome event ──────────
            const roleRecord = document.getElementById('role-record');
            if (roleRecord) {
              const historySections = roleRecord.querySelectorAll('.doc-section');
              for (const sec of historySections) {
                const heading = sec.querySelector('.doc-section-heading');
                if (heading && heading.textContent.trim() === 'History') {
                  const OUTCOME_DISPLAY = {
                    rejected: 'Rejected', skipped: 'Skipped', applied: 'Applied',
                    recruiter_replied: 'Recruiter replied', interviewed: 'Interviewed',
                    offer_received: 'Offer received', accepted: 'Accepted',
                    withdrew: 'Withdrew', no_response: 'No response', ghosted: 'Ghosted', closed: 'Role closed',
                  };
                  const activityEl = sec.querySelector('.doc-activity');
                  if (activityEl) {
                    const today = new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });
                    const newEntryHtml = `<div class="timeline-entry timeline-significant">
                      <div class="timeline-label">Outcome recorded: ${esc(OUTCOME_DISPLAY[newVal] || newVal)} <span class="timeline-date">\u2013 ${esc(today)}</span></div>
                    </div>`;
                    activityEl.insertAdjacentHTML('afterbegin', newEntryHtml);
                  }
                  break;
                }
              }
            }
          } catch (e) {
            if (msgEl) msgEl.textContent = 'Failed to save.';
          }
        });
      });
    }

    // ─────────────────────────────────────────────────────────────────────────
    // ─── Role Workspace v1 ───────────────────────────────────────────────────
    // Entry point: renderRoleDoc() → guard routes here for blank roles.
    // Do NOT bulk-load workspace data. Load on demand when workspace opens.
    // Everything below is scoped to the currently-open role workspace.
    // ─────────────────────────────────────────────────────────────────────────

    // Detect paste content type for source-card routing
    function _wsContentType(text) {
      const t = text.trim();
      if (/^https?:\/\//i.test(t) && !t.includes('\n')) return 'url';
      // Email heuristic: has From:/Subject:/To: header patterns
      if (/^(from|subject|to|date)\s*:/im.test(t) && t.length > 100) return 'email';
      // Long text ≥ 250 chars = treat as JD / document
      if (t.length >= 250) return 'jd';
      return 'chat';
    }

    // Assess whether text contains enough role signal to produce a meaningful analysis.
    // Used by _wsRunAnalysis after cleaning to annotate weak-signal pastes (e.g. partial
    // page pastes, nav-heavy content) before rendering the artefact.
    // Returns 'ok' if at least one meaningful JD keyword is found, 'weak' otherwise.
    function _wsJDSignalStrength(text) {
      if (!text || text.length < 80) return 'weak';
      const JD_SIGNALS = /\b(responsibilities?|requirements?|qualifications?|experience|skills?|duties|you.?will|about the role|we.?re looking|preferred|must have|nice to have|salary|benefits?|compensation|apply|applying|position|job title|report(?:s|ing) to|you.?ll|we.?re hiring|join our|key responsibilities|what you.?ll do|we offer|the team|the role)\b/i;
      return JD_SIGNALS.test(text) ? 'ok' : 'weak';
    }

    // Build a collapsed source card HTML string (rendered inside the timeline)
    // ── Timeline entry classification ─────────────────────────────────────────
    // Every element appended to the workspace timeline carries a data-ws-entry
    // attribute drawn from this constant set. This is a DOM-only classification —
    // no database column, no schema change. It ensures rendering helpers, scroll
    // logic, and future polish code can distinguish entry types without relying
    // on CSS class checks.
    //
    // Persistence contract:
    //   chat_user / chat_assistant  → role_conversations
    //   source                      → raw text in role_conversations (re-classified on reload)
    //   artifact                    → role_artifacts
    //   system                      → role_updates / role_interactions
    //   ui_temp                     → DOM only, never persisted
    const WS_ENTRY = Object.freeze({
      CHAT_USER:      'chat_user',
      CHAT_ASSISTANT: 'chat_assistant',
      SOURCE:         'source',
      ARTIFACT:       'artifact',
      SYSTEM:         'system',
      UI_TEMP:        'ui_temp',
    });

    // ── Document upload helpers ───────────────────────────────────────────────

    // Read a File object as text (for plaintext types) or raw base64 (for binary).
    // Returns { text, base64, mime_type } where exactly one of text/base64 is set.
    function _wsReadFileContent(file) {
      return new Promise((resolve, reject) => {
        const mime = file.type || 'application/octet-stream';
        const isPlainText = /^text\//.test(mime) || /\.(txt|md|csv)$/i.test(file.name);
        const reader = new FileReader();
        if (isPlainText) {
          reader.onload  = () => resolve({ text: reader.result, base64: null, mime_type: mime });
          reader.onerror = reject;
          reader.readAsText(file);
        } else {
          reader.onload  = () => {
            // DataURL is "data:<mime>;base64,<data>" — strip the prefix
            const b64 = reader.result.split(',')[1] ?? '';
            resolve({ text: null, base64: b64, mime_type: mime });
          };
          reader.onerror = reject;
          reader.readAsDataURL(file);
        }
      });
    }

    // ── Document context card HTML ────────────────────────────────────────────

    const DOC_TYPE_LABEL = {
      jd:       'Job description detected',
      cv:       'CV / résumé detected',
      recruiter:'Recruiter message detected',
      note:     'Document added',
      unknown:  'File attached',
    };

    const DOC_TYPE_ICON = { jd: '📄', cv: '👤', recruiter: '✉️', note: '📎', unknown: '📎' };

    function _wsDocumentContextCardHtml(file, result) {
      const dtype   = result.document_type || 'unknown';
      const label   = DOC_TYPE_LABEL[dtype] || 'File attached';
      const icon    = DOC_TYPE_ICON[dtype]  || '📎';
      const summary = result.summary
        ? `<div class="ws-doc-card-summary">${esc(result.summary)}</div>`
        : '';
      return `
        <div class="ws-doc-context-card" data-ws-entry="${WS_ENTRY.UI_TEMP}"
             data-file-name="${esc(file.name)}" data-doc-type="${esc(dtype)}">
          <div class="ws-doc-card-header">
            <span class="ws-doc-card-icon">${icon}</span>
            <div class="ws-doc-card-meta">
              <div class="ws-doc-card-name">${esc(file.name)}</div>
              <div class="ws-doc-card-type-label">${esc(label)}</div>
            </div>
          </div>
          ${summary}
          <div class="ws-doc-card-prompt">I've added <strong>${esc(file.name)}</strong>. What would you like to do with it?</div>
          <div class="ws-doc-card-options">
            <button class="ws-doc-option-btn" data-action="cv">Use as my CV</button>
            <button class="ws-doc-option-btn" data-action="analyse">Analyse for this role</button>
            <button class="ws-doc-option-btn" data-action="extract">Extract recruiter / role details</button>
            <button class="ws-doc-option-btn" data-action="note">Store as a note</button>
          </div>
        </div>`;
    }

    // Render an extracted-data block inside the timeline (used by "extract" option).
    function _wsDocumentExtractCardHtml(result) {
      const d = result.extracted_data || {};
      const rows = [
        d.role_title    && ['Role',       d.role_title],
        d.company_name  && ['Company',    d.company_name],
        d.salary_text   && ['Salary',     d.salary_text],
        d.location      && ['Location',   d.location],
        d.remote_model  && ['Remote',     d.remote_model],
        d.contact_name  && ['Contact',    d.contact_name],
        d.contact_email && ['Email',      d.contact_email],
        d.contact_phone && ['Phone',      d.contact_phone],
      ].filter(Boolean);

      const skillsHtml = d.skills?.length
        ? `<div class="ws-doc-extract-row"><span class="ws-doc-extract-key">Skills</span>
             <span class="ws-doc-extract-val">${esc(d.skills.join(', '))}</span></div>`
        : '';

      const rowsHtml = rows.map(([k, v]) =>
        `<div class="ws-doc-extract-row">
          <span class="ws-doc-extract-key">${esc(k)}</span>
          <span class="ws-doc-extract-val">${esc(String(v))}</span>
         </div>`
      ).join('');

      return `
        <div class="ws-doc-extract-block" data-ws-entry="${WS_ENTRY.ARTIFACT}">
          <div class="ws-doc-extract-title">Extracted details</div>
          <div class="ws-doc-extract-rows">
            ${rowsHtml}${skillsHtml}
          </div>
        </div>`;
    }

    // ── Document option handler ───────────────────────────────────────────────

    async function _wsHandleDocumentOption(action, file, result, extractedText, role, timelineEl, cardEl) {
      // Replace option buttons with a "Done" confirmation line, then process.
      const optionsEl = cardEl.querySelector('.ws-doc-card-options');
      if (optionsEl) optionsEl.innerHTML = '<span class="ws-doc-option-chosen">Processing…</span>';

      const isTemp = role._isTemp;
      const dtype  = result.document_type || 'unknown';

      try {
        if (action === 'cv') {
          // Store as CV document. For temp roles, just show a message.
          if (!isTemp) {
            await wsAddDocument(role.id, {
              file_name:      file.name,
              file_size:      file.size,
              mime_type:      file.type,
              document_type:  'cv',
              extracted_text: extractedText || null,
              extracted_data: result.extracted_data || {},
            });
          }
          if (optionsEl) optionsEl.innerHTML = '<span class="ws-doc-option-chosen">✓ Saved as your CV for this role</span>';
          _wsUpdateDocumentsSection(role, timelineEl);

        } else if (action === 'analyse') {
          if (optionsEl) optionsEl.innerHTML = '<span class="ws-doc-option-chosen">Analysing…</span>';
          // If it looks like a JD (or forced), pass the text through _wsHandlePaste
          const textToAnalyse = extractedText || result.summary || '';
          if (!textToAnalyse) {
            if (optionsEl) optionsEl.innerHTML = '<span class="ws-doc-option-chosen">⚠ No readable text found in this file.</span>';
            return;
          }
          if (!isTemp) await wsAddDocument(role.id, {
            file_name: file.name, file_size: file.size, mime_type: file.type,
            document_type: dtype, extracted_text: extractedText || null,
            extracted_data: result.extracted_data || {},
          });
          if (optionsEl) optionsEl.innerHTML = '<span class="ws-doc-option-chosen">✓ Analysing…</span>';
          _wsUpdateDocumentsSection(role, timelineEl);
          await _wsHandlePaste(role, textToAnalyse, timelineEl);

        } else if (action === 'extract') {
          if (!isTemp) await wsAddDocument(role.id, {
            file_name: file.name, file_size: file.size, mime_type: file.type,
            document_type: dtype, extracted_text: extractedText || null,
            extracted_data: result.extracted_data || {},
          });
          if (optionsEl) optionsEl.innerHTML = '<span class="ws-doc-option-chosen">✓ Details extracted</span>';
          _wsUpdateDocumentsSection(role, timelineEl);
          // Render extracted data block in the timeline
          _wsAppend(timelineEl, _wsDocumentExtractCardHtml(result));

        } else if (action === 'note') {
          if (!isTemp) await wsAddDocument(role.id, {
            file_name: file.name, file_size: file.size, mime_type: file.type,
            document_type: 'note', extracted_text: extractedText || null,
            extracted_data: result.extracted_data || {},
          });
          if (optionsEl) optionsEl.innerHTML = '<span class="ws-doc-option-chosen">✓ Stored as a note</span>';
          _wsUpdateDocumentsSection(role, timelineEl);
        }
      } catch (e) {
        console.error('[_wsHandleDocumentOption]', e);
        if (optionsEl) optionsEl.innerHTML = '<span class="ws-doc-option-chosen">⚠ Something went wrong. Please try again.</span>';
      }
    }

    // ── Document context card presenter ──────────────────────────────────────

    function _wsShowDocumentContextCard(file, result, extractedText, role, timelineEl) {
      const wrapper = document.createElement('div');
      wrapper.innerHTML = _wsDocumentContextCardHtml(file, result);
      const cardEl = wrapper.firstElementChild;

      cardEl.querySelectorAll('.ws-doc-option-btn').forEach(btn => {
        btn.addEventListener('click', () => {
          // Disable all buttons after first choice
          cardEl.querySelectorAll('.ws-doc-option-btn').forEach(b => { b.disabled = true; });
          _wsHandleDocumentOption(btn.dataset.action, file, result, extractedText, role, timelineEl, cardEl);
        });
      });

      timelineEl.appendChild(cardEl);
      _wsSettle(cardEl);
      _wsScrollIfNear(timelineEl);
    }

    // ── File processing pipeline ──────────────────────────────────────────────

    async function _wsProcessUploadedFile(file, role, timelineEl, supabaseClient) {
      // Show a brief status line while reading and classifying the file.
      const statusEl = _wsStatusLine(timelineEl, `Reading ${file.name}…`);
      _wsScrollIfNear(timelineEl);

      try {
        const { text, base64, mime_type } = await _wsReadFileContent(file);
        statusEl.textContent = `Classifying ${file.name}…`;

        const { data: fnData, error: fnErr } = await supabaseClient.functions.invoke('document-extract', {
          body: {
            file_name:    file.name,
            mime_type:    mime_type,
            content_text: text   || undefined,
            content_base64: base64 || undefined,
          },
        });

        statusEl.remove();

        const result = (!fnErr && fnData) ? fnData : {
          document_type: 'unknown', confidence: 0, summary: '',
          extracted_data: {
            role_title: null, company_name: null, salary_text: null,
            contact_name: null, contact_email: null, contact_phone: null,
            location: null, remote_model: null,
            skills: [], responsibilities: [], requirements: [],
          },
        };

        _wsShowDocumentContextCard(file, result, text || '', role, timelineEl);

      } catch (e) {
        statusEl.remove();
        console.error('[_wsProcessUploadedFile]', e);
        _wsShowDocumentContextCard(file, { document_type: 'unknown', extracted_data: {} }, '', role, timelineEl);
      }
    }

    // ── Documents section renderer ────────────────────────────────────────────

    // Refreshes the documents section in the workspace header area.
    // Called after wsAddDocument and on workspace init.
    async function _wsUpdateDocumentsSection(role, timelineEl) {
      const sectionEl = document.getElementById('ws-documents-section');
      const listEl    = document.getElementById('ws-docs-list');
      const countEl   = document.getElementById('ws-docs-count-label');
      if (!sectionEl || !listEl || !countEl) return;

      if (role._isTemp) { sectionEl.hidden = true; return; }

      let docs = [];
      try { docs = await wsLoadDocuments(role.id); } catch (_) {}

      if (!docs.length) { sectionEl.hidden = true; return; }

      sectionEl.hidden = false;
      countEl.textContent = `${docs.length} document${docs.length !== 1 ? 's' : ''}`;

      const DTYPE_ICON = { jd: '📄', cv: '👤', recruiter: '✉️', note: '📎', unknown: '📎' };
      listEl.innerHTML = docs.map(doc => {
        const icon = DTYPE_ICON[doc.document_type] || '📎';
        const date = new Date(doc.created_at).toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });
        return `
          <div class="ws-doc-pill" data-id="${esc(doc.id)}">
            <span class="ws-doc-pill-icon">${icon}</span>
            <span class="ws-doc-pill-name">${esc(doc.file_name)}</span>
            <span class="ws-doc-pill-date">${esc(date)}</span>
          </div>`;
      }).join('');
    }

    // sourceName: optional — shown as a compact badge in the header for URL type.
    function _wsSourceCardHtml(text, type, sourceName = null) {
      const LABELS = { url: 'Job link added', jd: 'Job description added', email: 'Recruiter email added' };
      const ICONS  = { url: '🔗', jd: '📄', email: '✉️' };
      const label  = LABELS[type] || 'Content added';
      const icon   = ICONS[type]  || '📎';

      // Compact metadata line — word count for JD/email, clickable URL for links.
      // The full content is still available behind the "Show" toggle.
      let meta = '';
      if (type === 'url') {
        meta = `<a href="${esc(text)}" target="_blank" rel="noopener" class="ws-source-card-link">${esc(text.length > 80 ? text.slice(0, 80) + '…' : text)}</a>`;
      } else {
        const wordCount = text.trim().split(/\s+/).filter(Boolean).length;
        meta = `<span class="ws-source-card-wordcount">${wordCount.toLocaleString()} words</span>`;
      }

      // Source badge: shown for URL type when the origin platform is recognised.
      const sourceBadgeHtml = (type === 'url' && sourceName)
        ? `<span class="ws-source-badge">${esc(sourceName)}</span>`
        : '';

      const fullId  = 'ws-sc-' + Math.random().toString(36).slice(2);
      return `
        <div class="ws-source-card" data-type="${esc(type)}" data-ws-entry="${WS_ENTRY.SOURCE}">
          <div class="ws-source-card-header">
            <span class="ws-source-card-icon">${icon}</span>
            <span class="ws-source-card-label">${esc(label)}</span>
            ${sourceBadgeHtml}
            <button class="ws-source-card-toggle" data-target="${fullId}" aria-expanded="false">Show</button>
          </div>
          <div class="ws-source-card-preview">${meta}</div>
          <div class="ws-source-card-full hidden" id="${fullId}"><pre>${esc(text)}</pre></div>
        </div>`;
    }

    // Inline recruiter confirmation block — shown when extraction confidence is 'medium'
    // (name found in signature but no email to confirm identity reliably).
    function _wsRecruiterConfirmHtml(name, company) {
      const who = company ? `${esc(name)} from ${esc(company)}` : esc(name);
      return `
        <div class="ws-recruiter-confirm">
          <span class="ws-recruiter-confirm-q">Is ${who} the recruiter for this role?</span>
          <div class="ws-recruiter-confirm-btns">
            <button class="ws-confirm-yes">Yes</button>
            <button class="ws-confirm-no">Not sure</button>
          </div>
        </div>`;
    }

    // Build an analysis artefact block HTML from analysis JSON
    function _wsAnalysisArtefactHtml(analysis, artifactId) {
      const company = analysis._company || '';
      const title   = analysis._roleTitle || '';
      const heading = [company, title].filter(Boolean).join(' — ') || 'Role Analysis';
      return `
        <div class="ws-artifact ws-artifact--analysis" data-artifact-id="${esc(artifactId)}" data-ws-entry="${WS_ENTRY.ARTIFACT}" data-artifact-type="analysis">
          <div class="ws-artifact-header">
            <span class="ws-artifact-type-badge">Analysis</span>
            <span class="ws-artifact-heading">${esc(heading)}</span>
          </div>
          <div class="ws-artifact-body">
            ${renderMatchOutput(analysis)}
          </div>
        </div>`;
    }

    // Append an item into the workspace timeline and scroll it into view
    // ── Respectful scroll helper ──────────────────────────────────────────────
    // Only auto-scrolls if the user is already near the bottom (within 80px).
    // If they've scrolled away, shows the nudge pill instead.
    // Debounced at 16ms (one frame) so rapid back-to-back calls (e.g. user
    // bubble + thinking bubble inserted synchronously) collapse into a single
    // layout read + scrollTop write, eliminating extra reflows.
    // Force-scroll to bottom unconditionally — used when the user explicitly
    // sends a message or when the assistant first starts responding. Deferred
    // via rAF so the newly-appended element is included in scrollHeight.
    function _wsScrollToBottom(timelineEl) {
      const scrollEl = timelineEl || document.getElementById('ws-timeline');
      if (!scrollEl) return;
      requestAnimationFrame(() => {
        scrollEl.scrollTop = scrollEl.scrollHeight;
        const nudge = document.getElementById('ws-scroll-nudge');
        if (nudge) nudge.classList.remove('visible');
      });
    }

    let _wsScrollDebounceId = null;
    function _wsScrollIfNear(timelineEl) {
      // ws-timeline is the scroll container (col-chat has overflow:hidden in the
      // responsive layout — scrolling col-chat has no effect).
      const scrollEl = timelineEl || document.getElementById('ws-timeline');
      if (!scrollEl) return;
      clearTimeout(_wsScrollDebounceId);
      // setTimeout(0) lets synchronous DOM mutations finish (e.g. bubble append),
      // then requestAnimationFrame defers the scroll read until AFTER the browser
      // has computed layout for the new element. Without rAF, scrollHeight can
      // still reflect the pre-append value, causing the scroll to land short and
      // leaving the newest message partially out of view.
      _wsScrollDebounceId = setTimeout(() => {
        requestAnimationFrame(() => {
          const distFromBottom = scrollEl.scrollHeight - scrollEl.scrollTop - scrollEl.clientHeight;
          if (distFromBottom < 80) {
            scrollEl.scrollTop = scrollEl.scrollHeight;
            // Dismiss nudge — we are at (or very near) the bottom.
            const nudge = document.getElementById('ws-scroll-nudge');
            if (nudge) nudge.classList.remove('visible');
          } else {
            const nudge = document.getElementById('ws-scroll-nudge');
            if (nudge) nudge.classList.add('visible');
          }
        });
      }, 0);
    }

    // ── Settle animation helper ───────────────────────────────────────────────
    // Adds ws-settle class to assistant chat, artefacts, and clarifications.
    // Uses data-ws-entry (the canonical classification) rather than CSS class
    // checks, so future element styling changes don't silently break animation.
    // ui_temp and chat_user entries appear instantly — no settle.
    function _wsSettle(el) {
      if (!el) return;
      const entry = el.dataset.wsEntry;
      if (entry === WS_ENTRY.CHAT_ASSISTANT || entry === WS_ENTRY.ARTIFACT) {
        el.classList.add('ws-settle');
      }
    }

    function _wsAppend(timelineEl, html) {
      const wrapper = document.createElement('div');
      wrapper.innerHTML = html;
      const node = wrapper.firstElementChild || wrapper;
      _wsSettle(node);
      timelineEl.appendChild(node);
      _wsScrollIfNear(timelineEl);
    }

    // Show a simple assistant status line in the timeline
    // ── Workspace header updater ──────────────────────────────────────────────
    // Called after analysis or stage changes to keep the header in sync.
    // Non-destructive: only updates existing elements, never recreates the header.
    function _wsUpdateHeader(role) {
      const hdrEl = document.getElementById('ws-workspace-header');
      if (!hdrEl) return;

      const company = role.company_name || null;
      const title   = role.role_title   || null;
      const parts   = [];
      if (role.location_text)  parts.push(role.location_text);
      if (role.current_stage && role.current_stage !== 'JD Review') parts.push(role.current_stage);
      const ctx = parts.join(' · ');

      if (company) {
        hdrEl.innerHTML =
          `<div class="ws-header-company">${esc(company)}</div>` +
          `<div class="ws-header-title">${esc(title || 'Untitled role')}</div>` +
          (ctx ? `<div class="ws-header-context">${esc(ctx)}</div>` : '');
      }
    }

    function _wsStatusLine(timelineEl, text, id) {
      const div = document.createElement('div');
      div.className = 'ws-assistant-status';
      div.dataset.wsEntry = WS_ENTRY.UI_TEMP;
      if (id) div.id = id;
      div.textContent = text;
      timelineEl.appendChild(div);
      _wsScrollIfNear(timelineEl);
      return div;
    }

    // ─── Thinking bubble — temporary "Rolewise is thinking…" indicator ────────
    // Shown immediately when the user sends a plain chat message. Removed when
    // the real assistant reply arrives (or on error). Only one can exist at a
    // time — calling _wsShowThinking while one is active replaces it.
    function _wsShowThinking(timelineEl, text) {
      _wsRemoveThinking(timelineEl); // ensure no duplicates
      const el = document.createElement('div');
      el.className = 'ws-thinking-bubble';
      el.dataset.wsEntry = WS_ENTRY.UI_TEMP;
      el.innerHTML = `<span>${esc(text || 'Rolewise is thinking')}</span>`
        + '<span class="ws-thinking-dots"><span></span><span></span><span></span></span>';
      timelineEl.appendChild(el);
      // Always force-scroll when thinking bubble appears — the user just sent
      // and must see the response area regardless of prior scroll position.
      _wsScrollToBottom(timelineEl);
      return el;
    }

    // Remove the thinking bubble. Fades out over ~180ms, then removes the node.
    // If immediate=true, removes without animation (used in error paths).
    // After the node is actually removed the timeline scrollHeight shrinks by the
    // bubble's height (~36px). Without correction this causes a visible upward jump.
    // We correct by snapping scrollTop back to the bottom when the user was pinned there.
    function _wsRemoveThinking(timelineEl, immediate) {
      const el = timelineEl?.querySelector('.ws-thinking-bubble');
      if (!el) return;
      if (immediate) { el.remove(); return; }
      el.classList.add('ws-thinking--out');
      setTimeout(() => {
        if (el.isConnected) el.remove();
        // Correct scroll after the height collapse caused by node removal.
        // Wrapped in rAF so the browser has finished reflowing the timeline
        // (recalculating scrollHeight after the node is gone) before we read
        // it. Without rAF, scrollHeight can still include the removed node's
        // height, causing an overshoot that snaps back on the next paint.
        if (timelineEl) {
          requestAnimationFrame(() => {
            const dist = timelineEl.scrollHeight - timelineEl.scrollTop - timelineEl.clientHeight;
            if (dist < 80) timelineEl.scrollTop = timelineEl.scrollHeight;
          });
        }
      }, 200);
    }

    // One optional clarification question after analysis — ask only if something meaningful is missing
    function _wsClarificationQuestion(role, analysis) {
      // Priority: salary → URL → source
      // Each question has a specific type so the reply handler can interpret the answer correctly.
      const hasSalary = !!(analysis?.practical_details?.salary_annual ||
                           analysis?.practical_details?.salary_range ||
                           role.salary_text_raw);
      const hasUrl    = !!(role.job_url);
      const hasSource = !!(role.source);

      if (!hasSalary)
        return { text: 'Do you know the salary range for this role?', type: 'missing_salary' };
      if (!hasUrl)
        return { text: 'Do you have the original job posting link? You can paste it here.', type: 'missing_job_url' };
      if (!hasSource)
        return { text: 'Where did you find this role?', type: 'missing_source', hint: 'e.g. LinkedIn, recruiter, company site' };

      return null; // nothing missing — don't ask
    }

    // Render a clarification question bubble into the timeline
    function _wsRenderClarification(timelineEl, question) {
      if (!question) return;
      // Job URL prompt → plain assistant message (no styled card)
      if (question.type === 'missing_job_url') {
        const msg = 'Do you have the original job posting link?\nIf you do, paste it here and I\'ll attach it to the role.';
        _wsAppend(timelineEl, `<div class="ws-assistant-reply ws-settle" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">${esc(msg)}</div>`);
        return;
      }
      // Other clarification types → styled card
      const hint = question.hint ? `<div class="ws-clarification-hint">${esc(question.hint)}</div>` : '';
      const div = document.createElement('div');
      div.className = 'ws-clarification ws-settle';
      div.dataset.wsEntry = WS_ENTRY.CHAT_ASSISTANT;
      div.innerHTML = `<div class="ws-clarification-text">${esc(question.text)}</div>${hint}`;
      timelineEl.appendChild(div);
      _wsScrollIfNear(timelineEl);
    }

    // Returns true if text is an explicit role-decision statement ("skip this", "I'm passing", etc.)
    // These should bypass the clarification handler and go straight to the generic AI chat path.
    function _wsIsRoleDecision(text) {
      return /\b(skip\s+this|i'?m\s+passing|not\s+for\s+me|i\s+don'?t\s+want\s+this|withdrawing|pulling\s+out|no\s+longer\s+(interested|pursuing)|i'?m\s+out)\b/i.test(text);
    }

    // ── Decision Ledger ───────────────────────────────────────────────────────
    // Detects skip / apply / withdraw intent in chat and offers reason capture chips.
    // Returns { decision: 'skip'|'apply'|'withdraw' } or null.
    function _wsDetectDecision(text) {
      const t = text.trim();
      if (t.length < 4 || t.length > 300) return null;
      if (/\b(withdrawing\s+my\s+(application|candidacy)|no\s+longer\s+pursuing|pulling\s+out\s+of|i'?m\s+withdrawing|going\s+to\s+withdraw)\b/i.test(t))
        return { decision: 'withdraw' };
      if (/\b(skip\s+this|i'?m\s+passing|not\s+for\s+me|i\s+don'?t\s+want\s+this|no\s+longer\s+interested|i'?m\s+out|going\s+to\s+skip|gonna\s+skip|i'?ll\s+skip|i'?m\s+going\s+to\s+skip)\b/i.test(t))
        return { decision: 'skip' };
      if (/\b(i'?m\s+going\s+to\s+apply|going\s+to\s+apply|i'?ll\s+apply|i'?m\s+applying|decided\s+to\s+apply|going\s+to\s+go\s+for\s+it|i'?m\s+going\s+for\s+it|i\s+want\s+to\s+apply)\b/i.test(t))
        return { decision: 'apply' };
      return null;
    }

    // Acknowledge a decision and, for skip/withdraw, offer reason chips.
    async function _wsHandleDecision(role, decision, timelineEl) {
      const ackText = {
        skip:     "Got it — passing on this one. Any particular reason?",
        withdraw: "Understood — noted that you're withdrawing. Any particular reason?",
        apply:    "Nice — good luck with the application! Let me know how it goes.",
      }[decision] || "Got it.";

      const bubble = document.createElement('div');
      bubble.className = 'ws-assistant-reply ws-settle';
      bubble.dataset.wsEntry = WS_ENTRY.CHAT_ASSISTANT;
      bubble.textContent = ackText;
      timelineEl.appendChild(bubble);
      _wsScrollIfNear(timelineEl);

      // Apply: append ledger record immediately (no reason prompt for apply)
      if (decision === 'apply') {
        await wsAppendDecision(role.id, 'apply', null);
        wsRefreshDecisionHistory(role.id).catch(() => {});
      }

      if (decision === 'skip' || decision === 'withdraw') {
        role._pendingDecisionCapture = decision;
        _wsRenderDecisionChips([
          'Salary too low',
          'Too much production coding',
          'Scope unclear',
          'Location / remote mismatch',
          'Senior / experience gap',
          'Not the right time',
          'Skip for now',
          'Other',
        ], timelineEl);
      }
    }

    // Render reason chips for a decision. Reuses ws:chip-send to flow through _wsHandlePaste.
    function _wsRenderDecisionChips(chips, timelineEl) {
      const row = document.createElement('div');
      row.className = 'ws-chat-chips ws-decision-chips';
      chips.forEach(label => {
        const btn = document.createElement('button');
        btn.className = 'ws-chip';
        btn.textContent = label;
        btn.addEventListener('click', () => {
          row.remove();
          timelineEl.dispatchEvent(new CustomEvent('ws:chip-send', {
            bubbles: true,
            detail: { text: label },
          }));
        });
        row.appendChild(btn);
      });
      timelineEl.appendChild(row);
      _wsScrollIfNear(timelineEl);
    }

    // ── Workspace Decision Bar ─────────────────────────────────────────────────
    // Shown in the workspace timeline after a fresh JD analysis completes.
    // Replaces the old static "conversation checkpoint" text block.
    //
    // Three actions:
    //   Apply         → user_decision = 'apply', ledger record, acknowledgement
    //   Explore Further → user_decision = 'save', acknowledgement
    //   Pass          → shows inline reason chips; records skip + optional reason
    //
    // Reason chips for Pass (spec-defined set — matches Decision Memory categories):
    //   Salary missing | Salary too low | Too much coding | Commute too long |
    //   Role unclear | Company not interesting | Other
    //   + "Skip this" to pass without recording a reason.
    //
    // Guard: checks role._isTemp before writing to DB. If role hasn't saved yet
    // (edge case — save usually completes in <1s), shows a gentle retry message.
    function _wsRenderDecisionBar(role, timelineEl) {
      if (!timelineEl.isConnected) return;
      const overviewEl = document.getElementById('ws-next-action');
      if (!overviewEl) return;

      const PASS_REASONS = [
        'Salary missing',
        'Salary too low',
        'Too much coding',
        'Commute too long',
        'Role unclear',
        'Company not interesting',
        'Other',
      ];

      const barEl = document.createElement('div');
      barEl.className = 'ws-decision-bar ws-settle';
      barEl.dataset.wsEntry = WS_ENTRY.UI_TEMP;

      function _showInitial() {
        barEl.innerHTML =
          `<div class="ws-dbar-prompt">What do you want to do with this role?</div>
           <div class="ws-dbar-actions">
             <button class="ws-dbar-btn ws-dbar-apply">Apply</button>
             <button class="ws-dbar-btn ws-dbar-explore">Explore Further</button>
             <button class="ws-dbar-btn ws-dbar-pass">Pass</button>
           </div>`;
        barEl.querySelector('.ws-dbar-apply').addEventListener('click', () => _decide('apply'));
        barEl.querySelector('.ws-dbar-explore').addEventListener('click', () => _decide('save'));
        barEl.querySelector('.ws-dbar-pass').addEventListener('click', _showPassReasons);
      }

      function _showPassReasons() {
        barEl.innerHTML =
          `<div class="ws-dbar-prompt">What made you decide to pass?</div>
           <div class="ws-dbar-reasons">
             ${PASS_REASONS.map(r => `<button class="ws-dbar-reason">${esc(r)}</button>`).join('')}
             <button class="ws-dbar-reason ws-dbar-reason--skip">Skip this</button>
           </div>`;
        barEl.querySelectorAll('.ws-dbar-reason:not(.ws-dbar-reason--skip)').forEach(btn => {
          btn.addEventListener('click', () => _pass(btn.textContent.trim()));
        });
        barEl.querySelector('.ws-dbar-reason--skip')?.addEventListener('click', () => _pass(null));
      }

      async function _decide(decision) {
        barEl.remove();
        overviewEl.style.display = 'none';
        if (role._isTemp) {
          _wsAppend(timelineEl, `<div class="ws-assistant-reply ws-settle" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">Still saving the role \u2014 give it a moment, then use the decision buttons in the panel.</div>`);
          return;
        }
        await _setUserDecision(role, decision);
        const ackText = decision === 'apply'
          ? 'Noted \u2014 good luck with the application.'
          : 'Saved for further exploration.';
        _wsAppend(timelineEl, `<div class="ws-assistant-reply ws-settle" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">${esc(ackText)}</div>`);
        if (decision === 'apply') wsAppendDecision(role.id, 'apply', null).catch(() => {});
        if (decision === 'save')  wsAppendDecision(role.id, 'other', null, 'explore_further').catch(() => {});
        wsRefreshDecisionHistory(role.id).catch(() => {});
        // Decision Confidence — optional reflective prompt shown after the decision is confirmed.
        setTimeout(() => _wsRenderDecisionConfidence(role, timelineEl), 120);
      }

      async function _pass(reason) {
        barEl.remove();
        overviewEl.style.display = 'none';
        if (role._isTemp) {
          _wsAppend(timelineEl, `<div class="ws-assistant-reply ws-settle" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">Still saving \u2014 give it a moment, then use the decision buttons in the panel.</div>`);
          return;
        }
        await _setUserDecision(role, 'skip');
        if (reason) {
          await _wsStoreDecisionReason(role, 'skip', reason, timelineEl);
        } else {
          wsAppendDecision(role.id, 'skip', null).catch(() => {});
          wsRefreshDecisionHistory(role.id).catch(() => {});
          _wsAppend(timelineEl, `<div class="ws-assistant-reply ws-settle" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">Got it \u2014 archived.</div>`);
        }
        // Decision Confidence — optional reflective prompt shown after the decision is confirmed.
        setTimeout(() => _wsRenderDecisionConfidence(role, timelineEl), 120);
      }

      _showInitial();
      overviewEl.innerHTML = '';
      overviewEl.appendChild(barEl);
      overviewEl.style.display = '';
    }

    // Returns true if text looks like a short decision reason rather than a new question.
    // Used to decide whether a message should be consumed as a reason or passed through to AI.
    // Rules: no question mark, no interrogative opener, not too long.
    function _wsIsDecisionReason(text) {
      const t = text.trim();
      if (t.includes('?')) return false;
      if (/^(what|how|why|when|where|who|is|are|do|does|can|could|would|should|will|has|have)\b/i.test(t)) return false;
      if (t.length > 100) return false;
      return true;
    }

    // Store the captured reason against the role and append a ledger record.
    // decisionType: the decision that triggered the reason prompt ('skip' | 'withdraw').
    async function _wsStoreDecisionReason(role, decisionType, reason, timelineEl) {
      // Keep roles.outcome_reason as the latest summary (existing behaviour unchanged)
      try {
        await db.from('roles').update({ outcome_reason: reason }).eq('id', role.id);
        allRoles = allRoles.map(r => r.id === role.id ? { ...r, outcome_reason: reason } : r);
        role.outcome_reason = reason;
      } catch (_) {}

      // Append an immutable ledger record, then refresh the history block if workspace is open
      await wsAppendDecision(role.id, decisionType, reason);
      wsRefreshDecisionHistory(role.id).catch(() => {});

      // Check for a cross-role pattern with the same reason (silent query, no throw)
      let patternNote = '';
      try {
        const { data } = await db.from('roles')
          .select('id')
          .not('outcome_reason', 'is', null)
          .ilike('outcome_reason', reason)
          .neq('id', role.id);
        if (data && data.length >= 2) {
          patternNote = ` You've flagged this for ${data.length} other role${data.length === 1 ? '' : 's'} too.`;
        }
      } catch (_) {}

      const conf = document.createElement('div');
      conf.className = 'ws-assistant-reply ws-settle';
      conf.dataset.wsEntry = WS_ENTRY.CHAT_ASSISTANT;
      conf.textContent = `Noted — saved.${patternNote}`;
      timelineEl.appendChild(conf);
      _wsScrollIfNear(timelineEl);
    }

    // ── Decision Confidence prompt ─────────────────────────────────────────────
    // Shown after the user marks a role as Apply, Explore Further, or Pass.
    // Optional — the user can skip without selecting. Captured signal is stored
    // in role_decisions.confidence for product evaluation purposes.
    // Tone: calm and reflective, not survey-like.
    function _wsRenderDecisionConfidence(role, timelineEl) {
      if (role._isTemp || !role.id) return;
      const card = document.createElement('div');
      card.className = 'ws-dc-card ws-settle';
      card.dataset.wsEntry = WS_ENTRY.UI_TEMP;
      card.innerHTML =
        `<div class="ws-dc-prompt">How confident do you feel about this decision?</div>` +
        `<div class="ws-dc-options">` +
          `<button class="ws-dc-btn" data-val="very_clear">Very clear decision</button>` +
          `<button class="ws-dc-btn" data-val="mostly_clear">Mostly clear</button>` +
          `<button class="ws-dc-btn" data-val="still_unsure">Still unsure</button>` +
          `<button class="ws-dc-skip">Skip</button>` +
        `</div>`;
      timelineEl.appendChild(card);
      _wsScrollIfNear(timelineEl);
      card.querySelectorAll('.ws-dc-btn').forEach(btn => {
        btn.addEventListener('click', () => {
          card.remove();
          wsUpdateDecisionConfidence(role.id, btn.dataset.val).catch(() => {});
        });
      });
      card.querySelector('.ws-dc-skip')?.addEventListener('click', () => card.remove());
    }

    // Handle a short reply that was directed at the active clarification question.
    // Gives a specific, contextual response rather than routing to the generic AI.
    async function _wsHandleClarificationReply(role, text, timelineEl) {
      const clarType = role._pendingClarification;
      role._pendingClarification = null; // always clear — one reply per clarification

      const t = text.trim().toLowerCase();
      const isNo  = /^(no|nope|nah|i\s+don'?t|don'?t\s+have|can'?t\s+find|haven'?t\s+got|not\s+sure|not\s+really|no\s+idea|i\s+can'?t)\b/i.test(t);
      const isYes = /^(yes|yeah|yep|sure|yup|ok|okay|yep|of\s+course)\b/i.test(t);

      let reply;

      if (clarType === 'missing_job_url') {
        if (isNo) {
          reply = "No problem — we can continue without the link for now. If you find it later, just paste it here and I'll attach it to this role.";
        } else if (isYes) {
          reply = "Great — paste the URL whenever you're ready and I'll attach it.";
        } else {
          // Unexpected answer — pass to AI with the full clarification context intact
          await _wsTriggerChat(role, text, timelineEl);
          return;
        }

      } else if (clarType === 'missing_salary') {
        if (isNo) {
          reply = "OK, we'll leave salary as unknown for now. Let me know if you find out the range.";
        } else if (isYes) {
          reply = "What's the salary or range?";
        } else {
          // Might contain actual salary info — let AI handle it
          await _wsTriggerChat(role, text, timelineEl);
          return;
        }

      } else if (clarType === 'missing_source') {
        if (isNo || isYes) {
          reply = "No problem, you can let me know where you found it later.";
        } else if (t.length < 80) {
          // Treat as the actual source name (e.g. "LinkedIn", "a recruiter")
          db.from('roles').update({ source: text.trim() }).eq('id', role.id).catch(() => {});
          role.source = text.trim();
          const srcLabel = text.trim().charAt(0).toUpperCase() + text.trim().slice(1);
          reply = `Got it — noted as "${srcLabel}".`;
        } else {
          await _wsTriggerChat(role, text, timelineEl);
          return;
        }

      } else {
        // Unknown clarification type — fall back to AI
        await _wsTriggerChat(role, text, timelineEl);
        return;
      }

      _wsAppend(timelineEl, `<div class="ws-assistant-reply" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">${esc(reply)}</div>`);
      wsAddMessage(role.id, 'assistant', reply).catch(() => {});
    }

    // ─── UK salary take-home calculator ──────────────────────────────────────
    // Deterministic client-side PAYE + NI estimate using 2024/25 rates.
    // Salary sacrifice model: pension deducted before income tax and NI.
    // Returns monthly and annual figures for display.
    // grossAnnual — full annual salary before any deductions (number, £)
    // pensionPct  — employer/employee sacrifice as % of gross (default 10)
    function calculateUKTakeHome(grossAnnual, pensionPct = 10) {
      // 2024/25 thresholds
      const PA_BASE        = 12570;   // personal allowance
      const BASIC_LIMIT    = 50270;   // basic rate ceiling
      const HIGHER_LIMIT   = 125140;  // higher rate ceiling (also PA taper end)
      const NI_PRIMARY     = 12570;   // NI primary threshold
      const NI_UPPER       = 50270;   // NI upper earnings limit

      // Salary sacrifice: pension off the top, both IT and NI on post-sacrifice pay
      const pensionAnnual  = Math.round(grossAnnual * (pensionPct / 100));
      const taxableGross   = grossAnnual - pensionAnnual;

      // Personal allowance — tapers £1 per £2 above £100k
      let pa = PA_BASE;
      if (taxableGross > 100000) {
        pa = Math.max(0, PA_BASE - Math.floor((taxableGross - 100000) / 2));
      }

      // Income tax
      const abovePA         = Math.max(0, taxableGross - pa);
      const basicBandWidth  = BASIC_LIMIT  - PA_BASE;  // £37,700
      const higherBandWidth = HIGHER_LIMIT - BASIC_LIMIT; // £74,870
      const inBasic      = Math.min(abovePA, basicBandWidth);
      const inHigher     = Math.max(0, Math.min(abovePA - basicBandWidth, higherBandWidth));
      const inAdditional = Math.max(0, abovePA - basicBandWidth - higherBandWidth);
      const incomeTax    = Math.round(inBasic * 0.20 + inHigher * 0.40 + inAdditional * 0.45);

      // NI Class 1 employee contributions
      const niable   = Math.max(0, taxableGross - NI_PRIMARY);
      const inNIMain = Math.min(niable, NI_UPPER - NI_PRIMARY); // 8% band
      const inNIHigh = Math.max(0, niable - (NI_UPPER - NI_PRIMARY));           // 2% band
      const ni       = Math.round(inNIMain * 0.08 + inNIHigh * 0.02);

      const takeHomeAnnual = taxableGross - incomeTax - ni;
      const m = n => Math.round(n / 12); // annual → monthly helper

      return {
        grossAnnual,      grossMonthly:    m(grossAnnual),
        pensionAnnual,    pensionMonthly:  m(pensionAnnual),
        taxableAnnual:    taxableGross,    taxableMonthly:  m(taxableGross),
        incomeTaxAnnual:  incomeTax,       taxMonthly:      m(incomeTax),
        niAnnual:         ni,              niMonthly:       m(ni),
        takeHomeAnnual,   takeHomeMonthly: m(takeHomeAnnual),
        pensionPct,
      };
    }

    // Parse a salary string into a structured object.
    // Handles: "£80k", "£80,000", "£80k–£100k", "£80,000 – £100,000", "80000"
    // Returns: { type: 'range', lower, upper, mid } | { type: 'single', value } | null
    function _wsParseSalaryText(text) {
      if (!text || typeof text !== 'string') return null;
      const t = text.replace(/,/g, '').replace(/\s+/g, ' ').trim();

      // Range pattern: two amounts separated by dash/to/–
      const rangeRe = /£?(\d+(?:\.\d+)?)(k)?\s*(?:[-–—]|to)\s*£?(\d+(?:\.\d+)?)(k)?/i;
      const rm = t.match(rangeRe);
      if (rm) {
        const lower = Math.round(parseFloat(rm[1]) * (rm[2] ? 1000 : 1));
        const upper = Math.round(parseFloat(rm[3]) * (rm[4] ? 1000 : 1));
        if (lower > 5000 && upper >= lower) {
          const mid = Math.round((lower + upper) / 2 / 1000) * 1000; // round mid to nearest £1k
          return { type: 'range', lower, upper, mid };
        }
      }

      // Single amount pattern
      const singleRe = /£?(\d+(?:\.\d+)?)(k)?/i;
      const sm = t.match(singleRe);
      if (sm) {
        const value = Math.round(parseFloat(sm[1]) * (sm[2] ? 1000 : 1));
        if (value > 5000) return { type: 'single', value };
      }

      return null;
    }

    // Format a salary number as a compact string, e.g. 110000 → "£110k"
    function _fmtSalaryK(n) {
      if (!n) return '';
      const k = Math.round(n / 1000);
      return `£${k}k`;
    }

    // ─── Preparation artefact ────────────────────────────────────────────────

    // Returns true if the user's text reads as a preparation intent
    function _wsPrepIntent(text) {
      return /\bprep(are|aration)?\b|\binterview\b|\brecruiter\s+(call|screen|chat)\b|\bhiring\s+manager\b|\bpanel\b|\bwhat\s+should\s+i\s+(ask|say|prepare)\b|\btalking\s+point|\bpractice\s+question|\bget\s+ready\b/i.test(text.trim());
    }

    // Build a structured preparation object from available role context
    function _wsBuildPrep(role, memory) {
      const fo      = role.analysis?.full_output || role.latest_match_output || {};
      const stage   = currentStageLabel(role);
      const company = role.company_name || '';
      const title   = role.role_title   || '';
      const pd      = fo.practical_details || {};
      const arch    = fo.role_archetype?.primary || null;

      // ── Soft interaction signal ──────────────────────────────────────────────
      // Use memory.interactions to infer what has already happened, even if
      // current_stage hasn't been updated. This enriches focus copy at any stage.
      const interactions   = memory?.interactions || [];
      const hadRecruiter   = interactions.some(i => i.interaction_type === 'recruiter_call' || i.interaction_type === 'recruiter_email');
      const hadInterview   = interactions.some(i => i.interaction_type === 'interview');
      const latestInteraction = interactions[0] || null; // newest first from wsLoadMemory

      // ── Analysis field helpers ───────────────────────────────────────────────
      const _extractText  = arr => (Array.isArray(arr) ? arr : [])
        .map(r => typeof r === 'object' ? (r.text || '') : String(r)).filter(Boolean);
      const reality       = _extractText(fo.fit_reality_summary);
      const rawRisks      = _extractText(fo.risks_and_unknowns);
      const wtado         = _extractText(fo.what_you_would_actually_do);    // responsibilities
      const wtrlf         = _extractText(fo.what_they_are_really_looking_for); // their criteria

      // ── Hard constraints, salary, commute, lens ────────────────────────────
      const hardConstraints = Array.isArray(fo.hard_constraints) ? fo.hard_constraints : [];
      const salaryReality   = pd.salary_monthly || pd.salary_reality || null;
      const commuteReality  = pd.commute_reality || null;
      const lens            = typeof _computeUserLens === 'function' ? _computeUserLens(allRoles) : null;
      const lensComparison  = lens ? _compareRoleToLens(fo, lens) : null;

      // ── 1. Interview focus ───────────────────────────────────────────────────
      // Each stage gets a specific, non-generic focus description.
      // Interaction signals can add context when stage is still early.
      let interview_focus;
      if (stage === 'Recruiter Screen' || (!hadInterview && hadRecruiter)) {
        const noticePart = pd.notice_period ? ` Your notice period is ${pd.notice_period} — have this ready.` : '';
        interview_focus = `A fit and availability check. Lead with what you do, what you are looking for, and why ${company || 'this role'} is interesting to you now.${noticePart}`;
      } else if (stage === 'Hiring Manager') {
        const scopeHint = wtado[0] ? ` The role centres on: ${wtado[0].toLowerCase().replace(/\.$/, '')}.` : '';
        interview_focus = `The hiring manager is assessing whether your experience directly maps to the role's scope and ownership expectations.${scopeHint} Come with specific examples of impact, not just responsibilities.`;
      } else if (stage === 'Panel') {
        interview_focus = `A panel interview tests depth across multiple dimensions. Different interviewers typically own distinct areas — technical depth, collaboration, culture. Prepare examples that show both breadth of context and precision in your own domain.`;
      } else if (stage === 'Final') {
        interview_focus = `Finals evaluate conviction and culture fit as much as capability. They want to see that you have thought hard about why this role, at this company, at this point in your career. Have a clear and honest answer.`;
      } else if (stage === 'Applied') {
        interview_focus = `You have applied — now prepare for first contact. Most initial screens are recruiter-led fit checks focused on availability, motivation, and salary alignment.`;
      } else {
        // JD Review / unknown — general but not throwaway
        interview_focus = company
          ? `Understand what ${company} actually needs for this role and assess whether the opportunity is genuinely worth your time to pursue.`
          : `Understand what the role actually requires and assess whether it is worth your time.`;
      }

      // ── 2. Questions to ask — stage-specific priority ────────────────────────
      const questions_to_ask = [];
      if (stage === 'Recruiter Screen' || stage === 'Applied' || (!hadInterview && hadRecruiter)) {
        // Recruiter screen: practical questions that can be answered in the first call
        if (!pd.salary_annual && !pd.salary_range && !role.salary_text_raw)
          questions_to_ask.push('What is the salary range or day rate for this role?');
        if (!pd.remote_model || pd.remote_model === 'Not stated')
          questions_to_ask.push('What does the working arrangement look like — remote, hybrid, or on-site?');
        questions_to_ask.push('What does the interview process look like from here and what is the timeline?');
        questions_to_ask.push('Why is this role open — new headcount or a replacement?');
      } else if (stage === 'Hiring Manager') {
        // HM screen: scope, autonomy, success definition
        if (arch) questions_to_ask.push(`What does good look like for someone in a ${arch} role here in the first 6 months?`);
        questions_to_ask.push('What does the team structure look like and who would I be working most closely with?');
        questions_to_ask.push('What are the biggest challenges the person in this role will face in the first quarter?');
        questions_to_ask.push('How much autonomy does this role have over priorities and approach?');
        questions_to_ask.push('What does the rest of the hiring process look like from here?');
      } else if (stage === 'Panel') {
        // Panel: depth, trade-offs, collaboration signals
        questions_to_ask.push('What does strong collaboration look like in this team?');
        questions_to_ask.push('Where do you see the biggest opportunity for this role to have an outsized impact?');
        questions_to_ask.push('What are the hardest trade-offs this team has to make regularly?');
        if (arch) questions_to_ask.push(`How does the ${arch} function interact with other parts of the business here?`);
      } else if (stage === 'Final') {
        questions_to_ask.push('What does success look like at 12 months and how is it measured?');
        questions_to_ask.push('What do the people who have thrived here have in common?');
        questions_to_ask.push('Is there anything about my background you want me to address before we close?');
      } else {
        // General / pre-application
        if (!pd.salary_annual && !pd.salary_range && !role.salary_text_raw)
          questions_to_ask.push('What is the salary range or compensation structure?');
        if (!pd.remote_model || pd.remote_model === 'Not stated')
          questions_to_ask.push('What does the working arrangement look like — remote, hybrid, or on-site?');
        if (arch)
          questions_to_ask.push(`Given the ${arch} nature of the role, how is success measured in the first 6 months?`);
        questions_to_ask.push('What does the team structure look like and who would I work most closely with?');
        questions_to_ask.push('What is driving the urgency to hire for this role now?');
      }

      // ── 3. Likely concerns — hard constraints, risks, stage-specific ────────
      const concerns_to_prepare = [];
      // Hard constraints surface first — these are non-negotiables
      hardConstraints.forEach(hc => {
        concerns_to_prepare.push(`Hard constraint: ${hc.label}. ${hc.reason || ''} Clarify this early — do not invest time if it is a dealbreaker.`.trim());
      });
      // Salary reality as concern when it looks problematic
      if (salaryReality && /below|under|lower|less than/i.test(salaryReality)) {
        concerns_to_prepare.push(`Salary concern: ${salaryReality}. Know your minimum before the conversation.`);
      }
      // Commute reality as concern when it looks heavy
      if (commuteReality && /5 days|daily|full.?time on.?site/i.test(commuteReality)) {
        concerns_to_prepare.push(`Commute note: ${commuteReality}. Confirm whether this is negotiable.`);
      }
      // Lens tensions as preparation topics
      if (lensComparison && lensComparison.tensions && lensComparison.tensions.length > 0) {
        const tensionLabels = lensComparison.tensions.slice(0, 2).map(t => t.label).join(', ');
        concerns_to_prepare.push(`This role diverges from your recent pattern on: ${tensionLabels}. Be ready to articulate why you are open to this.`);
      }
      // Then analysis risks
      rawRisks.slice(0, 3 - Math.min(concerns_to_prepare.length, 2)).forEach(r => concerns_to_prepare.push(r));
      if (stage === 'Recruiter Screen' || stage === 'Applied') {
        if (!concerns_to_prepare.length)
          concerns_to_prepare.push('Be ready to explain your specific interest in this company, not just the role type.');
        concerns_to_prepare.push('They will almost certainly ask about your notice period and availability.');
      } else if (stage === 'Hiring Manager') {
        if (!concerns_to_prepare.length)
          concerns_to_prepare.push('Be ready to address any apparent gaps between your background and the JD criteria.');
        concerns_to_prepare.push('Come prepared to discuss a specific example of ownership and measurable impact.');
        if (wtrlf[0]) concerns_to_prepare.push(`The role specifically looks for: "${wtrlf[0].toLowerCase().replace(/\.$/, '')}". Prepare a direct example.`);
      } else if (stage === 'Panel') {
        if (!concerns_to_prepare.length)
          concerns_to_prepare.push('Expect depth questions on your past decisions and trade-offs, not just outcomes.');
        concerns_to_prepare.push('Prepare two or three detailed examples you can adapt across different question angles.');
        concerns_to_prepare.push('Know what you would do differently and be ready to articulate it honestly.');
      } else if (stage === 'Final') {
        if (!concerns_to_prepare.length)
          concerns_to_prepare.push('Any residual concerns about fit will surface here — address them proactively.');
        concerns_to_prepare.push('Have a clear, honest answer for why you want this role specifically.');
      } else {
        if (!concerns_to_prepare.length) {
          concerns_to_prepare.push('Be ready to explain your specific interest in this company, not just the role type.');
          concerns_to_prepare.push('Prepare concrete examples for likely competency questions.');
        }
      }

      // ── 4. What to clarify — stage-specific open questions ──────────────────
      const _unknowns = (memory?.insights || []).filter(i => i.insight_type === 'unknown' || i.insight_type === 'clarification');
      const what_to_clarify = _unknowns.slice(0, 2).map(i => i.text);

      if (stage === 'Recruiter Screen' || stage === 'Applied') {
        if (what_to_clarify.length < 3 && !pd.salary_annual && !pd.salary_range)
          what_to_clarify.push('Clarify salary band on this call — it saves time for both sides.');
        if (what_to_clarify.length < 3)
          what_to_clarify.push('Ask how many stages are left and who makes the final decision.');
      } else if (stage === 'Hiring Manager') {
        if (what_to_clarify.length < 3)
          what_to_clarify.push('Clarify the team\'s current priorities and what they need most in the first 90 days.');
        if (what_to_clarify.length < 3)
          what_to_clarify.push('Understand the decision-making process and timeline for the offer.');
      } else if (stage === 'Panel') {
        if (what_to_clarify.length < 3)
          what_to_clarify.push('Clarify what each panellist specifically owns — adapt your answers to their context.');
        if (what_to_clarify.length < 3)
          what_to_clarify.push('Understand whether there is a practical exercise or presentation expected.');
      } else if (stage === 'Final') {
        if (what_to_clarify.length < 3)
          what_to_clarify.push('Confirm offer timing, decision process, and any outstanding steps.');
      } else {
        if (what_to_clarify.length < 2 && !pd.salary_annual && !pd.salary_range)
          what_to_clarify.push('Confirm salary band before investing more time in the process.');
        if (what_to_clarify.length < 3 && !role.job_url)
          what_to_clarify.push('Obtain the original job posting link to reference during interviews.');
      }

      // ── 5. Talking points — stage-aware source priority ──────────────────────
      const talking_points = [];
      if (stage === 'Hiring Manager' || stage === 'Panel' || stage === 'Final') {
        // For mid-to-late stages: lead with responsibilities and criteria match
        wtado.slice(0, 2).forEach(t => talking_points.push(t));
        if (talking_points.length < 2) wtrlf.slice(0, 2).forEach(t => talking_points.push(t));
        if (talking_points.length < 2) reality.slice(0, 2).forEach(t => talking_points.push(t));
      } else {
        // Early stages: lead with fit reality summary
        reality.slice(0, 3).forEach(t => talking_points.push(t));
      }
      // Fallbacks if analysis gave us nothing
      if (!talking_points.length) {
        if (title)   talking_points.push(`Articulate your specific experience relevant to ${title} with concrete examples.`);
        if (company) talking_points.push(`Explain why ${company} interests you at this point — be specific, not generic.`);
        if (!talking_points.length) talking_points.push('Prepare a clear, honest narrative of your relevant background and what you are looking for.');
      }

      // ── 6. Role context — grounded practical summary ────────────────────────
      const _contextParts = [];
      if (fo.why_this_role_exists) _contextParts.push(fo.why_this_role_exists);
      else if (fo.role_summary) _contextParts.push(fo.role_summary);
      if (pd.work_model && pd.work_model !== 'Not stated') _contextParts.push(`Work model: ${pd.work_model}.`);
      if (salaryReality) _contextParts.push(`Salary: ${salaryReality}.`);
      if (commuteReality) _contextParts.push(`Commute: ${commuteReality}.`);
      if (pd.company_type) _contextParts.push(`Company type: ${pd.company_type}.`);
      const context_notes = _contextParts.length ? _contextParts.join(' ') : null;

      return {
        stage, company, title,
        interview_focus,
        questions_to_ask:    questions_to_ask.slice(0, 5),
        concerns_to_prepare: concerns_to_prepare.slice(0, 5),
        what_to_clarify:     what_to_clarify.slice(0, 3),
        talking_points:      talking_points.slice(0, 4),
        context_notes,
      };
    }

    // Build the preparation artefact HTML block
    function _wsPrepArtefactHtml(prep, artifactId, updatedLabel = null) {
      const heading = [prep.company, prep.title].filter(Boolean).join(' — ') || 'Interview Preparation';
      // Stage label doubles as the freshness carrier when both are present:
      // "Recruiter Screen — Updated just now" keeps the header to one right-aligned element.
      const _stageText  = prep.stage && prep.stage !== 'JD Review' ? prep.stage : null;
      const _updateText = updatedLabel || null;
      let stageLabelHtml = '';
      if (_stageText && _updateText) {
        stageLabelHtml = `<span class="ws-artifact-stage-label">${esc(_stageText)} — ${esc(_updateText)}</span>`;
      } else if (_stageText) {
        stageLabelHtml = `<span class="ws-artifact-stage-label">${esc(_stageText)}</span>`;
      } else if (_updateText) {
        stageLabelHtml = `<span class="ws-artifact-stage-label">${esc(_updateText)}</span>`;
      }

      const _section = (sectionTitle, items) => {
        if (!items || !items.length) return '';
        const listHtml = `<ul class="doc-list">${items.map(t => `<li>${esc(String(t))}</li>`).join('')}</ul>`;
        return `<div class="doc-section"><div class="doc-section-heading">${esc(sectionTitle)}</div>${listHtml}</div>`;
      };
      const _prose = (sectionTitle, text) => {
        if (!text) return '';
        return `<div class="doc-section"><div class="doc-section-heading">${esc(sectionTitle)}</div><div class="doc-prose">${esc(text)}</div></div>`;
      };

      return `
        <div class="ws-artifact ws-artifact--preparation" data-artifact-id="${esc(artifactId)}" data-ws-entry="${WS_ENTRY.ARTIFACT}" data-artifact-type="preparation">
          <div class="ws-artifact-header">
            <span class="ws-artifact-type-badge ws-badge--preparation">Preparation</span>
            <span class="ws-artifact-heading">${esc(heading)}</span>
            ${stageLabelHtml}
          </div>
          <div class="ws-artifact-body">
            ${_prose('Interview Focus', prep.interview_focus)}
            ${_section('Questions Worth Asking', prep.questions_to_ask)}
            ${_section('Likely Concerns to Prepare For', prep.concerns_to_prepare)}
            ${_section('What to Clarify', prep.what_to_clarify)}
            ${_section('Talking Points', prep.talking_points)}
            ${_prose('Role Context', prep.context_notes)}
          </div>
        </div>`;
    }

    // Insert a prep artifact HTML block into the overview panel.
    // Placement: before the "Next Steps" section header, or before Risks if header absent,
    // or appended to col-overview-cards as a final fallback.
    function _wsInsertPrepToOverview(html) {
      const _ovCards = document.getElementById('col-overview-cards');
      if (!_ovCards) return;

      // Guard 2: remove any existing prep artifact cards before inserting the new one.
      // This prevents duplicates when prep is triggered multiple times in a session
      // or when the overview was re-rendered since the last prep insert.
      _ovCards.querySelectorAll('[data-artifact-type="preparation"]').forEach(el => el.remove());

      // Find the "Next Steps" section header (generated by renderMatchOutput's sectionHeader())
      const _nextStepsHdr = Array.from(_ovCards.querySelectorAll('.rw-section-header'))
        .find(el => el.textContent.includes('Next Steps'));
      if (_nextStepsHdr) {
        _nextStepsHdr.insertAdjacentHTML('beforebegin', html);
      } else {
        const _risksCard = _ovCards.querySelector('#section-risks');
        if (_risksCard) {
          _risksCard.insertAdjacentHTML('beforebegin', html);
        } else {
          _ovCards.insertAdjacentHTML('beforeend', html);
        }
      }
    }

    // Orchestrate create-or-update for the preparation artefact.
    // Status feedback stays in chat (timelineEl) — transient.
    // The artefact itself renders in col-overview-cards, not the chat timeline.
    async function _wsTriggerPrep(role, timelineEl) {
      const statusEl = _wsStatusLine(timelineEl, 'Building preparation…', 'ws-status-prep');
      try {
        const memory   = await wsLoadMemory(role.id);
        const prep     = _wsBuildPrep(role, memory);
        const heading  = [prep.company, prep.title].filter(Boolean).join(' — ') || 'Interview Preparation';
        const content  = JSON.stringify(prep);

        // Find existing preparation artifact (most recent)
        const existing = memory.artifacts.find(a => a.artifact_type === 'preparation');

        let artifactId;
        if (existing) {
          await wsUpdateArtifact(existing.id, heading, content);
          artifactId = existing.id;
          statusEl.remove();
          // Replace existing DOM node in-place if visible in overview; otherwise insert fresh.
          // Pass 'Updated just now' so the header shows a freshness cue on this refresh.
          const _ovCards     = document.getElementById('col-overview-cards');
          const existingNode =
            (_ovCards?.querySelector(`[data-artifact-id="${existing.id}"]`)) ||
            timelineEl.querySelector(`[data-artifact-id="${existing.id}"]`);
          if (existingNode) {
            existingNode.outerHTML = _wsPrepArtefactHtml(prep, artifactId, 'Updated just now');
          } else {
            _wsInsertPrepToOverview(_wsPrepArtefactHtml(prep, artifactId, 'Updated just now'));
          }
        } else {
          const art  = await wsAddArtifact(role.id, 'preparation', heading, content);
          artifactId = art?.id || ('local-prep-' + Date.now());
          statusEl.remove();
          _wsInsertPrepToOverview(_wsPrepArtefactHtml(prep, artifactId));
        }

        insertEvent(role.id, { event_type: 'prep_saved', title: 'Preparation updated', source: 'user' });
        _wsRefreshMemorySummary(role.id);
      } catch (e) {
        // Mirror analysis/save failure pattern: flex layout with an inline retry button.
        statusEl.innerHTML =
          '<span class="ws-status-msg">Preparation couldn\'t complete.</span>' +
          '<button class="ws-retry-btn">Try again</button>';
        statusEl.classList.add('ws-status-error');
        statusEl.querySelector('.ws-retry-btn')?.addEventListener('click', () => {
          statusEl.remove();
          _wsTriggerPrep(role, timelineEl);
        });
        console.error('[_wsTriggerPrep]', e);
      }
    }

    // ─── Thoughts artefact ───────────────────────────────────────────────────

    // Returns true if the user's text reads as a thought/note intent (conservative)
    function _wsThoughtIntent(text) {
      const t = text.trim().toLowerCase();
      // Explicit note-capture phrases only — do not over-trigger
      return /\b(add\s+(a\s+)?(note|thought)|note\s+this|my\s+thought\s+is|jot\s+(this|that)\s+down|worth\s+noting|remind\s+me|to\s+clarify\s+(later)?|follow\s+up\s+on|ask\s+about)\b/i.test(t)
          || (t.length < 200 && /^(need\s+to|want\s+to|should\s+ask|curious\s+(about|if|why)|not\s+sure\s+(about|if)|feels?\s+like|seems?\s+like|wondering\s+(about|if|why))/i.test(t));
    }

    // Returns true if the user is asking about take-home, salary breakdown, or tax
    function _wsSalaryIntent(text) {
      const t = text.trim();
      return /\b(take[\s-]?home|net\s+(?:pay|salary|income)|after[\s-]?tax|after[\s-]?deductions?|paye|national\s+insurance|\bni\b|income\s+tax|tax(?:able)?\s+(?:income|salary|on\s+this|breakdown)|pension\s+deduction|salary\s+(?:calc|breakdown|estimate|split)|how\s+much\s+(?:do\s+i|will\s+i\s+)?(?:take\s+home|keep|net|get\s+paid|earn\s+net)|monthly\s+(?:take[\s-]?home|net|breakdown|income\s+after)|what(?:'s|s|\s+is|\s+would)\s+(?:my\s+)?(?:take[\s-]?home|net\s+pay|monthly\s+pay))\b/i.test(t);
    }

    // Build a thoughts artefact HTML block from stored content (an array of strings)
    function _wsThoughtsArtefactHtml(thoughts, artifactId, updatedLabel = null) {
      const heading     = thoughts._heading || 'Thoughts';
      const items       = Array.isArray(thoughts.items) ? thoughts.items : [];
      const listHtml    = items.length
        ? `<ul class="ws-thoughts-list">${items.map(t => `<li>${esc(String(t))}</li>`).join('')}</ul>`
        : `<div class="doc-prose" style="color:var(--text-light);">No thoughts captured yet.</div>`;
      const freshnessHtml = updatedLabel
        ? `<span class="ws-artifact-freshness">${esc(updatedLabel)}</span>` : '';
      return `
        <div class="ws-artifact ws-artifact--thoughts" data-artifact-id="${esc(artifactId)}" data-ws-entry="${WS_ENTRY.ARTIFACT}" data-artifact-type="thoughts">
          <div class="ws-artifact-header">
            <span class="ws-artifact-type-badge ws-badge--thoughts">Thoughts</span>
            <span class="ws-artifact-heading">${esc(heading)}</span>
            ${freshnessHtml}
          </div>
          <div class="ws-artifact-body">
            <div class="doc-section">
              <div class="doc-section-heading">Captured notes</div>
              ${listHtml}
            </div>
          </div>
        </div>`;
    }

    // Orchestrate create-or-update for the thoughts artefact
    async function _wsTriggerThoughts(role, newThought, timelineEl) {
      try {
        const memory   = await wsLoadMemory(role.id);
        const existing = memory.artifacts.find(a => a.artifact_type === 'thoughts');
        const company  = role.company_name || '';
        const title    = role.role_title   || '';
        const heading  = [company, title].filter(Boolean).join(' — ') || 'Thoughts';

        let thoughts;
        if (existing) {
          try { thoughts = JSON.parse(existing.content || '{}'); } catch (_) { thoughts = {}; }
          if (!Array.isArray(thoughts.items)) thoughts.items = [];
        } else {
          thoughts = { items: [] };
        }
        thoughts._heading = heading;
        if (newThought) thoughts.items.push(newThought.trim());

        const content = JSON.stringify(thoughts);
        let artifactId;

        if (existing) {
          await wsUpdateArtifact(existing.id, heading, content);
          artifactId = existing.id;
          // Replace in-place if visible; pass freshness cue so the update is obvious.
          const existingNode = timelineEl.querySelector(`[data-artifact-id="${existing.id}"]`);
          if (existingNode) {
            existingNode.outerHTML = _wsThoughtsArtefactHtml(thoughts, artifactId, 'Updated just now');
            _wsScrollIfNear(timelineEl);
          } else {
            _wsAppend(timelineEl, _wsThoughtsArtefactHtml(thoughts, artifactId, 'Updated just now'));
          }
        } else {
          const art  = await wsAddArtifact(role.id, 'thoughts', heading, content);
          artifactId = art?.id || ('local-thoughts-' + Date.now());
          _wsAppend(timelineEl, _wsThoughtsArtefactHtml(thoughts, artifactId));
        }

        _wsRefreshMemorySummary(role.id);
      } catch (e) {
        // Show a brief error line — note was not saved. Auto-fades; user can re-submit.
        const _errEl = _wsStatusLine(timelineEl, 'Couldn\'t save note. Try again.');
        _errEl.classList.add('ws-status-error');
        setTimeout(() => { if (_errEl.isConnected) _errEl.remove(); }, 5000);
        console.error('[_wsTriggerThoughts]', e);
      }
    }

    // ── Simulated streaming helper ─────────────────────────────────────────────
    // Renders reply text into `el` progressively, word-by-word, giving the
    // impression of a live response. Uses textContent (safe, no HTML injection).
    // Punctuation at sentence ends triggers a slightly longer pause.
    async function _wsStreamText(el, text) {
      if (!text) return;
      // Walk up to the scroll container once so we can keep pinned users at the
      // bottom as the bubble grows taller word by word. Without this, a single
      // _wsScrollIfNear call before streaming starts means text beyond the first
      // screenful appears below the viewport and the user has to scroll manually.
      const tlEl = el.closest ? el.closest('#ws-timeline') : null;
      const words = text.split(' ');
      let rendered = '';
      for (let i = 0; i < words.length; i++) {
        if (!el.isConnected) return; // abort if bubble was removed
        rendered += (i > 0 ? ' ' : '') + words[i];
        el.textContent = rendered;
        const w = words[i];
        const delay = /[.?!]$/.test(w) ? 65 : /[,;:]$/.test(w) ? 40 : 22;
        // Re-pin every 6 words. Combined with the 16ms debounce on _wsScrollIfNear
        // this fires at most once per ~130ms — cheap and keeps the bottom in view.
        if (tlEl && (i % 6 === 0 || i === words.length - 1)) {
          _wsScrollIfNear(tlEl);
        }
        await new Promise(r => setTimeout(r, delay));
      }

      // Final pass: render **bold** markdown.
      // During streaming we use textContent (XSS-safe). Once the loop is
      // done we do one innerHTML pass — HTML special chars are escaped first
      // so injected markup in the AI text cannot execute.
      if (el.isConnected && text) {
        const safe = text
          .replace(/&/g, '&amp;')
          .replace(/</g, '&lt;')
          .replace(/>/g, '&gt;');
        el.innerHTML = safe
          .replace(/\*\*([^*\n]+)\*\*/g, '<strong>$1</strong>')
          .replace(/\n\n/g, '<br><br>')
          .replace(/\n/g, '<br>');
      }
    }

    // ── Decision history block renderer ───────────────────────────────────────
    // Prepends a small read-only factual timeline of the user's past decisions
    // about this role. Quiet visual treatment — not a hero component.
    // Shown above blank-state or chat history; never inside the chat stream.
    function _wsRenderDecisionHistory(decisions, timelineEl) {
      if (!decisions || decisions.length === 0) return;
      const TYPE_LABELS = { skip: 'Skipped', apply: 'Applied', withdraw: 'Withdrew', accept: 'Accepted', other: 'Other' };
      const fmt = iso => {
        try { return new Date(iso).toLocaleDateString('en-GB', { day: 'numeric', month: 'short' }); }
        catch (_) { return iso?.slice(0, 10) || '—'; }
      };
      const items = decisions.slice(0, 5).map(d => {
        const date = fmt(d.created_at);
        const type = TYPE_LABELS[d.decision_type] || d.decision_type;
        const reason = d.reason ? ` — ${esc(d.reason)}` : '';
        return `<li class="ws-dh-entry">${esc(date)} · ${esc(type)}${reason}</li>`;
      }).join('');
      const el = document.createElement('div');
      el.className = 'ws-decision-history';
      el.innerHTML = `<div class="ws-dh-heading">Decision history</div><ul class="ws-dh-list">${items}</ul>`;
      // Insert after the spacer (not prepend) so the spacer stays at position 0
      // and continues to push all content toward the bottom.
      const spacer = timelineEl.querySelector('.ws-timeline-spacer');
      if (spacer) {
        spacer.after(el);
      } else {
        timelineEl.prepend(el);
      }
    }

    // ── Quick choice chips renderer ────────────────────────────────────────────
    // Renders a row of pill buttons below an assistant message.
    // Clicking a chip dispatches a ws:chip-send event so the workspace input
    // handler can process it cleanly without needing direct refs to inputEl/sendBtn.
    function _wsRenderChips(chips, timelineEl) {
      const row = document.createElement('div');
      row.className = 'ws-chat-chips';
      chips.forEach(label => {
        const btn = document.createElement('button');
        btn.className = 'ws-chip';
        btn.type = 'button';
        btn.textContent = label;
        btn.addEventListener('click', () => {
          row.remove();
          timelineEl.dispatchEvent(new CustomEvent('ws:chip-send', {
            bubbles: true,
            detail: { text: label },
          }));
        });
        row.appendChild(btn);
      });
      timelineEl.appendChild(row);
      _wsScrollIfNear(timelineEl);
    }

    // ── Your Lens ──────────────────────────────────────────────────────────────
    // Surfaces recurring preference patterns from the user's decision history.
    // Calls generate-lens with all decided roles and their analysis signals.
    // Only shown when ≥3 decided roles exist. Panel is quiet and non-intrusive.

    // Cache: store lens result by content hash so we don't re-generate on every workspace open.
    let _lensCache = null;         // { decided_count, favoured, weaker, note } | null
    let _lensCacheCount = 0;       // decided role count at the time of last generation
    let _lensRendered = false;     // prevent duplicate render per workspace session

    async function _wsLoadYourLens() {
      try {
        // Load all decided roles with their latest analysis output
        const { data: decidedRoles } = await db
          .from('role_decisions')
          .select('role_id, decision_type')
          .in('decision_type', ['apply', 'skip', 'other'])
          .order('created_at', { ascending: false });

        if (!decidedRoles || decidedRoles.length < 3) return null;

        // Dedupe by role_id (keep most recent decision per role)
        const seenRoles = new Set();
        const unique = decidedRoles.filter(d => {
          if (seenRoles.has(d.role_id)) return false;
          seenRoles.add(d.role_id);
          return true;
        });

        if (unique.length < 3) return null;

        // Use cache if the count hasn't changed
        if (_lensCache && _lensCacheCount === unique.length) return _lensCache;

        // Fetch role metadata + latest analysis for each decided role (up to 20)
        const roleIds = unique.slice(0, 20).map(d => d.role_id);
        const { data: rolesData } = await db
          .from('roles')
          .select('id, company_name, role_title')
          .in('id', roleIds);

        const { data: matchesData } = await db
          .from('jd_matches')
          .select('role_id, output_json')
          .in('role_id', roleIds)
          .order('created_at', { ascending: false });

        // Build deduplicated map: roleId → latest match
        const matchMap = {};
        (matchesData || []).forEach(m => {
          if (!matchMap[m.role_id]) matchMap[m.role_id] = m.output_json;
        });

        const rolesMap = {};
        (rolesData || []).forEach(r => { rolesMap[r.id] = r; });

        // Assemble decisions payload for the edge function
        const decisions = unique.slice(0, 20).map(d => {
          const role   = rolesMap[d.role_id] || {};
          const output = matchMap[d.role_id] || {};
          return {
            decision:     d.decision_type === 'skip' ? 'pass' : d.decision_type,
            role_title:   role.role_title   || null,
            company_name: role.company_name || null,
            analysis_signals: {
              role_summary:        output.role_summary        || null,
              work_model:          output.practical_details?.remote_model || null,
              hiring_system_type:  output.hiring_system?.type || null,
              fit_signals:         output.fit_reality_summary || null,
              risks:               output.risks_unknowns      || output.risks_and_unknowns || null,
            },
          };
        });

        const resp = await fetch(`${SUPABASE_URL}/functions/v1/generate-lens`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'apikey': SUPABASE_ANON_KEY },
          body: JSON.stringify({ decisions }),
        });
        if (!resp.ok) return null;
        const json = await resp.json();
        if (!json.lens) return null;

        _lensCache = { decided_count: unique.length, ...json.lens };
        _lensCacheCount = unique.length;
        return _lensCache;
      } catch (_) { return null; }
    }

    // Render the Your Lens panel into the timeline (above blank state / below decision history).
    function _wsRenderYourLens(lensData, timelineEl) {
      if (!lensData) return;
      if (_lensRendered) return;
      _lensRendered = true;

      // Staleness guard: if the workspace timeline is no longer in the DOM, a role
      // switch happened while the async _wsLoadYourLens() was in flight. Abort so
      // we don't inject this role's lens into a different role's overview panel.
      if (timelineEl && !timelineEl.isConnected) return;

      const { favoured = [], weaker = [], note = null } = lensData;
      if (!favoured.length && !weaker.length) return;

      const _li = arr => arr.map(s => `<li>${esc(s)}</li>`).join('');

      const favouredHtml = favoured.length
        ? `<div class="yl-label">You tend to favour roles where:</div>
           <ul class="yl-list">${_li(favoured)}</ul>`
        : '';

      const weakerHtml = weaker.length
        ? `<div class="yl-label yl-label--weaker">Roles where outcomes have been weaker often include:</div>
           <ul class="yl-list yl-list--weaker">${_li(weaker)}</ul>`
        : '';

      const noteHtml = note
        ? `<div class="yl-note">${esc(note)}</div>`
        : '';

      // Persistent intelligence card — renders in the overview panel, not chat timeline.
      // rw-card--intel: matches the tier of Pattern/Hiring/Decision Signals (fade-in, bg).
      // Insert after Fit Reality Summary so the overview reads: Fit → Your Lens → Risks.
      const panel = document.createElement('div');
      panel.id        = 'section-your-lens';
      panel.className = 'rw-card rw-card--full rw-card--intel yl-panel ws-settle';
      panel.innerHTML = `
        <div class="doc-section-heading">Your Lens</div>
        ${favouredHtml}
        ${weakerHtml}
        ${noteHtml}`;

      const _ovCards  = document.getElementById('col-overview-cards');
      // Prefer anchoring after Search Pattern (if rendered); fall back to Fit Reality Summary,
      // then to the card grid, then to the overview container.
      const _spCard   = _ovCards?.querySelector('#section-search-pattern');
      const _fitCard  = _ovCards?.querySelector('#section-fit-reality');
      const _grid     = _ovCards?.querySelector('.rw-card-grid');

      if (_spCard) {
        // Ideal: Fit Reality Summary → Search Pattern → Your Lens
        _spCard.insertAdjacentElement('afterend', panel);
      } else if (_fitCard) {
        // Search Pattern not rendered yet: Fit Reality Summary → Your Lens
        _fitCard.insertAdjacentElement('afterend', panel);
      } else if (_grid) {
        _grid.appendChild(panel);
      } else if (_ovCards) {
        _ovCards.appendChild(panel);
      }
    }

    // ── Role briefing assembler ────────────────────────────────────────────────
    // Derives a compact structured summary from data already loaded via wsLoadMemory.
    // Pure client-side — no LLM call, no new DB writes. Safe to call on every chat.
    // Returns a plain object; unknown fields are null rather than invented.
    function _wsAssembleBriefing(role, memory, signals, decisions = []) {
      // ── Base fields from the role row ──────────────────────────────────────
      const briefing = {
        company:        role.company_name    || null,
        title:          role.role_title      || null,
        location:       role.location        || null,
        work_model:     null,
        salary:         null,
        employment:     role.employment_type || null,
        day_rate:       role.day_rate        || null,
        recruiter:      null,
        stage:          currentStageLabel(role),
        risks:          null,
        unknowns:       null,
        user_view:      null,
        last_decision:  null,   // most recent decision — type + optional reason + date
      };

      // ── Pull from latest analysis artifact ────────────────────────────────
      const analysis = memory.artifacts.find(a => a.artifact_type === 'analysis');
      if (analysis?.content) {
        try {
          const fo = JSON.parse(analysis.content);
          if (fo.practical_details) {
            const pd = fo.practical_details;
            if (pd.salary_annual  && !briefing.salary)     briefing.salary     = pd.salary_annual;
            if (pd.remote_model   && !briefing.work_model) briefing.work_model = pd.remote_model;
            if (pd.location       && !briefing.location)   briefing.location   = pd.location;
            if (pd.employment_type && !briefing.employment) briefing.employment = pd.employment_type;
          }
          if (Array.isArray(fo.risks_and_unknowns) && fo.risks_and_unknowns.length) {
            const riskTexts = fo.risks_and_unknowns
              .map(r => typeof r === 'object' ? (r.text || r.risk || '') : String(r))
              .filter(Boolean);
            briefing.risks = riskTexts.slice(0, 4).join('; ') || null;
          }
        } catch (_) {}
      }

      // ── Pull recruiter from interactions ──────────────────────────────────
      if (Array.isArray(memory.interactions) && memory.interactions.length) {
        const rec = memory.interactions.find(i => i.person_id);
        if (rec?.summary) briefing.recruiter = rec.summary.split(/[\n,]/)[0].trim() || null;
      }

      // ── Overlay memory signals (most-recent-first, already deduplicated) ─
      for (const s of signals) {
        const _factual = s.signal_type === 'fact' || s.signal_type === 'correction';
        switch (s.signal_key) {
          case 'salary':         if (!briefing.salary     || _factual) briefing.salary     = s.signal_value; break;
          case 'work_model':     if (!briefing.work_model || _factual) briefing.work_model = s.signal_value; break;
          case 'location':       if (!briefing.location   || _factual) briefing.location   = s.signal_value; break;
          case 'recruiter_name': if (!briefing.recruiter  || _factual) briefing.recruiter  = s.signal_value; break;
          case 'user_view':
          case 'sentiment':    briefing.user_view = s.signal_value; break;
        }
        if (s.signal_type === 'opinion' && !briefing.user_view) {
          briefing.user_view = `${s.signal_key}: ${s.signal_value}`;
        }
      }

      // ── Last decision from decision ledger ────────────────────────────────
      // decisions array is newest-first; take [0] for the most recent entry.
      // Format: "skip (2026-03-08) — Salary too low"  OR  "apply (2026-03-07)"
      if (Array.isArray(decisions) && decisions.length > 0) {
        const d = decisions[0];
        const date = d.created_at ? d.created_at.slice(0, 10) : null;
        const parts = [d.decision_type, date ? `(${date})` : null, d.reason ? `— ${d.reason}` : null];
        briefing.last_decision = parts.filter(Boolean).join(' ');
      }

      // ── Remove truly empty object (all nulls) ─────────────────────────────
      const hasContent = Object.values(briefing).some(v => v !== null);
      return hasContent ? briefing : null;
    }

    // ─── Pattern Signals ──────────────────────────────────────────────────────
    // Build cross-role pattern observations from decision stats.
    // Returns an array of plain-English observations, or null if below threshold.
    //
    // Threshold: 3+ total ledger decisions before surfacing anything.
    // For individual observations: 2+ matching decisions required.
    //
    // Phrasing follows Decision Memory tone rules:
    //   - Observational, never prescriptive
    //   - Describes patterns in roles, not claims about user identity
    //   - "One thing I'm noticing…" / "A small pattern is emerging…"
    //   - Never: "you always prefer" / "your type of job"
    //
    // Called in _wsTriggerChat; injected as context.pattern_signals.
    // The edge function surfaces these selectively via ## PATTERN SIGNALS.
    function _buildPatternSignals(stats) {
      if (!stats || stats.total < 3) return null;
      const observations = [];
      const reasonThreshold = 2;

      // ── Skip reason patterns ───────────────────────────────────────────────
      const skipReasonPhrases = {
        'Salary missing':          n => `${n} roles you\u2019ve passed on didn\u2019t list a salary band.`,
        'Salary too low':          n => `${n} roles you\u2019ve passed on had salary below your threshold.`,
        'Too much coding':         n => `${n} roles you\u2019ve passed on had heavier implementation expectations than usual.`,
        'Commute too long':        n => `${n} roles you\u2019ve passed on raised commute concerns.`,
        'Role unclear':            n => `${n} roles you\u2019ve passed on had unclear scope or structure.`,
        'Company not interesting': n => `${n} roles you\u2019ve passed on weren\u2019t the right company fit.`,
      };
      const skipReasons = Object.entries(stats.byTypeAndReason)
        .filter(([combo]) => combo.startsWith('skip::'))
        .map(([combo, count]) => ({ reason: combo.replace('skip::', ''), count }))
        .filter(({ count }) => count >= reasonThreshold)
        .sort((a, b) => b.count - a.count);
      for (const { reason, count } of skipReasons.slice(0, 2)) {
        const fn = skipReasonPhrases[reason];
        observations.push(fn ? fn(count) : `You\u2019ve flagged \u201c${reason}\u201d on ${count} roles you\u2019ve passed.`);
      }

      // ── Apply vs skip ratio ────────────────────────────────────────────────
      // Only surface if the pattern is notable (many skips, no applies yet).
      const skips  = stats.byType.skip  || 0;
      const applies = stats.byType.apply || 0;
      if (skips >= 4 && applies === 0) {
        observations.push(`You\u2019ve passed on ${skips} roles without applying to any yet.`);
      }

      return observations.length > 0 ? observations : null;
    }

    // ─── User Profile ─────────────────────────────────────────────────────────
    // Static profile for the single Rolewise user.
    // Injected into every workspace-chat call as USER CONTEXT so the assistant
    // can frame answers relative to known constraints and preferences.
    // Update these fields as the user's situation changes.
    // Future: replace with a live read from a user_profile DB table.
    const _ROLEWISE_USER_PROFILE = {
      location:             'Effingham Junction, Surrey',
      seniority:            'Senior / Lead Product Designer',
      work_focus:           'product design leadership, systems thinking',
      hard_constraints:     'avoid roles requiring production-level coding',
      hybrid_tolerance:     'hybrid or remote preferred',
      commute_tolerance:    'roughly 60 minutes',
      min_salary_permanent: 'around £110k for permanent roles',
    };

    // Returns the user profile as an object ready to pass to callWorkspaceChatAPI.
    // The edge function formats it into a USER CONTEXT block in the prompt.
    function _buildUserContext() {
      return { ..._ROLEWISE_USER_PROFILE };
    }
    // ─────────────────────────────────────────────────────────────────────────

    // Respond to plain conversational messages with a contextual AI reply.
    // Follows the same pattern as _wsTriggerPrep / _wsTriggerThoughts.
    async function _wsTriggerChat(role, text, timelineEl) {
      console.log('[_wsTriggerChat] called', { roleId: role.id, textLen: text.length });
      _wsShowThinking(timelineEl, 'Rolewise is thinking');

      // Fire signal extraction in background — doesn't block the reply
      if (!role._isTemp) _wsExtractAndStoreSignals(role.id, text);

      try {
        const [memory, signals, decisions, _decisionStats] = await Promise.all([
          wsLoadMemory(role.id),
          role._isTemp ? Promise.resolve([]) : wsLoadSignals(role.id),
          role._isTemp ? Promise.resolve([]) : wsLoadDecisions(role.id),
          // Cross-role stats for Pattern Signals / Decision Memory.
          // Fire-and-forget — errors are caught silently, no-op on temp roles.
          role._isTemp ? Promise.resolve(null) : wsDecisionStats().catch(() => null),
        ]);
        console.log('[_wsTriggerChat] memory loaded', { conversations: memory.conversations?.length, artifacts: memory.artifacts?.length, signals: signals.length });

        // ── Build context for the edge function ────────────────────────────────
        // ARCHITECTURE: The raw JD text is NEVER passed to the chat brain.
        // Only structured signals from stored analysis artifacts and the user's chat
        // message are sent to workspace-chat. This ensures:
        //   1. Each JD is analysed once (by analyse-jd), result stored
        //   2. Chat reasoning uses stored intelligence, not the raw JD
        //   3. AI costs remain predictable as the product scales
        // Exception: if the user asks about specific JD wording, workspace-chat
        // asks them to paste the relevant section (see ## INTELLIGENCE ARCHITECTURE).
        const analysisArtifact = memory.artifacts.find(a => a.artifact_type === 'analysis');
        let fo = null;
        if (analysisArtifact?.content) {
          try { fo = JSON.parse(analysisArtifact.content); } catch (_) {}
        }

        const context = {
          company_name: role.company_name || null,
          role_title:   role.role_title   || null,
          stage:        currentStageLabel(role),
        };

        if (fo) {
          if (fo.role_summary)             context.role_summary       = fo.role_summary;
          if (fo.practical_details)        context.practical_details  = fo.practical_details;
          if (Array.isArray(fo.risks_and_unknowns) && fo.risks_and_unknowns.length) {
            context.risks = fo.risks_and_unknowns
              .map(r => (typeof r === 'object' ? r.text || r.risk || '' : String(r)))
              .filter(Boolean).join('; ');
          }
          // What You Would Actually Do — core responsibilities distilled from the JD.
          if (Array.isArray(fo.what_you_would_actually_do) && fo.what_you_would_actually_do.length) {
            context.responsibilities = fo.what_you_would_actually_do
              .map(r => (typeof r === 'object' ? r.text || '' : String(r)))
              .filter(Boolean).join('; ');
          }
          // What They Are Really Looking For — the actual criteria behind the JD language.
          if (Array.isArray(fo.what_they_are_really_looking_for) && fo.what_they_are_really_looking_for.length) {
            context.criteria = fo.what_they_are_really_looking_for
              .map(r => (typeof r === 'object' ? r.text || '' : String(r)))
              .filter(Boolean).join('; ');
          }
          // Role archetype — the broad category of what this role actually is.
          if (fo.role_archetype) context.role_archetype = fo.role_archetype;
          // Hard constraints — non-negotiable dealbreakers detected from the JD.
          if (Array.isArray(fo.hard_constraints) && fo.hard_constraints.length) {
            context.hard_constraints = fo.hard_constraints.map(hc => hc.label + (hc.reason ? ': ' + hc.reason : ''));
          }
          // Suggested actions — what the user could focus on next.
          if (Array.isArray(fo.suggested_actions) && fo.suggested_actions.length) {
            context.suggested_actions = fo.suggested_actions
              .map(a => (typeof a === 'object' ? a.text || a.action || '' : String(a)))
              .filter(Boolean).slice(0, 3);
          }
          // Hiring system — AI-detected process type from analyse-jd.
          // Injected so the chat brain can frame process/timeline questions accurately.
          if (fo.hiring_system && fo.hiring_system.type) context.hiring_system = fo.hiring_system;
          // JD Health — clarity and transparency signals extracted from the JD at analysis time.
          // Passed as stored signals so the chat brain never needs to re-read the raw JD.
          if (Array.isArray(fo.jd_health) && fo.jd_health.length > 0) context.jd_health = fo.jd_health;
        }

        // ── User background context ──────────────────────────────────────────────
        // Wire the user's self-described preferences and default CV notes so the
        // chat brain can reference personal context when writing cover letters,
        // suggesting CV tweaks, or preparing for interviews.
        if (userProfile) {
          const _rpn = userProfile.role_preference_note;
          if (_rpn && typeof _rpn === 'string' && _rpn.trim().length > 10) {
            context.user_background = _rpn.trim();
          }
        }
        // Default CV notes — may contain a summary of what the CV covers
        try {
          const { data: _defCv } = await db.from('cv_versions')
            .select('notes, cv_text')
            .eq('is_default', true)
            .limit(1)
            .maybeSingle();
          if (_defCv) {
            if (_defCv.cv_text && _defCv.cv_text.trim().length > 20) {
              context.cv_summary = _defCv.cv_text.trim().slice(0, 1500);
            } else if (_defCv.notes && _defCv.notes.trim().length > 10) {
              context.cv_notes = _defCv.notes.trim();
            }
          }
        } catch (_cvErr) { /* non-critical — chat works without CV context */ }

        // Last 6 short messages as conversation history (skip very long ones like JD pastes).
        //
        // Briefing JSON blobs (stored as {"_type":"briefing",...} for the restore path)
        // typically exceed 800 chars and would be silently dropped by the length filter,
        // leaving the model with no awareness that a structured overview card was already
        // shown. Without that context a follow-up like "and the salary" looks like a fresh
        // query, so the model generates another full sections card instead of a focused
        // plain-text answer.
        //
        // Fix: before the length filter, decode briefing blobs into a compact one-line
        // summary. The model then sees e.g.:
        //   assistant: [Structured card: Role Overview] Sections: What the role is, …
        // and knows the overview was given, so follow-up questions receive focused replies.
        if (Array.isArray(memory.conversations)) {
          context.recent_messages = memory.conversations
            .slice(-8)                                                // wider window before filter
            .map(m => {
              const _isAsst = m.sender === 'assistant';
              let _content  = m.message || '';
              // Decode briefing blobs → compact summary so the model retains context.
              if (_isAsst && _content.startsWith('{') && _content.includes('"_type"')) {
                try {
                  const _bp = JSON.parse(_content);
                  if (_bp._type === 'briefing' && _bp.title) {
                    const _labels = Array.isArray(_bp.sections)
                      ? _bp.sections.map(s => s.label).filter(Boolean).join(', ')
                      : '';
                    _content = _labels
                      ? `[Structured card: ${_bp.title}] Sections: ${_labels}`
                      : `[Structured card: ${_bp.title}]`;
                  }
                } catch (_) {}
              }
              return { role: _isAsst ? 'assistant' : 'user', content: _content };
            })
            .filter(m => m.content && m.content.length < 800)        // drop JD pastes etc
            .slice(-6);
        }

        // Guard: _wsHandlePaste saves the user message fire-and-forget before calling
        // _wsTriggerChat. On fast inserts (short text), wsAddMessage may commit before
        // wsLoadMemory returns — so the current message appears as the last entry in
        // recent_messages, creating two consecutive user turns the Anthropic API rejects.
        // Fix: drop the trailing entry if it is a user message matching the current text.
        if (Array.isArray(context.recent_messages) && context.recent_messages.length > 0) {
          const last = context.recent_messages[context.recent_messages.length - 1];
          if (last.role === 'user' && last.content === text) {
            context.recent_messages = context.recent_messages.slice(0, -1);
          }
        }

        // Memory signals — deduplicated to most-recent value per key
        const dedupedSignals = [];
        if (signals.length > 0) {
          const seenKeys = new Set();
          for (const s of signals) { // already sorted newest-first
            if (!seenKeys.has(s.signal_key)) {
              seenKeys.add(s.signal_key);
              dedupedSignals.push(s);
            }
          }
          context.memory_signals = dedupedSignals.map(s =>
            `[${s.signal_type}] ${s.signal_key}: ${s.signal_value}${s.source && s.source !== 'user' ? ` (source: ${s.source})` : ''}`
          );
        }

        // Role briefing — compact structured summary derived from all known data.
        // Assembled client-side from existing sources; never invents missing values.
        // decisions passed so last_decision can be baked into the briefing object.
        const briefing = _wsAssembleBriefing(role, memory, dedupedSignals, decisions);
        if (briefing) context.briefing = briefing;

        // Decision history — newest-first, max 5, raw facts only.
        // Gives the assistant awareness of how the user has interacted with this role before.
        if (decisions.length > 0) {
          context.decision_history = decisions.slice(0, 5).map(d => {
            const date = d.created_at ? d.created_at.slice(0, 10) : 'unknown';
            return d.reason
              ? `${date} — ${d.decision_type}\nReason: ${d.reason}`
              : `${date} — ${d.decision_type}`;
          });
        }

        // ── Salary intent: inject pre-computed UK take-home breakdown ──────────
        // When the user asks a take-home/tax question and a salary is known,
        // compute the breakdown client-side and pass it to the model as structured
        // context so the model describes numbers rather than inventing them.
        const _salaryIntentDetected = _wsSalaryIntent(text);
        const _knownSalaryText = briefing?.salary || null;
        let   _salaryParsed    = null;

        if (_salaryIntentDetected && _knownSalaryText) {
          _salaryParsed = _wsParseSalaryText(_knownSalaryText);
          if (_salaryParsed) {
            // For ranges, pre-compute all three endpoints; for single values, just the one
            const _targets = _salaryParsed.type === 'range'
              ? [
                  { label: 'Midpoint',  gross: _salaryParsed.mid   },
                  { label: 'Lower end', gross: _salaryParsed.lower },
                  { label: 'Upper end', gross: _salaryParsed.upper },
                ]
              : [{ label: 'Salary', gross: _salaryParsed.value }];

            context.salary_calc = {
              salary_text: _knownSalaryText,
              pension_pct: (userProfile && userProfile.pension_pct) || 10,
              note: `Pre-computed 2024/25 UK PAYE estimate (salary sacrifice model, ${(userProfile && userProfile.pension_pct) || 10}% pension). Employee NI and income tax on post-sacrifice income.`,
              breakdowns: _targets.map(({ label, gross }) => {
                const r = calculateUKTakeHome(gross);
                return {
                  label,
                  gross_monthly:    r.grossMonthly,
                  pension_monthly:  r.pensionMonthly,
                  taxable_monthly:  r.taxableMonthly,
                  tax_monthly:      r.taxMonthly,
                  ni_monthly:       r.niMonthly,
                  take_home_monthly: r.takeHomeMonthly,
                };
              }),
            };
          }
        }
        // ──────────────────────────────────────────────────────────────────────

        // Pattern Signals — cross-role observations from past decisions.
        // Built from wsDecisionStats() (cross-role ledger query, not this role only).
        // Injected when the threshold is met (3+ total decisions, 2+ per reason).
        // The edge function surfaces these selectively via ## PATTERN SIGNALS.
        // Phrasing is observational — never prescriptive, never repeating constantly.
        const _patternSignals = _buildPatternSignals(_decisionStats);
        if (_patternSignals && _patternSignals.length > 0) {
          context.pattern_signals = _patternSignals;
        }

        // User context — inject known user profile so the assistant can frame answers
        // relative to the user's constraints, preferences, and situation.
        // Treated as decision framing by the model, not as hard filters.
        context.user_context = _buildUserContext();

        // Prompt layer: build a compact text representation of context for dev visibility.
        // buildRolewiseContextBlock is defined in /ai/prompts/rolewise-system-prompt.js.
        // The actual context object is passed as JSON to the edge function — this call
        // is for logging and future use (e.g. direct API calls that need a text block).
        if (typeof buildRolewiseContextBlock === 'function') {
          console.log('[Rolewise] context block:\n' + buildRolewiseContextBlock(context));
        }

        const chatResult = await callWorkspaceChatAPI(text, context);

        _wsRemoveThinking(timelineEl);

        if (chatResult?.reply) {
          const { reply, chips, sections } = chatResult;

          // Structured mini-briefing: render labeled sections when AI returns them.
          // Used for practical answers (commute, salary, etc.) where content fits the
          // fact → uncertainty → implication or Compensation Snapshot pattern.
          if (sections && sections.length > 0) {
            const bubble = document.createElement('div');
            bubble.className = 'ws-assistant-reply ws-briefing-block ws-settle';
            bubble.dataset.wsEntry = WS_ENTRY.CHAT_ASSISTANT;
            // Title line (the reply field becomes the section heading)
            const titleEl = document.createElement('div');
            titleEl.className = 'ws-briefing-title';
            titleEl.textContent = reply;
            bubble.appendChild(titleEl);
            // Labeled sections
            sections.forEach(sec => {
              const secEl = document.createElement('div');
              secEl.className = 'ws-briefing-section';
              const labelEl = document.createElement('div');
              labelEl.className = 'ws-briefing-label';
              labelEl.textContent = sec.label || '';
              const textEl = document.createElement('div');
              textEl.className = 'ws-briefing-text';
              textEl.textContent = sec.text || '';
              secEl.appendChild(labelEl);
              secEl.appendChild(textEl);
              bubble.appendChild(secEl);
            });
            timelineEl.appendChild(bubble);
            // Force-scroll so the card is immediately visible — same behaviour
            // as the plain-text streaming path. _wsScrollIfNear is intentionally
            // not used here because structured cards are always new responses,
            // not history restores, and should always scroll into view.
            _wsScrollToBottom(timelineEl);
          } else {
            // Standard plain-text reply — stream word-by-word
            const bubble = document.createElement('div');
            bubble.className = 'ws-assistant-reply ws-settle';
            bubble.dataset.wsEntry = WS_ENTRY.CHAT_ASSISTANT;
            timelineEl.appendChild(bubble);
            // Force-scroll so the response is immediately visible as it streams.
            _wsScrollToBottom(timelineEl);
            await _wsStreamText(bubble, reply);
          }

          // ── Salary follow-up chips ───────────────────────────────────────────
          // If this was a salary intent message and salary is known, render follow-up
          // chips after the reply. Only show if the model didn't already return chips
          // (model chips take precedence — they'll include actual figures).
          if (_salaryIntentDetected && _knownSalaryText && !chips?.length) {
            const _followChips = _salaryParsed?.type === 'range'
              ? [
                  `Midpoint (${_fmtSalaryK(_salaryParsed.mid)})`,
                  `Lower end (${_fmtSalaryK(_salaryParsed.lower)})`,
                  `Upper end (${_fmtSalaryK(_salaryParsed.upper)})`,
                  'Contract equivalent',
                ]
              : ['Show full breakdown', 'What about contract?', 'Pension impact'];
            _wsRenderChips(_followChips, timelineEl);
          } else if (chips?.length) {
            _wsRenderChips(chips, timelineEl);
          }
          // ────────────────────────────────────────────────────────────────────

          // Persist assistant reply for history.
          // Briefing responses (structured sections) are stored as a JSON envelope
          // so _wsRenderTimelineEntry can re-render the card on history restore.
          // Plain-text replies are stored as-is.
          const _storedReply = (sections && sections.length > 0)
            ? JSON.stringify({ _type: 'briefing', title: reply, sections })
            : reply;
          wsAddMessage(role.id, 'assistant', _storedReply).catch(() => {});
        } else {
          // Show a calm failure state — avoids silent drop
          console.warn('[_wsTriggerChat] no reply returned');
          const errBubble = document.createElement('div');
          errBubble.className = 'ws-assistant-reply ws-settle';
          errBubble.dataset.wsEntry = WS_ENTRY.CHAT_ASSISTANT;
          errBubble.textContent = "I couldn't respond just now. Try again or rephrase your question.";
          timelineEl.appendChild(errBubble);
          _wsScrollIfNear(timelineEl);
        }
      } catch (e) {
        _wsRemoveThinking(timelineEl, true);
        const errBubble = document.createElement('div');
        errBubble.className = 'ws-assistant-reply ws-settle';
        errBubble.dataset.wsEntry = WS_ENTRY.CHAT_ASSISTANT;
        errBubble.textContent = "Something went wrong. Try again in a moment.";
        timelineEl.appendChild(errBubble);
        _wsScrollIfNear(timelineEl);
        console.error('[_wsTriggerChat]', e);
      }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Main paste handler — called when user submits content from the chat input
    // ── Core analysis runner — called by _wsHandlePaste and by the retry button ──
    // Does NOT render a source card; that responsibility stays with _wsHandlePaste.
    // Safe to call multiple times on the same role without side effects on the timeline
    // (each call creates its own status element and appends a fresh artefact on success).
    async function _wsRunAnalysis(role, text, timelineEl) {
      // ── Analysis step list (shared _ANALYSIS_STAGES constant) ────────────────
      // Progressive vertical step list in the chat timeline. Steps advance on
      // timers and are cancelled as soon as the analysis returns. On error the
      // container is repurposed to show the retry message (matches old behaviour).
      const statusEl = document.createElement('div');
      statusEl.className = 'ws-analysis-steps';
      statusEl.dataset.wsEntry = WS_ENTRY.UI_TEMP;
      statusEl.id = 'ws-status-analysing';
      statusEl.innerHTML = _ANALYSIS_STAGES.map((s, i) =>
        `<div class="ws-step${i === 0 ? ' ws-step--active' : ''}" data-step="${i}">` +
          `<span class="ws-step-check"></span>` +
          `<span class="ws-step-label">${s}</span>` +
        `</div>`
      ).join('');
      timelineEl.appendChild(statusEl);
      _wsScrollIfNear(timelineEl);

      let _seqDone = false;
      const _advanceStep = (n) => {
        if (_seqDone || !statusEl.isConnected) return;
        const _stepEls = statusEl.querySelectorAll('.ws-step');
        for (let i = 0; i < n; i++) {
          _stepEls[i]?.classList.remove('ws-step--active');
          _stepEls[i]?.classList.add('ws-step--done');
        }
        if (n < _stepEls.length) {
          _stepEls[n]?.classList.remove('ws-step--done');
          _stepEls[n]?.classList.add('ws-step--active');
        }
      };
      const _seqTimers = _ANALYSIS_TIMINGS.map((t, i) =>
        setTimeout(() => _advanceStep(i + 1), t)
      );
      // When analysis returns: cancel timers and mark all remaining steps done,
      // then fade the list out before it is removed from the DOM.
      const _clearSeq = () => {
        _seqDone = true;
        _seqTimers.forEach(clearTimeout);
        if (statusEl.isConnected) {
          statusEl.querySelectorAll('.ws-step').forEach(el => {
            el.classList.remove('ws-step--active');
            el.classList.add('ws-step--done');
          });
          // Brief fade-out so the list doesn't vanish abruptly
          setTimeout(() => { if (statusEl.isConnected) statusEl.classList.add('ws-analysis-steps--fading'); }, 120);
        }
      };

      // ── Phase 1: Analysis ──────────────────────────────────────────────────────
      // Metadata extraction + AI analysis only. Failure here is a true analysis
      // failure — the JD was never processed. Retry reruns the whole function.
      let analysis, _company, _title, _location, _jobUrl, jdClean;

      try {
        const _meta = extractJDMetadata(text, cleanJobDescription(text));
        _company  = _meta.company_name  || role.company_name  || null;
        _title    = _meta.role_title    || role.role_title    || null;
        _location = _meta.location      || role.location_text || null;
        _jobUrl   = _meta.job_url       || role.job_url       || null;

        // Silently update the role record with extracted metadata
        const _updatePayload = {};
        if (_company  && !role.company_name)  _updatePayload.company_name  = _company;
        if (_title    && !role.role_title)    _updatePayload.role_title    = _title;
        if (_location && !role.location_text) _updatePayload.location_text = _location;
        if (_jobUrl   && !role.job_url)       _updatePayload.job_url       = _jobUrl;
        _updatePayload.job_description_raw = text;

        // For existing (saved) roles: update metadata fields in the background.
        // For temp roles: skip — the role doesn't exist in DB yet.
        if (!role._isTemp) {
          db.from('roles').update(_updatePayload).eq('id', role.id)
            .then(({ error }) => {
              if (!error) {
                Object.assign(role, _updatePayload);
                // Re-render JD section to pick up extracted job URL
                const _jdEl = document.getElementById('col-jd-section');
                if (_jdEl && _jdEl.style.display !== 'none') _renderJDSection(role, text);
                document.querySelectorAll('.inbox-role').forEach(row => {
                  if (row.dataset.id === role.id) {
                    const compEl = row.querySelector('.inbox-role-company');
                    const titlEl = row.querySelector('.inbox-role-title');
                    if (compEl && _company)  compEl.textContent = _company;
                    if (titlEl && _title)    titlEl.textContent = _title;
                  }
                });
              }
            }).catch(() => {});
        }

        jdClean  = cleanJobDescription(text);
        analysis = await callAnalysisAPI(jdClean || text);

        // ── Company/title backfill from AI output ────────────────────────────
        // extractJDMetadata runs before the AI call. If it missed the company
        // name but the AI extracted one (e.g. from "About Us" prose), adopt it.
        // Same for role title. This closes the gap where 19% of roles had null
        // company names despite the AI knowing the answer.
        if (!_company && analysis._company) {
          _company = analysis._company;
        }
        const _aiPd = analysis.practical_details || analysis.practicalDetails || {};
        if (!_company) {
          // AI practical_details sometimes carries a company_type like "Scaleup"
          // but the role_summary or _company field may carry the actual name.
          // Check role_summary for "at CompanyName" pattern as last resort.
          const _summ = analysis.role_summary || '';
          const _atMatch = _summ.match(/\bat\s+([A-Z][a-zA-Z0-9&. '-]{1,40}?)(?:[,.]|\s+(?:is|you|the|a|as|where|that|for|in)\b)/);
          if (_atMatch?.[1]) {
            const _cand = _atMatch[1].trim().replace(/[.,]+$/, '');
            if (_cand.length >= 3 && _cand.split(' ').length <= 4) {
              _company = sanitiseCompanyName(_cand) || _company;
            }
          }
        }
        if (!_title && analysis._roleTitle) _title = analysis._roleTitle;

        // Annotate analysis with role identity for artefact heading
        analysis._company   = _company;
        analysis._roleTitle = _title;

        // Signal strength check — run after cleaning, before render.
        // If the cleaned text lacks JD role signals (e.g. partial page paste, nav-heavy content),
        // mark the analysis so renderMatchOutput can show a graceful explanation.
        if (_wsJDSignalStrength(jdClean || text) === 'weak') {
          analysis._weakSignal = true;
        }

        // Update header immediately with extracted metadata (before save completes)
        if (_company || _title) {
          const _headerPatch = {};
          if (_company)  _headerPatch.company_name  = _company;
          if (_title)    _headerPatch.role_title    = _title;
          if (_location) _headerPatch.location_text = _location;
          Object.assign(role, _headerPatch);
          _wsUpdateHeader(role);
        }

      } catch (e) {
        // True analysis failure — the AI step did not complete.
        _clearSeq();
        // Clean up "Analyse anyway" processing state if present, so the user
        // can see the error message and retry from a clean overview panel.
        const _ovBodyErr = document.getElementById('col-overview-body');
        if (_ovBodyErr) {
          const _procErr = _ovBodyErr.querySelector('.ws-fp-processing');
          if (_procErr) {
            _procErr.remove();
            for (const _ch of _ovBodyErr.children) {
              if (_ch.style.display === 'none') _ch.style.display = '';
            }
            // Re-enable inputs locked during "Analyse anyway" processing
            const _csE = document.getElementById('ws-chat-send');
            const _cbE = document.getElementById('ws-chat-bar');
            const _clE = document.querySelector('.col-list');
            if (_csE) _csE.removeAttribute('disabled');
            if (_cbE) _cbE.classList.remove('ws-chat-bar--processing');
            if (_clE) _clE.classList.remove('col-list--locked');
          }
        }
        // Repurpose the step list container as a standard error status line
        statusEl.innerHTML =
          '<span class="ws-status-msg">I couldn\'t analyse that. Try pasting the job description again or send the job link.</span>' +
          '<button class="ws-retry-btn">Retry</button>';
        statusEl.className = 'ws-assistant-status ws-status-error';
        statusEl.dataset.wsEntry = WS_ENTRY.UI_TEMP;
        statusEl.querySelector('.ws-retry-btn')?.addEventListener('click', () => {
          statusEl.remove();
          _wsRunAnalysis(role, text, timelineEl);
        });
        console.error('[_wsRunAnalysis] analysis phase', e);
        return;
      }

      // ── Analysis succeeded — render artefact immediately ───────────────────────
      // Artefact is visible from this point on regardless of what the save step does.
      // Use a local placeholder id; wsAddArtifact will return the real one later.
      _clearSeq();
      const _localArtifactId = 'local-' + Date.now();
      // Fade the step list out — 150 ms matches Phase 6 loader exit target.
      if (statusEl.isConnected) {
        statusEl.classList.add('ws-analysis-steps--fading');
        setTimeout(() => { if (statusEl.isConnected) statusEl.remove(); }, 150);
      }
      // If the "Analyse anyway" path left a processing spinner in the overview body,
      // remove it and un-hide all children now that real content is about to render.
      // This prevents the blank scaffold from ever being visible — the children go
      // from hidden → immediately populated with analysis output in one frame.
      const _ovBody = document.getElementById('col-overview-body');
      if (_ovBody) {
        const _proc = _ovBody.querySelector('.ws-fp-processing');
        if (_proc) {
          // Unlock inputs immediately so the user is not blocked while the
          // overlay fades. Unhide children so analysis content renders beneath
          // the overlay in the same synchronous frame (no visible flash).
          const _cs = document.getElementById('ws-chat-send');
          const _cb = document.getElementById('ws-chat-bar');
          const _cl = document.querySelector('.col-list');
          if (_cs) _cs.removeAttribute('disabled');
          if (_cb) _cb.classList.remove('ws-chat-bar--processing');
          if (_cl) _cl.classList.remove('col-list--locked');
          for (const _ch of _ovBody.children) {
            if (_ch.style.display === 'none') _ch.style.display = '';
          }
          // Fade the processing overlay out (120 ms) so the transition to
          // analysis content feels calm rather than abrupt.
          _proc.style.transition = 'opacity 0.12s ease';
          _proc.style.opacity = '0';
          setTimeout(() => { if (_proc.isConnected) _proc.remove(); }, 130);
        }
      }
      // Analysis cards render in the overview panel, not the chat timeline.
      const _liveOvCards = document.getElementById('col-overview-cards');
      if (_liveOvCards) {
        // rw-analysis-arrive: brief fade-in so the analysis appears calmly
        // rather than snapping in. Animation is defined in styles.css.
        _liveOvCards.innerHTML = `<div class="rw-overview-wrap rw-analysis-arrive" data-artifact-id="${esc(_localArtifactId)}" data-artifact-type="analysis">${renderMatchOutput(analysis)}</div>`;
        _initCompSnapshot(_liveOvCards);
        const _liveRole = allRoles.find(r => r.id === role.id) || role;
        _renderRoleHeader(_liveRole);
        // Refresh decision capture card in case analysis was the first trigger
        _renderDecisionCapture(_liveRole);
        // Render blocker checklist + decision history (Decision Layer V1)
        _renderBlockersSection(_liveRole).catch(() => {});
        _renderDecisionHistoryDL(_liveRole).catch(() => {});
        // Render rail + JD section — wrap was just replaced, slots must be re-created
        renderRail(_liveRole);
        if (_liveRole.job_description_raw) {
          _renderJDSection(_liveRole, _liveRole.job_description_raw);
        }
        // Async-fill the CV recommendation in the Fit Assessment card
        _fillFitAssessmentCV();
      }
      _wsWireSourceCards(timelineEl);

      // ── State 3: Workspace Ready — exit intake mode, reveal col-chat ───────────
      // If this analysis was triggered via the intake panel (Add JD flow), tear down
      // the intake overlay and animate col-chat into view. The grid transition on
      // .app handles the smooth column reveal (0px → 360px).
      const _intakeEl = document.getElementById('intake-panel');
      if (_intakeEl && _intakeEl.dataset.cleanupPending) {
        _intakeEl._clearTimers?.();
        delete _intakeEl.dataset.cleanupPending;
        // Exit animation, then hide panel
        _intakeEl.classList.add('intake-panel--exit');
        setTimeout(() => {
          _intakeEl.setAttribute('hidden', '');
          _intakeEl.classList.remove('intake-panel--exit');
        }, 280);
        // Reveal col-chat: remove intake-mode, grid transition animates column in
        document.querySelector('.app')?.classList.remove('intake-mode');
        // Render sticky header now that we have extracted role data
        _renderStickyHeader(role);
      }

      // ── Decision Bar ──────────────────────────────────────────────────────────
      // Show the decision prompt a moment after the analysis appears.
      // Replaces the old static checkpoint — the user now gets actionable buttons
      // (Apply / Explore Further / Pass) rather than a static suggestions list.
      setTimeout(() => {
        _wsRenderDecisionBar(role, timelineEl);
      }, 900);

      // ── Phase 2: Save/promotion ────────────────────────────────────────────────
      // All DB writes happen here. Failure does not affect the already-visible artefact.
      // role._isTemp remains true until _doSave() succeeds.
      async function _doSave() {
        if (role._isTemp) {
          // ── BLOCKING STEP: roles.insert ───────────────────────────────────────
          // This is the ONLY step that blocks promotion. If it fails, _doSave()
          // throws and the user sees the save-error message. All subsequent steps
          // are non-blocking and must not propagate errors upward.
          console.log('[_doSave] step 1: roles.insert — start');
          const { data: newRole, error: createErr } = await db.from('roles').insert({
            company_name:        _company    || null,
            role_title:          _title      || null,
            location_text:       _location   || null,
            job_url:             _jobUrl     || role.job_url || null,
            job_description_raw: text,
            status:              'active',
          }).select().single();

          if (createErr) {
            console.error('[_doSave] step 1: roles.insert FAILED —', createErr.message || createErr);
            throw createErr;
          }
          console.log('[_doSave] step 1: roles.insert SUCCESS — id:', newRole.id);

          // ── Role is now saved. All following steps are best-effort. ──────────
          // None of these may throw through to the outer catch. If they fail,
          // the role is still saved and the analysis is still visible.
          try {
            insertEvent(newRole.id, { event_type: 'role_created', title: 'Role workspace opened', source: 'user' });

            // Promote: mutate the temp sentinel into the real role object in place.
            Object.assign(role, newRole, { _isTemp: false });
            // Role Header — skipped during Path C because _isTemp was true at that point.
            // Now that the role is promoted, render the header into the existing wrap.
            _renderRoleHeader(role);
            // Re-render JD section with saved role data (picks up job_url if extracted)
            const _jdEl2 = document.getElementById('col-jd-section');
            if (_jdEl2 && _jdEl2.style.display !== 'none') _renderJDSection(role, text);
            selectedRoleId = newRole.id;

            console.log('[_doSave] step 2: inbox refresh — start');
            allRoles.unshift({ ...newRole, role_updates: [], _appliedDate: null, _firstResponseDate: null });
            try {
              renderInbox(allRoles);
              console.log('[_doSave] step 2: inbox refresh SUCCESS');
            } catch (renderErr) {
              console.error('[_doSave] step 2: renderInbox FAILED (non-blocking) —', renderErr);
            }

            setTimeout(() => {
              document.querySelectorAll('.inbox-role').forEach(r =>
                r.classList.toggle('selected', r.dataset.id === newRole.id)
              );
            }, 50);

            // If a recruiter was captured from an email paste while still in temp state,
            // link them now that the role has a real DB record.
            if (role._pendingRecruiter) {
              console.log('[_doSave] step 3: pending recruiter link — start');
              _wsLinkRecruiterFromEmail(role, role._pendingRecruiter)
                .then(() => { role._pendingRecruiter = null; console.log('[_doSave] step 3: recruiter link SUCCESS'); })
                .catch(err => { role._pendingRecruiter = null; console.error('[_doSave] step 3: recruiter link FAILED (non-blocking) —', err); });
            }

            // Auto-detect recruiter/hiring-contact from JD text (and job URL as fallback).
            // runRecruiterAutoDetection guards internally: exits immediately if the role
            // already has a role_recruiters row, so this is safe to call unconditionally
            // even when step 3 ran. This is the PRIMARY wiring point for the workspace
            // paste flow — saveRole() (Add JD modal) has its own equivalent call.
            console.log('[_doSave] step 3b: recruiter auto-detect — start', {
              roleId:      role.id,
              textLen:     text ? text.length : 0,
              textSnippet: text ? text.slice(0, 120).replace(/\n/g, '↵') : '(empty)',
            });
            runRecruiterAutoDetection(role, text)
              .then(() => console.log('[_doSave] step 3b: recruiter auto-detect complete'))
              .catch(err => console.error('[_doSave] step 3b: recruiter auto-detect FAILED (non-blocking) —', err));

            // Back-fill the initial JD paste into role_conversations.
            console.log('[_doSave] step 4: wsAddMessage backfill — start');
            wsAddMessage(role.id, 'user', text)
              .then(() => console.log('[_doSave] step 4: wsAddMessage SUCCESS'))
              .catch(err => console.error('[_doSave] step 4: wsAddMessage FAILED (non-blocking) —', err));

          } catch (promotionErr) {
            // Catch anything unexpected in the post-insert promotion block.
            // Role IS saved — _isTemp is already false. Just log and continue.
            console.error('[_doSave] post-insert promotion block FAILED (non-blocking) —', promotionErr);
          }
        }

        // Save to jd_matches — critical for analysis persistence.
        // If this fails, the analysis is visible in the current session but will be
        // lost on reload. Surface a warning so the user knows to retry.
        console.log('[_doSave] step 5: jd_matches.insert — start');
        try {
          await db.from('jd_matches').insert({
            role_id:             role.id,
            job_description_raw: text,
            jd_text_raw:         text,
            jd_text:             jdClean || text,
            jd_text_clean:       jdClean || null,
            company_name:        _company,
            role_title:          _title,
            job_url:             _jobUrl || role.job_url,
            selected_cv_ids:     [],
            cv_version_ids:      [],
            output_json:         analysis,
          }).select('id').single();
          insertEvent(role.id, { event_type: 'analysis_saved', title: 'Analysis saved', detail: `Source: ${analysis._source || 'ai'}` });
          console.log('[_doSave] step 5: jd_matches.insert SUCCESS');
        } catch (jdErr) {
          console.error('[_doSave] step 5: jd_matches.insert FAILED —', jdErr);
          // Surface a user-visible warning — the analysis is visible now but won't
          // survive a page reload. Offer a retry that re-attempts only this step.
          const _saveWarnEl = document.createElement('div');
          _saveWarnEl.className = 'ws-save-warning';
          _saveWarnEl.innerHTML =
            '<span class="ws-save-warning-text">Analysis could not be saved. It is visible now but will be lost if you leave this page.</span>' +
            '<button class="ws-save-warning-retry">Retry save</button>';
          _saveWarnEl.querySelector('.ws-save-warning-retry').addEventListener('click', async () => {
            _saveWarnEl.querySelector('.ws-save-warning-retry').disabled = true;
            _saveWarnEl.querySelector('.ws-save-warning-retry').textContent = 'Saving…';
            try {
              await db.from('jd_matches').insert({
                role_id: role.id, job_description_raw: text, jd_text_raw: text,
                jd_text: jdClean || text, jd_text_clean: jdClean || null,
                company_name: _company, role_title: _title,
                job_url: _jobUrl || role.job_url,
                selected_cv_ids: [], cv_version_ids: [], output_json: analysis,
              }).select('id').single();
              _saveWarnEl.remove();
              console.log('[_doSave] step 5: jd_matches retry SUCCESS');
            } catch (_retryErr) {
              _saveWarnEl.querySelector('.ws-save-warning-retry').disabled = false;
              _saveWarnEl.querySelector('.ws-save-warning-retry').textContent = 'Retry save';
              console.error('[_doSave] step 5: jd_matches retry FAILED —', _retryErr);
            }
          });
          timelineEl.appendChild(_saveWarnEl);
        }

        // Compute and persist radar match key — non-blocking
        try {
          const _radarInput = { ...role, latest_match_output: analysis };
          const _radarResult = _computeRadarMatchKey(_radarInput);
          if (_radarResult.radar_match_key) {
            db.from('roles').update({
              radar_match_key:        _radarResult.radar_match_key,
              radar_match_confidence: _radarResult.radar_match_confidence,
              radar_match_basis:      _radarResult.radar_match_basis,
            }).eq('id', role.id).then(() => {
              role.radar_match_key        = _radarResult.radar_match_key;
              role.radar_match_confidence = _radarResult.radar_match_confidence;
              role.radar_match_basis      = _radarResult.radar_match_basis;
            }).catch(() => {});
          }
        } catch (_radarErr) { console.error('[_doSave] radar key computation failed (non-blocking) —', _radarErr); }

        // Save / update analysis artefact — non-blocking
        console.log('[_doSave] step 6: analysis artefact write — start');
        try {
          const _artMem    = await wsLoadMemory(role.id);
          const _artExist  = _artMem.artifacts.find(a => a.artifact_type === 'analysis');
          const _artTitle  = [_company, _title].filter(Boolean).join(' — ') || 'Role Analysis';
          const _artContent = JSON.stringify(analysis);
          let _realArtId;
          if (_artExist) {
            await wsUpdateArtifact(_artExist.id, _artTitle, _artContent);
            _realArtId = _artExist.id;
            console.log('[_doSave] step 6: artefact UPDATE SUCCESS — id:', _realArtId);
          } else {
            const art = await wsAddArtifact(role.id, 'analysis', _artTitle, _artContent);
            _realArtId = art?.id || _localArtifactId;
            console.log('[_doSave] step 6: artefact INSERT SUCCESS — id:', _realArtId);
          }
          // Patch the placeholder's data-artifact-id to the real DB id so that future
          // DOM lookups (e.g. in-place prep refresh targeting this node) resolve correctly.
          // Search the full document — analysis node is now in col-overview-cards, not timeline.
          const _artNode = document.querySelector(`[data-artifact-id="${_localArtifactId}"]`);
          if (_artNode) {
            _artNode.setAttribute('data-artifact-id', _realArtId);
            // If this was an update (not first save), inject a freshness cue into the
            // already-rendered header. The header is not re-rendered to avoid re-running
            // renderMatchOutput on the analysis body.
            if (_artExist) {
              const _hdr = _artNode.querySelector('.ws-artifact-header');
              if (_hdr && !_hdr.querySelector('.ws-artifact-freshness')) {
                const _fl = document.createElement('span');
                _fl.className = 'ws-artifact-freshness';
                _fl.textContent = 'Updated just now';
                _hdr.appendChild(_fl);
              }
            }
          }
        } catch (artErr) { console.error('[_doSave] step 6: artefact write FAILED (non-blocking) —', artErr); }

        // Update memory summary in right panel
        _wsRefreshMemorySummary(role.id);

        // Ask one clarification question after a short pause.
        // Store the question type on the role so the next short reply can be
        // resolved against it rather than sent to the generic AI chat path.
        setTimeout(async () => {
          const freshRole = allRoles.find(r => r.id === role.id) || role;
          const q = _wsClarificationQuestion(freshRole, analysis);
          if (q) {
            role._pendingClarification = q.type; // e.g. 'missing_job_url'
            _wsRenderClarification(timelineEl, q);
          }
        }, 1200);
      }

      try {
        await _doSave();
      } catch (e) {
        // Save/promotion failure — analysis is already visible, role stays temp.
        // Show a distinct save-error message; retry calls _doSave() directly.
        const saveErrEl = _wsStatusLine(timelineEl, '', 'ws-status-error');

        const _showSaveError = () => {
          saveErrEl.innerHTML =
            '<span class="ws-status-msg">Analysis completed, but we couldn\'t save this role yet.</span>' +
            '<button class="ws-retry-btn">Try saving again</button>';
          saveErrEl.querySelector('.ws-retry-btn')?.addEventListener('click', async () => {
            saveErrEl.innerHTML = '<span class="ws-status-msg">Saving…</span>';
            saveErrEl.classList.remove('ws-status-error');
            try {
              await _doSave();
              saveErrEl.remove();
            } catch (_) {
              saveErrEl.classList.add('ws-status-error');
              _showSaveError();
            }
          });
        };

        _showSaveError();
        console.error('[_wsRunAnalysis] save phase', e);
      }
    }

    async function _wsHandlePaste(role, text, timelineEl) {
      if (!text.trim()) return;
      const type = _wsContentType(text);
      console.log('[_wsHandlePaste]', { type, isTemp: role._isTemp, roleId: role.id, textLen: text.trim().length });

      // ── JD + saved role: mismatch detection before any side-effects ──────────
      // For JD pastes into existing saved roles, check for a role mismatch before
      // rendering anything or writing to the DB. If a mismatch is detected, show
      // the confirmation prompt and return — the original workspace stays clean.
      // Temp roles: _detectRoleMismatch returns false immediately (first guard).
      // wsAddMessage, source card rendering, and role._retryText are all deferred
      // to the "Keep here" handler so they only happen when the user confirms intent.
      if (type === 'jd' && _detectRoleMismatch(role, extractJDMetadata(text, cleanJobDescription(text)))) {
        _wsShowMismatchPrompt(role, text, timelineEl);
        return;
      }

      // 1. Save raw message to role_conversations (fire and forget).
      // Skip for temp roles — no DB record exists yet; message is saved after promotion.
      if (!role._isTemp) wsAddMessage(role.id, 'user', text).catch(() => {});

      // 2. Render source card (or chat bubble for short text).
      // Non-chat content (URL / email / JD) supersedes any pending clarification — clear it
      // so the next chat message is not incorrectly resolved against a stale question.
      if (type !== 'chat') {
        role._pendingClarification = null;
        if (type === 'jd') {
          // JD → overview card, not chat timeline
          _renderJDSection(role, text);
        } else if (type === 'email') {
          // Email → source card in chat timeline
          _wsAppend(timelineEl, _wsSourceCardHtml(text, type, null));
          _wsWireSourceCards(timelineEl);
        }
        // URL: no card here — plain acknowledgement is appended in the URL handler below
      } else {
        _wsAppend(timelineEl, `<div class="ws-chat-bubble ws-chat-bubble--user" data-ws-entry="${WS_ENTRY.CHAT_USER}">${esc(text)}</div>`);
      }

      // 3. If URL — save it to the role record; show plain acknowledgement in chat.
      // The URL is displayed in the overview Original job description block, not in chat.
      if (type === 'url') {
        if (!role._isTemp) {
          // LinkedIn search page — not a specific job posting, invalid as a source URL
          if (/linkedin\.com\/jobs\/search/i.test(text)) {
            const _invalidMsg = 'That looks like a LinkedIn search page — open the specific job posting and copy the URL from there.';
            _wsAppend(timelineEl, `<div class="ws-assistant-reply ws-settle" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">${esc(_invalidMsg)}</div>`);
            wsAddMessage(role.id, 'assistant', _invalidMsg).catch(() => {});
            return;
          }

          // Persist to DB only for real (saved) roles
          wsAddInsight(role.id, 'signal', `Company/role link: ${text}`, 'extraction').catch(() => {});
          if (!role.job_url) {
            db.from('roles').update({ job_url: text }).eq('id', role.id).then(() => {
              role.job_url = text; // patch local object
              // Also patch the canonical allRoles entry so any later look-ups see the URL
              const _arEntry = allRoles.find(r => r.id === role.id);
              if (_arEntry && _arEntry !== role) _arEntry.job_url = text;
              // Re-render JD section immediately so "View original posting" appears
              if (role.job_description_raw) {
                _renderJDSection(role, role.job_description_raw);
              }
            }).catch(() => {});
          }

          // Attempt background enrichment for supported ATS sources (Greenhouse / Lever / Ashby)
          const enrichSource = _wsDetectEnrichSource(text);
          if (enrichSource) {
            const statusEl = _wsStatusLine(timelineEl, `Fetching details from ${enrichSource}…`);
            _wsScrollIfNear(timelineEl);
            const result = await callEnrichRoleAPI(role.id, text);
            if (statusEl.isConnected) statusEl.remove();
            if (result?.fetch_ok && result.fields_found?.length > 0) {
              // Enrichment card handles its own feedback — no separate acknowledgement needed
              _wsRenderEnrichmentCard(
                role,
                result.enrichment_id,
                result.source_name || enrichSource,
                result.extracted,
                result.fields_found,
                timelineEl
              );
            } else {
              // Fetch failed or no fields — plain acknowledgement
              const _ackMsg = 'Got it \u2014 I\'ve attached the original job posting to this role.';
              _wsAppend(timelineEl, `<div class="ws-assistant-reply ws-settle" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">${esc(_ackMsg)}</div>`);
              wsAddMessage(role.id, 'assistant', _ackMsg).catch(() => {});
            }
          } else {
            // Unsupported URL — plain acknowledgement
            const _ackMsg = 'Got it \u2014 I\'ve attached the original job posting to this role.';
            _wsAppend(timelineEl, `<div class="ws-assistant-reply ws-settle" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">${esc(_ackMsg)}</div>`);
            wsAddMessage(role.id, 'assistant', _ackMsg).catch(() => {});
          }
        } else {
          // Temp role: keep URL in memory, plain acknowledgement (no DB write yet)
          role.job_url = text;
          const _ackMsg = 'Got it \u2014 I\'ve attached the original job posting to this role.';
          _wsAppend(timelineEl, `<div class="ws-assistant-reply ws-settle" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">${esc(_ackMsg)}</div>`);
        }
        return;
      }

      // 4. Email: dedicated handler — recruiter extraction, not JD analysis
      if (type === 'email') {
        await _wsHandleEmail(role, text, timelineEl);
        return;
      }

      // 5. JD: run AI analysis; for chat, check for stage signals then intent before returning
      if (type !== 'jd') {
        // Stage/interview signal detection and prep/thoughts intent require a saved role.
        // Silently ignore for temp (unsaved) roles.
        if (!role._isTemp) {
          // Check for interview/stage signals first — capture and log if found.
          // Return early so prep/thoughts intent does not also fire on the same message
          // (avoids double prep refresh when stage signal + prep keyword both match).
          const _stageSignal = _wsDetectStageSignal(text);
          if (_stageSignal) {
            await _wsHandleStageSignal(role, text, _stageSignal, timelineEl);
            return;
          }

          if (_wsPrepIntent(text))    { await _wsTriggerPrep(role, timelineEl); return; }
          if (_wsThoughtIntent(text)) { await _wsTriggerThoughts(role, text, timelineEl); return; }

          // Decision reason capture: if a decision was logged and we're awaiting a reason,
          // only consume the message as a reason if it looks like a reason (short, not a question).
          // Otherwise clear the pending state and let the message fall through to normal chat.
          if (role._pendingDecisionCapture) {
            if (_wsIsDecisionReason(text)) {
              const _decType = role._pendingDecisionCapture; // capture before clearing
              role._pendingDecisionCapture = null;
              await _wsStoreDecisionReason(role, _decType, text, timelineEl);
              return;
            }
            role._pendingDecisionCapture = null; // not a reason — discard pending state, fall through
          }

          // Decision detection: skip / apply / withdraw expressed as natural language.
          const _decisionSignal = _wsDetectDecision(text);
          if (_decisionSignal) {
            await _wsHandleDecision(role, _decisionSignal.decision, timelineEl);
            return;
          }

          // Clarification reply: if a question is pending and this is not an explicit role
          // decision ("skip this", "I'm passing"), resolve the reply against that question
          // rather than sending it to the generic AI — which has no context for the question.
          if (role._pendingClarification && !_wsIsRoleDecision(text)) {
            await _wsHandleClarificationReply(role, text, timelineEl);
            return;
          }

          // Plain chat: generate a contextual assistant response
          console.log('[plain-chat] branch reached → _wsTriggerChat', { roleId: role.id, type, textLen: text.length });
          await _wsTriggerChat(role, text, timelineEl);
          return;
        }
        console.log('[plain-chat] temp role — no response sent');
        return; // temp role: no role context for a meaningful response
      }

      // Role fingerprint check — lightweight duplicate detection.
      // Runs before analysis starts. Compares the pasted JD's company + title
      // against all roles already in memory (pure JS, no API call).
      // If a strong match is found, surface a non-blocking notice letting the user
      // choose: open the existing role, or analyse as a new one.
      // Defers role._retryText to the "Analyse here" handler (see _wsRenderFingerprintNotice).
      // Guard: if the workspace is already in the duplicate_detected state (a notice
      // is visible and awaiting user action), do not run fingerprint detection again
      // and do not proceed to analysis. The user must act on the existing notice first.
      if (_wsDuplicateDetected) {
        console.warn('[fingerprint] workspace in duplicate_detected state — ignoring duplicate paste');
        return;
      }
      const _fpResult = _wsRoleFingerprintCheck(text, role.id);
      if (_fpResult) {
        _wsRenderFingerprintNotice(_fpResult.role, _fpResult.score, role, text, timelineEl);
        return;
      }

      // Store text on the role object so the retry button can re-run analysis
      // without requiring another paste from the user.
      // Mismatch was already ruled out above — safe to set here.
      role._retryText = text;

      await _wsRunAnalysis(role, text, timelineEl);
    }

    // ── Stage transition timeline event ──────────────────────────────────────
    // Lightweight divider — not a full artifact block, just a contextual marker.
    function _wsStageEventHtml(stage) {
      return `<div class="ws-stage-event" data-ws-entry="${WS_ENTRY.SYSTEM}">
        <span class="ws-stage-event-label">Moved to</span>
        <strong>${esc(stage)}</strong>
      </div>`;
    }

    // ── Role mismatch detection ───────────────────────────────────────────────
    // Returns true only when high-confidence signals indicate the pasted content
    // belongs to a different opportunity than the current workspace role.
    // Only fires on saved roles that already have at least one identity signal.
    // Two strong signals are checked: company name and job URL domain.
    // Each is independently sufficient — no need for both to fire.
    function _detectRoleMismatch(role, newMeta) {
      if (role._isTemp) return false;
      if (!role.company_name && !role.job_url) return false;

      // Normalise company name: lowercase, strip common legal suffixes + non-alphanumeric
      const normCompany = s => s.toLowerCase()
        .replace(/\b(inc|ltd|llc|plc|co|corp|group|the)\b\.?/g, '')
        .replace(/[^a-z0-9]/g, '');

      // Signal 1: both sides have a company name and they clearly don't match
      if (role.company_name && newMeta.company_name) {
        const a = normCompany(role.company_name);
        const b = normCompany(newMeta.company_name);
        if (a.length > 1 && b.length > 1 && !a.includes(b) && !b.includes(a)) return true;
      }

      // Signal 2: both sides have a job URL and the root domains differ
      const getDomain = url => { try { return new URL(url).hostname.replace(/^www\./, ''); } catch { return null; } };
      const dA = getDomain(role.job_url), dB = getDomain(newMeta.job_url);
      if (dA && dB && dA !== dB) return true;

      return false;
    }

    // ── Stage/interview signal detection ─────────────────────────────────────
    // Classifies short user chat messages for interview and scheduling signals.
    // Returns { type, stage, summary, confidence } or null.
    // 'high'   = explicit stage keyword (recruiter/HM/panel/final) present.
    // 'medium' = interview/call + scheduling context but no specific stage name.
    // null     = no useful signal — do not write anything to DB.
    function _wsDetectStageSignal(text) {
      const t = text.trim();
      if (t.length < 6 || t.length > 600) return null;

      // Scheduling / event context words — make medium signals more reliable
      const _sched = /\b(tomorrow|today|next\s+week|this\s+week|this\s+month|on\s+(monday|tuesday|wednesday|thursday|friday|saturday|sunday)|at\s+\d|scheduled|booked|confirmed|arranged|set\s+up|lined\s+up|coming\s+up|happening)\b/i;
      const _hasSched = _sched.test(t);

      // ── HIGH CONFIDENCE ────────────────────────────────────────────────────

      // Final round / stage / interview
      if (/\bfinal\s+(round|stage|interview|call)\b/i.test(t)) {
        return { type: 'interview', stage: 'Final', summary: 'Final round', confidence: 'high' };
      }

      // Panel interview — require scheduling context or explicit interview keyword
      if (
        /\bpanel\b/i.test(t) &&
        (_hasSched || /\b(interview|booked|scheduled|confirmed|invited)\b/i.test(t))
      ) {
        return { type: 'interview', stage: 'Panel', summary: 'Panel interview', confidence: 'high' };
      }

      // Hiring manager — any mention with scheduling or interview context
      if (
        /\bhiring\s+manager\b/i.test(t) &&
        (_hasSched || /\b(interview|call|screen|meeting|chat|booked|scheduled)\b/i.test(t))
      ) {
        return { type: 'interview', stage: 'Hiring Manager', summary: 'Hiring manager interview', confidence: 'high' };
      }

      // Recruiter call / screen — explicit keyword pair is enough
      if (/\brecruiter\s+(call|screen|chat|interview)\b/i.test(t)) {
        return { type: 'recruiter_call', stage: 'Recruiter Screen', summary: 'Recruiter call', confidence: 'high' };
      }

      // ── MEDIUM CONFIDENCE ──────────────────────────────────────────────────
      // Interview + scheduling context, but no specific stage name
      if (/\binterview\b/i.test(t) && _hasSched) {
        return { type: 'interview', stage: null, summary: 'Interview noted', confidence: 'medium' };
      }

      return null;
    }

    // Compact interaction event line — inline in timeline, distinct from stage dividers.
    // Not a source card, not an artifact — just a contextual signal marker.
    function _wsInteractionEventHtml(summary, type) {
      const ICONS = {
        recruiter_call:  '📞',
        recruiter_email: '✉️',
        interview:       '🗓',
        follow_up:       '🔁',
        other:           '•',
      };
      const icon = ICONS[type] || '•';
      return `<div class="ws-interaction-event" data-type="${esc(type)}" data-ws-entry="${WS_ENTRY.SYSTEM}">
        <span class="ws-interaction-event-icon">${icon}</span>
        <span class="ws-interaction-event-text">${esc(summary)}</span>
      </div>`;
    }

    // Advance the role stage when a workspace signal has high confidence.
    // Only moves forward — never downgrades. Does not show the undo bar.
    // Refreshes an existing prep artefact if one is present (same pattern as markStage).
    async function _wsAdvanceStage(role, detectedStage, timelineEl) {
      // Guard: only advance if the detected stage is strictly ahead of current
      const currentIdx  = currentStageIndex(role);
      const detectedIdx = RAIL_STAGE_STEPS.findIndex(s => s.stage === detectedStage);
      if (detectedIdx <= currentIdx) return; // no backward moves, no same-stage moves

      // Write a stage row to role_updates
      const { data: insertedRow, error } = await db.from('role_updates').insert({
        role_id:       role.id,
        event_type:    'stage',
        status:        'in_progress',
        stage_reached: detectedStage,
        note:          null,
      }).select('id').single();
      if (error) return; // silent fail — don't surface DB errors to user here

      const newEntry = {
        id:            insertedRow?.id || crypto.randomUUID(),
        role_id:       role.id,
        event_type:    'stage',
        status:        'in_progress',
        stage_reached: detectedStage,
        note:          null,
        created_at:    new Date().toISOString(),
      };

      // Mutate role_updates in place so currentStageLabel(role) reflects it immediately
      role.role_updates.unshift(newEntry);
      role.current_stage = detectedStage;

      // Update allRoles cache + sync DB current_stage column
      allRoles = allRoles.map(r => r.id === role.id ? { ...r, current_stage: detectedStage } : r);
      db.from('roles').update({ current_stage: detectedStage }).eq('id', role.id).catch(() => {});

      // Update stage display text in the right rail if visible
      const stageDisplay = document.getElementById('rail-stage-display');
      if (stageDisplay) stageDisplay.textContent = detectedStage;

      // Append a stage transition divider in the timeline
      if (timelineEl) _wsAppend(timelineEl, _wsStageEventHtml(detectedStage));

      // If a preparation artefact already exists, refresh it with the new stage context
      try {
        const mem = await wsLoadMemory(role.id);
        if (mem.artifacts.some(a => a.artifact_type === 'preparation')) {
          _wsTriggerPrep(role, timelineEl).catch(() => {});
        }
      } catch (_) {}
    }

    // ── Role mismatch confirmation prompt ─────────────────────────────────────
    // Renders an inline card asking the user to confirm whether pasted content
    // should create a new role or be kept in the current workspace.
    // "Create new role" → opens a blank workspace and passes the text through.
    // "Keep here"       → removes the card and runs analysis on the current role.
    function _wsShowMismatchPrompt(role, text, timelineEl) {
      const label = [role.company_name, role.role_title].filter(Boolean).join(' — ') || 'the current role';
      const card = document.createElement('div');
      card.className = 'ws-mismatch-prompt';
      card.dataset.wsEntry = WS_ENTRY.UI_TEMP;
      card.innerHTML =
        `<div class="ws-mismatch-msg">` +
          `This looks like a different opportunity from <strong>${esc(label)}</strong>. ` +
          `Would you like to create a new role for it?` +
        `</div>` +
        `<div class="ws-mismatch-actions">` +
          `<button class="ws-mismatch-btn-primary">Create new role</button>` +
          `<button class="ws-mismatch-btn-ghost">Keep here</button>` +
        `</div>`;
      timelineEl.appendChild(card);
      card.scrollIntoView({ behavior: 'smooth', block: 'nearest' });

      card.querySelector('.ws-mismatch-btn-primary').addEventListener('click', () => {
        card.remove();
        // Open a fresh blank workspace (switches center pane, creates new tempRole)
        const newTempRole = openBlankWorkspace();
        // renderWorkspaceView has rebuilt the DOM — get the new timeline element
        const newTimelineEl = document.getElementById('ws-timeline');
        // Clear blank state before injecting content
        document.querySelector('.ws-blank-state')?.remove();
        // Pass the pasted text into the new workspace as if the user pasted it there
        _wsHandlePaste(newTempRole, text, newTimelineEl);
      });

      card.querySelector('.ws-mismatch-btn-ghost').addEventListener('click', () => {
        card.remove();
        // Perform the steps that were deferred pending mismatch confirmation:
        // message persistence, source card, and retryText all happen now, as they
        // would have if no mismatch had been detected.
        if (!role._isTemp) wsAddMessage(role.id, 'user', text).catch(() => {});
        _renderJDSection(role, text);
        role._retryText = text;
        _wsRunAnalysis(role, text, timelineEl);
      });
    }

    // ─── Duplicate detection workspace state ────────────────────────────────
    // When true, the workspace is in the "duplicate_detected" state — a fingerprint
    // notice is visible and awaiting user decision. No further fingerprint checks
    // or notice renders should fire until the user acts (Open / Analyse anyway).
    let _wsDuplicateDetected = false;

    // ─── Role fingerprint check ───────────────────────────────────────────────
    // Lightweight cross-role duplicate detection triggered when a JD is pasted.
    // Compares the pasted JD's company + title signals against allRoles (in memory).
    // Returns the strongest matching existing role, or null if no match found.
    // Company name match is required (score ≥ 2) to avoid false-positive noise.
    function _wsRoleFingerprintCheck(text, currentRoleId) {
      if (!Array.isArray(allRoles) || allRoles.length === 0) return null;

      const meta = extractJDMetadata(text, cleanJobDescription(text));
      if (!meta.company_name && !meta.role_title) return null;

      // Normalise company: lowercase, strip legal suffixes, strip non-alphanumeric
      const normCompany = s => (s || '').toLowerCase()
        .replace(/\b(inc|ltd|llc|plc|co\.?|corp|group|the)\b\.?/g, '')
        .replace(/[^a-z0-9]/g, '');

      // Normalise title: lowercase, strip seniority qualifiers, strip non-alphanumeric
      const normTitle = s => (s || '').toLowerCase()
        .replace(/\b(senior|junior|lead|principal|staff|head of|chief|director|vp|vice president|associate|founding)\b/gi, '')
        .replace(/[^a-z0-9]/g, '');

      const srcCompany = normCompany(meta.company_name);
      const srcTitle   = normTitle(meta.role_title);

      let bestMatch = null;
      let bestScore = 0;

      for (const r of allRoles) {
        if (r.id === currentRoleId) continue;
        if (isArchivedRole(r)) continue; // skip permanently closed roles

        let score = 0;

        // Company match — exact normalised equality required (score += 2).
        // Substring containment is intentionally excluded: "Acme" must not match
        // "Acme Capital" or vice versa.
        if (srcCompany.length > 1 && r.company_name) {
          const rc = normCompany(r.company_name);
          if (rc.length > 1 && rc === srcCompany) {
            score += 2;
          }
        }

        // Title match — supplementary signal (score += 1)
        if (srcTitle.length > 2 && r.role_title) {
          const rt = normTitle(r.role_title);
          if (rt.length > 2 && (rt === srcTitle || rt.includes(srcTitle) || srcTitle.includes(rt))) {
            score += 1;
          }
        }

        // Require both company AND title to match (score must reach 3).
        // Company-only matches (score == 2) no longer trigger the duplicate notice.
        if (score >= 3 && score > bestScore) {
          bestScore = score;
          bestMatch = r;
        }
      }

      return bestMatch ? { role: bestMatch, score: bestScore } : null;
    }

    // Renders a centered workspace notice in the Overview panel when a pasted JD
    // resembles an existing role. This is a system-state notice, not a chat message,
    // so it must NOT appear in the chat timeline.
    //
    // LAYOUT NOTE: During intake mode the intake-panel sits on top of #col-overview-cards
    // as a position:absolute overlay with z-index:20 and an opaque background.
    // If we append to col-overview-cards without dismissing the intake panel, the notice
    // renders behind the overlay and is invisible — silently blocking the user.
    // Fix: dismiss the intake panel before rendering, same pattern as _wsRunAnalysis.
    //
    // "Open existing role"  — navigates to the matching role's workspace via selectRole().
    // "Analyse anyway"      — dismisses the notice and proceeds with _wsRunAnalysis normally.
    function _wsRenderFingerprintNotice(match, matchScore, currentRole, text, timelineEl) {

      // ── Guard: prevent multiple duplicate notices from stacking ─────────────
      // If a notice already exists in the DOM, do not render another one.
      const _existingNotice = document.querySelector('#col-overview-body .ws-fp-notice-overlay');
      if (_existingNotice) {
        console.warn('[fingerprint] notice already visible — suppressing duplicate render');
        return;
      }

      // Enter the duplicate_detected workspace state. This flag prevents the
      // fingerprint check from even running while a notice is awaiting user action.
      _wsDuplicateDetected = true;

      // ── Role preview details ─────────────────────────────────────────────────
      const _title   = match.role_title   || 'Untitled role';
      const _company = match.company_name || '';
      const _stage   = currentStageLabel(match);

      // Relative time from the role's last analysis or creation date
      const _dateRaw = match.latest_match_at || match.created_at;
      let _when = '';
      if (_dateRaw) {
        const _days = Math.round((Date.now() - new Date(_dateRaw).getTime()) / 86400000);
        if (_days === 0)       _when = 'Analysed today';
        else if (_days === 1)  _when = 'Analysed yesterday';
        else if (_days < 14)   _when = `Analysed ${_days} days ago`;
        else                   _when = `Analysed ${Math.round(_days / 7)} weeks ago`;
      }

      // ── Match basis transparency ─────────────────────────────────────────────
      // The notice only fires when score >= 3, so company + title always matched.
      const _basis = 'Matched on company name and role title';

      // ── Outcome label ────────────────────────────────────────────────────────
      const _outcomeDisp = {
        rejected:       'Rejected',
        skipped:        'Skipped',
        withdrew:       'Withdrew',
        offer_accepted: 'Offer accepted',
        offer_received: 'Offer received',
        no_response:    'No response',
        ghosted:        'Ghosted',
        closed:         'Closed',
      };
      const _outcomeLabel = match.outcome_state
        ? (_outcomeDisp[match.outcome_state] || match.outcome_state)
        : '';

      // ── Build the preview block ──────────────────────────────────────────────
      const _detailParts = [_when, _stage, _outcomeLabel].filter(Boolean);
      const _detailLine  = _detailParts.length
        ? `<div class="ws-fp-preview-detail">${esc(_detailParts.join(' \u00B7 '))}</div>`
        : '';

      // ── Dismiss the intake panel so the overview area becomes visible ─────────
      // During Add JD flow the intake-panel is a full opaque overlay (z-index 20)
      // covering #col-overview-cards. Without this step the notice renders invisibly
      // behind it, silently blocking the user with no visible UI.
      const _intakeEl = document.getElementById('intake-panel');
      const _wasIntakeVisible = _intakeEl && !_intakeEl.hasAttribute('hidden');
      if (_wasIntakeVisible) {
        _intakeEl._clearTimers?.();
        delete _intakeEl.dataset.cleanupPending;
        // Fade out the intake overlay so the overview panel behind it becomes visible.
        // Keep intake-mode on the app so the grid stays in overview-only layout (no chat).
        _intakeEl.classList.add('intake-panel--exit');
        setTimeout(() => {
          _intakeEl.setAttribute('hidden', '');
          _intakeEl.classList.remove('intake-panel--exit');
        }, 280);
      }

      // ── Take over the entire middle panel ──────────────────────────────────
      // Target #col-overview-body — the full scroll container that holds the
      // sticky header, rail, overview cards, and chips. Hiding all its children
      // and inserting the notice ensures nothing else shows through.
      // Both action paths (selectRole / _wsRunAnalysis) fully re-render the
      // overview body, so saved-content restoration is not needed.
      const bodyEl = document.getElementById('col-overview-body');

      // ── Safety fallback: if the mount target is missing, do not silently block ──
      if (!bodyEl) {
        console.warn('[fingerprint] #col-overview-body not found — falling through to analysis');
        _wsDuplicateDetected = false;   // reset — notice was never shown
        currentRole._retryText = text;
        _wsRunAnalysis(currentRole, text, timelineEl);
        return;
      }

      // Hide every existing child (sticky header, rail, cards, chips) so the
      // notice occupies the panel alone. Use visibility/display hiding so the
      // DOM stays intact for downstream re-renders.
      const _hiddenChildren = [];
      for (const child of bodyEl.children) {
        _hiddenChildren.push({ el: child, prevDisplay: child.style.display });
        child.style.display = 'none';
      }

      const notice = document.createElement('div');
      notice.className = 'ws-fp-notice-overlay';
      notice.innerHTML =
        `<div class="ws-fp-notice-card">` +
          // Icon — small document-check symbol
          `<div class="ws-fp-notice-icon">` +
            `<svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">` +
              `<path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8Z"/>` +
              `<polyline points="14 2 14 8 20 8"/>` +
              `<path d="m9 15 2 2 4-4"/>` +
            `</svg>` +
          `</div>` +
          // Title
          `<div class="ws-fp-notice-title">Role already analysed</div>` +
          // Body
          `<div class="ws-fp-notice-body">This job description matches a role you\u2019ve already analysed.</div>` +
          // Role preview
          `<div class="ws-fp-preview">` +
            `<div class="ws-fp-preview-label">Existing role</div>` +
            `<div class="ws-fp-preview-title">${esc(_title)}</div>` +
            `${_company ? `<div class="ws-fp-preview-company">${esc(_company)}</div>` : ''}` +
            `${_detailLine}` +
          `</div>` +
          // Match basis
          `<div class="ws-fp-notice-basis">${esc(_basis)}</div>` +
          // Actions
          `<div class="ws-fp-notice-actions">` +
            `<button class="ws-fp-btn-primary">Open existing role</button>` +
            `<button class="ws-fp-btn-ghost">Analyse anyway</button>` +
          `</div>` +
        `</div>`;

      bodyEl.appendChild(notice);

      // ── Cleanup helpers ────────────────────────────────────────────────────
      // _dismissAndRestore: remove notice AND restore hidden children (for
      // "Open existing role" where selectRole immediately re-renders everything).
      function _dismissAndRestore() {
        notice.remove();
        for (const { el, prevDisplay } of _hiddenChildren) {
          el.style.display = prevDisplay;
        }
      }

      // _dismissOnly: remove the notice but leave children hidden (for
      // "Analyse anyway" where we show a processing state until _wsRunAnalysis
      // fully re-renders the overview body).
      function _dismissOnly() {
        notice.remove();
      }

      notice.querySelector('.ws-fp-btn-primary').addEventListener('click', () => {
        _wsDuplicateDetected = false;   // exit duplicate_detected state
        _dismissAndRestore();
        selectRole(match.id);
      });

      notice.querySelector('.ws-fp-btn-ghost').addEventListener('click', () => {
        _wsDuplicateDetected = false;   // exit duplicate_detected state
        // Remove the notice but do NOT restore hidden scaffold children — they
        // would flash as a blank/empty scaffold before _wsRunAnalysis replaces
        // them. Instead, show a centred "Analysing…" processing state that
        // occupies the panel until analysis output re-renders it.
        _dismissOnly();

        // Lock the chat input and role list during analysis to prevent
        // conflicting interactions while "Analyse anyway" is processing.
        const _chatSend = document.getElementById('ws-chat-send');
        const _chatBar  = document.getElementById('ws-chat-bar');
        const _colList  = document.querySelector('.col-list');
        if (_chatSend) _chatSend.setAttribute('disabled', '');
        if (_chatBar)  _chatBar.classList.add('ws-chat-bar--processing');
        if (_colList)  _colList.classList.add('col-list--locked');

        const _processingEl = document.createElement('div');
        _processingEl.className = 'ws-fp-notice-overlay ws-fp-processing';
        _processingEl.innerHTML =
          `<div class="ws-fp-notice-card">` +
            `<div class="ws-fp-processing-spinner"></div>` +
            `<div class="ws-fp-notice-title">Analysing role\u2026</div>` +
            `<div class="ws-fp-notice-body">This may take a moment.</div>` +
          `</div>`;
        bodyEl.appendChild(_processingEl);

        // Restore cleanupPending so _wsRunAnalysis's intake teardown fires normally
        // (removes intake-mode, reveals col-chat). The intake panel is already hidden
        // but the grid is still in intake layout.
        const _iEl = document.getElementById('intake-panel');
        if (_iEl) _iEl.dataset.cleanupPending = '1';
        currentRole._retryText = text;
        _wsRunAnalysis(currentRole, text, timelineEl);
      });
    }

    // ─── Web enrichment helpers ────────────────────────────────────────────────
    // Source registry: recognisable job-board / ATS domains.
    // canEnrich: true  → enrichment service can fetch this source (must match enrich-role edge fn)
    // canEnrich: false → recognisable for badge display, but not currently supported for enrichment
    const WS_URL_SOURCES = {
      'boards.greenhouse.io': { name: 'Greenhouse', canEnrich: true  },
      'jobs.lever.co':        { name: 'Lever',       canEnrich: true  },
      'jobs.ashbyhq.com':     { name: 'Ashby',       canEnrich: true  },
      'linkedin.com':         { name: 'LinkedIn',    canEnrich: false },
      'www.linkedin.com':     { name: 'LinkedIn',    canEnrich: false },
    };

    // Returns { name, canEnrich } for any recognisable source URL, otherwise null.
    function _wsDetectUrlSource(url) {
      try {
        const { hostname } = new URL(url);
        for (const [domain, info] of Object.entries(WS_URL_SOURCES)) {
          if (hostname === domain || hostname.endsWith('.' + domain)) return info;
        }
        return null;
      } catch { return null; }
    }

    // Returns source name (e.g. "Greenhouse") for URLs the enrichment service can fetch.
    // Returns null for unsupported or unrecognised sources.
    function _wsDetectEnrichSource(url) {
      const src = _wsDetectUrlSource(url);
      return (src?.canEnrich) ? src.name : null;
    }

    // Render the enrichment confirmation card.
    // Fields are displayed but NOT merged until the user clicks "Apply to role".
    // Only null role fields can be merged — existing values are never overwritten.
    function _wsRenderEnrichmentCard(role, enrichmentId, sourceName, extracted, fieldsFound, timelineEl) {
      const FIELD_MAP = [
        { key: 'role_title',      label: 'Job title',       roleField: 'role_title'      },
        { key: 'company_name',    label: 'Company',         roleField: 'company_name'    },
        { key: 'location',        label: 'Location',        roleField: 'location_text'   },
        { key: 'work_model',      label: 'Work model',      roleField: 'work_model'      },
        { key: 'salary',          label: 'Salary',          roleField: 'salary_text_raw' },
        { key: 'employment_type', label: 'Employment type', roleField: 'engagement_type' },
        { key: 'day_rate',        label: 'Day rate',        roleField: 'day_rate_text'   },
      ];

      // Only show fields that were extracted
      const rows = FIELD_MAP
        .filter(f => fieldsFound.includes(f.key) && extracted[f.key])
        .map(f => ({ ...f, value: extracted[f.key], isNew: !role[f.roleField] }));

      if (rows.length === 0) return;
      const hasNewFields = rows.some(r => r.isNew);

      const rowsHtml = rows.map(r =>
        `<tr class="ws-enrich-row${r.isNew ? '' : ' ws-enrich-row--exists'}">` +
          `<td class="ws-enrich-label">${esc(r.label)}</td>` +
          `<td class="ws-enrich-value">${esc(r.value)}</td>` +
          (r.isNew
            ? `<td class="ws-enrich-badge ws-enrich-badge--new">New</td>`
            : `<td class="ws-enrich-badge ws-enrich-badge--exists">Already set</td>`) +
        `</tr>`
      ).join('');

      const card = document.createElement('div');
      card.className = 'ws-enrich-card';
      card.dataset.wsEntry = WS_ENTRY.UI_TEMP;
      if (enrichmentId) card.dataset.enrichmentId = enrichmentId;

      // Logo: prefer company logo if explicitly provided, fall back to source logo.
      // Never guessed — only rendered when the enrichment pipeline returns a URL.
      const _logoUrl  = extracted?.company_logo_url || extracted?.source_logo_url || null;
      const _logoHtml = _logoUrl
        ? `<img class="ws-enrich-logo" src="${esc(_logoUrl)}" alt="" loading="lazy" onerror="this.remove()">`
        : '';

      card.innerHTML =
        `<div class="ws-enrich-header">` +
          _logoHtml +
          `<span class="ws-enrich-source">${esc(sourceName || 'Job page')}</span>` +
          `<span class="ws-enrich-title">Details found</span>` +
        `</div>` +
        `<table class="ws-enrich-table">${rowsHtml}</table>` +
        (hasNewFields
          ? `<div class="ws-enrich-note">Only empty fields will be updated.</div>`
          : `<div class="ws-enrich-note">All fields are already set — nothing to apply.</div>`) +
        `<div class="ws-enrich-actions">` +
          (hasNewFields
            ? `<button class="ws-mismatch-btn-primary ws-enrich-btn-apply">Apply to role</button>`
            : '') +
          `<button class="ws-mismatch-btn-ghost ws-enrich-btn-dismiss">Dismiss</button>` +
        `</div>`;

      timelineEl.appendChild(card);
      _wsScrollIfNear(timelineEl);

      card.querySelector('.ws-enrich-btn-dismiss')?.addEventListener('click', () => card.remove());

      card.querySelector('.ws-enrich-btn-apply')?.addEventListener('click', async () => {
        const applyBtn = card.querySelector('.ws-enrich-btn-apply');
        if (applyBtn) { applyBtn.disabled = true; applyBtn.textContent = 'Applying…'; }

        // Build update object from new-only fields
        const updates      = {};
        const mergeFields  = [];
        for (const r of rows) {
          if (r.isNew && r.value) {
            updates[r.roleField] = r.value;
            mergeFields.push(r.key);
          }
        }

        if (Object.keys(updates).length === 0) { card.remove(); return; }

        try {
          await db.from('roles').update(updates).eq('id', role.id);
          Object.assign(role, updates); // patch local object so briefing reflects merge

          // Mark enrichment row as merged (best-effort, non-blocking)
          if (enrichmentId) {
            db.from('role_enrichments').update({
              merged:       true,
              merge_fields: mergeFields,
              merged_at:    new Date().toISOString(),
            }).eq('id', enrichmentId).catch(() => {});
          }

          card.innerHTML =
            `<div class="ws-enrich-applied">` +
              `✓ ${mergeFields.length} field${mergeFields.length !== 1 ? 's' : ''} applied to role.` +
            `</div>`;
          setTimeout(() => { if (card.isConnected) card.classList.add('ws-enrich-faded'); }, 3000);
          setTimeout(() => { if (card.isConnected) card.remove(); }, 4000);
        } catch (_err) {
          if (applyBtn) { applyBtn.disabled = false; applyBtn.textContent = 'Apply to role'; }
          const errEl = _wsStatusLine(timelineEl, 'Couldn\'t apply fields. Try again.');
          errEl.classList.add('ws-status-error');
          setTimeout(() => { if (errEl.isConnected) errEl.remove(); }, 5000);
        }
      });
    }

    // Orchestrate a workspace stage signal: log interaction, render event, maybe advance stage.
    async function _wsHandleStageSignal(role, text, signal, timelineEl) {
      // Simple in-session de-dupe: skip if the exact same signal type fired within 5s
      // (prevents double-log from rapid identical pastes).
      if (!role._lastSignalTime) role._lastSignalTime = {};
      const _sigKey = signal.type + ':' + (signal.stage || '');
      const _now    = Date.now();
      if (role._lastSignalTime[_sigKey] && _now - role._lastSignalTime[_sigKey] < 5000) return;
      role._lastSignalTime[_sigKey] = _now;

      // 1. Persist interaction to role_interactions
      wsAddInteraction(role.id, {
        interaction_type: signal.type,
        summary:          signal.summary,
        raw_content:      text.slice(0, 300),
      }).catch(() => {});

      // 2. Render a compact interaction event in the timeline
      _wsAppend(timelineEl, _wsInteractionEventHtml(signal.summary, signal.type));

      // 3. For high confidence with a specific stage: advance stage if it's ahead of current
      if (signal.confidence === 'high' && signal.stage) {
        try { await _wsAdvanceStage(role, signal.stage, timelineEl); } catch (_) {}
      }
    }

    // Wire source-card expand/collapse toggles
    function _wsWireSourceCards(container) {
      container.querySelectorAll('.ws-source-card-toggle').forEach(btn => {
        if (btn.dataset.wired) return;
        btn.dataset.wired = '1';
        btn.addEventListener('click', () => {
          const targetId = btn.dataset.target;
          const fullEl   = document.getElementById(targetId);
          if (!fullEl) return;
          const isOpen = !fullEl.classList.contains('hidden');
          fullEl.classList.toggle('hidden', isOpen);
          btn.textContent      = isOpen ? 'Show' : 'Hide';
          btn.setAttribute('aria-expanded', String(!isOpen));
        });
      });
    }

    // ── Cover Letter prompt builder ───────────────────────────────────────────
    // Builds a grounded prompt using structured analysis data so the chat brain
    // can produce a cover letter that references the actual role, not boilerplate.
    function _buildCoverLetterPrompt(role) {
      const fo      = role.analysis?.full_output || role.latest_match_output || {};
      const pd      = fo.practical_details || {};
      const company = role.company_name || 'this company';
      const title   = role.role_title   || 'this role';
      const _extract = arr => (Array.isArray(arr) ? arr : [])
        .map(r => typeof r === 'object' ? (r.text || '') : String(r)).filter(Boolean);

      const parts = ['Write a tailored cover letter for the role of ' + title + ' at ' + company + '.'];

      // What they are actually looking for — the real criteria
      const wtrlf = _extract(fo.what_they_are_really_looking_for);
      if (wtrlf.length) {
        parts.push('The role specifically looks for: ' + wtrlf.slice(0, 3).join('; ') + '.');
      }

      // Core responsibilities — what the person will actually do
      const wtado = _extract(fo.what_you_would_actually_do);
      if (wtado.length) {
        parts.push('The day-to-day centres on: ' + wtado.slice(0, 2).join('; ') + '.');
      }

      // Role archetype — frame the letter around the right positioning
      const arch = fo.role_archetype?.primary;
      if (arch) parts.push('The role archetype is: ' + arch + '.');

      // Company type / seniority — tone calibration
      if (pd.company_type) parts.push('Company type: ' + pd.company_type + '.');
      if (pd.seniority_level) parts.push('Seniority level: ' + pd.seniority_level + '.');

      // Fit reality — what the analysis says about alignment
      const reality = _extract(fo.fit_reality_summary);
      if (reality.length) {
        parts.push('Fit analysis notes: ' + reality.slice(0, 2).join('; ') + '.');
      }

      // User background — if available in profile prefs, reference it
      const _rpn = userProfile?.role_preference_note;
      if (_rpn && _rpn.trim().length > 10) {
        parts.push('The user describes their preferences and background as: "' + _rpn.trim().slice(0, 300) + '".');
      }

      parts.push('Use these specifics to write 3–4 short paragraphs. Be direct, specific, and grounded in the role details — not generic. Avoid flattery and clichés. If user background context is provided, weave it naturally into the letter.');

      return parts.join(' ');
    }

    // ── CV Alignment prompt builder ──────────────────────────────────────────
    // Builds a grounded prompt so the chat brain can suggest CV tweaks that
    // reference the actual criteria, responsibilities, and risks from the JD.
    function _buildCvAlignmentPrompt(role) {
      const fo      = role.analysis?.full_output || role.latest_match_output || {};
      const pd      = fo.practical_details || {};
      const company = role.company_name || 'this company';
      const title   = role.role_title   || 'this role';
      const _extract = arr => (Array.isArray(arr) ? arr : [])
        .map(r => typeof r === 'object' ? (r.text || '') : String(r)).filter(Boolean);

      const parts = ['Suggest specific, targeted tweaks to my CV for the role of ' + title + ' at ' + company + '.'];

      // What they really want — align CV language to these criteria
      const wtrlf = _extract(fo.what_they_are_really_looking_for);
      if (wtrlf.length) {
        parts.push('They are specifically looking for: ' + wtrlf.slice(0, 4).join('; ') + '.');
      }

      // What the person will actually do — CV should mirror these
      const wtado = _extract(fo.what_you_would_actually_do);
      if (wtado.length) {
        parts.push('Core responsibilities include: ' + wtado.slice(0, 3).join('; ') + '.');
      }

      // Role archetype and seniority — framing
      const arch = fo.role_archetype?.primary;
      if (arch) parts.push('The role archetype is: ' + arch + '.');
      if (pd.seniority_level) parts.push('Seniority level: ' + pd.seniority_level + '.');

      // Risks — these are potential gaps to address in the CV
      const risks = _extract(fo.risks_and_unknowns);
      if (risks.length) {
        parts.push('Identified risks/gaps: ' + risks.slice(0, 2).join('; ') + '.');
      }

      // Hard constraints — critical flags to factor in
      const hc = Array.isArray(fo.hard_constraints) ? fo.hard_constraints : [];
      if (hc.length) {
        parts.push('Hard constraints detected: ' + hc.map(h => h.label).join(', ') + '.');
      }

      // User background — helps target advice to what the user actually has on their CV
      const _rpn = userProfile?.role_preference_note;
      if (_rpn && _rpn.trim().length > 10) {
        parts.push('The user describes their background as: "' + _rpn.trim().slice(0, 300) + '".');
      }

      parts.push('Focus on language, emphasis, and what to highlight, reorder, or de-emphasise. Reference specific criteria from the analysis — not generic advice. If user background or CV context is available, tailor suggestions to their actual experience.');

      return parts.join(' ');
    }

    // ── Role Action Card delegation ───────────────────────────────────────────
    // Wire once at app init on the stable #col-overview-cards container.
    // The container's innerHTML changes per role, but the delegation listener
    // survives. Uses module-level selectedRoleId + allRoles at click time so
    // it always dispatches to the current role without re-wiring.
    function _wsInitActionCardDelegation() {
      const _ovCards = document.getElementById('col-overview-cards');
      if (!_ovCards) return;
      if (_ovCards.dataset.actionDelegationWired) return;
      _ovCards.dataset.actionDelegationWired = '1';

      _ovCards.addEventListener('click', async e => {
        const btn = e.target.closest('[data-ws-action]');
        if (!btn) return;

        const action = btn.dataset.wsAction;

        // ── Guard 1: role context must be present ────────────────────────────
        // selectedRoleId and the matching role in allRoles must both exist.
        // If either is missing (no role selected, or role archived/removed),
        // do nothing and log a clear warning rather than throwing.
        if (!selectedRoleId) {
          console.warn('[Rolewise] action ignored — no role selected');
          return;
        }
        const role = allRoles.find(r => r.id === selectedRoleId);
        if (!role) {
          console.warn('[Rolewise] action ignored — role not found (may have been archived)', { selectedRoleId });
          return;
        }

        const timelineEl = document.getElementById('ws-timeline');
        if (!timelineEl) return;

        // ── Guard 3: loading state lifecycle ────────────────────────────────
        // Applied immediately; cleared in finally so it always resets even
        // on error. Checks isConnected so a removed button doesn't throw.
        if (btn.classList.contains('rw-action-btn--loading')) return; // already in flight
        btn.classList.add('rw-action-btn--loading');
        const resetBtn = () => {
          if (btn.isConnected) btn.classList.remove('rw-action-btn--loading');
        };

        // ── Guard 4: ensure chat panel is open for chat actions ──────────────
        // cover-letter and cv-tweaks write to the chat timeline.
        // Ensure col-chat has ws-active so the timeline layout is correct,
        // then scroll the chat into view after the action completes.
        const _ensureChatOpen = () => {
          const _chatEl = document.getElementById('col-chat');
          if (_chatEl && !_chatEl.classList.contains('ws-active')) {
            _chatEl.classList.add('ws-active');
          }
        };
        const _scrollChatToBottom = () => {
          // ws-timeline is the scroll container; col-chat has overflow:hidden
          const _tlEl = document.getElementById('ws-timeline');
          if (_tlEl) _tlEl.scrollTop = _tlEl.scrollHeight;
        };

        try {
          if (action === 'prep') {
            await _wsTriggerPrep(role, timelineEl);
          } else if (action === 'cover-letter') {
            _ensureChatOpen();
            const _prompt = _buildCoverLetterPrompt(role);
            await _wsTriggerChat(role, _prompt, timelineEl);
            _scrollChatToBottom();
          } else if (action === 'cv-tweaks') {
            _ensureChatOpen();
            const _prompt = _buildCvAlignmentPrompt(role);
            await _wsTriggerChat(role, _prompt, timelineEl);
            _scrollChatToBottom();
          }
        } finally {
          resetBtn();
        }
      });
    }

    // ── Recruiter linking from email extraction ──────────────────────────────
    // Finds or creates a recruiter record and links it to the role.
    // De-duplication: checks existing role_recruiters for same email before writing.
    // Returns { linked: bool, name?: string, reason?: string }.
    async function _wsLinkRecruiterFromEmail(role, extracted) {
      if (!role.id || role._isTemp) return { linked: false, reason: 'temp' };
      if (!extracted || (!extracted.name && !extracted.email)) return { linked: false, reason: 'no_signal' };

      // De-dupe: check if the same recruiter email is already linked to this role
      if (extracted.email) {
        try {
          const { data: existingLinks } = await db.from('role_recruiters')
            .select('id, recruiters!inner(email)')
            .eq('role_id', role.id);
          if (existingLinks?.some(l => l.recruiters?.email?.toLowerCase() === extracted.email.toLowerCase())) {
            return { linked: false, reason: 'already_linked' };
          }
        } catch (_) {}
      }

      // Find existing recruiter record (email → name, in priority order)
      let recruiterId = null;
      if (extracted.email) {
        const { data: byEmail } = await db.from('recruiters').select('id')
          .ilike('email', extracted.email).limit(1);
        if (byEmail?.length) recruiterId = byEmail[0].id;
      }
      if (!recruiterId && extracted.name) {
        const { data: byName } = await db.from('recruiters').select('id')
          .ilike('name', extracted.name).limit(1);
        if (byName?.length) recruiterId = byName[0].id;
      }

      // Create new recruiter record if no existing match
      if (!recruiterId) {
        const { data: newRec, error: re } = await db.from('recruiters').insert({
          name:    extracted.name    || null,
          email:   extracted.email   || null,
          company: extracted.company || null,
        }).select('id').single();
        if (re || !newRec) return { linked: false, reason: 'create_failed' };
        recruiterId = newRec.id;
      }

      // Link role → recruiter
      const { error: linkErr } = await db.from('role_recruiters').insert({
        role_id:      role.id,
        recruiter_id: recruiterId,
        link_source:  'email',
      });
      if (linkErr) return { linked: false, reason: 'link_failed' };

      // Update allRoles in-memory cache so memory summary reflects it without a full reload
      const _recEntry = {
        recruiter_id: recruiterId,
        link_source:  'email',
        created_at:   new Date().toISOString(),
        recruiters:   { id: recruiterId, name: extracted.name || null, email: extracted.email || null, company: extracted.company || null },
      };
      allRoles = allRoles.map(r => {
        if (r.id !== role.id) return r;
        return { ...r, role_recruiters: [...(r.role_recruiters || []), _recEntry] };
      });
      if (!role.role_recruiters) role.role_recruiters = [];
      role.role_recruiters.push(_recEntry);

      insertEvent(role.id, {
        event_type: 'recruiter_linked',
        title:      `Recruiter linked from email${extracted.name ? ' — ' + extracted.name : ''}`,
      });

      return { linked: true, name: extracted.name };
    }

    // ── Workspace email handler ────────────────────────────────────────────────
    // Called when the user pastes content classified as 'email' type.
    // Source card rendering + wsAddMessage already done by _wsHandlePaste before this.
    // Responsibilities: log interaction, extract recruiter, show status / confirmation.
    async function _wsHandleEmail(role, text, timelineEl) {
      // Log a recruiter_email interaction for saved roles only
      if (!role._isTemp) {
        wsAddInteraction(role.id, {
          interaction_type: 'recruiter_email',
          summary:          'Recruiter email received',
          raw_content:      text.slice(0, 500),
        }).catch(() => {});
      }

      // Extract recruiter signals from the email content
      const extracted = extractRecruiterFromEmail(text);

      // ── No useful signal ─────────────────────────────────────────────────────
      if (!extracted || (!extracted.name && !extracted.email)) {
        const st = _wsStatusLine(timelineEl, 'Recruiter email captured.');
        setTimeout(() => { if (st.isConnected) st.classList.add('ws-status-faded'); }, 5000);
        if (!role._isTemp) _wsRefreshMemorySummary(role.id);
        return;
      }

      // ── Temp role — defer recruiter link until promotion ─────────────────────
      if (role._isTemp) {
        role._pendingRecruiter = extracted;
        const who = extracted.name || extracted.email;
        const st = _wsStatusLine(timelineEl, `Recruiter email noted${who ? ' — ' + who : ''}.`);
        setTimeout(() => { if (st.isConnected) st.classList.add('ws-status-faded'); }, 5000);
        return;
      }

      // ── High confidence — link silently ─────────────────────────────────────
      if (extracted.confidence === 'high') {
        try {
          const result = await _wsLinkRecruiterFromEmail(role, extracted);
          let msg;
          if (result.linked) {
            msg = `Recruiter email captured — linked to ${extracted.name || extracted.email}.`;
            // Refresh recruiter meta in doc header and inbox card immediately
            _refreshDocRecruiterMeta(role);
            renderInbox(allRoles);
          } else if (result.reason === 'already_linked') {
            msg = 'Recruiter email captured.';
          } else {
            msg = 'Recruiter email captured.';
          }
          const st = _wsStatusLine(timelineEl, msg);
          setTimeout(() => { if (st.isConnected) st.classList.add('ws-status-faded'); }, 5000);
        } catch (_) {
          const st = _wsStatusLine(timelineEl, 'Recruiter email captured.');
          setTimeout(() => { if (st.isConnected) st.classList.add('ws-status-faded'); }, 5000);
        }
        _wsRefreshMemorySummary(role.id);
        return;
      }

      // ── Medium confidence — show one binary confirmation question ────────────
      _wsAppend(timelineEl, _wsRecruiterConfirmHtml(extracted.name, extracted.company));
      const confirmEl = timelineEl.lastElementChild;

      confirmEl.querySelector('.ws-confirm-yes')?.addEventListener('click', async () => {
        confirmEl.remove();
        try {
          const result = await _wsLinkRecruiterFromEmail(role, extracted);
          const msg = result.linked ? `Linked to ${extracted.name}.` : 'Recruiter email captured.';
          const st = _wsStatusLine(timelineEl, msg);
          setTimeout(() => { if (st.isConnected) st.classList.add('ws-status-faded'); }, 4000);
          // Refresh recruiter meta in doc header and inbox card immediately
          if (result.linked) {
            _refreshDocRecruiterMeta(role);
            renderInbox(allRoles);
          }
        } catch (_) {}
        _wsRefreshMemorySummary(role.id);
      });

      confirmEl.querySelector('.ws-confirm-no')?.addEventListener('click', () => {
        confirmEl.remove();
      });
    }

    // ── Central timeline entry renderer ───────────────────────────────────────
    // Canonical render function for all persisted timeline entries.
    // Used by both history restoration (renderWorkspaceView) and any future
    // replay/refresh path. Does NOT handle ui_temp entries — those are managed
    // by their owning async operations and are never persisted or replayed.
    //
    // item shape (normalised from the merged timeline sort):
    //   { type: 'msg'|'artifact'|'interaction'|'stage_advance', data: <row> }
    function _wsRenderTimelineEntry(item, timelineEl, updateOverview = true, role = null) {
      if (item.type === 'msg') {
        const msg = item.data;
        if (msg.sender === 'user') {
          const ct = _wsContentType(msg.message);
          if (ct === 'jd') {
            // JD → overview card during history restore
            if (role) _renderJDSection(role, msg.message);
          } else if (ct === 'url') {
            // URL → overview block only; suppress from chat timeline
          } else if (ct !== 'chat') {
            // Email and other types → source card in chat timeline
            timelineEl.insertAdjacentHTML('beforeend', _wsSourceCardHtml(msg.message, ct, null));
          } else {
            timelineEl.insertAdjacentHTML('beforeend',
              `<div class="ws-chat-bubble ws-chat-bubble--user" data-ws-entry="${WS_ENTRY.CHAT_USER}">${esc(msg.message)}</div>`);
          }
        } else {
          // Try to re-hydrate structured briefing cards stored as JSON envelopes.
          // Fall back to plain-text rendering for any message that isn't JSON or
          // doesn't carry the _type:'briefing' marker.
          let _rendered = false;
          try {
            const _parsed = JSON.parse(msg.message);
            if (_parsed._type === 'briefing' && Array.isArray(_parsed.sections)) {
              const _sectionsHtml = _parsed.sections.map(s =>
                `<div class="ws-briefing-section">` +
                  `<div class="ws-briefing-label">${esc(s.label || '')}</div>` +
                  `<div class="ws-briefing-text">${esc(s.text || '')}</div>` +
                `</div>`
              ).join('');
              timelineEl.insertAdjacentHTML('beforeend',
                `<div class="ws-assistant-reply ws-briefing-block" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">` +
                  `<div class="ws-briefing-title">${esc(_parsed.title || '')}</div>` +
                  _sectionsHtml +
                `</div>`);
              _rendered = true;
            }
          } catch (_) {}
          if (!_rendered) {
            // Apply the same safe markdown rendering as the live _wsStreamText final pass.
            // esc() escapes HTML special chars first; markdown patterns are then applied to
            // the escaped string so the injected <strong> / <br> tags cannot be spoofed by
            // content in the message itself. Mirrors _wsStreamText's post-stream innerHTML pass.
            const _safeHtml = esc(msg.message)
              .replace(/\*\*([^*\n]+)\*\*/g, '<strong>$1</strong>')
              .replace(/\n\n/g, '<br><br>')
              .replace(/\n/g, '<br>');
            timelineEl.insertAdjacentHTML('beforeend',
              `<div class="ws-assistant-reply" data-ws-entry="${WS_ENTRY.CHAT_ASSISTANT}">${_safeHtml}</div>`);
          }
        }
      } else if (item.type === 'artifact') {
        try {
          const parsed = JSON.parse(item.data.content || '{}');
          const artType = item.data.artifact_type;
          if (artType === 'analysis') {
            // Analysis cards render in the overview panel, not the chat timeline.
            if (updateOverview) {
              const _histOvCards = document.getElementById('col-overview-cards');
              if (_histOvCards) {
                _histOvCards.innerHTML = `<div class="rw-overview-wrap">${renderMatchOutput(parsed)}</div>`;
                _initCompSnapshot(_histOvCards);
                _fillFitAssessmentCV();
                _renderRoleHeader(role);
                // Re-render lower overview cards — the wrap was just replaced, so
                // any previously created slots were destroyed. Re-create and populate.
                _renderDecisionCapture(role);
                _renderBlockersSection(role).catch(() => {});    // Decision Layer V1
                _renderDecisionHistoryDL(role).catch(() => {});  // Decision Layer V1: history
                renderRail(role);
                if (role && role.job_description_raw) {
                  _renderJDSection(role, role.job_description_raw);
                }
              }
            }
            // No entry added to the chat timeline for analysis artifacts.
          } else if (artType === 'preparation') {
            // Preparation is a persistent workspace card — render in overview, not chat timeline.
            _wsInsertPrepToOverview(_wsPrepArtefactHtml(parsed, item.data.id));
          } else if (artType === 'thoughts') {
            timelineEl.insertAdjacentHTML('beforeend', _wsThoughtsArtefactHtml(parsed, item.data.id));
          }
        } catch (_) {}
      } else if (item.type === 'interaction') {
        const summary = item.data.summary || item.data.interaction_type;
        timelineEl.insertAdjacentHTML('beforeend',
          _wsInteractionEventHtml(summary, item.data.interaction_type));
      } else if (item.type === 'stage_advance') {
        timelineEl.insertAdjacentHTML('beforeend',
          _wsStageEventHtml(item.data.stage_reached));
      }
    }

    // Main workspace renderer — blank state + chat input
    async function renderWorkspaceView(role, { skipOverview = false } = {}) {
      // If a real (saved) role is being opened while the intake panel is showing,
      // exit intake mode so col-chat is visible and the intake overlay is dismissed.
      if (!role._isTemp) _exitIntakeMode();

      const el = document.getElementById('col-chat');
      el.classList.add('ws-active');
      // Sticky header shows immediately (before async memory load)
      if (!role._isTemp) _renderStickyHeader(role);

      // Load any existing workspace data (on-demand, not from loadData).
      // Skip for temp roles — they have no DB record yet.
      let memory = null;
      let _wsDecisions = [];
      if (!role._isTemp) {
        try {
          [memory, _wsDecisions] = await Promise.all([
            wsLoadMemory(role.id),
            wsLoadDecisions(role.id).catch(() => []),
          ]);
        } catch (_) {}
      }

      const hasHistory = memory && (
        (memory.conversations?.length > 0) ||
        (memory.artifacts?.length    > 0) ||
        (memory.interactions?.length > 0)
      );

      // ── Diagnostic log — makes next .conversations failure immediately obvious ──
      console.log('[renderWorkspaceView] state', {
        roleId:    role.id,
        isTemp:    role._isTemp || false,
        memory:    memory ? 'loaded' : 'null',
        convLen:   memory?.conversations?.length ?? '—',
        artLen:    memory?.artifacts?.length     ?? '—',
        hasHistory: !!hasHistory,
      });

      // ── Derive header content from role state ────────────────────────────────
      const _wsHeaderCompany = role.company_name || (role._isTemp ? null : null);
      const _wsHeaderTitle   = role.role_title   || null;
      const _wsContextParts  = [];
      if (role.location_text)   _wsContextParts.push(role.location_text);
      if (role.current_stage && role.current_stage !== 'JD Review') _wsContextParts.push(role.current_stage);
      const _wsContextLine = _wsContextParts.join(' · ');

      // Build workspace scaffold
      el.innerHTML = `
        <div class="ws-workspace" id="ws-workspace">
          <div class="ws-workspace-header" id="ws-workspace-header">
            ${_wsHeaderCompany
              ? `<div class="ws-header-company">${esc(_wsHeaderCompany)}</div>
                 <div class="ws-header-title">${esc(_wsHeaderTitle || 'Untitled role')}</div>
                 ${_wsContextLine ? `<div class="ws-header-context">${esc(_wsContextLine)}</div>` : ''}`
              : `<div class="ws-header-company ws-header-company--new">New Role</div>
                 <div class="ws-header-title ws-header-title--hint">Paste a job description to begin</div>`
            }
          </div>
          <div class="ws-documents-section" id="ws-documents-section" hidden>
            <button class="ws-docs-toggle" id="ws-docs-toggle" aria-expanded="false">
              <span class="ws-docs-toggle-icon">📎</span>
              <span id="ws-docs-count-label">0 documents</span>
              <span class="ws-docs-chevron">›</span>
            </button>
            <div class="ws-docs-list" id="ws-docs-list" hidden></div>
          </div>
          <div class="ws-timeline" id="ws-timeline"><div class="ws-timeline-spacer"></div></div>
          <div id="ws-scroll-nudge" role="button" aria-label="Scroll to latest">↓ New response</div>
          <div class="ws-chat-bar" id="ws-chat-bar">
            <div class="ws-salary-hint" id="ws-salary-hint" hidden></div>
            <div class="ws-attachment-preview" id="ws-attachment-preview"></div>
            <div class="ws-chat-inner">
              <button class="ws-attach-btn" id="ws-attach-btn" type="button" aria-label="Attach file">+</button>
              <input type="file" class="ws-attach-file-input" id="ws-attach-input"
                accept=".pdf,.doc,.docx,.txt,.md,.png,.jpg,.jpeg,.csv"
                multiple>
              <textarea
                class="ws-chat-input"
                id="ws-chat-input"
                placeholder="Paste a job description here…"
                rows="1"
                autocomplete="off"
                spellcheck="false"
              ></textarea>
              <button class="ws-chat-send" id="ws-chat-send" disabled aria-label="Send">↑</button>
            </div>
          </div>
        </div>`;

      // ── Populate overview panel with analysis card grid ──────────────────────
      // The overview panel (col-overview-body) shows the role analysis card grid.
      // skipOverview = true for legacy roles (overview already populated separately).
      if (!skipOverview) {
        const _ovBody = document.getElementById('col-overview-cards');
        if (_ovBody) {
          const _analysisArt = memory?.artifacts?.find(a => a.artifact_type === 'analysis');
          if (_analysisArt?.content) {
            try {
              const _aJson = JSON.parse(_analysisArt.content);
              _ovBody.innerHTML = `<div class="rw-overview-wrap">${renderMatchOutput(_aJson)}</div>`;
              _initCompSnapshot(_ovBody);
              _renderRoleHeader(role);
            } catch (e) {
              _ovBody.innerHTML = '<div class="doc-empty">Could not load analysis</div>';
            }
          } else {
            _ovBody.innerHTML = '<div class="rw-overview-wrap"><div class="doc-empty" style="color:var(--text-light);font-size:13.5px;">Paste a job description to understand whether this role is worth pursuing.</div></div>';
            _renderRoleHeader(role);
          }
        }
      }

      // ── Decision Capture card — always shown when a role is loaded ────────────
      _renderDecisionCapture(role);
      _renderBlockersSection(role).catch(() => {});    // Decision Layer V1
      _renderDecisionHistoryDL(role).catch(() => {});  // Decision Layer V1: history

      // ── Rail + JD section — rendered here so the wrap + slots exist first ─────
      // renderRail is also called from selectRole, but that fires synchronously
      // before the async await in renderWorkspaceView resolves. By the time we
      // reach here the .rw-overview-wrap exists and _ensureOverviewLowerCards has
      // already injected the three slot divs (via _renderDecisionCapture above).
      if (!role._isTemp && !skipOverview) {
        renderRail(role);
        // Pre-populate JD card from role.job_description_raw so it shows immediately
        // even before history restore fires _wsRenderTimelineEntry for the JD message.
        if (role.job_description_raw) {
          _renderJDSection(role, role.job_description_raw);
        }
      }

      const timelineEl  = document.getElementById('ws-timeline');
      timelineEl.dataset.roleId = role.id; // guard for wsRefreshDecisionHistory
      const inputEl     = document.getElementById('ws-chat-input');
      const sendBtn     = document.getElementById('ws-chat-send');

      // ── Smart input awareness ─────────────────────────────────────────────────
      // Placeholder adapts to the current workspace context.
      // If the role has been analysed: fixed "Ask a question…" placeholder.
      // If a URL was saved but no JD yet: prompt for description.
      // Otherwise: rotate through onboarding prompts to show what's possible.
      // Self-clears when the textarea is removed (workspace re-renders).
      const _hasAnalysis = memory?.artifacts?.some(a => a.artifact_type === 'analysis');
      const _hasUrlNoJd  = role.job_url && !role.job_description_raw;

      if (_hasAnalysis) {
        inputEl.placeholder = 'Ask about salary, fit, or what to do next…';
      } else if (_hasUrlNoJd) {
        inputEl.placeholder = 'Paste the job description to begin analysis…';
      } else {
        // Rotate between onboarding hints for blank/unknown states
        const _wsPlaceholders = [
          'Paste a job description here…',
          'Paste a job link from LinkedIn or Greenhouse…',
          'Paste a recruiter email…',
          'Ask a question about this role…',
          'Add a note about this opportunity…',
        ];
        let _wsPhIdx = 0;
        const _wsPhInterval = setInterval(() => {
          if (!inputEl.isConnected) { clearInterval(_wsPhInterval); return; }
          if (document.activeElement === inputEl || inputEl.value) return;
          _wsPhIdx = (_wsPhIdx + 1) % _wsPlaceholders.length;
          inputEl.placeholder = _wsPlaceholders[_wsPhIdx];
        }, 4000);
      }
      // ─────────────────────────────────────────────────────────────────────────

      // ── Salary hint above composer ────────────────────────────────────────────
      // When a salary is known (from analysis or signals), show a quiet contextual
      // one-liner above the chat bar. Not a card, not a warning — just a hint.
      // Hidden on temp roles and when no salary is available.
      if (!role._isTemp) {
        const _hintEl = document.getElementById('ws-salary-hint');
        if (_hintEl) {
          // Prefer the briefing salary (already assembled above) but fall back to
          // parsing analysis output directly. We need the briefing here but it is
          // assembled inside _wsTriggerChat — so we derive salary from the same
          // sources _wsAssembleBriefing would use, keeping it lightweight.
          const _hintAnalysis = memory?.artifacts?.find(a => a.artifact_type === 'analysis');
          let _hintSalary = null;
          if (_hintAnalysis?.content) {
            try {
              const _hfo = JSON.parse(_hintAnalysis.content);
              _hintSalary = _hfo.practical_details?.salary_annual || null;
            } catch (_) {}
          }
          // Fall back to the raw salary field on the role row
          if (!_hintSalary || _hintSalary === 'Not stated') {
            _hintSalary = role.salary_text_raw || null;
          }

          if (_hintSalary && _hintSalary !== 'Not stated') {
            _hintEl.textContent = `Salary: ${_hintSalary} · ask about take-home, pension, or contract equivalent`;
            _hintEl.removeAttribute('hidden');
          }
        }
      }
      // ─────────────────────────────────────────────────────────────────────────

      if (!hasHistory) {
        // ── Blank state ───────────────────────────────────────────────────────
        // Shown for: new real roles with no history, temp (Add JD) roles, and
        // any role where memory failed to load (memory === null fallback).
        // Guard: was previously `!hasHistory && !role._isTemp`, which incorrectly
        // routed temp roles (memory=null) into the history restoration else-branch,
        // causing: TypeError: Cannot read properties of null (reading 'conversations').
        if (!role._isTemp) {
          // Spacer must always be first child for bottom-anchoring to work.
          timelineEl.innerHTML = `
            <div class="ws-timeline-spacer"></div>
            <div class="ws-blank-state">
              <div class="ws-blank-title">New Role</div>
              <div class="ws-blank-prompt">Paste the job description or link for the role.</div>
              <div class="ws-blank-hint">You can also paste recruiter emails, company links, or anything related to the opportunity.</div>
            </div>`;
        }
        // Temp roles: intake-mode is active (col-chat hidden); timeline left empty.
        if (role._isTemp && !memory) {
          console.log('[renderWorkspaceView] temp role — memory not loaded, timeline left empty');
        }
      } else {
        // ── Restore existing workspace history ───────────────────────────────
        // Four streams merged into a single chronological timeline:
        //   1. role_conversations  → source cards (url/email/jd) + chat bubbles
        //   2. role_artifacts      → analysis / preparation / thoughts artefacts
        //   3. role_interactions   → compact inline events (recruiter call, interview…)
        //      Note: 'recruiter_email' interactions are skipped — the source card from
        //      role_conversations already represents that paste; adding a second event
        //      line would be redundant noise.
        //   4. role_updates        → stage-advance dividers (stage event_type rows only)
        //      Covers both rail-stepper (markStage) and workspace-signal (_wsAdvanceStage)
        //      advances. The implied initial 'JD Review' stage (set on the roles row at
        //      creation) never produces a role_updates row, so no spurious first divider.
        // Guard: memory must be non-null here (hasHistory guarantees it), but add
        // a safety check to ensure no crash if memory is unexpectedly null.
        if (!memory) {
          console.warn('[renderWorkspaceView] hasHistory is true but memory is null — skipping history restore', {
            roleId: role.id, isTemp: role._isTemp,
          });
        } else {
          const timeline = [];

          for (const msg of (memory.conversations || [])) {
            timeline.push({ t: new Date(msg.created_at), type: 'msg', data: msg });
          }
          for (const art of (memory.artifacts || [])) {
            timeline.push({ t: new Date(art.created_at), type: 'artifact', data: art });
          }
          for (const inter of (memory.interactions || [])) {
            // Skip recruiter_email — source card from conversations already covers it
            if (inter.interaction_type === 'recruiter_email') continue;
            timeline.push({ t: new Date(inter.created_at), type: 'interaction', data: inter });
          }
          for (const upd of (role.role_updates || [])) {
            // Only stage-advance rows; skip outcome rows and rows without a stage name
            if (upd.event_type && upd.event_type !== 'stage') continue;
            if (!upd.stage_reached) continue;
            timeline.push({ t: new Date(upd.created_at), type: 'stage_advance', data: upd });
          }

          timeline.sort((a, b) => a.t - b.t);

          for (const item of timeline) {
            // updateOverview=false when skipOverview (legacy doc fills the overview panel)
            _wsRenderTimelineEntry(item, timelineEl, !skipOverview, role);
          }

          _wsWireSourceCards(timelineEl);
          // Defer scroll until after browser has laid out the new flex heights.
          // Without rAF the timeline's scrollHeight may still be 0 at this point.
          requestAnimationFrame(() => {
            timelineEl.scrollTop = timelineEl.scrollHeight;
          });
        }
      }

      // ── Decision history — prepended at top, above blank state or chat entries ──
      if (_wsDecisions.length > 0) {
        _wsRenderDecisionHistory(_wsDecisions, timelineEl);
      }

      // ── Your Lens — contextual preference panel (async, non-blocking) ────────
      // Loads pattern analysis across all decided roles. Only renders when ≥3 decided
      // roles exist. Reset per workspace open so fresh data is always attempted.
      _lensRendered = false;
      _wsLoadYourLens().then(lensData => {
        if (lensData) _wsRenderYourLens(lensData, timelineEl);
      }).catch(() => {}); // non-critical

      // ── Chat input wiring ────────────────────────────────────────────────
      let _wsSubmitting = false;
      const chatBarEl = document.getElementById('ws-chat-bar');

      // Soft lock helpers — dims the bar without fully disabling the textarea.
      // Uses a CSS class rather than the disabled attribute so the input stays
      // readable and copy-able. The send button is still disabled (can't double-send).
      const _wsLock = () => {
        _wsSubmitting = true;
        sendBtn.disabled = true;
        chatBarEl?.classList.add('ws-chat-bar--processing');
        if (!inputEl.value) inputEl.placeholder = 'Working on that…';
      };
      const _wsUnlock = () => {
        _wsSubmitting = false;
        sendBtn.disabled = !inputEl.value.trim();
        chatBarEl?.classList.remove('ws-chat-bar--processing');
        // Restore smart placeholder after unlock
        if (!inputEl.value) {
          const _hasAnalysis = !!document.querySelector('.ws-artifact[data-artifact-type="analysis"]') ||
                               !!timelineEl.querySelector('.ws-artifact');
          inputEl.placeholder = _hasAnalysis
            ? 'Ask a question about this role…'
            : 'Paste a job description here…';
        }
      };

      // Scroll nudge wiring — click to jump to bottom and dismiss
      const nudgeEl = document.getElementById('ws-scroll-nudge');
      if (nudgeEl) {
        // ws-timeline is the scroll container (col-chat has overflow:hidden)
        const scrollContainer = timelineEl;
        nudgeEl.addEventListener('click', () => {
          // User-initiated scroll: smooth behaviour for a polished feel.
          // scrollTo({ behavior:'smooth' }) takes per-call precedence over the
          // scroll-behavior:auto set on ws-timeline (which keeps streaming instant).
          scrollContainer.scrollTo({ top: scrollContainer.scrollHeight, behavior: 'smooth' });
          nudgeEl.classList.remove('visible');
        });
        // Auto-dismiss nudge when user manually scrolls near the bottom
        scrollContainer.addEventListener('scroll', () => {
          const distFromBottom = scrollContainer.scrollHeight - scrollContainer.scrollTop - scrollContainer.clientHeight;
          if (distFromBottom < 80) nudgeEl.classList.remove('visible');
        }, { passive: true });
      }

      // Auto-grow textarea — max matches CSS max-height
      inputEl.addEventListener('input', () => {
        inputEl.style.height = 'auto';
        inputEl.style.height = Math.min(inputEl.scrollHeight, 160) + 'px';
        sendBtn.disabled = !inputEl.value.trim() || _wsSubmitting;
        // Remove blank state on first keystroke
        document.querySelector('.ws-blank-state')?.remove();
      });

      // ── Attachment wiring ─────────────────────────────────────────────────
      // Files are tracked in _wsAttachments[]. Clicking + opens a system file
      // picker. Selected files render as dismissible pills above the shell.
      // Cleared automatically on send. Actual file upload is wired to the
      // send path — the array is available for future API integration.
      let _wsAttachments = [];
      const attachBtn    = document.getElementById('ws-attach-btn');
      const attachInput  = document.getElementById('ws-attach-input');
      const previewEl    = document.getElementById('ws-attachment-preview');

      const _wsRenderAttachmentPills = () => {
        if (!previewEl) return;
        previewEl.innerHTML = '';
        _wsAttachments.forEach((file, idx) => {
          const pill = document.createElement('div');
          pill.className = 'ws-attachment-pill';
          pill.innerHTML =
            `<span class="ws-attachment-pill-name">📎 ${esc(file.name)}</span>` +
            `<button class="ws-attachment-pill-remove" aria-label="Remove ${esc(file.name)}" data-idx="${idx}">×</button>`;
          previewEl.appendChild(pill);
        });
      };

      previewEl?.addEventListener('click', e => {
        const btn = e.target.closest('.ws-attachment-pill-remove');
        if (!btn) return;
        const idx = parseInt(btn.dataset.idx, 10);
        _wsAttachments.splice(idx, 1);
        _wsRenderAttachmentPills();
      });

      attachBtn?.addEventListener('click', () => attachInput?.click());

      attachInput?.addEventListener('change', () => {
        if (!attachInput.files?.length) return;
        const files = Array.from(attachInput.files);
        attachInput.value = ''; // reset so same file can be re-added
        files.forEach(f => {
          _wsAttachments.push(f);
          // Immediately begin reading + classifying — no need to press Send.
          // Pass the Supabase client so the edge function can be invoked.
          _wsProcessUploadedFile(f, role, timelineEl, getSupabase());
        });
        _wsRenderAttachmentPills();
      });

      // ── Documents section wiring ──────────────────────────────────────────
      const docsToggleEl = document.getElementById('ws-docs-toggle');
      const docsListEl   = document.getElementById('ws-docs-list');
      docsToggleEl?.addEventListener('click', () => {
        const expanded = docsToggleEl.getAttribute('aria-expanded') === 'true';
        docsToggleEl.setAttribute('aria-expanded', String(!expanded));
        if (docsListEl) docsListEl.hidden = expanded;
        const chevron = docsToggleEl.querySelector('.ws-docs-chevron');
        if (chevron) chevron.textContent = expanded ? '›' : '‹';
      });

      // Load existing documents for saved roles
      if (!role._isTemp) _wsUpdateDocumentsSection(role, timelineEl);

      // Send on Enter (not Shift+Enter), or button click
      const doSend = async () => {
        if (_wsSubmitting) return;
        const text = inputEl.value.trim();
        if (!text) return;
        _wsLock();
        inputEl.value = '';
        inputEl.style.height = 'auto';
        // Clear any pending attachments from the preview
        _wsAttachments = [];
        _wsRenderAttachmentPills();
        // Remove blank state if still showing
        document.querySelector('.ws-blank-state')?.remove();
        await _wsHandlePaste(role, text, timelineEl);
        _wsUnlock();
        inputEl.focus();
      };

      sendBtn.addEventListener('click', doSend);
      inputEl.addEventListener('keydown', e => {
        if (e.key === 'Enter' && !e.shiftKey) {
          e.preventDefault();
          doSend();
        }
      });

      // ── Quick chip selection handler ──────────────────────────────────────
      // Fired by _wsRenderChips when the user clicks a chip pill.
      // Mirrors doSend but bypasses the textarea (chip text goes straight to _wsHandlePaste).
      timelineEl.addEventListener('ws:chip-send', async (e) => {
        const chipText = e.detail?.text;
        if (!chipText || _wsSubmitting) return;
        _wsLock();
        document.querySelector('.ws-blank-state')?.remove();
        await _wsHandlePaste(role, chipText, timelineEl);
        _wsUnlock();
        inputEl.focus();
      });

      // ── Action button wiring ─────────────────────────────────────────────
      const _wsRunAction = (actionFn) => async () => {
        if (_wsSubmitting) return;
        _wsLock();
        document.querySelector('.ws-blank-state')?.remove();
        try { await actionFn(); } finally {
          _wsUnlock();
          inputEl.focus();
        }
      };

      inputEl.focus();
    }

    // ─── Workspace memory summary helpers ────────────────────────────────────
    // Called after analysis to refresh the right-panel summary without re-rendering the rail
    async function _wsRefreshMemorySummary(roleId) {
      try {
        const summaryEl = document.getElementById('ws-memory-summary');
        if (!summaryEl) return;
        const mem = await wsLoadMemory(roleId);

        // Recruiter count: query DB fresh rather than reading stale allRoles cache.
        // A recruiter may have been linked during the current session without a full reload.
        let recCount = 0;
        try {
          const { count } = await db.from('role_recruiters')
            .select('id', { count: 'exact', head: true }).eq('role_id', roleId);
          recCount = count || 0;
        } catch (_) {
          // Fallback to in-memory count
          recCount = allRoles.find(r => r.id === roleId)?.role_recruiters?.length || 0;
        }

        const interCount = mem.interactions.length;
        const linkCount  = mem.insights.filter(i => i.insight_type === 'signal').length;
        const noteCount  = mem.insights.filter(i => i.insight_type !== 'signal').length;
        const artCount   = mem.artifacts.length;
        const empty      = !recCount && !interCount && !linkCount && !noteCount && !artCount;

        summaryEl.innerHTML = `
          <div class="rail-label">Role Memory</div>
          ${recCount   ? `<div class="ws-mem-row"><span class="ws-mem-count">${recCount}</span> contact${recCount !== 1 ? 's' : ''}</div>` : ''}
          ${interCount ? `<div class="ws-mem-row"><span class="ws-mem-count">${interCount}</span> interaction${interCount !== 1 ? 's' : ''}</div>` : ''}
          ${linkCount  ? `<div class="ws-mem-row"><span class="ws-mem-count">${linkCount}</span> link${linkCount !== 1 ? 's' : ''}</div>` : ''}
          ${noteCount  ? `<div class="ws-mem-row"><span class="ws-mem-count">${noteCount}</span> note${noteCount !== 1 ? 's' : ''}</div>` : ''}
          ${artCount   ? `<div class="ws-mem-row"><span class="ws-mem-count">${artCount}</span> artefact${artCount !== 1 ? 's' : ''}</div>` : ''}
          ${empty ? '<div class="ws-mem-empty">No memory yet</div>' : ''}`;
      } catch (_) {}
    }

    // ─── Center: Role Document ────────────────────────────────────────────────
    // Stages where the workflow is the primary signal (user has taken action)
    const PROGRESSED_STAGES = new Set(['Applied', 'Recruiter Screen', 'Hiring Manager', 'Panel', 'Final', 'Offer']);

    // ── Workspace: guard rail ─────────────────────────────────────────────────
    // Roles without a job description get the workspace view.
    // Roles with a JD use the existing renderRoleDoc path.
    // This is the ONLY entry point to the workspace — do not call renderWorkspaceView directly.

    // ─── Recruiter meta line refresh ──────────────────────────────────────────
    // Populates (or clears) #doc-meta-recruiter from the role's current
    // role_recruiters data. Safe to call at any time after the role doc HTML
    // has been rendered. Also called after email-confirm recruiter linking so
    // the header updates without a full re-render.
    function _refreshDocRecruiterMeta(role) {
      const _recMetaEl = document.getElementById('doc-meta-recruiter');
      if (!_recMetaEl) return;
      const _recRaw = role.role_recruiters?.[0]?.recruiters || null;
      if (!_recRaw || !_recRaw.name) {
        _recMetaEl.style.display = 'none';
        _recMetaEl.innerHTML = '';
        return;
      }

      // Identity line — name (bold; also a link if profile URL exists)
      const _rNameHtml = _recRaw.linkedin_url
        ? `<a href="${esc(_recRaw.linkedin_url)}" target="_blank" rel="noopener" class="doc-meta-recruiter-link">${esc(_recRaw.name)}</a>`
        : `<strong style="font-weight:500;color:var(--text);">${esc(_recRaw.name)}</strong>`;
      // Company — dot separator matches "Name · Company · Type" scan pattern
      const _rCompanyHtml = _recRaw.company
        ? ` <span class="doc-meta-recruiter-company">· ${esc(_recRaw.company)}</span>`
        : '';

      // Type badge — show stored value (including Unknown when explicit);
      // only suppress Unknown when it comes from the heuristic fallback.
      const _storedType = _recRaw.recruiter_type;
      const _rType      = _storedType
        || (_recruiterTypeLabel(_recRaw) !== 'Unknown' ? _recruiterTypeLabel(_recRaw) : null);
      const _rTypeHtml  = _rType
        ? ` <span class="doc-meta-rec-type">${esc(_rType)}</span>`
        : '';

      // Email sub-line
      const _rEmailHtml = _recRaw.email
        ? `<div class="doc-meta-rec-detail"><a href="mailto:${esc(_recRaw.email)}">${esc(_recRaw.email)}</a></div>`
        : '';

      // Profile link — explicit visible link (LinkedIn ↗ or Profile ↗)
      const _rProfileHtml = _recRaw.linkedin_url
        ? `<div class="doc-meta-rec-detail"><a href="${esc(_recRaw.linkedin_url)}" target="_blank" rel="noopener">${_recRaw.linkedin_url.includes('linkedin.com') ? 'LinkedIn' : 'Profile'} ↗</a></div>`
        : '';

      // Last interaction — priority: newest role event > recruiter link date > role created_at
      const _lastEvDate = role.role_updates?.[0]?.created_at
        || role.role_recruiters?.[0]?.created_at
        || role.created_at
        || null;
      const _rLastHtml = _lastEvDate
        ? `<div class="doc-meta-rec-detail">Last interaction: ${_rcRelativeDate(_lastEvDate)}</div>`
        : '';

      // ── History facts — derived from allRecruiters (already in memory) ──
      const _recFull   = allRecruiters.find(r => r.id === _recRaw.id);
      const _recRoles  = _recFull?.roles || [];
      let   _historyHtml = '';

      if (_recRoles.length > 1) {
        const _total     = _recRoles.length;
        const _applied   = _recRoles.filter(r => r._appliedDate).length;
        const _responses = _recRoles.filter(r => r._firstResponseDate).length;

        // Last activity across OTHER linked roles (exclude current)
        let _lastDate = null;
        for (const _r of _recRoles) {
          if (_r.id === role.id) continue;
          const _d = _r.role_updates?.[0]?.created_at || _r.created_at;
          if (_d && (!_lastDate || _d > _lastDate)) _lastDate = _d;
        }
        const _daysSince = _lastDate
          ? Math.floor((Date.now() - new Date(_lastDate).getTime()) / 86400000)
          : null;

        const _facts = [];
        _facts.push(`${_total} role${_total !== 1 ? 's' : ''}`);
        if (_applied   > 0) _facts.push(`${_applied} applied`);
        if (_responses > 0) _facts.push(`${_responses} response${_responses !== 1 ? 's' : ''}`);
        if (_facts.length < 3 && _daysSince !== null && _daysSince > 1) {
          _facts.push(`Last active ${_daysSince}d ago`);
        }

        const _safeId   = esc(_recRaw.id);
        const _factsStr = _facts.slice(0, 3).join(' · ');
        _historyHtml = `<div class="doc-meta-rec-history">` +
          `<span class="doc-meta-rec-history-link" role="button" tabindex="0" ` +
          `onclick="_openRecruiterById('${_safeId}')" ` +
          `onkeydown="if(event.key==='Enter')_openRecruiterById('${_safeId}')">` +
          `${_factsStr}</span></div>`;
      }

      _recMetaEl.innerHTML = `Recruiter: ${_rNameHtml}${_rCompanyHtml}${_rTypeHtml}${_rEmailHtml}${_rProfileHtml}${_rLastHtml}${_historyHtml}`;
      _recMetaEl.style.display = '';
    }

    async function renderRoleDoc(role) {
      // Exit intake mode if active (user selected a role while Add JD was open)
      _exitIntakeMode();

      // ── WORKSPACE ROUTING GUARD ──────────────────────────────────────────────
      // Rule: open workspace if:
      //   (a) role has no job_description_raw (blank role), OR
      //   (b) role has any workspace data (conversations, artifacts, interactions, insights)
      // Only fall through to legacy doc view if role has a JD AND no workspace data at all.

      // Fast path — blank role, no async check needed
      if (!role.job_description_raw) {
        renderWorkspaceView(role);
        return;
      }

      // Async path — check for workspace data presence before committing to legacy view
      const _routingRoleId = role.id; // snapshot for race guard
      const hasWs = await _wsHasData(role.id);

      // If the user navigated to a different role while the check was in flight, abort
      if (selectedRoleId !== _routingRoleId) return;

      if (hasWs) {
        renderWorkspaceView(role);
        return;
      }

      // ── Legacy doc view (no workspace data) ─────────────────────────────────
      _renderStickyHeader(role);
      const el = document.getElementById('col-overview-cards');
      // Ensure workspace mode class is cleared for legacy doc view
      document.getElementById('col-chat')?.classList.remove('ws-active');
      // Show workspace in blank state in the chat panel for legacy roles
      // skipOverview: true so overview body is set by renderRoleDoc, not overwritten
      renderWorkspaceView(role, { skipOverview: true });

      const fo = role.analysis?.full_output;
      const decision = role.analysis?.decision;

      // Is the role past JD Review? If so, workflow > decision visually.
      const _currentStage  = currentStageLabel(role);
      const _isProgressed  = PROGRESSED_STAGES.has(_currentStage) && !isArchivedRole(role);

      // Header section
      const decisionClass = decision
        ? { Apply: 'apply', Maybe: 'maybe', Skip: 'skip' }[decision] || 'none'
        : 'none';
      const decisionLabel = decision || '';

      // Build meta line 3: City, Country · Work model · Engagement type
      // engagement_type is stored on the role (synchronous); employment_type from analysis is async fallback.
      // Salary (line 4) is filled async below the meta row.
      // Source channel is shown with a label in the doc-meta-application block below, not here.
      const _metaParts = [];
      if (role.location_text) _metaParts.push(esc(role.location_text));
      if (role.work_model && role.work_model !== 'unknown') {
        _metaParts.push(esc(role.work_model.charAt(0).toUpperCase() + role.work_model.slice(1)));
      }
      if (role.engagement_type && role.engagement_type !== 'Unknown') {
        _metaParts.push(esc(role.engagement_type));
      }
      if (role.day_rate_text) {
        _metaParts.push(esc(role.day_rate_text));
      }
      if (role.ir35_status === 'Outside IR35' || role.ir35_status === 'Inside IR35') {
        _metaParts.push(esc(role.ir35_status));
      }
      if (role.contract_length) {
        _metaParts.push(esc(role.contract_length));
      }
      const _metaLine3 = _metaParts.join(' · ');

      // Secondary meta line: "Added X days ago" derived from when the role was saved.
      const _daysSinceAdded = Math.floor((Date.now() - new Date(role.created_at).getTime()) / 86400000);
      const _addedLabel = _daysSinceAdded === 0 ? 'Added today'
        : _daysSinceAdded === 1 ? 'Added yesterday'
        : `Added ${_daysSinceAdded} days ago`;

      // Helper: render a prose section
      function section(heading, content) {
        if (!content) return '';
        return `<div class="doc-section">
          <div class="doc-section-heading">${heading}</div>
          <p class="doc-prose">${esc(content)}</p>
        </div>`;
      }

      // Helper: render a list section
      function listSection(heading, items) {
        if (!items || !items.length) return '';
        const lis = items.map(item => `<li>${esc(item)}</li>`).join('');
        return `<div class="doc-section">
          <div class="doc-section-heading">${heading}</div>
          <ul class="doc-list">${lis}</ul>
        </div>`;
      }

      let docBody = '';
      // Primary content slot — async block below replaces the placeholder with
      // renderMatchOutput(output_json) from jd_matches, or falls back to raw JD.
      docBody = '<div id="match-output-panel"><p class="doc-no-analysis" style="color:#aaa;font-style:italic;">Loading analysis…</p></div>';

      // Response Time — computed from role_updates; only shown when applied event exists.
      // Only stage rows are considered — outcome rows and legacy status values are ignored.
      const stageUpdatesAsc = [...role.role_updates]
        .filter(u => !u.event_type || u.event_type === 'stage')
        .reverse(); // chronological order (oldest first)
      const appliedEvent = stageUpdatesAsc.find(u => u.stage_reached === 'Applied');

      let responseTimeSectionHtml = '';
      if (appliedEvent) {
        const appliedTime        = new Date(appliedEvent.created_at).getTime();
        const daysSinceApplied   = Math.floor((Date.now() - appliedTime) / 86400000);

        // Stages that represent an employer response after the application
        const RESPONSE_STAGES = new Set([
          'Recruiter Screen', 'Hiring Manager', 'Panel', 'Final', 'Offer',
        ]);

        const appliedIdx    = stageUpdatesAsc.indexOf(appliedEvent);
        const responseEvent = stageUpdatesAsc.slice(appliedIdx + 1).find(u =>
          RESPONSE_STAGES.has(u.stage_reached)
        );

        let statsHtml = '';
        if (responseEvent) {
          const appliedToResponse = Math.floor(
            (new Date(responseEvent.created_at).getTime() - appliedTime) / 86400000
          );
          statsHtml += `<div class="response-stat">
            <span class="response-stat-label">Applied to first response</span>
            <span class="response-stat-value">${appliedToResponse} day${appliedToResponse !== 1 ? 's' : ''}</span>
          </div>`;
        }

        statsHtml += `<div class="response-stat">
          <span class="response-stat-label">Days since applied</span>
          <span class="response-stat-value">${daysSinceApplied} day${daysSinceApplied !== 1 ? 's' : ''}</span>
        </div>`;

        if (!responseEvent) {
          statsHtml += `<div class="response-no-response">No response yet</div>`;
        }

        responseTimeSectionHtml = `<div class="doc-section" style="margin-top:32px;">
          <div class="doc-section-heading">Response time</div>
          ${statsHtml}
        </div>`;
      }

      // Activity — date-grouped, chronological (oldest first)
      {
        const _OUTCOME_DISP = {
          rejected:       'Rejected',
          skipped:        'Skipped',
          withdrew:       'Withdrew',
          offer_accepted: 'Offer accepted',
          offer_received: 'Offer received',
          accepted:       'Accepted',
          no_response:    'No response',
          ghosted:        'Ghosted',
          closed:         'Closed',
        };
        // Map stage_reached / event_type → human-readable event label
        const _STAGE_LABELS = {
          'JD Review':        'Under review',
          'jd_review':        'Under review',
          'Applied':          'Application submitted',
          'applied':          'Application submitted',
          'Recruiter Screen': 'Recruiter replied',
          'recruiter_screen': 'Recruiter replied',
          'Recruiter screen': 'Recruiter replied',
          'Hiring Manager':   'Interview scheduled',
          'hiring_manager':   'Interview scheduled',
          'Panel':            'Interview scheduled',
          'panel':            'Interview scheduled',
          'Final':            'Interview scheduled',
          'final':            'Interview scheduled',
          'Offer':            'Offer received',
          'offer':            'Offer received',
          'In progress':      'In progress',
          'in_progress':      'In progress',
        };
        const _EVENT_TYPE_LABELS = {
          'analysis_saved':   'Analysis saved',
          'role_created':     'Role created',
          'role_archived':    'Archived',
          'outcome':          null, // handled separately
          'stage':            null, // handled via stage_reached
        };

        // ── Relative date label: Today / Yesterday / "5 Mar" ───────────
        const _relDate = ts => {
          const now = new Date(); now.setHours(0,0,0,0);
          const d   = new Date(ts); d.setHours(0,0,0,0);
          const diff = Math.round((now - d) / 86400000);
          if (diff === 0) return 'Today';
          if (diff === 1) return 'Yesterday';
          return ts.toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });
        };

        // ── System events (background) — treated as lower hierarchy ─────
        const _SYSTEM_EVENTS = new Set(['role_created', 'analysis_saved']);
        // Significant events (stage progress + outcomes) — treated as higher hierarchy
        const _SIG_STAGES = new Set([
          'Applied','applied','Recruiter Screen','recruiter_screen','Recruiter screen',
          'Hiring Manager','hiring_manager','Panel','panel','Final','final','Offer','offer',
        ]);

        // Build all history entries — start with synthetic ones, then DB rows
        const _rawEntries = [];

        // Synthetic: Role created
        _rawEntries.push({
          ts: new Date(role.created_at),
          label: 'Role created',
          note: null,
          kind: 'system',
        });

        // Synthetic: JD analysed (if latest_match_at exists)
        if (role.latest_match_at) {
          _rawEntries.push({
            ts: new Date(role.latest_match_at),
            label: 'JD analysed',
            note: null,
            kind: 'system',
          });
        }

        // DB rows from role_updates (currently sorted desc — iterate all)
        for (const u of role.role_updates) {
          let label;
          let kind = 'default';
          if (u.event_type === 'outcome') {
            label = _OUTCOME_DISP[u.outcome_state] || u.outcome_state || 'Outcome set';
            kind  = 'significant';
          } else {
            // Try stage_reached first, then event_type label, then status fallback
            const sr = (u.stage_reached || '').trim();
            label = (sr && (_STAGE_LABELS[sr] || sr))
                  || (_EVENT_TYPE_LABELS[u.event_type] !== undefined ? _EVENT_TYPE_LABELS[u.event_type] : null)
                  || STATUS_LABELS[u.status]
                  || u.status
                  || 'Update';
            if (_SYSTEM_EVENTS.has(u.event_type))  kind = 'system';
            else if (sr && _SIG_STAGES.has(sr))    kind = 'significant';
          }
          if (!label) continue; // skip null-label entries (handled differently)
          _rawEntries.push({ ts: new Date(u.created_at), label, note: u.note || null, kind });
        }

        // Sort chronological, oldest first
        _rawEntries.sort((a, b) => a.ts - b.ts);

        // Deduplicate: if "Role created" & a DB row land on exact same ts, keep only one
        const _seen = new Set();
        const _dedupedEntries = _rawEntries.filter(e => {
          const key = `${e.ts.getTime()}|${e.label}`;
          if (_seen.has(key)) return false;
          _seen.add(key);
          return true;
        });

        // Group by date string (year-inclusive key keeps cross-year dates separate)
        const _groups = [];
        let _lastDateStr = null;
        for (const e of _dedupedEntries) {
          const dateStr    = e.ts.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
          const displayStr = _relDate(e.ts);
          if (dateStr !== _lastDateStr) {
            _groups.push({ dateStr, displayStr, entries: [] });
            _lastDateStr = dateStr;
          }
          _groups[_groups.length - 1].entries.push(e);
        }

        const activityEntries = _groups.length
          ? _groups.map(g => {
              const rows = g.entries.map(e => {
                const noteHtml   = e.note ? `<div class="timeline-note">${esc(e.note)}</div>` : '';
                const kindClass  = e.kind && e.kind !== 'default' ? ` timeline-${e.kind}` : '';
                return `<div class="timeline-entry${kindClass}">
                  <div class="timeline-label">${esc(e.label)}</div>
                  ${noteHtml}
                </div>`;
              }).join('');
              const isRecent = g.displayStr === 'Today' || g.displayStr === 'Yesterday';
              return `<div class="timeline-date-group">
                <div class="timeline-date-group-header${isRecent ? ' tl-recent' : ''}">${esc(g.displayStr)}</div>
                ${rows}
              </div>`;
            }).join('')
          : `<div class="activity-empty">No activity logged yet.</div>`;

        // Expose for use in docBody template below (block-scoped so use var to hoist)
        var _activityHtml = activityEntries;
      } // end activity block

      // ── Role Record — collapsible container for metadata, JD, history, and deep analysis ──
      docBody += `<details class="role-record" id="role-record">
        <summary class="role-record-summary">
          <span class="role-record-title">Role Record</span>
          <span class="role-record-subtitle">History, notes, snapshots &amp; full analysis</span>
          <span class="role-record-chevron">&#9656;</span>
        </summary>
        <div class="role-record-body">

          <!-- Deep analysis placeholder — filled async when analysis panel loads -->
          <div id="role-record-deep-analysis"></div>

          <!-- JD placeholder — filled async once analysis panel loads -->
          <div id="role-record-jd-placeholder"></div>

          ${responseTimeSectionHtml ? responseTimeSectionHtml : ''}

          <div class="doc-section">
            <div class="doc-section-heading">History</div>
            <div class="doc-activity">${_activityHtml || ''}</div>
          </div>

          <!-- Role memory placeholder — filled async after render -->
          <div class="doc-section" id="role-memory-section">
            <div class="doc-section-heading">Notes</div>
            <div class="role-memory-empty">Loading…</div>
          </div>

          <!-- Role snapshots placeholder — filled async after render -->
          <div class="doc-section" id="role-snapshots-section">
            <div class="doc-section-heading">Snapshots</div>
            <div class="role-snapshots-empty">Loading\u2026</div>
          </div>

          <!-- Outcome learning placeholder — filled async after render -->
          <div class="doc-section" id="role-outcome-section">
            <div class="doc-section-heading">Outcome</div>
            <div class="outcome-empty">Loading\u2026</div>
          </div>

        </div>
      </details>`;

      // Build the top-of-page signal element based on whether role has progressed
      const _stageClass     = stageTagClass(_currentStage);
      const _topSignalHtml  = _isProgressed && decisionLabel
        // Progressed: stage is primary, initial decision is secondary context
        ? `<div class="doc-stage-context">
             <span class="stage-tag${_stageClass ? ' ' + _stageClass : ''}">${esc(_currentStage)}</span>
             <span class="doc-initial-decision">Initial decision: ${esc(decisionLabel)}</span>
           </div>`
        // JD Review or no decision yet: show decision badge as before
        : decisionLabel
          ? `<div class="doc-decision ${decisionClass}">${esc(decisionLabel)}</div>`
          : '';

      el.innerHTML = `
        <div id="sticky-decision-bar" class="sticky-decision-bar"></div>
        <div class="col-center-inner">
          ${_topSignalHtml}
          <div class="doc-header-bar">
            <div class="doc-header-left">
              <div class="doc-company">${esc(sanitiseCompanyName(role.company_name) || 'Company not specified')}</div>
              <h1 class="doc-role-title">${esc(role.role_title)}</h1>
              <div class="doc-meta">${_metaLine3 ? `<span id="doc-meta-line3">${_metaLine3}</span>` : ''}<span id="doc-meta-emptype"></span></div>
              <div class="doc-meta-posted">${esc(_addedLabel)}</div>
              <div id="doc-meta-salary" class="doc-meta-salary" style="display:none;"></div>
              <div id="doc-meta-recruiter" class="doc-meta-recruiter" style="display:none;"></div>
              <div id="doc-meta-start" class="doc-meta-start" style="display:none;"></div>
              <div id="doc-meta-application" class="doc-meta-application" style="display:none;"></div>
            </div>
            <div class="doc-header-right">
              <button class="btn-edit-details" id="btn-edit-role-details" data-role-id="${esc(role.id)}">Edit details</button>
              <button class="btn-share-analysis" id="btn-share-analysis" style="display:none;" data-role-id="${esc(role.id)}">Share analysis</button>
            </div>
          </div>
          <!-- Recruiter row — filled synchronously from role.role_recruiters -->
          <div id="doc-recruiter-row" class="doc-recruiter-row" style="display:none;"></div>
          <div id="doc-archetype-row" class="doc-archetype-row" style="display:none;"></div>
          <!-- Decision Summary — filled async when analysis loads (decision-first order) -->
          <div id="doc-decision-summary" style="display:none;"></div>
          <!-- Next Action — filled async after decision summary -->
          <div id="doc-next-action"></div>
          <!-- Role Lens — filled async when analysis loads -->
          <div id="doc-role-lens" style="display:none;"></div>
          <!-- Jump links — filled async when analysis loads -->
          <div id="doc-jump-links" style="display:none;"></div>
          <!-- Pattern Signals — filled async when analysis loads -->
          <div id="doc-pattern-signals" style="display:none;"></div>
          <!-- Pattern Notice — filled async, shown below Role Lens -->
          <div id="doc-pattern-notice"></div>
          ${docBody}
          <!-- Decision action bar — injected after analysis loads -->
          <div id="doc-decision-bar"></div>
        </div>
      `;

      // ── Fill recruiter meta line (synchronous — data already in role.role_recruiters) ──
      _refreshDocRecruiterMeta(role);

      // ── Fill start timeline meta line (synchronous — data already on role) ──
      {
        const _startMetaEl = document.getElementById('doc-meta-start');
        if (_startMetaEl && role.start_timeline && role.start_timeline !== 'Unknown') {
          _startMetaEl.textContent = `Start: ${role.start_timeline}`;
          _startMetaEl.style.display = '';
        }
      }

      // ── Fill role context block: Source channel · Applied date · Response status ──
      // Source is derived (role.source > URL pattern > recruiter signal > hidden).
      // Applied and Status only shown when role._appliedDate is set.
      // No extra DB calls — all data already on the loaded role object.
      {
        const _appMetaEl = document.getElementById('doc-meta-application');
        if (_appMetaEl) {
          const _ctxLines = [];

          // ── Source channel ────────────────────────────────────────────────
          // Priority: stored role.source > URL pattern match > recruiter signal > omit
          const _jobUrlLc = (role.job_url || '').toLowerCase();
          let _srcLabel   = role.source || null;
          if (!_srcLabel) {
            if      (_jobUrlLc.includes('linkedin.com'))   _srcLabel = 'LinkedIn';
            else if (_jobUrlLc.includes('greenhouse.io')
                  || _jobUrlLc.includes('lever.co')
                  || _jobUrlLc.includes('workable.com'))   _srcLabel = 'Direct company site';
            else if (_jobUrlLc.includes('indeed.')
                  || _jobUrlLc.includes('reed.co.uk')
                  || _jobUrlLc.includes('totaljobs.')
                  || _jobUrlLc.includes('cwjobs.'))        _srcLabel = 'Job board';
            else if (role.role_recruiters?.length)         _srcLabel = 'Recruiter outreach';
            // Unknown omitted — hide per display rules
          }
          if (_srcLabel) _ctxLines.push(`<div>Source: ${esc(_srcLabel)}</div>`);

          // ── Applied date ──────────────────────────────────────────────────
          if (role._appliedDate) {
            const _appDateStr = new Date(role._appliedDate)
              .toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
            _ctxLines.push(`<div>Applied: ${_appDateStr}</div>`);
          }

          // ── Response status ───────────────────────────────────────────────
          const _ars = _appResponseStatus(role);
          if (_ars) {
            const _arsColour = (_ars.status === 'stale' || _ars.status === 'ghosted')
              ? '#B45309'
              : 'inherit';
            _ctxLines.push(`<div>Status: <span style="color:${_arsColour};">${esc(_ars.label)}</span></div>`);
          }

          if (_ctxLines.length) {
            _appMetaEl.innerHTML = _ctxLines.join('');
            _appMetaEl.style.display = '';
          }
        }
      }

      // Populate match output panel — analysis is primary content, raw JD is collapsible fallback
      (async () => {
        const panel = document.getElementById('match-output-panel');
        if (!panel) return;
        try {
          const { data: match } = await db.from('jd_matches')
            .select('output_json')
            .eq('role_id', role.id)
            .order('created_at', { ascending: false })
            .limit(1)
            .maybeSingle();

          if (match && match.output_json) {
            // Analysis found — show share button
            const _shareBtn = document.getElementById('btn-share-analysis');
            if (_shareBtn) {
              _shareBtn.style.display = '';
              _shareBtn.dataset.matchId = match.id || '';
            }
            // Analysis found — render as primary, raw JD goes into Role Record
            panel.innerHTML = renderMatchOutput(match.output_json);
            _initCompSnapshot(panel);
            renderFitDecisionPanel(role);
            // Inject deep context sections into Role Record
            const _deepEl = document.getElementById('role-record-deep-analysis');
            if (_deepEl) _deepEl.innerHTML = renderDeepContextHtml(match.output_json);
            if (role.job_description_raw) {
              const rawJdForPanel = role.job_description_raw;
              const jdPlaceholder = document.getElementById('role-record-jd-placeholder');
              if (jdPlaceholder) {
                jdPlaceholder.innerHTML = `<div class="doc-section" style="padding-top:0;">
                  <details>
                    <summary class="doc-section-heading" style="cursor:pointer;list-style:none;display:flex;align-items:center;gap:6px;">
                      <span style="font-size:11px;opacity:0.5;">▶</span> Original job description
                    </summary>
                    <p class="doc-prose" style="white-space:pre-wrap;margin-top:12px;">${esc(rawJdForPanel)}</p>
                  </details>
                </div>`;
              }
              const jdHealthHtml = jdHealthPanel(rawJdForPanel, cleanJobDescription(rawJdForPanel));
              if (jdHealthHtml) {
                const healthTarget = jdPlaceholder || panel;
                healthTarget.insertAdjacentHTML('beforeend', jdHealthHtml);
              }
            }
            // Back-fill employment type — only when no structured engagement_type is stored on role
            // (engagement_type is already rendered synchronously in _metaLine3; avoid duplication)
            const _empTypeEl = document.getElementById('doc-meta-emptype');
            if (_empTypeEl && !role.engagement_type) {
              const _et = match.output_json?.practical_details?.employment_type
                       || match.output_json?.practical_details?.working_pattern;
              if (_et && _et !== 'Not stated') {
                const _line3El = document.getElementById('doc-meta-line3');
                const _prefix = (_line3El && _line3El.textContent.trim()) ? ' · ' : '';
                _empTypeEl.textContent = _prefix + _et;
              }
            }
            // Back-fill salary as line 4 below meta row
            const _salaryLineEl = document.getElementById('doc-meta-salary');
            if (_salaryLineEl) {
              const _sal = match.output_json?.practical_details?.salary_annual;
              if (_sal && _sal !== 'Not stated') {
                _salaryLineEl.textContent = _sal;
                _salaryLineEl.style.display = '';
              }
            }
            // Back-fill role archetype row
            const _archRow = document.getElementById('doc-archetype-row');
            if (_archRow) {
              const _arch = match.output_json?.role_archetype;
              if (_arch && _arch.primary) {
                const _secHtml = _arch.secondary
                  ? `<span class="archetype-secondary">${esc(_arch.secondary)}</span>`
                  : '';
                _archRow.innerHTML = `<span class="archetype-primary">${esc(_arch.primary)}</span>${_secHtml}`;
                _archRow.style.display = '';
              }
            }

            // ── Back-fill Role Lens ────────────────────────────────────────────
            {
              const _rlEl  = document.getElementById('doc-role-lens');
              const _rlOut = match.output_json;
              if (_rlEl && _rlOut) {
                // Source text for domain / structural detection
                const _rlText = [
                  typeof _rlOut.role_reality === 'string' ? _rlOut.role_reality : '',
                  Array.isArray(_rlOut.fit_reality_summary)
                    ? _rlOut.fit_reality_summary.map(x => typeof x === 'object' ? (x.text || '') : String(x || '')).join(' ')
                    : (typeof _rlOut.fit_reality_summary === 'string' ? _rlOut.fit_reality_summary : ''),
                  (_rlOut.role_archetype?.primary || '') + ' ' + (_rlOut.role_archetype?.secondary || ''),
                ].join(' ');

                // ── Structural signals (priority 1 — highest) ──
                // Strong signals: include when present
                const _rlStruct = [];
                if (_rlOut.hard_no) _rlStruct.push('Production code required');
                const _rlRep = (_rlOut.practical_details?.reporting_line || '').toLowerCase();
                if (/no pm|without pm|no product manager|self.direct/i.test(_rlRep))  _rlStruct.push('PM absent');
                if (/\bfounder\b|ceo|co.founder/i.test(_rlText + ' ' + _rlRep))       _rlStruct.push('Founder collaboration');
                // Salary undisclosed — weak signal, only include when no stronger structural signals
                if (_rlStruct.length === 0) {
                  const _rlSal = _rlOut.practical_details?.salary_annual;
                  if (!_rlSal || _rlSal === 'Not stated') _rlStruct.push('Salary undisclosed');
                }
                const _rlStructFinal = _rlStruct.slice(0, 2);

                // ── Role shape (priority 2) ──
                let _rlShape = null;
                const _rlArch = (_rlOut.role_archetype?.primary || '').trim();
                if (_rlArch) {
                  if (/founding|early.stage/i.test(_rlArch)) {
                    // Preserve specificity (e.g. "Founding designer") if short enough
                    const _base = _rlArch.split(/[,;(]/)[0].trim();
                    _rlShape = _base.length <= 30 ? _base : 'Founding scope';
                  } else if (/principal|staff/i.test(_rlArch))               _rlShape = 'Principal IC';
                  else if (/player.coach|ic.to.manager/i.test(_rlArch))      _rlShape = 'Player-coach';
                  else if (/squad|delivery/i.test(_rlArch))                  _rlShape = 'Squad delivery';
                  else if (/platform|systems|infrastructure/i.test(_rlArch)) _rlShape = 'Platform systems';
                  else if (/design\s*system/i.test(_rlArch))                 _rlShape = 'Design systems';
                  else if (/senior|sr\./i.test(_rlArch))                     _rlShape = 'Senior IC';
                  else if (/lead|leadership/i.test(_rlArch))                 _rlShape = 'IC lead';
                  else _rlShape = _rlArch.length > 28 ? _rlArch.slice(0, 26) + '\u2026' : _rlArch;
                }

                // ── Domain / company type (priority 3) ──
                let _rlDomain = null;
                if      (/healthcare|clinical|medical|health\s*tech/i.test(_rlText)) _rlDomain = 'Healthcare';
                else if (/fintech|financial\s*tech|payment/i.test(_rlText))          _rlDomain = 'Fintech';
                else if (/b2b\s*saas|enterprise\s*saas/i.test(_rlText))              _rlDomain = 'B2B SaaS';
                else if (/\bconsumer\b/i.test(_rlText))                              _rlDomain = 'Consumer product';
                else if (/public\s*sector|government|\bgov\b/i.test(_rlText))        _rlDomain = 'Public sector';
                else if (/marketplace/i.test(_rlText))                               _rlDomain = 'Marketplace';
                else if (/enterprise\s*software|enterprise\s*saas/i.test(_rlText))   _rlDomain = 'Enterprise software';
                else if (/regulated|compliance.driven/i.test(_rlText))               _rlDomain = 'Regulated domain';
                if (_rlDomain && /\bai\b|artificial\s*intell|machine\s*learn/i.test(_rlText))
                  _rlDomain += ' AI';

                // ── Work model (priority 4 — lowest, dropped first when trimming) ──
                let _rlWork = null;
                const _rlWM = (role.work_model || '').toLowerCase();
                if      (_rlWM === 'remote')                         _rlWork = 'Remote';
                else if (_rlWM === 'hybrid')                         _rlWork = 'Hybrid';
                else if (_rlWM === 'onsite' || _rlWM === 'on-site') _rlWork = 'Onsite';

                // ── Selection: keep highest-priority items when total > 4 ──
                // Tag each candidate with priority so we can trim from lowest first
                const _rlCandidates = [
                  ..._rlStructFinal.map(v => ({ v, p: 1 })),
                  ...(_rlShape  ? [{ v: _rlShape,  p: 2 }] : []),
                  ...(_rlDomain ? [{ v: _rlDomain, p: 3 }] : []),
                  ...(_rlWork   ? [{ v: _rlWork,   p: 4 }] : []),
                ];
                const _rlKept = _rlCandidates.length <= 4
                  ? _rlCandidates
                  : [..._rlCandidates].sort((a, b) => a.p - b.p).slice(0, 4);

                // ── Display order: domain (3) → role shape (2) → work model (4) → structural (1) ──
                const _rlOrder = [3, 2, 4, 1];
                const _rlFinal = _rlOrder
                  .flatMap(p => _rlKept.filter(c => c.p === p).map(c => c.v));

                // Fail-safe: hide if fewer than 2 useful items
                if (_rlFinal.length >= 2) {
                  _rlEl.innerHTML = `<div class="doc-role-lens">
                    <div class="doc-role-lens-label">Role Lens</div>
                    <div class="doc-role-lens-items">${_rlFinal.map(esc).join(' \u00B7 ')}</div>
                  </div>`;
                  _rlEl.style.display = '';
                }
              }
            }

            // ── Back-fill Decision Summary ─────────────────────────────────────
            {
              const _dsEl  = document.getElementById('doc-decision-summary');
              const _dsOut = match.output_json;
              if (_dsEl && _dsOut) {
                const _dsSA  = _dsOut.suggested_actions || {};
                const _dsRV  = _dsOut.rolewise_verdict  || {};
                const _dsNS  = _dsSA.next_step || _dsSA.primary || 'Review';
                const _dsFS  = Array.isArray(_dsOut.friction_signals) ? _dsOut.friction_signals : [];
                const _dsFit = Array.isArray(_dsOut.fit_reality_summary)
                  ? _dsOut.fit_reality_summary.filter(Boolean) : [];

                // Outcome — exactly one of: Hard No | Likely Not Worth Pursuing | Worth Exploring | Strong Fit
                let _dsOutcome;
                if (_dsOut.hard_no) {
                  _dsOutcome = 'Hard No';
                } else {
                  const _rvText = (_dsRV.outcome || '').toLowerCase();
                  if (/strong\s*fit|excellent|great\s*fit/i.test(_rvText))         _dsOutcome = 'Strong Fit';
                  else if (/worth\s*explor|worth\s*apply|likely\s*worth/i.test(_rvText)) _dsOutcome = 'Worth Exploring';
                  else if (/not\s*worth|unlikely|skip|avoid/i.test(_rvText))       _dsOutcome = 'Likely Not Worth Pursuing';
                  else if (_dsNS === 'Apply')                                       _dsOutcome = 'Strong Fit';
                  else if (_dsNS === 'Skip')                                        _dsOutcome = 'Likely Not Worth Pursuing';
                  else                                                              _dsOutcome = 'Worth Exploring';
                }

                // Reason — short factual phrase from signals
                let _dsReason;
                if (_dsOut.hard_no) {
                  _dsReason = 'Production coding required';
                } else if (_dsFS.length && _dsFS[0].label) {
                  _dsReason = _dsFS[0].label;
                } else {
                  const _ff = _dsFit[0];
                  const _ft = _ff && typeof _ff === 'object' ? _ff.text : (typeof _ff === 'string' ? _ff : '');
                  _dsReason = _ft ? (_ft.length > 70 ? _ft.slice(0, 68) + '\u2026' : _ft) : 'See analysis below';
                }

                // Suggested action — must match allowed values, derived from outcome
                const _dsActionMap = {
                  'Hard No':                   'Skip',
                  'Likely Not Worth Pursuing': 'Investigate further',
                  'Worth Exploring':           'Ask questions',
                  'Strong Fit':                'Apply',
                };
                const _dsAction = _dsActionMap[_dsOutcome] || 'Investigate further';

                // Card colour class based on outcome
                const _dsColorMap = {
                  'Strong Fit':                'ds-green',
                  'Hard No':                   'ds-red',
                  'Worth Exploring':           'ds-amber',
                  'Likely Not Worth Pursuing': 'ds-amber',
                };
                const _dsColorClass = _dsColorMap[_dsOutcome] || '';

                // Recommended CV — only shown when outcome is NOT Hard No
                const _isHardNo = (_dsOutcome === 'Hard No');
                const _dsCvName = _isHardNo ? null : ((_dsSA.recommended_cv || '').trim() || null);
                const _dsCvName_clean = (_dsCvName && _dsCvName !== 'Not stated') ? _dsCvName : null;
                const _dsCvRowHtml = _dsCvName_clean
                  ? `<div class="decision-summary-row">
                      <span class="decision-summary-key">Recommended CV</span>
                      <span class="decision-summary-val">${esc(_dsCvName_clean)}</span>
                    </div>`
                  : '';

                _dsEl.innerHTML = `<div class="decision-summary${_dsColorClass ? ' ' + _dsColorClass : ''}">
                  <div class="decision-summary-header">Decision Summary</div>
                  <div class="decision-summary-rows">
                    <div class="decision-summary-row">
                      <span class="decision-summary-key">Outcome</span>
                      <span class="decision-summary-val">${esc(_dsOutcome)}</span>
                    </div>
                    <div class="decision-summary-row">
                      <span class="decision-summary-key">Reason</span>
                      <span class="decision-summary-val">${esc(_dsReason)}</span>
                    </div>
                    <div class="decision-summary-row">
                      <span class="decision-summary-key">Suggested action</span>
                      <span class="decision-summary-val">${esc(_dsAction)}</span>
                    </div>
                    ${_dsCvRowHtml}
                  </div>
                </div>`;
                _dsEl.style.display = '';
                // If role has progressed past JD Review, DS card becomes secondary context
                if (_isProgressed) {
                  const _dsCard = _dsEl.querySelector('.decision-summary');
                  if (_dsCard) _dsCard.classList.add('ds-secondary');
                }

                // ── Next Action + Pattern Notice + Decision Bar ────────────────
                renderNextAction(role);
                renderPatternNotice(role);
                renderDecisionBar(role);

                // ── Sticky Decision Bar ────────────────────────────────────────
                // Populate the sticky bar (shown via IntersectionObserver when DS scrolls out)
                {
                  const _sdbEl = document.getElementById('sticky-decision-bar');
                  if (_sdbEl) {
                    const _sdbColorMap = {
                      'Strong Fit':                'sdb-green',
                      'Hard No':                   'sdb-red',
                      'Worth Exploring':           'sdb-amber',
                      'Likely Not Worth Pursuing': 'sdb-amber',
                    };
                    const _sdbClass = _sdbColorMap[_dsOutcome] || '';
                    if (_sdbClass) _sdbEl.classList.add(_sdbClass);
                    // CV name filled after CV block; store for now
                    _sdbEl.dataset.outcome = _dsOutcome;
                    _sdbEl.dataset.action  = _dsAction;
                    // Will be updated when CV block runs
                    _sdbEl.innerHTML = `<div class="sticky-decision-inner">
                      <span class="sticky-decision-outcome">${esc(_dsOutcome)}</span>
                      <span class="sticky-decision-meta">
                        <span>Suggested: ${esc(_dsAction)}</span>
                        <span id="sticky-decision-cv-slot"></span>
                      </span>
                    </div>`;
                    // IntersectionObserver: show sticky bar when DS scrolls out of view
                    const _colCenter = document.getElementById('col-overview-body');
                    if (_colCenter && window.IntersectionObserver) {
                      const _sdbObs = new IntersectionObserver(entries => {
                        entries.forEach(entry => {
                          // Show sticky bar when decision card is scrolled OUT of view
                          _sdbEl.style.display = entry.isIntersecting ? 'none' : 'block';
                        });
                      }, { root: document.getElementById('col-overview-body') || _colCenter, threshold: 0 });
                      _sdbObs.observe(_dsEl);
                    }
                  }
                }

                // ── Jump Links ─────────────────────────────────────────────────
                {
                  const _jlEl = document.getElementById('doc-jump-links');
                  if (_jlEl) {
                    _jlEl.innerHTML = `<div class="jump-links-wrap">
                      <span class="jump-links-label">Jump to</span>
                      <button class="jump-link" data-jump="section-risks">Risks</button>
                      <span class="jump-link-sep">&middot;</span>
                      <button class="jump-link" data-jump="section-questions">Questions</button>
                      <span class="jump-link-sep">&middot;</span>
                      <button class="jump-link" data-jump="section-practical">Practical Details</button>
                    </div>`;
                    _jlEl.style.display = '';
                    // Smooth scroll on click (delegated)
                    _jlEl.addEventListener('click', e => {
                      const btn = e.target.closest('[data-jump]');
                      if (!btn) return;
                      const target = document.getElementById(btn.dataset.jump);
                      if (target) target.scrollIntoView({ behavior: 'smooth', block: 'start' });
                    });
                  }
                }

                // ── Questions emphasis for Maybe outcome ───────────────────────
                if (decision === 'Maybe') {
                  const _qEl = document.getElementById('section-questions');
                  if (_qEl) _qEl.classList.add('questions-maybe');
                }
              }
            }

            // ── Update sticky bar CV slot (CV is now inside Decision Summary card) ─
            {
              const _rcvSA   = match.output_json?.suggested_actions || {};
              const _rcvName = (_rcvSA.recommended_cv || '').trim();
              const _rcvIsHardNo = (document.getElementById('doc-decision-summary')
                ?.querySelector('.decision-summary')
                ?.classList.contains('ds-red')) || false;
              if (_rcvName && _rcvName !== 'Not stated' && !_rcvIsHardNo) {
                const _sdbCvSlot = document.getElementById('sticky-decision-cv-slot');
                if (_sdbCvSlot) {
                  _sdbCvSlot.innerHTML = `<span class="sticky-decision-sep">&middot;</span> CV: ${esc(_rcvName)}`;
                }
              }
            }

            // ── Back-fill Pattern Signals ──────────────────────────────────────
            {
              const _psEl = document.getElementById('doc-pattern-signals');
              if (_psEl && typeof allRoles !== 'undefined') {
                const _analysed = allRoles.filter(r => {
                  const fo = r.analysis?.full_output || r.latest_match_output;
                  return fo && typeof fo === 'object';
                });

                if (_analysed.length >= 2) {
                  const _sigs = [];

                  // Signal: production coding requirement in multiple roles
                  const _hardNoCount = _analysed.filter(r => {
                    const fo = r.analysis?.full_output || r.latest_match_output;
                    return fo && fo.hard_no === true;
                  }).length;
                  if (_hardNoCount >= 2) {
                    _sigs.push(`Production coding requirement present in ${_hardNoCount} of your analysed roles`);
                  }

                  // Signal: salary missing from most listings
                  const _noSalary = _analysed.filter(r => {
                    const fo = r.analysis?.full_output || r.latest_match_output;
                    const pd = fo?.practical_details;
                    return !pd?.salary_annual || pd.salary_annual === 'Not stated';
                  }).length;
                  if (_noSalary >= 2) {
                    _sigs.push(`Salary information absent from ${_noSalary} of ${_analysed.length} analysed roles`);
                  }

                  // Signal: reporting structure unspecified
                  const _noReporting = _analysed.filter(r => {
                    const fo = r.analysis?.full_output || r.latest_match_output;
                    const pd = fo?.practical_details;
                    return !pd?.reporting_line || pd.reporting_line === 'Not stated';
                  }).length;
                  if (_noReporting >= 2) {
                    _sigs.push(`Reporting structure unspecified in ${_noReporting} of ${_analysed.length} roles`);
                  }

                  // Signal: remote / hybrid majority
                  const _remoteHybrid = _analysed.filter(r =>
                    r.work_model === 'remote' || r.work_model === 'hybrid'
                  ).length;
                  if (_remoteHybrid >= 2 && _remoteHybrid > _analysed.length / 2) {
                    _sigs.push(`Majority of analysed roles (${_remoteHybrid} of ${_analysed.length}) offer remote or hybrid work`);
                  }

                  if (_sigs.length > 0) {
                    const _items = _sigs.slice(0, 3).map(s => `<li class="pattern-signal-item">${esc(s)}</li>`).join('');
                    _psEl.innerHTML = `<div class="pattern-signals">
                      <div class="pattern-signals-header">Pattern Signals</div>
                      <ul class="pattern-signals-list">${_items}</ul>
                    </div>`;
                    _psEl.style.display = '';
                  }
                }
              }
            }

            // ── Back-fill Preference Signal ────────────────────────────────────
            // Derives from repeated user behaviour on past roles.
            // Renders nothing if fewer than 3 past roles share a pattern with the current role.
            // Injected at top of analysis panel (inside the analysis flow, not the header zone).
            {
              if (typeof allRoles !== 'undefined' && match && match.output_json) {
                const _fo = match.output_json;

                // Extracts behavioural signals from a single role record.
                // Only includes signals that represent genuine user choices — NOT structural market patterns.
                // Salary and reporting structure are market patterns (captured by Pattern Signals instead).
                const _extractSigs = (workModel, fo) => {
                  const s = new Set();
                  // Work model — a genuine role-type preference (user actively filters on this)
                  if (workModel === 'remote' || workModel === 'hybrid') s.add('remote · hybrid');
                  else if (workModel === 'on-site' || workModel === 'onsite') s.add('onsite');
                  if (!fo || typeof fo !== 'object') return s;
                  // Production coding hard-no — clear behavioural avoidance pattern
                  if (fo.hard_no) s.add('production coding');
                  // NOTE: salary signals deliberately excluded here.
                  // Salary absence is a market pattern (already shown in Pattern Signals),
                  // not a behavioural preference of the user.
                  // Role archetype — genuine scope/seniority preferences
                  const _arch = (fo.role_archetype?.primary || '').toLowerCase();
                  if (/founding|early.stage|startup/i.test(_arch))              s.add('early-stage · founding');
                  if (/platform|systems|infrastructure/i.test(_arch))           s.add('platform · systems');
                  if (/squad|delivery/i.test(_arch))                            s.add('squad delivery');
                  if (/leadership|lead\b|head\b|director|manager/i.test(_arch)) s.add('leadership');
                  if (/design system/i.test(_arch))                             s.add('design systems');
                  return s;
                };

                // Categorise past roles (excluding current) into pursued vs avoided
                const _PURSUED_OUTCOMES = new Set(['applied','recruiter_replied','interviewed','offer_received','accepted']);
                const _AVOIDED_OUTCOMES = new Set(['skipped']);
                const _otherRoles = allRoles.filter(r => r.id !== role.id);

                const _pursued = _otherRoles.filter(r =>
                  r.analysis?.decision === 'Apply' || _PURSUED_OUTCOMES.has(r.outcome_state)
                );
                const _avoided = _otherRoles.filter(r =>
                  r.analysis?.decision === 'Skip' ||
                  _AVOIDED_OUTCOMES.has(r.outcome_state) ||
                  !!(r.analysis?.full_output?.hard_no || r.latest_match_output?.hard_no)
                );

                // Count signal frequencies across each behaviour group
                const _countSigs = roles => {
                  const counts = {};
                  for (const r of roles) {
                    const fo = r.analysis?.full_output || r.latest_match_output;
                    for (const sig of _extractSigs(r.work_model, fo)) {
                      counts[sig] = (counts[sig] || 0) + 1;
                    }
                  }
                  return counts;
                };
                const _pursuedCounts = _countSigs(_pursued);
                const _avoidedCounts = _countSigs(_avoided);

                // Extract signals from the current role (use live analysis output)
                const _currentSigs = _extractSigs(role.work_model, _fo);

                // Minimum 3 past roles must share a signal for it to qualify
                const _MIN = 3;
                const _alignSigs    = [];
                const _conflictSigs = [];
                for (const sig of _currentSigs) {
                  if ((_pursuedCounts[sig] || 0) >= _MIN)
                    _alignSigs.push({ sig, count: _pursuedCounts[sig] });
                  if ((_avoidedCounts[sig] || 0) >= _MIN)
                    _conflictSigs.push({ sig, count: _avoidedCounts[sig] });
                }
                _alignSigs.sort((a, b)    => b.count - a.count);
                _conflictSigs.sort((a, b) => b.count - a.count);

                // Build 2-part observational block — calm, factual, no scoring language
                // Only renders when signal reflects actual user behaviour (pursuit or avoidance),
                // not a structural market pattern.
                let _prefBodyHtml = '';
                if (_alignSigs.length > 0) {
                  // Pursuit pattern — user has consistently applied to/pursued these role types
                  const _sigs = _alignSigs.slice(0, 3);
                  const _labels = esc(_sigs.map(s => s.sig).join(' \u00b7 '));
                  const _line1 = _sigs.length === 1
                    ? `You\u2019ve usually pursued roles with ${_labels}.`
                    : `You\u2019ve usually pursued roles with: ${_labels}.`;
                  _prefBodyHtml =
                    `<p class="doc-prose" style="color:var(--text-muted);margin-bottom:6px;">${esc(_line1)}</p>` +
                    `<p class="doc-prose" style="color:var(--text-muted);">This role shares those patterns.</p>`;
                } else if (_conflictSigs.length > 0) {
                  // Avoidance pattern — user has consistently skipped roles with these traits
                  const _sigs = _conflictSigs.slice(0, 3);
                  const _labels = esc(_sigs.map(s => s.sig).join(' \u00b7 '));
                  const _line1 = _sigs.length === 1
                    ? `You\u2019ve often skipped roles with ${_labels}.`
                    : `You\u2019ve often skipped roles with: ${_labels}.`;
                  _prefBodyHtml =
                    `<p class="doc-prose" style="color:var(--text-muted);margin-bottom:6px;">${esc(_line1)}</p>` +
                    `<p class="doc-prose" style="color:var(--text-muted);">This role contains those signals.</p>`;
                }

                // Only render if there is something meaningful to show — insert inside analysis panel
                if (_prefBodyHtml && panel) {
                  const _prefSectionHtml =
                    `<div class="doc-section" id="pref-signal-section" style="padding-top:0;margin-bottom:0;">` +
                    `<div class="doc-section-heading">Preference Signal</div>` +
                    `${_prefBodyHtml}` +
                    `</div>`;
                  panel.insertAdjacentHTML('afterbegin', _prefSectionHtml);
                }
                // If no strong pattern → nothing rendered, panel unchanged
              }
            }
          } else {
            // No saved analysis — empty state with Generate button; raw JD goes to Role Record
            const rawJD = role.job_description_raw || '';
            if (rawJD) {
              // Put JD collapsible into the Role Record placeholder
              const jdPlaceholder = document.getElementById('role-record-jd-placeholder');
              if (jdPlaceholder) {
                jdPlaceholder.innerHTML = `<div class="doc-section" style="padding-top:0;">
                  <details>
                    <summary class="doc-section-heading" style="cursor:pointer;list-style:none;display:flex;align-items:center;gap:6px;">
                      <span style="font-size:11px;opacity:0.5;">▶</span> Original job description
                    </summary>
                    <p class="doc-prose" style="white-space:pre-wrap;margin-top:12px;">${esc(rawJD)}</p>
                  </details>
                </div>`;
              }
              panel.innerHTML = `
                <div class="doc-section">
                  <p class="doc-no-analysis" style="margin-bottom:14px;">No analysis saved for this role yet.</p>
                  <button id="btn-generate-analysis" class="btn-primary" style="font-size:13px;">Generate analysis</button>
                </div>`;

              const genBtn = document.getElementById('btn-generate-analysis');
              if (genBtn) {
                genBtn.addEventListener('click', async () => {
                  genBtn.disabled = true;
                  genBtn.textContent = 'Generating…';
                  try {
                    const analysis = await callAnalysisAPI(rawJD);
                    const { data: insertedMatch, error: insertErr } = await db.from('jd_matches').insert({
                      role_id:             role.id,
                      job_description_raw: rawJD,
                      jd_text:             rawJD,
                      company_name:        role.company_name,
                      role_title:          role.role_title,
                      job_url:             role.job_url || null,
                      selected_cv_ids:     [],
                      cv_version_ids:      [],
                      output_json:         analysis,
                    }).select('id').single();
                    if (insertErr) throw insertErr;
                    insertEvent(role.id, { event_type: 'analysis_saved', title: 'Analysis saved', ref_match_id: insertedMatch?.id || null });
                    const _dec1 = analysis.suggested_actions?.next_step || null;
                    createSnapshot(role.id, 'initial_analysis', 'Analysis recorded', {
                      stage:                            'JD Review',
                      decision:                         _dec1,
                      company_name:                     role.company_name,
                      role_title:                       role.role_title,
                      work_model:                       role.work_model || null,
                      location_text:                    role.location_text || null,
                      salary_text_raw:                  role.salary_text_raw || null,
                      raw_jd:                           rawJD,
                      fit_reality_summary:              analysis.fit_reality_summary              || null,
                      what_they_are_really_looking_for: analysis.what_they_are_really_looking_for || null,
                      what_you_would_actually_do:       analysis.what_you_would_actually_do       || null,
                      risks_and_unknowns:               analysis.risks_and_unknowns               || null,
                    });
                    if (_dec1) createSnapshot(role.id, 'decision_set', _decisionSnapTitle(_dec1), { stage: 'JD Review', decision: _dec1 });

                    // Auto-detect recruiter from JD (fire-and-forget)
                    runRecruiterAutoDetection(role, rawJD).catch(() => {});

                    let _html2 = renderMatchOutput(analysis);
                    _html2 += `
                      <div class="rw-card rw-card--full" style="margin-top:4px;">
                        <details>
                          <summary class="doc-section-heading" style="cursor:pointer;list-style:none;display:flex;align-items:center;gap:6px;">
                            <span style="font-size:11px;opacity:0.5;">▶</span> Original job description
                          </summary>
                          <p class="doc-prose" style="white-space:pre-wrap;margin-top:12px;">${esc(rawJD)}</p>
                        </details>
                      </div>`;
                    panel.innerHTML = _html2;
                    _initCompSnapshot(panel);
                    renderFitDecisionPanel(role);
                    // Inject deep context into Role Record
                    const _deepElA = document.getElementById('role-record-deep-analysis');
                    if (_deepElA) _deepElA.innerHTML = renderDeepContextHtml(analysis);
                    renderDecisionBar(role);
                  } catch (genErr) {
                    genBtn.disabled = false;
                    genBtn.textContent = 'Generate analysis';
                    const errP = document.createElement('p');
                    errP.style.cssText = 'color:#c0392b;font-size:12px;margin-top:8px;';
                    errP.textContent = 'Failed to generate: ' + (genErr.message || 'Unknown error');
                    genBtn.insertAdjacentElement('afterend', errP);
                  }
                });
              }
            } else {
              panel.innerHTML = `<p class="doc-no-analysis">No analysis saved for this role yet.</p>`;
            }
          }
        } catch (_) {
          // On error — error empty state; raw JD in collapsible + Generate button if available
          const rawJD = role.job_description_raw || '';
          const collapsibleJD = rawJD ? `
            <div class="doc-section" style="margin-top:24px;">
              <details>
                <summary class="doc-section-heading" style="cursor:pointer;list-style:none;display:flex;align-items:center;gap:6px;">
                  <span style="font-size:11px;opacity:0.5;">▶</span> Original job description
                </summary>
                <p class="doc-prose" style="white-space:pre-wrap;margin-top:12px;">${esc(rawJD)}</p>
              </details>
            </div>` : '';

          if (rawJD) {
            panel.innerHTML = `
              <div class="doc-section">
                <p class="doc-no-analysis" style="margin-bottom:14px;">Couldn't load saved analysis right now.</p>
                <button id="btn-generate-analysis" class="btn-primary" style="font-size:13px;">Generate analysis</button>
              </div>
              ${collapsibleJD}`;

            const genBtn = document.getElementById('btn-generate-analysis');
            if (genBtn) {
              genBtn.addEventListener('click', async () => {
                genBtn.disabled = true;
                genBtn.textContent = 'Generating…';
                try {
                  const analysis = await callAnalysisAPI(rawJD);
                  const { data: insertedMatch, error: insertErr } = await db.from('jd_matches').insert({
                    role_id:             role.id,
                    job_description_raw: rawJD,
                    jd_text:             rawJD,
                    company_name:        role.company_name,
                    role_title:          role.role_title,
                    job_url:             role.job_url || null,
                    selected_cv_ids:     [],
                    cv_version_ids:      [],
                    output_json:         analysis,
                  }).select('id').single();
                  if (insertErr) throw insertErr;
                  insertEvent(role.id, { event_type: 'analysis_saved', title: 'Analysis saved', ref_match_id: insertedMatch?.id || null });
                  const _dec2 = analysis.suggested_actions?.next_step || null;
                  createSnapshot(role.id, 'initial_analysis', 'Analysis recorded', {
                    stage:                            'JD Review',
                    decision:                         _dec2,
                    company_name:                     role.company_name,
                    role_title:                       role.role_title,
                    work_model:                       role.work_model || null,
                    location_text:                    role.location_text || null,
                    salary_text_raw:                  role.salary_text_raw || null,
                    raw_jd:                           rawJD,
                    fit_reality_summary:              analysis.fit_reality_summary              || null,
                    what_they_are_really_looking_for: analysis.what_they_are_really_looking_for || null,
                    what_you_would_actually_do:       analysis.what_you_would_actually_do       || null,
                    risks_and_unknowns:               analysis.risks_and_unknowns               || null,
                  });
                  if (_dec2) createSnapshot(role.id, 'decision_set', _decisionSnapTitle(_dec2), { stage: 'JD Review', decision: _dec2 });

                  // Auto-detect recruiter from JD (fire-and-forget)
                  runRecruiterAutoDetection(role, rawJD).catch(() => {});

                  let _html3 = renderMatchOutput(analysis);
                  _html3 += `
                    <div class="rw-card rw-card--full" style="margin-top:4px;">
                      <details>
                        <summary class="doc-section-heading" style="cursor:pointer;list-style:none;display:flex;align-items:center;gap:6px;">
                          <span style="font-size:11px;opacity:0.5;">▶</span> Original job description
                        </summary>
                        <p class="doc-prose" style="white-space:pre-wrap;margin-top:12px;">${esc(rawJD)}</p>
                      </details>
                    </div>`;
                  panel.innerHTML = _html3;
                  _initCompSnapshot(panel);
                  renderFitDecisionPanel(role);
                  // Inject deep context into Role Record
                  const _deepElB = document.getElementById('role-record-deep-analysis');
                  if (_deepElB) _deepElB.innerHTML = renderDeepContextHtml(analysis);
                  renderDecisionBar(role);
                } catch (genErr) {
                  genBtn.disabled = false;
                  genBtn.textContent = 'Generate analysis';
                  const errP = document.createElement('p');
                  errP.style.cssText = 'color:#c0392b;font-size:12px;margin-top:8px;';
                  errP.textContent = 'Failed to generate: ' + (genErr.message || 'Unknown error');
                  genBtn.insertAdjacentElement('afterend', errP);
                }
              });
            }
          } else {
            panel.innerHTML = `<p class="doc-no-analysis">Couldn't load saved analysis right now.</p>`;
          }
        }
      })();

      // ── Role memory — load timeline async after main doc is rendered ──────
      (async () => {
        const memorySec = document.getElementById('role-memory-section');
        if (!memorySec) return;
        const events = await loadTimeline(role.id);
        renderTimelineSection(events, role.id, memorySec);
      })();

      // Load and render role snapshots asynchronously
      (async () => {
        const snapshotsSec = document.getElementById('role-snapshots-section');
        if (!snapshotsSec) return;
        const snapshots = await loadSnapshots(role.id);
        renderSnapshotsSection(snapshots, snapshotsSec);
      })();

      // Load and render outcome learning asynchronously
      (async () => {
        const outcomeSec = document.getElementById('role-outcome-section');
        if (!outcomeSec) return;
        const learnings = await loadLearnings(role.id);
        renderOutcomeSection(role, learnings, outcomeSec);
      })();
    }

    // ─── Right: Decision Rail ─────────────────────────────────────────────────
    // Stage steps — process progression only, never sets outcome.
    // "Saved" is not a stage — the role is automatically saved when the JD is pasted.
    const RAIL_STAGE_STEPS = [
      { label: 'JD Review',        status: 'active',      stage: 'JD Review' },
      { label: 'Applied',          status: 'applied',     stage: 'Applied' },
      { label: 'Recruiter Screen', status: 'in_progress', stage: 'Recruiter Screen' },
      { label: 'Hiring Manager',   status: 'in_progress', stage: 'Hiring Manager' },
      { label: 'Panel',            status: 'in_progress', stage: 'Panel' },
      { label: 'Final',            status: 'in_progress', stage: 'Final' },
      { label: 'Offer',            status: 'in_progress', stage: 'Offer' },
    ];

    // Outcomes — how the role journey ended (separate from stage)
    // Skipped ≠ Withdrew: never conflate
    // Progress outcomes (applied/interviewing/offer_received) appear first; terminal outcomes follow.
    const RAIL_OUTCOMES = [
      { label: 'Applied',        outcomeState: 'applied',        hasReason: false, progress: true },
      { label: 'Interviewing',   outcomeState: 'interviewing',   hasReason: false, progress: true },
      { label: 'Offer received', outcomeState: 'offer_received', hasReason: false, progress: true },
      { label: 'Rejected',       outcomeState: 'rejected',       hasReason: true  },
      { label: 'No response',    outcomeState: 'no_response',    hasReason: false, desc: 'Applied — nothing came back' },
      { label: 'Ghosted',        outcomeState: 'ghosted',        hasReason: false, desc: 'Had contact, then they went silent' },
      { label: 'Skipped',        outcomeState: 'skipped',        hasReason: true  },
      { label: 'Withdrew',       outcomeState: 'withdrew',       hasReason: true  },
      { label: 'Offer Accepted', outcomeState: 'offer_accepted', hasReason: false },
      { label: 'Closed',         outcomeState: 'closed',         hasReason: false },
    ];

    // Returns the index of the current stage in RAIL_STAGE_STEPS (-1 = none recorded)
    function currentStageIndex(role) {
      if (!role.role_updates || !role.role_updates.length) return -1;
      // Walk updates newest-first; only consider event_type='stage' rows
      // (outcome rows must never influence the current stage position)
      for (const u of role.role_updates) {
        if (u.event_type && u.event_type !== 'stage') continue;
        // Normalize legacy 'Reviewed' to 'JD Review'
        const sr = (u.stage_reached === 'Reviewed' ? 'JD Review' : u.stage_reached) || '';
        const idx = RAIL_STAGE_STEPS.findIndex(s =>
          s.stage.toLowerCase() === sr.toLowerCase()
        );
        if (idx !== -1) return idx;
      }
      return -1;
    }

    // Build stepper HTML. locked = true when outcome is set (all steps read-only).
    // outcomeLabel: when provided, truncates timeline at effectiveIdx and appends ✕ outcome step.
    // All steps except the current one are clickable when not locked.
    function buildStepperItems(stageIdx, locked, _outcomeLabel) {
      // _outcomeLabel kept for call-site compat; outcomes now render in their own chip row.
      // Treat -1 (no stage updates yet) as index 0 so JD Review renders as current.
      const effectiveIdx = stageIdx < 0 ? 0 : stageIdx;

      return RAIL_STAGE_STEPS.map((s, i) => {
        const isCurrent = i === effectiveIdx;
        const isDone    = i < effectiveIdx;
        const clickable = !locked && !isCurrent;

        const stateClass = isCurrent ? 'current' : isDone ? 'done' : 'upcoming';
        const classes = [
          'rail-chip', 'rail-step',
          stateClass,
          clickable ? 'clickable' : '',
          locked    ? 'locked'    : '',
        ].filter(Boolean).join(' ');

        const attrs = clickable
          ? `data-status="${esc(s.status)}" data-stage="${esc(s.stage)}" tabindex="0"`
          : '';

        return `<div class="${classes}" ${attrs}>${esc(s.label)}</div>`;
      }).join('');
    }

    // Wire click + keyboard handlers onto .rail-step.clickable inside #rail-stepper
    function wireStepperHandlers(roleId) {
      const stepperEl = document.getElementById('rail-stepper');
      if (!stepperEl) return;
      stepperEl.querySelectorAll('.rail-step.clickable').forEach(step => {
        const handler = () => markStage(roleId, step.dataset.status, step.dataset.stage);
        step.addEventListener('click', handler);
        step.addEventListener('keydown', e => {
          if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); handler(); }
        });
      });
    }

    // Returns a human-readable label for an outcome state (for stepper termination step)
    function outcomeDisplayLabel(outcomeState) {
      return RAIL_OUTCOMES.find(o => o.outcomeState === outcomeState)?.label || outcomeState || '';
    }

    // Returns the decision-accent key for the stepper data attribute.
    // 'green' | 'amber' | 'red' | 'neutral'
    // Reverts to 'neutral' once the role reaches Recruiter Screen or later
    // (stageIdx >= 2) so the decision colour doesn't conflict with real interview progress.
    function stepperDecisionAccent(role, stageIdx) {
      const effectiveIdx = stageIdx < 0 ? 0 : stageIdx;
      if (effectiveIdx >= 2) return 'neutral'; // Recruiter Screen or later
      const fo  = role.latest_match_output || role.analysis?.full_output;
      const dec = role.analysis?.decision;
      if (fo?.hard_no || dec === 'Skip') return 'red';
      if (dec === 'Apply')               return 'green';
      if (dec === 'Maybe')               return 'amber';
      return 'neutral';
    }

    // ─── Your Decision panel ─────────────────────────────────────────────────
    // Lightweight fit assessment panel. Stored in roles.fit_assessment +
    // roles.fit_reasons. Separate from stage tracking — captures personal
    // "does this role fit me?" signal for later pattern recognition.

    const FIT_REASONS = [
      { id: 'salary',       label: 'Salary' },
      { id: 'ownership',    label: 'Ownership' },
      { id: 'domain',       label: 'Domain' },
      { id: 'team',         label: 'Team structure' },
      { id: 'location',     label: 'Location' },
      { id: 'coding',       label: 'Coding expectations' },
      { id: 'stage',        label: 'Company stage' },
    ];

    function renderFitDecisionPanel(role, containerEl) {
      const el = containerEl || document.getElementById('fit-decision-panel');
      if (!el) return;

      const current = role.fit_assessment || null; // 'fits' | 'doesnt_fit' | null
      const reasons = Array.isArray(role.fit_reasons) ? role.fit_reasons : [];

      const _btn = (val, label, cls) =>
        `<button class="fd-choice-btn ${cls}${current === val ? ' fd-choice-btn--active' : ''}" data-val="${val}">${label}</button>`;

      const reasonsHtml = (current && current !== null)
        ? `<div class="fd-reasons-block">
            <div class="fd-reasons-label">What influenced this?</div>
            <div class="fd-reasons-chips">
              ${FIT_REASONS.map(r =>
                `<button class="fd-reason-chip${reasons.includes(r.id) ? ' fd-reason-chip--active' : ''}" data-reason="${r.id}">${esc(r.label)}</button>`
              ).join('')}
            </div>
          </div>`
        : '';

      const timestampHtml = role.fit_assessed_at
        ? `<div class="fd-timestamp">Last recorded ${relativeTime(role.fit_assessed_at)}</div>`
        : '';

      el.innerHTML = `
        <div class="fd-panel">
          <div class="fd-heading">Your Decision</div>
          <div class="fd-choices">
            ${_btn('fits',      'This role fits me',          'fd-choice-btn--fits')}
            ${_btn('doesnt_fit','This role doesn\'t fit me',  'fd-choice-btn--nope')}
            ${_btn(null,        'Undecided',                  'fd-choice-btn--undecided')}
          </div>
          ${reasonsHtml}
          ${timestampHtml}
          <div class="fd-saving-msg" id="fd-saving-msg"></div>
        </div>`;

      // Wire decision buttons
      el.querySelectorAll('.fd-choice-btn').forEach(btn => {
        btn.addEventListener('click', async () => {
          const newVal = btn.dataset.val || null;
          const toggle = newVal === current; // clicking active = toggle off to null
          await _saveFitAssessment(role, toggle ? null : newVal, role.fit_reasons || []);
        });
      });

      // Wire reason chips (only visible when assessment is set)
      el.querySelectorAll('.fd-reason-chip').forEach(chip => {
        chip.addEventListener('click', async () => {
          const rid = chip.dataset.reason;
          const cur = Array.isArray(role.fit_reasons) ? [...role.fit_reasons] : [];
          const updated = cur.includes(rid) ? cur.filter(r => r !== rid) : [...cur, rid];
          await _saveFitAssessment(role, role.fit_assessment, updated);
        });
      });
    }

    async function _saveFitAssessment(role, fitAssessment, fitReasons) {
      const msgEl = document.getElementById('fd-saving-msg');
      if (msgEl) msgEl.textContent = 'Saving…';

      try {
        const { error } = await db.from('roles').update({
          fit_assessment: fitAssessment || null,
          fit_reasons:    fitReasons && fitReasons.length > 0 ? fitReasons : null,
          fit_assessed_at: new Date().toISOString(),
        }).eq('id', role.id);
        if (error) throw error;

        // Update in-memory role
        role.fit_assessment  = fitAssessment || null;
        role.fit_reasons     = fitReasons && fitReasons.length > 0 ? fitReasons : [];
        role.fit_assessed_at = new Date().toISOString();

        // Re-render the panel with updated state
        const panelEl = document.getElementById('fit-decision-panel');
        renderFitDecisionPanel(role, panelEl);

        if (msgEl) {
          msgEl.textContent = 'Saved';
          setTimeout(() => { const m = document.getElementById('fd-saving-msg'); if (m) m.textContent = ''; }, 1500);
        }
      } catch (e) {
        if (msgEl) msgEl.textContent = 'Error saving';
      }
    }

    function renderRail(role) {
      _ensureOverviewLowerCards();
      const chipsEl = document.getElementById('role-chips-section');
      _setRailVisible(true); // show role-chips-section (and col-rail-section) when a role is selected

      const currentStage   = currentStageLabel(role);
      const currentOutcome = role.outcome_state || null;
      const stageIdx       = currentStageIndex(role);
      const locked         = !!currentOutcome; // outcome locks the progress stepper
      // Human-readable outcome label for stepper termination step (null when no outcome)
      const _outcomeStepLabel  = locked ? outcomeDisplayLabel(currentOutcome) : null;
      // Decision accent for dot colouring (reverts to neutral at Recruiter Screen+)
      const _decisionAccent    = stepperDecisionAccent(role, stageIdx);

      // ── Re-open button (only when outcome is set) ─────────────────
      const reopenHtml = locked
        ? `<button class="rail-reopen-btn" id="btn-reopen-role">Re-open role</button>`
        : '';

      // ── Outcome chips ─────────────────────────────────────────────────────
      const outcomeChips = RAIL_OUTCOMES.map(o => {
        const isSelected = currentOutcome === o.outcomeState;
        return `<div class="rail-chip rail-outcome-item${isSelected ? ' selected' : ''}" data-outcome="${esc(o.outcomeState)}" data-has-reason="${o.hasReason}" tabindex="0">${esc(o.label)}</div>`;
      }).join('');

      // ── Stage + Outcome chips + Admin → role-chips-section (single card) ───
      if (chipsEl) {
        chipsEl.innerHTML = `
          <div class="rail-chips-area">
            <div class="rail-chips-row">
              <span class="rail-chips-label">Stage</span>
              <div class="rail-chips-list" id="rail-stepper" data-decision-accent="${_decisionAccent}">
                ${buildStepperItems(stageIdx, locked)}
              </div>
            </div>

            <div class="rail-chips-row">
              <span class="rail-chips-label">Outcome</span>
              <div class="rail-chips-list${locked ? ' outcome-disabled' : ''}" id="rail-outcome-list">
                ${outcomeChips}
              </div>
            </div>

            ${reopenHtml}
            <div class="rail-undo-bar" id="rail-undo-bar"></div>
            <div class="rail-outcome-form" id="rail-outcome-form"></div>
            <div class="rail-confirm" id="rail-confirm"></div>

            <div class="rail-admin">
              <button class="rail-admin-btn" id="btn-archive-role">Archive role</button>
              <div class="rail-admin-confirm" id="archive-confirm"></div>
              <button class="rail-admin-btn danger" id="btn-delete-role">Delete role</button>
              <div class="rail-admin-confirm" id="delete-confirm"></div>
            </div>
          </div>
        `;

        // Re-open role (when outcome is set)
        document.getElementById('btn-reopen-role')?.addEventListener('click', () => reopenRole(role.id));

        // Outcome chip click handlers
        chipsEl.querySelectorAll('.rail-outcome-item').forEach(item => {
          item.addEventListener('click', () => {
            const outcomeState = item.dataset.outcome;
            const hasReason    = item.dataset.hasReason === 'true';
            if (hasReason) {
              showOutcomeReasonForm(role.id, outcomeState);
            } else {
              setOutcome(role.id, outcomeState, null);
            }
          });
        });

        // Admin action handlers
        document.getElementById('btn-archive-role').addEventListener('click', () => archiveRole(role.id));
        document.getElementById('btn-delete-role').addEventListener('click', () => deleteRole(role.id));
      }

      // Wire stage stepper (all clickable steps, not just upcoming)
      if (!locked) wireStepperHandlers(role.id);
    }

    // ─── Archive role ────────────────────────────────────────────────────────
    // Archive is visibility-only: sets archived = true.
    // Does NOT touch stage or outcome state.
    async function archiveRole(roleId) {
      const btn       = document.getElementById('btn-archive-role');
      const confirmEl = document.getElementById('archive-confirm');
      if (btn) btn.disabled = true;
      try {
        const { error } = await db.from('roles').update({ archived: true }).eq('id', roleId);
        if (error) throw error;
        insertEvent(roleId, { event_type: 'role_archived', title: 'Archived' });
        allRoles = allRoles.map(r => r.id === roleId ? { ...r, archived: true } : r);
        renderInbox(allRoles);
        selectedRoleId = null;
        document.getElementById('col-overview-cards').innerHTML =
          `<div class="doc-empty">${NAV_EMPTY_STATES[currentNav] || ''}</div>`;
        document.getElementById('col-rail-section').innerHTML = '';
        _setRailVisible(false);
        _resetChatPanel();
      } catch (e) {
        if (btn) btn.disabled = false;
        if (confirmEl) confirmEl.textContent = e.message || 'Archive failed.';
      }
    }

    // ─── Delete role ─────────────────────────────────────────────────────────
    async function deleteRole(roleId) {
      const btn       = document.getElementById('btn-delete-role');
      const confirmEl = document.getElementById('delete-confirm');
      if (!btn) return;

      // Two-step confirm: first click arms it, second click executes
      // Stable toggle — no timeout, stays armed until cancelled or executed
      if (btn.dataset.armed !== 'true') {
        btn.dataset.armed = 'true';
        btn.textContent = 'Confirm delete';
        btn.style.background = '#FEF2F2';
        if (confirmEl) {
          confirmEl.innerHTML = 'This cannot be undone. <a href="#" id="delete-cancel-link" style="color:var(--text-muted);text-decoration:underline;">Cancel</a>';
          document.getElementById('delete-cancel-link')?.addEventListener('click', e => {
            e.preventDefault();
            btn.dataset.armed = 'false';
            btn.textContent = 'Delete role';
            btn.style.background = '';
            if (confirmEl) confirmEl.textContent = '';
          });
        }
        return;
      }

      btn.disabled = true;
      btn.textContent = 'Deleting…';
      if (confirmEl) confirmEl.textContent = '';
      try {
        // Delete child rows first (FK constraints, no cascade on these tables)
        await db.from('role_updates').delete().eq('role_id', roleId);
        await db.from('analyses').delete().eq('role_id', roleId);
        await db.from('status_events').delete().eq('role_id', roleId);
        // jd_matches.role_id has ON DELETE SET NULL — no manual delete needed
        const { error } = await db.from('roles').delete().eq('id', roleId);
        if (error) throw error;

        allRoles = allRoles.filter(r => r.id !== roleId);
        renderInbox(allRoles);
        selectedRoleId = null;
        document.getElementById('col-overview-cards').innerHTML =
          `<div class="doc-empty">${NAV_EMPTY_STATES[currentNav] || ''}</div>`;
        document.getElementById('col-rail-section').innerHTML = '';
        _setRailVisible(false);
        _resetChatPanel();
      } catch (e) {
        btn.disabled = false;
        btn.textContent = 'Delete role';
        btn.style.background = '';
        btn.dataset.armed = 'false';
        if (confirmEl) confirmEl.textContent = e.message || 'Delete failed.';
      }
    }

    // ─── Mark stage (process progression only — never sets outcome) ──────────
    // Appends a new role_updates row; history is NEVER deleted.
    // Undo inserts a corrective row reverting to the previous stage,
    // preserving the full audit trail.
    async function markStage(roleId, status, stageReached) {
      // Capture the stage we're leaving BEFORE inserting anything
      const roleBeforeMove = allRoles.find(r => r.id === roleId);
      const prevStageName  = roleBeforeMove ? currentStageLabel(roleBeforeMove) : null;
      const hasPrevStage   = !!prevStageName;

      // Disable all interactive rail elements during the async write
      document.querySelectorAll('.rail-step.clickable').forEach(b => { b.disabled = true; });
      const _outcomeList1 = document.getElementById('rail-outcome-list');
      if (_outcomeList1) _outcomeList1.classList.add('outcome-disabled');

      try {
        // Insert the forward move row; get back its id for potential undo
        const { data: insertedRow, error } = await db.from('role_updates').insert({
          role_id:       roleId,
          event_type:    'stage',
          status:        'in_progress',
          stage_reached: stageReached,
          note:          null,
        }).select('id').single();
        if (error) throw error;

        const insertedId = insertedRow?.id || null;

        // Snapshot for each stage reached — type keyed by stage name
        if (stageReached) {
          const _snapRole = allRoles.find(r => r.id === roleId);
          const _snapDecision = _snapRole?.analysis?.decision ||
            _snapRole?.latest_match_output?.suggested_actions?.next_step || null;
          const _stageNorm = (stageReached || '').toLowerCase().replace(/\s+/g, '_');
          const _stageSnapMap = {
            'applied':           { type: 'stage_applied',          title: 'Application submitted' },
            'recruiter_screen':  { type: 'stage_recruiter_screen', title: 'Recruiter replied'     },
            'hiring_manager':    { type: 'stage_interview',        title: 'Interview scheduled'   },
            'panel':             { type: 'stage_interview',        title: 'Interview scheduled'   },
            'final':             { type: 'stage_interview',        title: 'Interview scheduled'   },
            'offer':             { type: 'stage_offer',            title: 'Offer received'        },
          };
          const _snapDef = _stageSnapMap[_stageNorm];
          if (_snapDef) {
            createSnapshot(roleId, _snapDef.type, _snapDef.title, {
              stage:    stageReached,
              decision: _snapDecision,
            });
          } else if (/hiring\s*manager|panel|final|interview/i.test(stageReached)) {
            // Fallback for legacy naming
            createSnapshot(roleId, 'interview_stage', 'Interview stage reached', {
              stage:    stageReached,
              decision: _snapDecision,
            });
          }
        }

        // ── Analytics event — only when user marks a role as Applied ───────────
        // 'applied' is distinct from user_decision='apply' (intent vs action).
        // Other stage moves (Recruiter Screen, Interview etc.) are not user decisions.
        if (stageReached && stageReached.toLowerCase() === 'applied') {
          _logDecisionEvent({
            decisionType:  'applied',
            roleId,
            previousState: prevStageName ?? null,
            newState:      stageReached,
            sourceSurface: 'progress_stepper',
          });
        }
        // ─────────────────────────────────────────────────────────────────────

        // Build new local entry
        const newEntry = {
          id:            insertedId || crypto.randomUUID(),
          role_id:       roleId,
          event_type:    'stage',
          status:        'in_progress',
          stage_reached: stageReached,
          note:          null,
          created_at:    new Date().toISOString(),
        };

        // Update local state (newest first)
        allRoles = allRoles.map(r => {
          if (r.id !== roleId) return r;
          r.role_updates.unshift(newEntry);
          return r;
        });

        // Refresh inbox label
        renderInbox(allRoles);

        // Update stage display text in rail header
        const stageDisplay = document.getElementById('rail-stage-display');
        if (stageDisplay) stageDisplay.textContent = stageReached;

        // Re-render stepper in-place with new position
        const updatedRole = allRoles.find(r => r.id === roleId);
        if (updatedRole) {
          const newIdx    = currentStageIndex(updatedRole);
          const stepperEl = document.getElementById('rail-stepper');
          if (stepperEl) {
            stepperEl.innerHTML = buildStepperItems(newIdx, false);
            stepperEl.dataset.decisionAccent = stepperDecisionAccent(updatedRole, newIdx);
            wireStepperHandlers(roleId);
          }
        }

        // ── Workspace: keep current_stage in sync + fire stage event ──────────
        // 1. Keep roles.current_stage column current so _wsBuildPrep always reads
        //    the right value and page refreshes load the correct stage.
        db.from('roles').update({ current_stage: stageReached }).eq('id', roleId).catch(() => {});

        // 2. Patch local allRoles so _wsBuildPrep sees the new stage without a refetch.
        allRoles = allRoles.map(r => r.id === roleId ? { ...r, current_stage: stageReached } : r);

        // 3. Log the stage move as a role_interaction — durable workspace memory.
        wsAddInteraction(roleId, {
          interaction_type: 'other',
          summary:          `Stage moved to ${stageReached}`,
          person_id:        null,
          raw_content:      null,
        }).catch(() => {});

        // 4. If workspace is currently open for this role, append a timeline marker
        //    and refresh any existing preparation artefact (update in place, never force-create).
        if (selectedRoleId === roleId) {
          const _wsTimeline = document.getElementById('ws-timeline');
          if (_wsTimeline) {
            _wsAppend(_wsTimeline, _wsStageEventHtml(stageReached));
            wsLoadMemory(roleId).then(mem => {
              const hasPrepArtifact = mem.artifacts.some(a => a.artifact_type === 'preparation');
              if (hasPrepArtifact) {
                const _liveRole = allRoles.find(r => r.id === roleId);
                if (_liveRole) _wsTriggerPrep(_liveRole, _wsTimeline).catch(() => {});
              }
            }).catch(() => {});
          }
        }

        // ── Undo bar ──────────────────────────────────────────────────
        // History is always preserved. Undo writes a corrective stage row
        // (prevStageName) rather than deleting the forward row.
        const undoBar = document.getElementById('rail-undo-bar');
        if (undoBar) {
          let undoTimer = null;

          undoBar.innerHTML = `
            <span>Moved to ${esc(stageReached)}.
              <button id="rail-undo-btn"
                style="background:none;border:none;padding:0;font-size:11.5px;color:var(--accent,#2563EB);cursor:pointer;font-family:var(--font);text-decoration:underline;margin-left:4px;">
                Undo
              </button>
            </span>`;

          document.getElementById('rail-undo-btn')?.addEventListener('click', async () => {
            if (undoTimer) clearTimeout(undoTimer);
            undoBar.innerHTML = '<span>Reverting\u2026</span>';

            try {
              if (hasPrevStage) {
                // Insert a corrective row reverting to the previous stage
                const { data: revertRow, error: revertErr } = await db.from('role_updates').insert({
                  role_id:       roleId,
                  event_type:    'stage',
                  status:        'in_progress',
                  stage_reached: prevStageName,
                  note:          'Correction',
                }).select('id').single();
                if (revertErr) throw revertErr;

                const revertEntry = {
                  id:            revertRow?.id || crypto.randomUUID(),
                  role_id:       roleId,
                  event_type:    'stage',
                  status:        'in_progress',
                  stage_reached: prevStageName,
                  note:          'Correction',
                  created_at:    new Date().toISOString(),
                };
                allRoles = allRoles.map(r => {
                  if (r.id !== roleId) return r;
                  r.role_updates.unshift(revertEntry);
                  return r;
                });
              } else {
                // No meaningful previous stage (brand-new role): delete the forward row
                if (insertedId) {
                  await db.from('role_updates').delete().eq('id', insertedId);
                }
                allRoles = allRoles.map(r => {
                  if (r.id !== roleId) return r;
                  r.role_updates = r.role_updates.filter(u => u.id !== newEntry.id);
                  return r;
                });
              }

              renderInbox(allRoles);

              // Re-render stepper to reverted position
              const revertedRole = allRoles.find(r => r.id === roleId);
              if (revertedRole) {
                const revertedIdx = currentStageIndex(revertedRole);
                const stepperEl   = document.getElementById('rail-stepper');
                if (stepperEl) {
                  stepperEl.innerHTML = buildStepperItems(revertedIdx, false);
                  stepperEl.dataset.decisionAccent = stepperDecisionAccent(revertedRole, revertedIdx);
                  wireStepperHandlers(roleId);
                }
                const sd = document.getElementById('rail-stage-display');
                if (sd) sd.textContent = currentStageLabel(revertedRole);
              }
              undoBar.innerHTML = '';
            } catch (e) {
              undoBar.innerHTML = `<span style="color:#c0392b;">Undo failed: ${esc(e.message)}</span>`;
            }
          });

          // Auto-dismiss after 5 seconds
          undoTimer = setTimeout(() => { if (undoBar) undoBar.innerHTML = ''; }, 5000);
        }

      } catch (e) {
        const confirmEl = document.getElementById('rail-confirm');
        if (confirmEl) confirmEl.textContent = 'Error: ' + e.message;
      } finally {
        // Re-enable outcome list (stepper handlers are re-wired above)
        const _outcomeList2 = document.getElementById('rail-outcome-list');
        if (_outcomeList2) _outcomeList2.classList.remove('outcome-disabled');
      }
    }

    // ─── Decision Capture ─────────────────────────────────────────────────────
    // Renders a 3-button verdict card into #ws-decision-capture.
    // Reflects the role's current verdict_state ('fits'|'not_for_me'|'undecided'|null).
    // Clicking a selected button deselects (clears to null); clicking another sets it.
    // If the role is nudge-eligible, also renders the Nudge Card below (Phase 6).
    function _renderDecisionCapture(role) {
      _ensureOverviewLowerCards();
      const el = document.getElementById('ws-decision-capture');
      if (!el) return;
      if (!role) { el.style.display = 'none'; el.innerHTML = ''; return; }

      const state = role.verdict_state || null;
      const opts = [
        { label: 'This fits me', value: 'fits'       },
        { label: 'Not for me',   value: 'not_for_me' },
        { label: 'Undecided',    value: 'undecided'  },
      ];

      // Build nudge card HTML if role is eligible (Phase 6)
      const _nudgeHtml = _isNudgeEligible(role) ? `
        <div class="ws-nudge-card">
          <div class="ws-nudge-label">What happened?</div>
          <div class="ws-nudge-body">You marked this as a fit — did anything come of it?</div>
          <div class="ws-nudge-buttons">
            <button class="ws-nudge-btn" data-nudge-action="applied">I applied</button>
            <button class="ws-nudge-btn" data-nudge-action="interviewing">In conversation</button>
            <button class="ws-nudge-btn" data-nudge-action="no_response">Nothing came back</button>
            <button class="ws-nudge-btn ws-nudge-btn--soft" data-nudge-action="snooze">Remind me later</button>
          </div>
        </div>
      ` : '';

      el.style.display = '';
      el.innerHTML = `
        <div class="ws-dc-card">
          <div class="ws-dc-label">My verdict</div>
          <div class="ws-dc-buttons">
            ${opts.map(o => `
              <button class="ws-dc-btn${state === o.value ? ' ws-dc-btn--selected' : ''}"
                      data-dc-val="${esc(o.value)}">${esc(o.label)}</button>
            `).join('')}
          </div>
        </div>
        ${_nudgeHtml}
      `;

      el.querySelectorAll('.ws-dc-btn').forEach(btn => {
        btn.addEventListener('click', () => {
          const newState = btn.dataset.dcVal;
          // Clicking the active selection clears it; otherwise set the new state
          setDecision(role.id, newState === state ? null : newState);
        });
      });

      // Wire nudge action buttons (Phase 7)
      el.querySelectorAll('.ws-nudge-btn').forEach(btn => {
        btn.addEventListener('click', () => _handleNudgeAction(role.id, btn.dataset.nudgeAction));
      });
    }

    // ─── Decision Layer V1 — Blocker detection ────────────────────────────────
    // Controlled set of blocker types the system can detect from analysis data.
    const BLOCKER_DEFS = {
      production_coding: 'Production coding required',
      salary_missing:    'Salary not stated',
      hybrid_onsite:     'Hybrid / on-site requirement',
      scope_unclear:     'Scope unclear',
      domain_concern:    'Domain or product concern',
      marketing_heavy:   'Marketing-heavy',
    };

    // Analyses a role's analysis output to surface likely blockers.
    // Only produces blockers that can be inferred reliably — never invents.
    // Returns: Array<{ key, label, evidence: string|null }>
    function _detectBlockers(role) {
      if (!role) return [];
      const output  = role.latest_match_output || role.analysis || {};
      const pd      = output.practical_details  || {};
      const fs      = Array.isArray(output.friction_signals)   ? output.friction_signals   : [];
      const risks   = Array.isArray(output.risks_and_unknowns) ? output.risks_and_unknowns : [];
      const jdRaw   = (role.job_description_raw || '').toLowerCase();
      const detected = [];

      // ── 1. Production coding ─────────────────────────────────────────────────
      const CODING_PHRASES = [
        'production code', 'production ui', 'write code', 'write production',
        'frontend code', 'front-end code', 'hands-on code', 'hands-on front-end',
        'hands-on frontend', 'full-stack designer', 'design and code',
        'implement ui', 'build the ui', 'engineer the ', 'engineer our',
      ];
      const _codingFs = fs.find(f => {
        const t = ((f.label || '') + ' ' + (f.text || '')).toLowerCase();
        return CODING_PHRASES.some(p => t.includes(p));
      });
      const _codingInJd = CODING_PHRASES.some(p => jdRaw.includes(p));
      if (_codingFs || _codingInJd) {
        detected.push({
          key:      'production_coding',
          label:    BLOCKER_DEFS.production_coding,
          evidence: _codingFs ? (_codingFs.label || _codingFs.text || null) : null,
        });
      }

      // ── 2. Salary missing ────────────────────────────────────────────────────
      const _salaryAnnual = (pd.salary_annual || '').toLowerCase();
      const _salaryMissing = !pd.salary_annual
        || _salaryAnnual === 'not stated'
        || _salaryAnnual.includes('not stated')
        || _salaryAnnual.includes('not specified')
        || _salaryAnnual.includes('competitive')
        || _salaryAnnual.includes('tbc')
        || _salaryAnnual.includes('doe');
      if (_salaryMissing && !role.salary_text_raw) {
        detected.push({
          key:      'salary_missing',
          label:    BLOCKER_DEFS.salary_missing,
          evidence: null,
        });
      }

      // ── 3. Hybrid / on-site ──────────────────────────────────────────────────
      const _wm  = (role.work_model || '').toLowerCase();
      const _loc = (pd.location    || '').toLowerCase();
      const _pat = (pd.working_pattern || '').toLowerCase();
      const _isHybridOnsite =
        _wm === 'hybrid' || _wm === 'onsite' || _wm === 'on-site' ||
        _loc.includes('hybrid') || _loc.includes('on-site') || _loc.includes('onsite') ||
        _pat.includes('hybrid') || _pat.includes('in-office') || _pat.includes('on-site') ||
        _pat.includes('days per week in');
      if (_isHybridOnsite) {
        const _evid = [pd.location, pd.working_pattern].filter(Boolean).join(' · ') || null;
        detected.push({
          key:      'hybrid_onsite',
          label:    BLOCKER_DEFS.hybrid_onsite,
          evidence: _evid,
        });
      }

      // ── 4. Scope unclear ─────────────────────────────────────────────────────
      const _scopeClar = output.scope_clarity || null;
      const _scopeFs   = fs.find(f => {
        const t = ((f.label || '') + ' ' + (f.text || '')).toLowerCase();
        return t.includes('scope') || t.includes('unclear') || t.includes('undefined role');
      });
      if (_scopeClar === 'vague' || _scopeFs) {
        const _evid = _scopeFs
          ? (_scopeFs.label || _scopeFs.text || null)
          : null;
        detected.push({
          key:      'scope_unclear',
          label:    BLOCKER_DEFS.scope_unclear,
          evidence: _evid,
        });
      }

      // ── 5. Domain concern (friction signals only — never guess) ──────────────
      const DOMAIN_PHRASES = [
        'domain mismatch', 'wrong domain', 'b2c product', 'e-commerce', 'gaming',
        'brand design', 'marketing design', 'consumer product', 'not b2b',
      ];
      const _domainFs = fs.find(f => {
        const t = ((f.label || '') + ' ' + (f.text || '')).toLowerCase();
        return DOMAIN_PHRASES.some(p => t.includes(p));
      });
      if (_domainFs) {
        detected.push({
          key:      'domain_concern',
          label:    BLOCKER_DEFS.domain_concern,
          evidence: _domainFs.label || _domainFs.text || null,
        });
      }

      // ── 6. Marketing heavy (archetype + friction signals required) ────────────
      const _arch  = (output.role_archetype?.primary || '').toLowerCase();
      const _mktFs = fs.find(f => {
        const t = ((f.label || '') + ' ' + (f.text || '')).toLowerCase();
        return t.includes('marketing') || t.includes('brand campaign') || t.includes('campaign design');
      });
      if (_arch.includes('growth') && _mktFs) {
        detected.push({
          key:      'marketing_heavy',
          label:    BLOCKER_DEFS.marketing_heavy,
          evidence: _mktFs.label || _mktFs.text || null,
        });
      }

      return detected;
    }

    // ─── Decision Layer V1 — Blockers section UI ─────────────────────────────
    // Renders "Potential blockers" in the #ws-blockers-section slot.
    // Detects from analysis, loads any saved user states, renders confirm checklist.
    async function _renderBlockersSection(role) {
      const el = document.getElementById('ws-blockers-section');
      if (!el) return;

      // Require analysis data; hide for temp/unanalysed roles
      const output = role?.latest_match_output || role?.analysis || null;
      if (!output || role?._isTemp) {
        el.style.display = 'none';
        el.innerHTML = '';
        return;
      }

      const detected = _detectBlockers(role);
      if (detected.length === 0) {
        el.style.display = 'none';
        el.innerHTML = '';
        return;
      }

      // Load saved states and user boundaries in parallel
      const [savedBlockers, boundaries] = await Promise.all([
        _loadRoleBlockers(role.id),
        _loadUserBoundaries(),
      ]);

      const blockerStateMap = {};
      savedBlockers.forEach(b => { blockerStateMap[b.blocker_key] = b; });
      const boundaryKeys = new Set(boundaries.map(b => b.blocker_key));

      const itemsHtml = detected.map(blocker => {
        const saved      = blockerStateMap[blocker.key] || null;
        const state      = saved?.user_state || null;
        const isBoundary = boundaryKeys.has(blocker.key);
        const stateClass = state ? ` dl-blocker-item--${state}` : '';

        const evidenceHtml = blocker.evidence
          ? `<div class="dl-blocker-evidence">${esc(blocker.evidence)}</div>`
          : '';

        const boundaryHtml = isBoundary
          ? `<span class="dl-boundary-indicator">&#x25CF; Saved boundary</span>`
          : (state === 'hard'
              ? `<button class="dl-boundary-cta" data-bkey="${esc(blocker.key)}" data-blabel="${esc(blocker.label)}">Save as boundary</button>`
              : '');

        return `
          <div class="dl-blocker-item${stateClass}"
               data-bkey="${esc(blocker.key)}"
               data-blabel="${esc(blocker.label)}"
               data-bevid="${esc(blocker.evidence || '')}">
            <div class="dl-blocker-top">
              <span class="dl-blocker-label">${esc(blocker.label)}</span>
              ${evidenceHtml}
            </div>
            <div class="dl-blocker-actions">
              <button class="dl-blocker-btn${state === 'hard'  ? ' dl-blocker-btn--active' : ''}" data-state="hard">Hard blocker</button>
              <button class="dl-blocker-btn${state === 'soft'  ? ' dl-blocker-btn--active' : ''}" data-state="soft">Soft concern</button>
              <button class="dl-blocker-btn${state === 'clear' ? ' dl-blocker-btn--active' : ''}" data-state="clear">Not an issue</button>
            </div>
            <div class="dl-blocker-boundary-row">${boundaryHtml}</div>
          </div>`;
      }).join('');

      el.innerHTML = `
        <div class="dl-blockers-section">
          <div class="dl-blockers-header">
            <span class="dl-blockers-title">Potential blockers</span>
            <span class="dl-blockers-hint">Confirm which apply to you</span>
          </div>
          <div class="dl-blockers-list">${itemsHtml}</div>
        </div>`;
      el.style.display = '';

      // Wire state buttons
      el.querySelectorAll('.dl-blocker-item').forEach(itemEl => {
        const bKey  = itemEl.dataset.bkey;
        const bLbl  = itemEl.dataset.blabel;
        const bEvid = itemEl.dataset.bevid || null;

        itemEl.querySelectorAll('.dl-blocker-btn').forEach(btn => {
          btn.addEventListener('click', async () => {
            const newState        = btn.dataset.state;
            const isCurrentActive = btn.classList.contains('dl-blocker-btn--active');
            const stateToSet      = isCurrentActive ? null : newState;

            // Optimistic UI update
            itemEl.className = 'dl-blocker-item' + (stateToSet ? ` dl-blocker-item--${stateToSet}` : '');
            itemEl.querySelectorAll('.dl-blocker-btn').forEach(b => {
              b.classList.toggle('dl-blocker-btn--active', !isCurrentActive && b.dataset.state === newState);
            });

            // Persist
            await _upsertRoleBlocker(role.id, bKey, bLbl, bEvid || null, stateToSet);

            // Update boundary row
            const bRow = itemEl.querySelector('.dl-blocker-boundary-row');
            if (bRow) {
              if (boundaryKeys.has(bKey)) {
                bRow.innerHTML = `<span class="dl-boundary-indicator">&#x25CF; Saved boundary</span>`;
              } else if (stateToSet === 'hard') {
                bRow.innerHTML = `<button class="dl-boundary-cta" data-bkey="${esc(bKey)}" data-blabel="${esc(bLbl)}">Save as boundary</button>`;
                const newCta = bRow.querySelector('.dl-boundary-cta');
                if (newCta) _wireBoundaryCta(newCta, bKey, bLbl, boundaryKeys, bRow);
              } else {
                bRow.innerHTML = '';
              }
            }
          });
        });

        // Wire any pre-existing boundary CTA
        const existingCta = itemEl.querySelector('.dl-boundary-cta');
        if (existingCta) {
          _wireBoundaryCta(existingCta, bKey, bLbl, boundaryKeys, itemEl.querySelector('.dl-blocker-boundary-row'));
        }
      });
    }

    // Wires the "Save as boundary" button on a blocker item.
    function _wireBoundaryCta(btn, bKey, bLbl, boundaryKeys, bRowEl) {
      if (!btn) return;
      btn.addEventListener('click', async () => {
        btn.disabled    = true;
        btn.textContent = 'Saving…';
        await _saveUserBoundary(bKey, bLbl, 'hard');
        boundaryKeys.add(bKey);
        if (bRowEl) bRowEl.innerHTML = `<span class="dl-boundary-indicator">&#x25CF; Boundary saved</span>`;
      });
    }

    // ─── Decision Layer V1 — Decision History Read View ───────────────────────
    // Renders per-role decision history (role_decision_snapshots) into
    // #ws-decision-history-dl. Shows each snapshot: decision type, timestamp,
    // confirmed blockers, skip reason, and notes. Hidden when no records exist.
    async function _renderDecisionHistoryDL(role) {
      const el = document.getElementById('ws-decision-history-dl');
      if (!el) return;

      if (!role?.id || role._isTemp) {
        el.style.display = 'none';
        el.innerHTML = '';
        return;
      }

      let snaps = [];
      try {
        const { data, error } = await db
          .from('role_decision_snapshots')
          .select('id, user_decision, confirmed_blockers, skip_reason, skip_reason_other, notes, created_at')
          .eq('role_id', role.id)
          .order('created_at', { ascending: false });
        if (!error) snaps = data || [];
      } catch (_) {}

      if (snaps.length === 0) {
        el.style.display = 'none';
        el.innerHTML = '';
        return;
      }

      const DEC_LABELS = { skip: 'Skipped', save: 'Saved', apply: 'Applied' };
      const DEC_CLS    = { skip: 'dl-dh-badge--skip', save: 'dl-dh-badge--save', apply: 'dl-dh-badge--apply' };

      // Build skip reason label map from SKIP_REASONS constant
      const SKIP_REASON_LABELS = {};
      SKIP_REASONS.forEach(r => { SKIP_REASON_LABELS[r.key] = r.label; });

      const fmt = iso => {
        try {
          return new Date(iso).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
        } catch (_) { return iso?.slice(0, 10) || '—'; }
      };

      const entriesHtml = snaps.map(snap => {
        const decLabel    = DEC_LABELS[snap.user_decision] || snap.user_decision;
        const decCls      = DEC_CLS[snap.user_decision]    || '';
        const dateStr     = fmt(snap.created_at);
        const blockers    = Array.isArray(snap.confirmed_blockers) ? snap.confirmed_blockers : [];

        const blockersHtml = blockers.length
          ? `<div class="dl-dh-entry-blockers">${
              blockers.map(b =>
                `<span class="dl-dh-blocker-tag dl-dh-blocker-tag--${esc(b.state || 'soft')}">${esc(b.label)}</span>`
              ).join('')
            }</div>`
          : '';

        const skipReasonLabel = snap.skip_reason
          ? (SKIP_REASON_LABELS[snap.skip_reason] || snap.skip_reason)
          : null;
        const skipReasonHtml = skipReasonLabel
          ? `<div class="dl-dh-entry-reason">Reason: ${esc(skipReasonLabel)}${snap.skip_reason_other ? ` — ${esc(snap.skip_reason_other)}` : ''}</div>`
          : '';

        const notesHtml = snap.notes
          ? `<div class="dl-dh-entry-notes">${esc(snap.notes)}</div>`
          : '';

        return `
          <div class="dl-dh-entry">
            <div class="dl-dh-entry-header">
              <span class="dl-dh-badge ${decCls}">${esc(decLabel)}</span>
              <span class="dl-dh-entry-date">${esc(dateStr)}</span>
            </div>
            ${blockersHtml}
            ${skipReasonHtml}
            ${notesHtml}
          </div>`;
      }).join('');

      el.innerHTML = `
        <div class="dl-history-section">
          <div class="dl-history-header">
            <span class="dl-history-title">Decision history</span>
            <span class="dl-history-count">${snaps.length} record${snaps.length !== 1 ? 's' : ''}</span>
          </div>
          <div class="dl-history-entries">${entriesHtml}</div>
        </div>`;
      el.style.display = '';
    }
    // ─────────────────────────────────────────────────────────────────────────

    // Persists a verdict_state update to DB, syncs local state, logs to timeline.
    async function setDecision(roleId, state) {
      try {
        const { error } = await db.from('roles')
          .update({ verdict_state: state })
          .eq('id', roleId);
        if (error) throw error;

        // Sync local role object
        allRoles = allRoles.map(r =>
          r.id !== roleId ? r : { ...r, verdict_state: state }
        );

        // Timeline log
        const _labelMap = { fits: 'This fits me', not_for_me: 'Not for me', undecided: 'Undecided' };
        insertEvent(roleId, {
          event_type: 'decision_recorded',
          title: state
            ? `Decision recorded: ${_labelMap[state] || state}`
            : 'Decision cleared',
        });

        // Re-render card to reflect updated state
        const _updated = allRoles.find(r => r.id === roleId);
        if (_updated) _renderDecisionCapture(_updated);
      } catch (e) {
        console.error('setDecision error:', e);
      }
    }

    // ─── Nudge action handler (Phase 7) ──────────────────────────────────────
    // Called when the user taps a button on the Nudge Card.
    // Actions: applied | interviewing | no_response | snooze
    async function _handleNudgeAction(roleId, action) {
      if (!roleId || !action) return;
      if (action === 'snooze') {
        // Snooze for 7 days — update DB field nudge_snoozed_until
        const _until = new Date(Date.now() + 7 * 86_400_000).toISOString();
        try {
          await db.from('roles').update({ nudge_snoozed_until: _until }).eq('id', roleId);
          allRoles = allRoles.map(r =>
            r.id !== roleId ? r : { ...r, nudge_snoozed_until: _until }
          );
        } catch (e) {
          console.error('nudge snooze error:', e);
        }
        // Re-render to hide the nudge card
        const _r = allRoles.find(r => r.id === roleId);
        if (_r) _renderDecisionCapture(_r);
        return;
      }
      // For apply/interviewing/no_response — record as outcome_state
      // These are progress states (not terminal), so no reason form needed.
      try {
        const now = new Date().toISOString();
        const { error } = await db.from('roles').update({
          outcome_state: action,
          outcome_at:    now,
        }).eq('id', roleId);
        if (error) throw error;

        await db.from('role_updates').insert({
          role_id:       roleId,
          event_type:    'outcome',
          outcome_state: action,
          status:        'in_progress',
          note:          null,
        });

        allRoles = allRoles.map(r => {
          if (r.id !== roleId) return r;
          return { ...r, outcome_state: action, outcome_at: now };
        });

        insertEvent(roleId, {
          event_type: 'decision_changed',
          title:      'Progress updated via nudge',
          detail:     action,
        });

        // Re-render decision capture to hide the nudge card (role no longer eligible)
        const _updated = allRoles.find(r => r.id === roleId);
        if (_updated) _renderDecisionCapture(_updated);
      } catch (e) {
        console.error('nudge action error:', e);
      }
    }

    // ─── Structured reflection options for terminal outcomes (Phase 3) ──────────
    const _REFLECTION_OPTIONS = {
      rejected:    ['Salary or rate mismatch', 'Location or remote mismatch', 'Overqualified', 'Underqualified', 'Role changed or cancelled', 'No reason given'],
      skipped:     ['Salary or rate too low',  'Location or remote mismatch', 'Role scope not right', 'Company concerns', 'Too many unknowns'],
      withdrew:    ['Found a better opportunity', 'Salary or rate too low', 'Role scope changed', 'Timeline didn\'t work', 'Company culture concerns'],
    };

    // ─── Show outcome reason form ─────────────────────────────────────────────
    function showOutcomeReasonForm(roleId, outcomeState) {
      const formEl = document.getElementById('rail-outcome-form');
      if (!formEl) return;

      // Disable all rail buttons while the form is open
      document.querySelectorAll('.rail-btn').forEach(b => { b.disabled = true; });
      const _outcomeListForm = document.getElementById('rail-outcome-list');
      if (_outcomeListForm) _outcomeListForm.classList.add('outcome-disabled');

      const label   = RAIL_OUTCOMES.find(o => o.outcomeState === outcomeState)?.label || outcomeState;
      const _opts   = _REFLECTION_OPTIONS[outcomeState] || [];
      const _chipsHtml = _opts.length ? `
        <div class="rc-chips" style="display:flex;flex-wrap:wrap;gap:5px;margin-bottom:8px;">
          ${_opts.map(opt => `
            <button class="rc-chip" data-rc-opt="${esc(opt)}" style="padding:3px 10px;font-size:11.5px;font-family:var(--font);background:var(--bg);color:var(--text-light);border:1px solid var(--border);border-radius:var(--radius);cursor:pointer;">${esc(opt)}</button>
          `).join('')}
        </div>
      ` : '';

      formEl.innerHTML = `
        <div style="padding:12px;background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);">
          <div style="font-size:12px;font-weight:500;color:var(--text);margin-bottom:8px;">Mark as ${esc(label)}</div>
          ${_chipsHtml}
          <textarea id="outcome-reason-input" placeholder="Reason (optional)" spellcheck="true" style="width:100%;box-sizing:border-box;padding:7px 10px;font-size:12px;font-family:var(--font);border:1px solid var(--border);border-radius:var(--radius);background:var(--bg);color:var(--text);resize:vertical;min-height:56px;"></textarea>
          <div style="display:flex;gap:6px;margin-top:8px;">
            <button id="outcome-confirm-btn" style="flex:1;padding:7px 0;font-size:12.5px;font-family:var(--font);background:var(--text);color:var(--bg);border:none;border-radius:var(--radius);cursor:pointer;">Confirm</button>
            <button id="outcome-cancel-btn" style="flex:1;padding:7px 0;font-size:12.5px;font-family:var(--font);background:var(--surface);color:var(--text-muted);border:1px solid var(--border);border-radius:var(--radius);cursor:pointer;">Cancel</button>
          </div>
        </div>
      `;

      // Structured reason chips — clicking populates textarea; clicking again clears it
      formEl.querySelectorAll('.rc-chip').forEach(chip => {
        chip.addEventListener('click', () => {
          const textEl = document.getElementById('outcome-reason-input');
          if (!textEl) return;
          const _chipVal = chip.dataset.rcOpt;
          const _isActive = chip.classList.contains('rc-chip--active');
          // Deactivate all chips first
          formEl.querySelectorAll('.rc-chip').forEach(c => {
            c.classList.remove('rc-chip--active');
            c.style.background = 'var(--bg)';
            c.style.color = 'var(--text-light)';
            c.style.borderColor = 'var(--border)';
          });
          if (_isActive) {
            // Toggle off — clear textarea if it still contains the chip value
            if (textEl.value === _chipVal) textEl.value = '';
          } else {
            // Activate this chip, populate textarea
            chip.classList.add('rc-chip--active');
            chip.style.background = 'var(--text)';
            chip.style.color = 'var(--bg)';
            chip.style.borderColor = 'var(--text)';
            textEl.value = _chipVal;
          }
        });
      });

      document.getElementById('outcome-confirm-btn').addEventListener('click', () => {
        const reason = document.getElementById('outcome-reason-input')?.value.trim() || null;
        setOutcome(roleId, outcomeState, reason);
      });

      document.getElementById('outcome-cancel-btn').addEventListener('click', () => {
        formEl.innerHTML = '';
        document.querySelectorAll('.rail-btn').forEach(b => { b.disabled = false; });
        const _ol = document.getElementById('rail-outcome-list');
        if (_ol) _ol.classList.remove('outcome-disabled');
      });
    }

    // ─── Set outcome (how the role journey ended) ─────────────────────────────
    async function setOutcome(roleId, outcomeState, reason) {
      const formEl    = document.getElementById('rail-outcome-form');
      const confirmEl = document.getElementById('rail-confirm');

      document.querySelectorAll('.rail-btn').forEach(b => { b.disabled = true; });
      const _outcomeListSet = document.getElementById('rail-outcome-list');
      if (_outcomeListSet) _outcomeListSet.classList.add('outcome-disabled');
      if (formEl) formEl.innerHTML = '';

      try {
        // Capture previous outcome state before mutation (for analytics)
        const _prevOutcome = (() => { const r = allRoles.find(x => x.id === roleId); return r ? r.outcome_state ?? null : null; })();

        const now = new Date().toISOString();
        const { error } = await db.from('roles').update({
          outcome_state:  outcomeState,
          outcome_reason: reason || null,
          outcome_at:     now,
        }).eq('id', roleId);
        if (error) throw error;

        // Record outcome in the timeline — uses event_type='outcome' and dedicated
        // outcome_state column; status is set to a safe neutral value never the outcome value.
        await db.from('role_updates').insert({
          role_id:       roleId,
          event_type:    'outcome',
          outcome_state: outcomeState,
          status:        'in_progress',
          note:          reason || null,
        });

        // Update local state
        const now2 = new Date().toISOString();
        allRoles = allRoles.map(r => {
          if (r.id !== roleId) return r;
          r.outcome_state  = outcomeState;
          r.outcome_reason = reason || null;
          r.outcome_at     = now2;
          r.role_updates.unshift({
            id:            crypto.randomUUID(),
            role_id:       roleId,
            event_type:    'outcome',
            outcome_state: outcomeState,
            status:        'in_progress',
            stage_reached: null,
            note:          reason || null,
            created_at:    now2,
          });
          return r;
        });

        insertEvent(roleId, {
          event_type: 'decision_changed',
          title:      'Outcome set',
          detail:     outcomeState + (reason ? ` — ${reason}` : ''),
        });
        const _outcomeTitle = {
          rejected:       'Rejected',
          withdrew:       'Withdrew',
          offer_accepted: 'Accepted',
          closed:         'Closed',
          skipped:        'Closed',
          no_response:    'No response',
          ghosted:        'Ghosted',
        }[outcomeState] || 'Outcome recorded';
        createSnapshot(roleId, 'outcome_set', _outcomeTitle, {
          outcome: outcomeState,
          reason:  reason || null,
          stage:   (() => { const r = allRoles.find(x => x.id === roleId); return r ? currentStageLabel(r) : null; })(),
        });

        // Decision analytics — only log user-driven closures; received states are excluded
        if (['withdrew', 'offer_accepted', 'skipped'].includes(outcomeState)) {
          _logDecisionEvent({
            decisionType:  outcomeState,
            roleId,
            previousState: _prevOutcome,
            newState:      outcomeState,
            sourceSurface: 'outcome_rail',
          });
        }

        // Append to decision ledger — maps outcome_state to ledger decision_type
        const _ledgerType = { skipped: 'skip', withdrew: 'withdraw', offer_accepted: 'accept' }[outcomeState] || 'other';
        await wsAppendDecision(roleId, _ledgerType, reason || null);
        wsRefreshDecisionHistory(roleId).catch(() => {});

        renderInbox(allRoles);

        // Full rail re-render — this locks the progress stepper and shows the outcome
        const updatedRole = allRoles.find(r => r.id === roleId);
        if (updatedRole) renderRail(updatedRole);

        // Show a brief confirmation in rail-confirm (now re-rendered, re-query)
        const freshConfirm = document.getElementById('rail-confirm');
        if (freshConfirm) {
          freshConfirm.textContent = 'Outcome saved.';
          setTimeout(() => { if (freshConfirm) freshConfirm.textContent = ''; }, 2500);
        }

      } catch (e) {
        if (confirmEl) confirmEl.textContent = 'Error: ' + e.message;
      } finally {
        // On success renderRail re-renders the whole rail; on error, restore interactivity
        document.querySelectorAll('.rail-btn').forEach(b => { b.disabled = false; });
        const _ol = document.getElementById('rail-outcome-list');
        if (_ol) _ol.classList.remove('outcome-disabled');
      }
    }

    // ─── Re-open role (clears outcome, unlocks progress stepper) ─────────────
    async function reopenRole(roleId) {
      const reopenBtn = document.getElementById('btn-reopen-role');
      if (reopenBtn) { reopenBtn.disabled = true; reopenBtn.textContent = 'Reopening\u2026'; }

      try {
        const { error } = await db.from('roles').update({
          outcome_state:  null,
          outcome_reason: null,
          outcome_at:     null,
        }).eq('id', roleId);
        if (error) throw error;

        insertEvent(roleId, {
          event_type: 'decision_changed',
          title:      'Role re-opened',
          detail:     'Outcome cleared — role returned to active tracking',
        });

        allRoles = allRoles.map(r =>
          r.id !== roleId ? r
            : { ...r, outcome_state: null, outcome_reason: null, outcome_at: null }
        );

        renderInbox(allRoles);

        // Full re-render of the rail — stepper unlocks automatically
        const role = allRoles.find(r => r.id === roleId);
        if (role) renderRail(role);

      } catch (e) {
        if (reopenBtn) { reopenBtn.disabled = false; reopenBtn.textContent = 'Re-open role'; }
        const confirmEl = document.getElementById('rail-confirm');
        if (confirmEl) confirmEl.textContent = 'Error: ' + e.message;
      }
    }

    // ─── Restore archived role (unarchive) ───────────────────────────────────
    async function restoreRole(roleId) {
      const { error } = await db.from('roles').update({ archived: false }).eq('id', roleId);
      if (error) { console.error('[RESTORE]', error.message); return; }
      allRoles = allRoles.map(r => r.id === roleId ? { ...r, archived: false } : r);
      renderInbox(allRoles);
      selectRole(roleId);
    }

    function renderPeekSections(output) {
      if (!output || typeof output !== 'object') {
        return '<div style="font-size:13px;color:var(--text-light);font-style:italic;padding:8px 0;">No analysis available yet.</div>';
      }
      // Convert legacy format
      const isLegacy = !output.fit_reality_summary && !output.why_this_role_exists &&
                       !output.what_you_would_actually_do && (output.decision || output.reasons);
      if (isLegacy) output = legacyToCanonical(output);

      let html = '';

      // Hard No banner
      if (output.hard_no) {
        html += `<div class="hn-banner">
          <div class="hn-label">Hard No</div>
          <div class="hn-reason">Production coding required.</div>
          <div class="hn-body">This role explicitly expects frontend code contributions to production, which conflicts with your saved role rules.</div>
          <div class="hn-hint">Suggested outcome: <span class="hn-hint-value">Skip</span></div>
        </div>`;
      }
      // Degraded notice
      if (output._degraded) {
        html += `<div style="background:#FEF3C7;border:1px solid #FDE68A;border-radius:6px;padding:8px 12px;margin-bottom:14px;font-size:12px;color:#92400E;">Full analysis unavailable. Review the JD manually.</div>`;
      }

      const peekSection = (heading, content) => content
        ? `<div class="peek-section"><div class="peek-section-heading">${heading}</div>${content}</div>`
        : '';

      const bulletHtml = arr => Array.isArray(arr) && arr.length
        ? `<ul>${arr.map(s => `<li>${esc(String(s))}</li>`).join('')}</ul>`
        : `<p style="color:var(--text-light);font-style:italic;">Not stated</p>`;

      // Tagged bullets for peek — signal tags on applicable sections
      const taggedBulletHtml = (arr, sectionKey) => {
        if (!Array.isArray(arr) || !arr.length)
          return `<p style="color:var(--text-light);font-style:italic;">Not stated</p>`;
        return `<ul>${arr.map(s => {
          const text = String(s);
          const tag  = tagBullet(text, sectionKey);
          return `<li class="tagged"><span class="peek-signal-tag">${esc(tag)}</span> ${esc(text)}</li>`;
        }).join('')}</ul>`;
      };

      const proseHtml = str => (!str || str === 'Not stated' || str === 'Unknown')
        ? `<p style="color:var(--text-light);font-style:italic;">${esc(str || 'Not stated')}</p>`
        : `<p>${esc(str)}</p>`;

      html += peekSection('Fit Reality Summary',        taggedBulletHtml(output.fit_reality_summary,       'fit_reality_summary'));
      html += peekSection('Role Summary',               proseHtml(output.role_summary));
      html += peekSection('What You Would Actually Do', taggedBulletHtml(output.what_you_would_actually_do, 'what_you_would_actually_do'));
      return html || '<div style="font-size:13px;color:var(--text-light);font-style:italic;padding:8px 0;">No analysis available yet.</div>';
    }

    // ─── Open blank workspace (new Add Role path) ────────────────────────────
    // Does NOT create a DB record immediately.
    // A real role record is created only after the first successful JD analysis.
    // Until then the workspace operates on a lightweight in-memory sentinel object.
    function openBlankWorkspace() {
      selectedRoleId = '_temp';
      _setAppFilter('active');
      switchNav('applications');
      // Clear any existing inbox selection highlight — nothing in the list maps to temp
      document.querySelectorAll('.inbox-role').forEach(r => r.classList.remove('selected'));
      // Build a lightweight temp role object — no DB backing until first analysis
      const tempRole = {
        _isTemp:             true,
        id:                  null,
        company_name:        null,
        role_title:          null,
        job_description_raw: null,
        analysis:            null,
        job_url:             null,
        location_text:       null,
        current_stage:       'JD Review',
        role_updates:        [],
        user_decision:       null,
        status:              'active',
      };
      // ── Enter State 1 (Intake): show centered input, hide col-chat ──────────
      document.querySelector('.app')?.classList.add('intake-mode');
      const intakeEl = document.getElementById('intake-panel');
      if (intakeEl) intakeEl.removeAttribute('hidden');

      // Render workspace scaffold into col-chat (hidden during intake).
      // This sets up the full chat plumbing (doSend, _wsHandlePaste, etc.)
      // so the intake panel can delegate submission to it.
      renderWorkspaceView(tempRole);

      // Wire intake panel submit to the hidden ws-workspace
      _wireIntakePanel(tempRole);

      return tempRole; // allows callers (e.g. mismatch handler) to reference the new role object
    }

    // ─── Add role modal ───────────────────────────────────────────────────────
    function openAddModal() {
      ['add-jd', 'add-company', 'add-title', 'add-location', 'add-source', 'add-url']
        .forEach(id => { document.getElementById(id).value = ''; });
      const _engTypeEl = document.getElementById('add-engagement-type');
      if (_engTypeEl) _engTypeEl.value = '';
      // Reset recruiter section
      ['add-rec-name', 'add-rec-company', 'add-rec-email', 'add-rec-url'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.value = '';
      });
      const _recTypeEl = document.getElementById('add-rec-type');
      if (_recTypeEl) _recTypeEl.value = '';
      const _recSection = document.getElementById('recruiter-details-section');
      if (_recSection) _recSection.removeAttribute('open');
      document.getElementById('recruiter-autofill-badge')?.classList.add('hidden');
      // Reset role details section
      ['add-ir35-status', 'add-start-timeline'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.value = '';
      });
      ['add-day-rate', 'add-contract-length'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.value = '';
      });
      const _roleDetailsSection = document.getElementById('role-details-section');
      if (_roleDetailsSection) _roleDetailsSection.removeAttribute('open');
      document.getElementById('role-details-autofill-badge')?.classList.add('hidden');
      document.getElementById('add-error').classList.add('hidden');
      // Reset truncation warning state on every open
      const _jdEl = document.getElementById('add-jd');
      if (_jdEl) _jdEl.dataset.pasteAnyway = '';
      document.getElementById('jd-truncation-warning')?.classList.add('hidden');
      document.getElementById('modal-add').classList.remove('hidden');
      setTimeout(() => document.getElementById('add-jd').focus(), 60);
    }

    function closeAddModal() {
      document.getElementById('modal-add').classList.add('hidden');
      // Reset analysis trace state so it's clean on next open
      const _traceEl = document.getElementById('add-analysis-trace');
      const _formEl  = document.getElementById('add-modal-form-body');
      if (_traceEl) { _traceEl.classList.add('hidden'); _traceEl.classList.remove('add-analysis-trace--done'); _traceEl.innerHTML = ''; }
      if (_formEl)  { _formEl.classList.remove('add-modal-form--hidden'); }
    }

    async function saveRole() {
      const jd_raw  = document.getElementById('add-jd').value;
      const jd_clean = cleanJobDescription(jd_raw);
      const jd      = jd_clean || jd_raw;   // canonical JD text for analysis
      const errEl   = document.getElementById('add-error');

      if (!jd.trim()) {
        errEl.textContent = 'Job description is required.';
        errEl.classList.remove('hidden');
        return;
      }

      errEl.classList.add('hidden');
      const btn = document.getElementById('btn-save-add');
      btn.disabled = true;
      btn.textContent = 'Saving...';

      try {
        // ── Step 1: Create role ───────────────────────────────────────────────
        // Extract metadata as a safety net for any fields the autofill may have missed
        const _meta = extractJDMetadata(jd_raw, jd_clean);
        const _company   = document.getElementById('add-company').value.trim()   || _meta.company_name  || null;
        const _title     = document.getElementById('add-title').value.trim()     || _meta.role_title    || null;
        const _location  = document.getElementById('add-location').value.trim()  || _meta.location      || null;
        const _jobUrl    = document.getElementById('add-url').value.trim()       || _meta.job_url       || null;
        const _source    = document.getElementById('add-source').value.trim()                           || null;

        // Map extracted remote_model to work_model values the app uses
        const _workModelMap = { remote: 'remote', hybrid: 'hybrid', 'on-site': 'onsite', onsite: 'onsite' };
        const _workModel = _meta.remote_model ? (_workModelMap[_meta.remote_model.toLowerCase()] || null) : null;
        // Salary: prefer cleaned annual string; fallback to raw salary mention
        const _salary = _meta.salary_annual || null;
        // Engagement type: manual dropdown > auto-detected from JD text > null (Unknown)
        const _manualEngType = document.getElementById('add-engagement-type')?.value || null;
        const _engType = _manualEngType || _detectEngagementType(jd_raw || jd) || null;
        // Practical fields: manual override > auto-detect > null
        const _manualIr35 = document.getElementById('add-ir35-status')?.value || null;
        const _ir35Status = _manualIr35 || _detectIr35Status(jd_raw || jd, _engType) || null;
        const _dayRateRaw = document.getElementById('add-day-rate')?.value.trim() || null;
        const _dayRateText = _dayRateRaw || _detectDayRateText(jd_raw || jd) || null;
        const _contractLenRaw = document.getElementById('add-contract-length')?.value.trim() || null;
        const _contractLength = _contractLenRaw || _detectContractLength(jd_raw || jd) || null;
        const _manualStart = document.getElementById('add-start-timeline')?.value || null;
        const _startTimeline = _manualStart || _detectStartTimeline(jd_raw || jd) || null;

        const { data: role, error: re } = await db.from('roles').insert({
          company_name:        _company,
          role_title:          _title,
          location_text:       _location,
          source:              _source,
          job_url:             _jobUrl,
          job_description_raw: jd_raw || jd,
          status:              'active',
          work_model:          _workModel,
          salary_text_raw:     _salary,
          engagement_type:     _engType,
          ir35_status:         _ir35Status,
          day_rate_text:       _dayRateText,
          contract_length:     _contractLength,
          start_timeline:      _startTimeline,
        }).select().single();
        if (re) throw re;

        insertEvent(role.id, { event_type: 'role_created', title: 'Role created', detail: 'Added via Add JD' });

        const { error: ue } = await db.from('role_updates').insert({
          role_id:       role.id,
          event_type:    'stage',
          status:        'in_progress',
          stage_reached: 'JD Review',
        });
        if (ue) throw ue;

        // ── Step 2: Generate analysis — same path as Match a JD ──────────────
        // callAnalysisAPI() tries AI first, falls back to local automatically.
        btn.textContent = 'Analysing…';

        // ── Show staged analysis trace in the modal ───────────────────────────
        // The modal stays open during analysis. Replace the form fields with a
        // calm step-by-step trace so the user can see what's happening.
        const _traceEl = document.getElementById('add-analysis-trace');
        const _modalFormEl = document.getElementById('add-modal-form-body');
        if (_traceEl) {
          _traceEl.innerHTML = _ANALYSIS_STAGES.map((s, i) =>
            `<div class="ws-step${i === 0 ? ' ws-step--active' : ''}" data-step="${i}">` +
              `<span class="ws-step-check"></span>` +
              `<span class="ws-step-label">${s}</span>` +
            `</div>`
          ).join('');
          _traceEl.classList.remove('hidden');
          _traceEl.classList.remove('add-analysis-trace--done');
        }
        if (_modalFormEl) _modalFormEl.classList.add('add-modal-form--hidden');

        let _modalTraceDone = false;
        const _modalTraceTimers = _ANALYSIS_TIMINGS.map((t, i) => setTimeout(() => {
          if (_modalTraceDone || !_traceEl?.isConnected) return;
          const _stepEls = _traceEl.querySelectorAll('.ws-step');
          for (let j = 0; j <= i; j++) {
            _stepEls[j]?.classList.remove('ws-step--active');
            _stepEls[j]?.classList.add('ws-step--done');
          }
          if (i + 1 < _stepEls.length) {
            _stepEls[i + 1]?.classList.remove('ws-step--done');
            _stepEls[i + 1]?.classList.add('ws-step--active');
          }
        }, t));
        const _clearModalTrace = (success = false) => {
          _modalTraceDone = true;
          _modalTraceTimers.forEach(clearTimeout);
          if (!_traceEl?.isConnected) return;
          // Mark all remaining steps done immediately
          _traceEl.querySelectorAll('.ws-step').forEach(el => {
            el.classList.remove('ws-step--active');
            el.classList.add('ws-step--done');
          });
          if (success) {
            // Add done class briefly for a completion moment, then modal closes
            _traceEl.classList.add('add-analysis-trace--done');
          } else {
            // On error: hide trace and restore the form
            _traceEl.classList.add('hidden');
            if (_modalFormEl) _modalFormEl.classList.remove('add-modal-form--hidden');
          }
        };
        // ─────────────────────────────────────────────────────────────────────

        let analysis;
        try {
          analysis = await callAnalysisAPI(jd);
          _clearModalTrace(true);
        } catch (_analysisErr) {
          _clearModalTrace(false);
          throw _analysisErr;
        }
        const analysisSource = analysis?._source || 'local';

        // ── Step 2b: Company/title backfill from AI output ──────────────────
        // If client-side extraction missed company/title but AI found them,
        // update the role record so it doesn't remain blank.
        {
          const _patch = {};
          if (!role.company_name) {
            let _aiCompany = analysis._company || null;
            if (!_aiCompany) {
              const _summ = analysis.role_summary || '';
              const _m = _summ.match(/\bat\s+([A-Z][a-zA-Z0-9&. '-]{1,40}?)(?:[,.]|\s+(?:is|you|the|a|as|where|that|for|in)\b)/);
              if (_m?.[1]) _aiCompany = sanitiseCompanyName(_m[1].trim().replace(/[.,]+$/, '')) || null;
            }
            if (_aiCompany) { _patch.company_name = _aiCompany; role.company_name = _aiCompany; }
          }
          if (!role.role_title && analysis._roleTitle) {
            _patch.role_title = analysis._roleTitle; role.role_title = analysis._roleTitle;
          }
          if (Object.keys(_patch).length) {
            db.from('roles').update(_patch).eq('id', role.id).catch(() => {});
          }
        }

        // ── Step 3: Insert jd_matches row (non-fatal — role already saved) ───
        try {
          const { error: me } = await db.from('jd_matches').insert({
            role_id:             role.id,
            job_description_raw: jd_raw || jd,
            jd_text_raw:         jd_raw || jd,
            jd_text:             jd,
            jd_text_clean:       jd_clean || null,
            company_name:        role.company_name,
            role_title:          role.role_title,
            job_url:             role.job_url,
            selected_cv_ids:     [],
            cv_version_ids:      [],
            output_json:         analysis,
          });
          if (me) throw me;

          insertEvent(role.id, { event_type: 'analysis_saved', title: 'Analysis saved', detail: `Source: ${analysisSource}` });
          const _dec3 = analysis.suggested_actions?.next_step || null;
          createSnapshot(role.id, 'initial_analysis', 'Analysis recorded', {
            stage:                            'JD Review',
            decision:                         _dec3,
            company_name:                     role.company_name,
            role_title:                       role.role_title,
            work_model:                       role.work_model || null,
            location_text:                    role.location_text || null,
            salary_text_raw:                  role.salary_text_raw || null,
            raw_jd:                           jd,
            fit_reality_summary:              analysis.fit_reality_summary              || null,
            what_they_are_really_looking_for: analysis.what_they_are_really_looking_for || null,
            what_you_would_actually_do:       analysis.what_you_would_actually_do       || null,
            risks_and_unknowns:               analysis.risks_and_unknowns               || null,
          });
          if (_dec3) createSnapshot(role.id, 'decision_set', _decisionSnapTitle(_dec3), { stage: 'JD Review', decision: _dec3 });
        } catch (matchErr) {
          // Analysis insert failed — role is still saved. User can regenerate from role detail.
          console.error('[saveRole] jd_matches insert failed:', matchErr);
        }

        // ── Recruiter linking — must complete before refresh() ───────────────
        // IMPORTANT: This is awaited so the role_recruiters join row exists before
        // loadData() runs inside refresh(). If it fires after refresh(), the recruiter
        // never appears in the panel for that session.
        //
        // Priority: manual entry (user-provided) > auto-detection from JD/URL.
        // Manual entry fields are only used if any of them are non-empty.
        const _manualRecName    = document.getElementById('add-rec-name')?.value.trim()    || null;
        const _manualRecCompany = document.getElementById('add-rec-company')?.value.trim() || null;
        const _manualRecEmail   = document.getElementById('add-rec-email')?.value.trim()   || null;
        const _manualRecUrl     = document.getElementById('add-rec-url')?.value.trim()     || null;
        // '' means user left type as "Unknown" — treat as null (no explicit choice)
        const _manualRecType    = document.getElementById('add-rec-type')?.value           || null;
        const _hasManualRec     = !!(_manualRecName || _manualRecEmail || _manualRecUrl);

        if (_hasManualRec) {
          await runManualRecruiterLink(role, {
            name:        _manualRecName,
            company:     _manualRecCompany,
            email:       _manualRecEmail,
            profile_url: _manualRecUrl,
            type:        _manualRecType,
          }).catch(() => {});
        } else {
          // No manual entry — fall back to auto-detection from JD text + job URL.
          // Prefer jd_raw so recruiter signals in headers/footers not stripped by cleaning.
          await runRecruiterAutoDetection(role, jd_raw || jd).catch(() => {});
        }

        closeAddModal();
        // ── Force-switch to Applications before refresh so all nav state is consistent ──
        // Clear selectedRoleId first so neither switchNav's renderInbox nor refresh()'s
        // renderInbox highlight the old/stale selection before selectRole() runs.
        selectedRoleId = null;
        // Ensure Active filter is showing — a new role (user_decision=null, no outcome) will
        // never appear in the Archive or All filters, so the card would be missing from
        // the DOM and selectRole() couldn't apply the .active class.
        _setAppFilter('active');
        switchNav('applications');
        await refresh();
        // Reset scroll to top: new role sorts to position 0 in Needs Decision group.
        // Without this, renderInbox restores the old scroll position and selectRole
        // then jumps from there to the top — a double-scroll jerk.
        const _inboxEl = document.getElementById('role-inbox');
        if (_inboxEl) _inboxEl.scrollTop = 0;
        // selectRole with scrollIntoView: new role is at top, scroll confirms it's visible
        selectRole(role.id, { scrollIntoView: true });
      } catch (e) {
        errEl.textContent = e.message || 'Something went wrong.';
        errEl.classList.remove('hidden');
        // Ensure trace is hidden and form is restored on any non-analysis error
        // (analysis errors are handled inside the try block via _clearModalTrace).
        const _traceElCatch = document.getElementById('add-analysis-trace');
        const _formElCatch  = document.getElementById('add-modal-form-body');
        if (_traceElCatch && !_traceElCatch.classList.contains('hidden')) {
          _traceElCatch.classList.add('hidden');
          _traceElCatch.classList.remove('add-analysis-trace--done');
        }
        if (_formElCatch) _formElCatch.classList.remove('add-modal-form--hidden');
      } finally {
        btn.disabled = false;
        btn.textContent = 'Save JD';
      }
    }

    // ─── CV version helpers ────────────────────────────────────────────────────
    async function loadCvVersions() {
      const { data, error } = await db
        .from('cv_versions')
        .select('id, name, notes, is_default, cv_file_url, cv_text, created_at')
        .order('created_at', { ascending: false });
      if (error) throw error;
      _cachedCvVersions = data || [];  // Cache for synchronous access by computeFitAssessment
      return _cachedCvVersions;
    }

    function renderCvList(cvs) {
      const el = document.getElementById('cv-list');
      if (!el) return;
      if (!cvs.length) {
        el.innerHTML = '<div class="cv-empty">No CVs saved yet.</div>';
        return;
      }
      el.innerHTML = cvs.map(cv => {
        const date = new Date(cv.created_at).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
        return `<div class="cv-card">
          <div class="cv-card-header">
            <span class="cv-card-name">${esc(cv.name)}</span>
            ${cv.is_default ? '<span class="cv-default-badge">Default</span>' : ''}
          </div>
          ${cv.notes ? `<div class="cv-card-notes">${esc(cv.notes)}</div>` : ''}
          <div class="cv-card-footer">
            <span class="cv-card-date">Added ${esc(date)}</span>
            ${cv.cv_file_url ? `<a class="cv-card-link" href="${esc(cv.cv_file_url)}" target="_blank" rel="noopener">View PDF</a>` : ''}
            ${!cv.is_default ? `<button class="cv-set-default-btn" data-id="${esc(cv.id)}">Set as default</button>` : ''}
          </div>
        </div>`;
      }).join('');
      el.querySelectorAll('.cv-set-default-btn').forEach(btn => {
        btn.addEventListener('click', () => setDefaultCv(btn.dataset.id));
      });
    }

    async function loadAndRenderCvs() {
      const el = document.getElementById('cv-list');
      if (!el) return;
      el.innerHTML = '<div class="cv-empty" style="color:var(--text-light)">Loading…</div>';
      try {
        renderCvList(await loadCvVersions());
      } catch (e) {
        el.innerHTML = `<div class="cv-empty" style="color:#B91C1C;">${esc(e.message)}</div>`;
      }
    }

    async function saveCvVersion() {
      const name         = document.getElementById('cv-name')?.value.trim();
      const notes        = document.getElementById('cv-notes')?.value.trim() || null;
      const cv_text      = document.getElementById('cv-text')?.value.trim() || null;
      const is_default   = document.getElementById('cv-is-default')?.checked || false;
      const fileInput    = document.getElementById('cv-pdf-input');
      const errEl        = document.getElementById('cv-save-error');
      const saveBtn      = document.getElementById('btn-save-cv');

      if (!name) {
        if (errEl) { errEl.textContent = 'Name is required.'; errEl.classList.remove('hidden'); }
        return;
      }
      if (errEl) errEl.classList.add('hidden');
      if (saveBtn) { saveBtn.disabled = true; saveBtn.textContent = 'Saving…'; }

      try {
        let cv_file_url = null;
        const file = fileInput?.files?.[0];
        if (file) {
          const path = `${Date.now()}-${file.name.replace(/[^a-zA-Z0-9._-]/g, '_')}`;
          const { error: upErr } = await db.storage.from('cvs').upload(path, file, { upsert: false });
          if (upErr) throw upErr;
          const { data: urlData } = db.storage.from('cvs').getPublicUrl(path);
          cv_file_url = urlData.publicUrl;
        }

        // If setting as default, unset all others first
        if (is_default) {
          await db.from('cv_versions').update({ is_default: false }).not('id', 'is', null);
        }

        const { error } = await db.from('cv_versions').insert({ name, notes, cv_text, is_default, cv_file_url });
        if (error) throw error;

        // Clear form
        document.getElementById('cv-name').value  = '';
        document.getElementById('cv-notes').value = '';
        document.getElementById('cv-text').value  = '';
        if (document.getElementById('cv-is-default')) document.getElementById('cv-is-default').checked = false;
        if (fileInput) fileInput.value = '';
        document.getElementById('cv-filename-display').textContent = '';

        await loadAndRenderCvs();
      } catch (e) {
        if (errEl) { errEl.textContent = e.message || 'Save failed.'; errEl.classList.remove('hidden'); }
      } finally {
        if (saveBtn) { saveBtn.disabled = false; saveBtn.textContent = 'Save as new CV version'; }
      }
    }

    async function setDefaultCv(id) {
      try {
        await db.from('cv_versions').update({ is_default: false }).not('id', 'is', null);
        const { error } = await db.from('cv_versions').update({ is_default: true }).eq('id', id);
        if (error) throw error;
        await loadAndRenderCvs();
      } catch (e) {
        console.error('setDefaultCv error:', e.message);
      }
    }

    // ─── Edit Role Details modal ──────────────────────────────────────────────

    // Maps a free-text source value to the nearest canonical option for the select.
    // Called when opening the Edit Role modal so legacy free-text values are handled gracefully.
    function _mapToSourceOption(rawSource) {
      if (!rawSource) return '';
      const canonicals = ['LinkedIn', 'Recruiter outreach', 'Direct company site', 'Job board', 'Referral', 'Other'];
      if (canonicals.includes(rawSource)) return rawSource; // exact match — already canonical
      const sl = rawSource.toLowerCase();
      if (sl === 'linkedin' || sl.includes('linkedin'))                       return 'LinkedIn';
      if (sl.includes('recruiter') || sl.includes('outreach') || sl.includes('headhunt')) return 'Recruiter outreach';
      if (sl.includes('direct') || sl.includes('greenhouse') || sl.includes('lever') || sl.includes('workable')) return 'Direct company site';
      if (sl.includes('job board') || sl.includes('indeed') || sl.includes('reed') || sl.includes('totaljobs') || sl.includes('monster')) return 'Job board';
      if (sl.includes('referral') || sl.includes('referred'))                 return 'Referral';
      return 'Other'; // unrecognised free-text → Other
    }

    function openEditRoleModal(role) {
      document.getElementById('edit-details-role-id').value = role.id;
      document.getElementById('edit-engagement-type').value  = role.engagement_type  || '';
      document.getElementById('edit-ir35-status').value      = role.ir35_status      || '';
      document.getElementById('edit-day-rate').value         = role.day_rate_text     || '';
      document.getElementById('edit-contract-length').value  = role.contract_length  || '';
      document.getElementById('edit-start-timeline').value   = role.start_timeline   || '';
      document.getElementById('edit-location').value         = role.location_text    || '';
      document.getElementById('edit-work-model').value       = role.work_model       || '';
      document.getElementById('edit-source').value           = _mapToSourceOption(role.source);
      document.getElementById('edit-job-url').value          = role.job_url          || '';
      document.getElementById('edit-details-error')?.classList.add('hidden');
      const _confirmEl = document.getElementById('edit-details-confirm');
      if (_confirmEl) _confirmEl.textContent = '';
      document.getElementById('modal-edit-details').classList.remove('hidden');
    }

    function closeEditRoleModal() {
      document.getElementById('modal-edit-details').classList.add('hidden');
    }

    async function saveRoleDetails() {
      const roleId = document.getElementById('edit-details-role-id')?.value;
      if (!roleId) return;
      const errEl     = document.getElementById('edit-details-error');
      const confirmEl = document.getElementById('edit-details-confirm');
      const saveBtn   = document.getElementById('btn-save-edit-details');
      if (errEl) errEl.classList.add('hidden');
      if (confirmEl) confirmEl.textContent = '';
      if (saveBtn) { saveBtn.disabled = true; saveBtn.textContent = 'Saving…'; }

      try {
        const _engType        = document.getElementById('edit-engagement-type')?.value  || null;
        const _ir35Status     = document.getElementById('edit-ir35-status')?.value      || null;
        const _dayRateText    = document.getElementById('edit-day-rate')?.value.trim()  || null;
        const _contractLength = document.getElementById('edit-contract-length')?.value.trim() || null;
        const _startTimeline  = document.getElementById('edit-start-timeline')?.value   || null;
        const _locationText   = document.getElementById('edit-location')?.value.trim()  || null;
        const _workModel      = document.getElementById('edit-work-model')?.value        || null;
        const _source         = document.getElementById('edit-source')?.value           || null;
        const _jobUrl         = document.getElementById('edit-job-url')?.value.trim()   || null;

        const { error } = await db.from('roles').update({
          engagement_type:  _engType,
          ir35_status:      _ir35Status,
          day_rate_text:    _dayRateText,
          contract_length:  _contractLength,
          start_timeline:   _startTimeline,
          location_text:    _locationText,
          work_model:       _workModel,
          source:           _source,
          job_url:          _jobUrl,
        }).eq('id', roleId);
        if (error) throw error;

        // Update in-memory role object so the UI refreshes without a full reload
        const _roleIdx = allRoles.findIndex(r => r.id === roleId);
        if (_roleIdx >= 0) {
          allRoles[_roleIdx].engagement_type  = _engType;
          allRoles[_roleIdx].ir35_status      = _ir35Status;
          allRoles[_roleIdx].day_rate_text    = _dayRateText;
          allRoles[_roleIdx].contract_length  = _contractLength;
          allRoles[_roleIdx].start_timeline   = _startTimeline;
          allRoles[_roleIdx].location_text    = _locationText;
          allRoles[_roleIdx].work_model       = _workModel;
          allRoles[_roleIdx].source           = _source;
          allRoles[_roleIdx].job_url          = _jobUrl;
        }

        if (confirmEl) {
          confirmEl.textContent = 'Saved.';
          setTimeout(() => { if (confirmEl) confirmEl.textContent = ''; }, 2500);
        }

        // Re-render the role detail so changes are immediately visible
        const _updatedRole = allRoles.find(r => r.id === roleId);
        if (_updatedRole) {
          renderRoleDoc(_updatedRole);
          renderRoleList();
        }
        closeEditRoleModal();
      } catch (e) {
        if (errEl) { errEl.textContent = e.message || 'Save failed.'; errEl.classList.remove('hidden'); }
      } finally {
        if (saveBtn) { saveBtn.disabled = false; saveBtn.textContent = 'Save changes'; }
      }
    }

    // ─── Profile preferences persistence ──────────────────────────────────────
    async function loadOrCreateProfile() {
      // Try to fetch the single existing profile row
      const { data, error } = await db
        .from('profiles')
        .select('id, preferences_json')
        .limit(1)
        .maybeSingle();
      if (error) throw error;
      if (data) return data;

      // No profile yet — create one with default values
      const defaults = {
        work_model:    'unsure',
        location:      '',
        contract_type: 'either',
        hard_rules:    { production_coding_hard_no: false },
      };
      const { data: created, error: createErr } = await db
        .from('profiles')
        .insert({ preferences_json: defaults })
        .select('id, preferences_json')
        .single();
      if (createErr) throw createErr;
      return created;
    }

    function fillPreferencesForm(prefs) {
      if (!prefs) return;

      // Identity
      const nameEl = document.getElementById('pref-display-name');
      if (nameEl) nameEl.value = prefs.display_name || '';

      // Profile page avatar initials
      const _ppInitialsEl = document.getElementById('profile-page-initials');
      if (_ppInitialsEl) {
        const _n = prefs.display_name || '';
        if (_n.trim()) {
          const _p = _n.trim().split(/\s+/);
          _ppInitialsEl.textContent = _p.length >= 2
            ? (_p[0][0] + _p[_p.length - 1][0]).toUpperCase()
            : _p[0].slice(0, 2).toUpperCase();
        } else {
          _ppInitialsEl.textContent = '?';
        }
      }

      // Work model radio
      const wmVal = prefs.work_model || 'unsure';
      const wmEl  = document.querySelector(`input[name="pref-work-model"][value="${wmVal}"]`);
      if (wmEl) wmEl.checked = true;

      // Location text
      const locEl = document.getElementById('pref-location');
      if (locEl) locEl.value = prefs.location || '';

      // Role preference free-text note
      const noteEl = document.getElementById('pref-role-note');
      if (noteEl) noteEl.value = prefs.role_preference_note || '';

      // Contract type radio
      const ctVal = prefs.contract_type || 'either';
      const ctEl  = document.querySelector(`input[name="pref-contract"][value="${ctVal}"]`);
      if (ctEl) ctEl.checked = true;

      // Hard rule checkbox
      const noCodingEl = document.querySelector('input[name="pref-rule-no-coding"]');
      if (noCodingEl) noCodingEl.checked = !!(prefs.hard_rules?.production_coding_hard_no);

      // Contract baseline fields
      const drEl = document.getElementById('pref-day-rate');
      if (drEl && prefs.day_rate) drEl.value = prefs.day_rate;

      const ir35Val = prefs.ir35_status || 'na';
      const ir35El  = document.querySelector(`input[name="pref-ir35"][value="${ir35Val}"]`);
      if (ir35El) ir35El.checked = true;

      const dpmEl = document.getElementById('pref-days-per-month');
      if (dpmEl && prefs.days_per_month) dpmEl.value = prefs.days_per_month;
    }

    async function savePreferences() {
      const errEl     = document.getElementById('pref-save-error');
      const confirmEl = document.getElementById('pref-save-confirm');
      const saveBtn   = document.getElementById('btn-save-prefs');

      if (errEl)     errEl.classList.add('hidden');
      if (confirmEl) confirmEl.textContent = '';
      if (saveBtn)   { saveBtn.disabled = true; saveBtn.textContent = 'Saving…'; }

      try {
        // Build the JSON object from current form state
        const _rawDayRate  = parseFloat(document.getElementById('pref-day-rate')?.value);
        const _rawDpm      = parseFloat(document.getElementById('pref-days-per-month')?.value);
        const preferences_json = {
          display_name:  document.getElementById('pref-display-name')?.value.trim() || '',
          work_model:    document.querySelector('input[name="pref-work-model"]:checked')?.value || 'unsure',
          location:      document.getElementById('pref-location')?.value.trim() || '',
          contract_type: document.querySelector('input[name="pref-contract"]:checked')?.value || 'either',
          hard_rules: {
            production_coding_hard_no: !!(document.querySelector('input[name="pref-rule-no-coding"]')?.checked),
          },
          // Contract baseline
          day_rate:       (_rawDayRate > 0) ? _rawDayRate : null,
          ir35_status:    document.querySelector('input[name="pref-ir35"]:checked')?.value || 'na',
          days_per_month: (_rawDpm > 0) ? _rawDpm : 20,
          // Free-text role preference note
          role_preference_note: document.getElementById('pref-role-note')?.value || '',
        };

        // Retrieve the profile id stored in the hidden element
        const profileId = document.getElementById('pref-profile-id')?.dataset.id;
        if (!profileId) throw new Error('Profile not loaded — try reloading the view.');

        const { error } = await db
          .from('profiles')
          .update({ preferences_json, updated_at: new Date().toISOString() })
          .eq('id', profileId);
        if (error) throw error;

        // Update in-memory profile so renderCompensationContext reflects new values immediately
        userProfile = preferences_json;

        // Update profile nav row (initials + name) when display_name changes
        const _nameForInitials = preferences_json.display_name || '';
        const _initialsEl = document.getElementById('nav-profile-initials');
        if (_initialsEl) {
          if (_nameForInitials) {
            const _parts = _nameForInitials.trim().split(/\s+/);
            _initialsEl.textContent = _parts.length >= 2
              ? (_parts[0][0] + _parts[_parts.length - 1][0]).toUpperCase()
              : _parts[0].slice(0, 2).toUpperCase();
          } else {
            _initialsEl.textContent = 'P';
          }
        }
        const _navNameEl = document.getElementById('nav-profile-name');
        if (_navNameEl) _navNameEl.textContent = _nameForInitials || 'Profile';

        if (confirmEl) {
          confirmEl.textContent = 'Saved.';
          setTimeout(() => { if (confirmEl) confirmEl.textContent = ''; }, 2500);
        }
      } catch (e) {
        if (errEl) { errEl.textContent = e.message || 'Save failed.'; errEl.classList.remove('hidden'); }
      } finally {
        if (saveBtn) { saveBtn.disabled = false; saveBtn.textContent = 'Save preferences'; }
      }
    }

